# ── Login rate-limiting (in-memory, resets on restart) ──────────────────────
_LOGIN_ATTEMPTS: dict = defaultdict(list)   # email → [epoch timestamps]
_LOGIN_MAX       = 5        # max failures before lockout
_LOGIN_WINDOW    = 900      # 15-minute sliding window (seconds)

def _rl_allowed(email: str) -> bool:
    """Return True if this email is NOT rate-limited."""
    now = time.time()
    _LOGIN_ATTEMPTS[email] = [t for t in _LOGIN_ATTEMPTS[email] if now - t < _LOGIN_WINDOW]
    return len(_LOGIN_ATTEMPTS[email]) < _LOGIN_MAX

def _rl_record_failure(email: str):
    _LOGIN_ATTEMPTS[email].append(time.time())

def _rl_clear(email: str):
    _LOGIN_ATTEMPTS.pop(email, None)

# ── Audit log ────────────────────────────────────────────────────────────────
_AUDIT_PATH = Path(__file__).resolve().parent.parent / "audit.log"

def _audit(action: str, user: str, ip: str, ok: bool, detail: str = ""):
    entry = {
        "ts":     datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ"),
        "action": action,
        "user":   user,
        "ip":     ip,
        "ok":     ok,
        "detail": detail,
    }
    try:
        with open(_AUDIT_PATH, "a") as f:
            f.write(json.dumps(entry) + "\n")
    except Exception:
        pass

# ── Demo-mode LP anonymisation ────────────────────────────────────────────
_GREEK_LABELS = [
    "Alpha", "Beta", "Gamma", "Delta", "Epsilon", "Zeta", "Eta", "Theta",
    "Iota", "Kappa", "Lambda", "Mu", "Nu", "Xi", "Omicron", "Pi",
    "Rho", "Sigma", "Tau", "Upsilon", "Phi", "Chi", "Psi", "Omega",
]

def _demo_label(idx: int) -> str:
    """Return 'LP Alpha', 'LP Beta', …, 'LP Alpha 2', … deterministically."""
    cycle = idx % len(_GREEK_LABELS)
    generation = idx // len(_GREEK_LABELS)
    suffix = f" {generation + 1}" if generation > 0 else ""
    return f"LP {_GREEK_LABELS[cycle]}{suffix}"

def _anonymize_users_for_demo(users: list[dict]) -> list[dict]:
    """Replace LP names/emails with deterministic anonymous labels.

    Only anonymises lp-role accounts. Admins/GPs keep their names
    (the demo account itself and the GP are visible as-is).
    Sort is by lp_id for determinism across reloads.
    """
    lp_users = sorted([u for u in users if u.get("role") == "lp"], key=lambda u: u.get("lp_id", ""))
    label_map = {u["lp_id"]: _demo_label(i) for i, u in enumerate(lp_users)}
    out = []
    for u in users:
        u2 = dict(u)
        if u2.get("role") == "lp":
            label = label_map.get(u2["lp_id"], "LP —")
            u2["name"]  = label
            u2["email"] = "—"
            # Keep fund_memberships keys (fund names) but blank the alias values
            u2["fund_memberships"] = {k: "" for k in (u2.get("fund_memberships") or {})}
        out.append(u2)
    return out

def _anonymize_lp_roster_for_demo(lps: list[dict]) -> list[dict]:
    """Anonymise the per-fund LP roster (legal_name, primary_email fields).

    lps is the raw DB list from the fund detail endpoint.
    Sort deterministically by 'id'.
    """
    sorted_lps = sorted(lps, key=lambda l: str(l.get("id", "")))
    out = []
    for i, lp in enumerate(sorted_lps):
        lp2 = dict(lp)
        lp2["legal_name"]    = _demo_label(i)
        lp2["primary_email"] = "—"
        out.append(lp2)
    return out

def _acct_demo_label(idx: int) -> str:
    """Return 'Acct Alpha', 'Acct Beta', … for managed accounts."""
    cycle = idx % len(_GREEK_LABELS)
    generation = idx // len(_GREEK_LABELS)
    suffix = f" {generation + 1}" if generation > 0 else ""
    return f"Acct {_GREEK_LABELS[cycle]}{suffix}"

def _build_acct_label_map(fund_ids: list) -> dict:
    """Build a deterministic {fund_id: label} map for managed accounts.

    Sorted by fund_id string for stability across reloads.
    """
    sorted_ids = sorted([str(fid) for fid in fund_ids])
    return {fid: _acct_demo_label(i) for i, fid in enumerate(sorted_ids)}

# ── Global NaN / Inf guard ───────────────────────────────────────────────────
# Monkey-patch starlette's JSONResponse.render so that NaN/Inf floats
# (common from yfinance when a stock has no data) are silently converted to
# null instead of crashing with "Out of range float values are not JSON
# compliant: nan".  Patching the class directly — rather than setting
# app.router.default_response_class — ensures ALL responses are covered,
# including explicit JSONResponse(...) calls inside endpoint handlers.
def _nan_safe_render(self, content) -> bytes:
    def _s(o):
        if isinstance(o, float) and (math.isnan(o) or math.isinf(o)):
            return None
        if isinstance(o, dict):
            return {k: _s(v) for k, v in o.items()}
        if isinstance(o, list):
            return [_s(v) for v in o]
        return o
    return json.dumps(_s(content), ensure_ascii=False,
                      allow_nan=False, separators=(",", ":")).encode("utf-8")

import starlette.responses as _sr
_sr.JSONResponse.render = _nan_safe_render  # type: ignore[method-assign]

