# ── Unified live-quote cache (TTL: 10 min) ────────────────────────────────────
# Shared by _fetch_prices() and batch_quotes() — any endpoint that fetches price
# data for a ticker warms the cache for ALL other endpoints.  No duplicate
# yfinance HTTP requests for the same symbol within _QUOTE_TTL seconds.
# Format: { symbol: {"price": float|None, "pct_change": float|None, "_ts": float} }
_QUOTE_CACHE: dict = {}
# Short TTL so watchlist / mobile day-change stays near live (was 10 min and
# often served wrong multi-ticker yfinance closes + bad day-over-day %).
_QUOTE_TTL = 90    # seconds

# Cache for information_schema column checks (avoid slow system-table hits per request)
_col_exists_cache: dict = {}   # { "table.column": bool }

# ── Per-user response cache for hot read endpoints (TTL: 25 sec) ─────────────
# Keyed by (endpoint, user_id, role). On a fresh reload the cached JSON is
# returned instantly — no DB queries, no yfinance calls. Mutating endpoints
# (NAV save, CSV upload, etc.) call _invalidate_user_cache() to flush.
_user_resp_cache: dict = {}   # { key_tuple: (payload, fetched_at) }
_USER_RESP_TTL   = 25         # seconds


def _request_json_sync(request):
    """Parse the JSON body from a SYNC (threadpool) endpoint.

    Part of the async→def sweep (ui336): endpoints doing blocking work
    (psycopg2, yfinance, SnapTrade, Anthropic) were `async def`, which froze
    the whole event loop — every concurrent request — for the duration. As
    sync `def` they run in the threadpool, but can't `await request.json()`;
    anyio.from_thread runs the coroutine on the event loop from the worker.
    Returns {} on an empty/invalid body, matching the try/except-{} pattern
    the call sites used.
    """
    import anyio
    try:
        return anyio.from_thread.run(request.json)
    except Exception:
        return {}


def _request_body_sync(request):
    """Raw body bytes from a SYNC (threadpool) endpoint — see _request_json_sync."""
    import anyio
    try:
        return anyio.from_thread.run(request.body)
    except Exception:
        return b""


def _user_cache_get(key: tuple):
    hit = _user_resp_cache.get(key)
    if not hit: return None
    payload, ts = hit
    if (time.time() - ts) > _USER_RESP_TTL:
        _user_resp_cache.pop(key, None)
        return None
    return payload

def _user_cache_put(key: tuple, payload):
    _user_resp_cache[key] = (payload, time.time())

def _invalidate_user_cache(user_id: str | None = None):
    """Drop cached responses. If user_id is None, flush everything."""
    if user_id is None:
        _user_resp_cache.clear()
        return
    for k in list(_user_resp_cache.keys()):
        if len(k) >= 2 and k[1] == user_id:
            _user_resp_cache.pop(k, None)

# ── Ticker alias / ignore dictionary ─────────────────────────────────────────
# Hard-coded fallbacks that survive deploys. The kv_store layer on top allows
# runtime edits; these are the boot-time defaults.
#
# _TICKER_ALIASES : {fidelity_symbol → yahoo_symbol}   (e.g. BRKB → BRK-B)
# _TICKER_IGNORE  : {symbol → reason_string}            (e.g. EM50 → "portfolio name")
#   Ignored symbols are skipped by _fetch_prices and treated as cost-basis only.
#
# Bond detection rule (no entry needed in the dict):
#   Any symbol whose first character is a digit after stripping leading '$'
#   is a CUSIP/bond identifier (e.g. 36966TKX9, $36966TKX9).
#   These are priced at cost basis — never sent to Yahoo Finance.

_TICKER_ALIASES: dict[str, str] = {
    # Berkshire Hathaway class B
    "BRKB":   "BRK-B",
    # Annaly Capital preferred F  (Fidelity: NLYPRF, Yahoo: NLY-PF)
    "NLYPRF": "NLY-PF",
    # Flagstar preferred A (Fidelity: FLGPRA, SnapTrade: FLG.PA, Yahoo: FLG-PA)
    "FLGPRA": "FLG-PA",
    "FLG.PA": "FLG-PA",
    # Add more as needed — key = as-imported, value = Yahoo symbol
}

_TICKER_IGNORE: dict[str, str] = {
    # Portfolio / sleeve names that appear as ticker-column values in Fidelity exports
    "EM50":  "portfolio_name",
    "$EM50": "portfolio_name",
    # Bonds: handled by _is_bond_cusip() at fetch time; listed here only as docs
}

# ── Scan exclusion list ───────────────────────────────────────────────────────
# Tickers skipped by ALL scan endpoints (/api/scan, /api/scan/reports, single-ticker).
# Reasons:
#   alias    — symbol maps to a different Yahoo symbol; scanner would fail/waste time
#   etf      — ETF with no meaningful analyst coverage
#   preferred — preferred stock; use the common share instead
_SCAN_EXCLUDE: dict[str, str] = {
    # Alias mismatches — Yahoo uses a different symbol; price fetch handles this but
    # the scan (which uses the raw ticker string) would stall or return garbage.
    "BRKB":   "alias",   # Yahoo: BRK-B — use BRKB only for price, not scan
    # ETFs
    "SRLN":   "etf",
    "BKLN":   "etf",
    # Preferred stocks — Fannie Mae / Freddie Mac; use FNMA / FMCC commons instead
    "FNMAP":  "preferred",
    "FMCCS":  "preferred",
    "FMCCN":  "preferred",
    "FMCKI":  "preferred",
    "FMCCM":  "preferred",
    "FMCKM":  "preferred",
    "FMCCJ":  "preferred",
    # Other preferred stocks
    "FLGPRA": "preferred",
    "NLYPRF": "preferred",
}

def _filter_scan_tickers(tickers: list[str]) -> list[str]:
    """Remove tickers that should not be scanned (aliases, ETFs, preferreds).
    Also strips any trailing '*' Fidelity adds to restricted symbols."""
    out = []
    for t in tickers:
        clean = t.strip().upper().rstrip("*")
        if clean in _SCAN_EXCLUDE:
            print(f"[scan-filter] skipping {clean} ({_SCAN_EXCLUDE[clean]})")
            continue
        out.append(clean)
    return out


def _is_bond_cusip(sym: str) -> bool:
    """Return True if sym looks like a CUSIP/bond identifier rather than an equity.

    Rule: after stripping a leading '$', if the first character is a digit the
    symbol is a fixed-income CUSIP (e.g. 36966TKX9, $912810RR7).  These are
    priced at cost basis — Yahoo Finance won't have them.
    """
    clean = sym.lstrip("$").rstrip("*")
    return bool(clean) and clean[0].isdigit()


def _ticker_should_ignore(sym: str) -> bool:
    """Return True if this symbol should be completely skipped (no pricing, no display)."""
    clean = sym.rstrip("*")
    return clean.upper() in _TICKER_IGNORE or clean.lstrip("$").upper() in _TICKER_IGNORE


def _resolve_ticker_alias(sym: str) -> str:
    """Return the Yahoo-compatible symbol for sym, applying alias map first.
    Generic rule: SnapTrade's dot-preferred form "XXX.PY" → Yahoo "XXX-PY"
    (e.g. FLG.PA → FLG-PA). US brokerage context — these are preferreds, not
    Paris listings."""
    clean = sym.rstrip("*")
    hit = _TICKER_ALIASES.get(clean.upper(), _TICKER_ALIASES.get(clean))
    if hit:
        return hit
    m = re.fullmatch(r"([A-Z]{1,6})\.P([A-Z])", clean.upper())
    if m:
        return f"{m.group(1)}-P{m.group(2)}"
    return clean


def _fetch_prices(symbols: list) -> dict:
    """Return {symbol: last_price | None} for the given list.

    Special cases (money-market funds → $1.00, bond CUSIPs → None, ignored
    tickers → None) are handled here.  Actual yfinance fetching is fully
    delegated to batch_quotes() so both functions share the unified per-ticker
    _QUOTE_CACHE — no duplicate Yahoo HTTP requests for the same ticker within
    _QUOTE_TTL seconds regardless of which endpoint requested it first.
    """
    if not symbols:
        return {}

    MM_FUNDS = ('SPAXX', 'FDRXX', 'SPRXX', 'FZFXX', 'FZDXX')
    out: dict = {}
    need: list = []

    for sym in symbols:
        clean = sym.rstrip('*')
        if _ticker_should_ignore(clean):
            out[sym] = None
            continue
        if _is_bond_cusip(clean):
            out[sym] = None
            continue
        if any(mm in clean.upper() for mm in MM_FUNDS):
            out[sym] = 1.0
            continue
        need.append(sym)

    if need and _YFINANCE_OK:
        raw = batch_quotes(",".join(s.rstrip('*') for s in need))
        for sym in need:
            clean = sym.rstrip('*')
            q = raw.get(clean) or {}
            out[sym] = q.get("price")
    else:
        for sym in need:
            out[sym] = None

    return out


def _fund_market_nav(cur, fid: str) -> float:
    """Return fund NAV = Σ(open_qty × live_price) across all tax_lots.

    Pricing priority:
      1. Live yfinance price (cached 15 min)
      2. Cost-basis fallback when no live price (prevents NAV from going to zero
         on data outages or unlisted securities)

    Money-market positions (asset_class='cash') are priced at $1.00/unit via
    the existing _fetch_prices() logic (SPAXX/FDRXX/SPRXX → 1.0).
    """
    cur.execute("""
        SELECT s.symbol, s.asset_class,
               SUM(tl.quantity)                                       AS total_qty,
               SUM(tl.quantity * tl.cost_basis_per_unit)              AS total_cost,
               SUM(tl.quantity * tl.cost_basis_per_unit)
                 / NULLIF(SUM(tl.quantity), 0)                        AS avg_cost
          FROM tax_lots tl
          JOIN securities s ON s.id = tl.security_id
         WHERE tl.fund_id = %s AND tl.closed_at IS NULL
         GROUP BY s.symbol, s.asset_class
    """, (fid,))
    rows = cur.fetchall()
    if not rows:
        return 0.0

    symbols = [r["symbol"] for r in rows if r["symbol"]]
    prices  = _fetch_prices(symbols)

    total = 0.0
    for r in rows:
        qty      = float(r["total_qty"] or 0)
        avg_cost = float(r["avg_cost"]  or 0)
        sym      = r["symbol"]
        price    = prices.get(sym)
        total   += qty * (price if price is not None else avg_cost)
    return round(total, 2)


def _bulk_fund_market_nav(cur, fids: list) -> dict:
    """Return {fund_id_str: nav_float} for all fund IDs in one SQL query.

    Prices are assumed to be already warmed in _price_cache via a preceding
    _fetch_prices() call.  Falls back to cost-basis per position when a live
    price is unavailable.  Much faster than calling _fund_market_nav() in a loop.
    """
    if not fids:
        return {}

    cur.execute("""
        SELECT tl.fund_id,
               s.symbol,
               s.asset_class,
               SUM(tl.quantity)                                               AS total_qty,
               SUM(tl.quantity * tl.cost_basis_per_unit)
                 / NULLIF(SUM(tl.quantity), 0)                                AS avg_cost
          FROM tax_lots tl
          JOIN securities s ON s.id = tl.security_id
         WHERE tl.fund_id::text = ANY(%s) AND tl.closed_at IS NULL
         GROUP BY tl.fund_id, s.symbol, s.asset_class
    """, (fids,))
    rows = cur.fetchall()

    # Collect all symbols so we can do ONE price fetch for the whole batch
    all_syms = list({r["symbol"] for r in rows if r["symbol"]})
    prices   = _fetch_prices(all_syms)

    totals: dict = {}
    for r in rows:
        fid      = str(r["fund_id"])
        qty      = float(r["total_qty"] or 0)
        avg_cost = float(r["avg_cost"]  or 0)
        sym      = r["symbol"]
        price    = prices.get(sym)
        totals[fid] = round(totals.get(fid, 0.0) + qty * (price if price is not None else avg_cost), 2)

    # Funds with no positions → 0.0
    for fid in fids:
        totals.setdefault(str(fid), 0.0)
    return totals


