@app.get("/api/config/models")
def config_models():
    """Zero-cost: the LLM model ids actually configured right now (live env
    values, not hardcoded strings) PLUS cost estimates computed from the
    pricing tables so UI chips re-price themselves on any model change.
    Pure local math — no API calls, no tokens."""
    g_model = getattr(analyst, "GROK_MODEL", "grok")
    c_model = getattr(analyst, "CLAUDE_MODEL", "claude")
    out = {
        "grok":    g_model,
        "claude":  c_model,
        "agentic": _AGENTIC_MODEL,
        # Option 4 volume harness — never used for full reports / podcast
        "volume":  getattr(analyst, "volume_llm_status", lambda: {})(),
    }
    try:
        # Single-ticker report envelope: ~30-45K input, 6-10K output,
        # 2-4 live searches (Grok only). Claude thinks more → longer output.
        g_lo = analyst.estimate_grok_cost(g_model, 30_000, 6_000, 2)
        g_hi = analyst.estimate_grok_cost(g_model, 45_000, 10_000, 4)
        c_in, c_out = analyst.CLAUDE_PRICING_PER_MTOK.get(c_model, (5.0, 25.0))
        c_lo = (30_000 * c_in + 8_000 * c_out) / 1e6
        c_hi = (45_000 * c_in + 16_000 * c_out) / 1e6
        # Market-pulse per ticker: tiny prompt + ~1-2 searches dominate.
        p_est = analyst.estimate_grok_cost(g_model, 2_500, 700, 1.5)
        # Volume jobs (DeepSeek etc.): much smaller envelopes, no live-search surcharge.
        # Host pricing varies — these are order-of-magnitude UI hints only.
        vol = out.get("volume") or {}
        vol_on = bool(vol.get("enabled"))
        out["est"] = {
            "grok_report":   [round(g_lo, 2), round(g_hi, 2)],
            "claude_report": [round(c_lo, 2), round(c_hi, 2)],
            "both_report":   [round(g_lo + c_lo, 2), round(g_hi + c_hi, 2)],
            "pulse_per_ticker": round(p_est, 3),
            # Daily brief / intel when volume on vs Grok+live
            "daily_brief_volume": [0.01, 0.05],
            "daily_brief_grok":   [round(analyst.estimate_grok_cost(g_model, 8_000, 3_000, 3), 2),
                                   round(analyst.estimate_grok_cost(g_model, 15_000, 6_000, 6), 2)],
            "intel_volume":       [0.02, 0.08],
            "intel_grok":         [round(analyst.estimate_grok_cost(g_model, 10_000, 4_000, 4), 2),
                                   round(analyst.estimate_grok_cost(g_model, 20_000, 8_000, 8), 2)],
            "prioritize_volume":  [0.005, 0.03],
            "prioritize_grok":    [round(analyst.estimate_grok_cost(g_model, 6_000, 1_500, 0), 3),
                                   round(analyst.estimate_grok_cost(g_model, 12_000, 3_000, 0), 2)],
            # Market pulse / per-ticker scan
            "pulse_volume":       [0.002, 0.015],
            "agentic":            [0.05, 0.30],
            "strategist":         [0.30, 1.00],
            "volume_active":      vol_on,
        }
    except Exception:
        pass    # estimates are optional — UI falls back to its static strings
    return out


_VOLUME_KV_KEY = "dga.volume_llm.enabled"


def _load_volume_llm_override_from_db() -> None:
    """Hydrate Settings master + per-job toggles from kv_store."""
    try:
        raw = _kv_get(_VOLUME_KV_KEY)
        if raw is None:
            return
        if isinstance(raw, dict):
            en = raw.get("enabled")
            jobs = raw.get("jobs")
        else:
            en = raw
            jobs = None
        if en is True or en is False:
            analyst.set_volume_llm_runtime(bool(en))
            print(f"[volume-llm] runtime override from DB: enabled={bool(en)}", flush=True)
        if isinstance(jobs, dict):
            analyst.set_volume_llm_jobs(jobs)
            print(f"[volume-llm] job toggles from DB: {analyst.get_volume_llm_jobs()}", flush=True)
    except Exception as e:
        print(f"[volume-llm] load override failed: {e!s:.120}", flush=True)


def _persist_volume_llm_settings() -> None:
    """Write master + per-job map to kv (survives redeploy)."""
    try:
        if analyst.get_volume_llm_runtime() is not None:
            en = bool(analyst.get_volume_llm_runtime())
        else:
            en = bool(analyst.volume_llm_enabled())
        _kv_put(_VOLUME_KV_KEY, {
            "enabled": en,
            "jobs": analyst.get_volume_llm_jobs(),
            "updated_at": _now_pacific().isoformat(),
        })
    except Exception as e:
        print(f"[volume-llm] kv_put failed: {e!s:.120}", flush=True)


