@app.post("/api/config/volume-llm")
def set_volume_llm_config(request: Request):
    """Enable / roll back the volume LLM and/or set per-job toggles.

    Body (any combination):
      { "enabled": true|false }   — master: false = all volume jobs → Grok
      { "jobs": { "daily_brief": true, "intelligence": false, ... } }

    Full reports (Grok + Claude) and podcasts are never affected.
    """
    _claims_or_401(request)
    try:
        body = _request_json_sync(request) or {}
    except Exception:
        body = {}
    if "enabled" not in body and "jobs" not in body:
        raise HTTPException(
            status_code=422,
            detail="Body must include {enabled: bool} and/or {jobs: {job_id: bool}}",
        )
    message_bits = []
    if "enabled" in body:
        enabled = bool(body.get("enabled"))
        analyst.set_volume_llm_runtime(enabled)
        message_bits.append(
            "Volume master ON — jobs use cheap model when their toggle is on."
            if enabled else
            "Volume master OFF — all volume jobs use Grok (premium)."
        )
    if "jobs" in body and isinstance(body.get("jobs"), dict):
        jobs = analyst.set_volume_llm_jobs(body.get("jobs"))
        on = [k for k, v in jobs.items() if v]
        off = [k for k, v in jobs.items() if not v]
        message_bits.append(
            "Jobs on volume: " + (", ".join(on) if on else "none")
            + ((" · on Grok: " + ", ".join(off)) if off else "")
        )
    _persist_volume_llm_settings()
    st = analyst.volume_llm_status()
    enabled = bool(st.get("enabled"))
    return {
        "ok": True,
        "enabled": enabled,
        "jobs": st.get("jobs"),
        "routes": st.get("routes"),
        "model": st.get("model"),
        "configured": st.get("configured"),
        "message": " ".join(message_bits) if message_bits else "Saved.",
        "volume": {
            "enabled": enabled,
            "model": st.get("model"),
            "configured": st.get("configured"),
            "jobs": st.get("jobs"),
            "routes": st.get("routes"),
        },
    }


def _volume_evidence_pack(lp_id: str | None = "anon") -> str:
    """Free facts for volume daily brief (no LLM). Market wire + fund filings."""
    lines: list[str] = []
    try:
        mw = _build_market_wire(limit=10)
        items = (mw or {}).get("items") or []
        if items:
            lines.append("MARKET WIRE (macro RSS, free):")
            for it in items[:10]:
                title = (it.get("title") or "").strip()
                feed = it.get("feed") or it.get("publisher") or ""
                if title:
                    lines.append(f"  · [{feed}] {title}")
    except Exception as e:
        lines.append(f"(market wire unavailable: {e!s:.80})")
    try:
        ff = _build_fund_filings(lp_id or "anon", limit=20, days=14)
        items = (ff or {}).get("items") or []
        if items:
            lines.append("FUND FILINGS (SEC EDGAR, saved-report universe, free):")
            for it in items[:20]:
                lines.append(
                    f"  · {it.get('ticker')} {it.get('form')} filed {it.get('filed')} "
                    f"({it.get('age_days')}d)"
                )
    except Exception as e:
        lines.append(f"(fund filings unavailable: {e!s:.80})")
    return "\n".join(lines)


@app.get("/api/health/data")
def health_data():
    """Data-freshness health for uptime monitors + the GP Data Health card.
    Exposes only booleans and ages (no account values) so it can stay
    unauthenticated and be pinged by any free monitor. Old /health is a
    static ok — useless for 'is my data silently stale?'."""
    out = {"status": "ok", "timestamp": datetime.utcnow().isoformat(),
           "db": False, "schedulers": {}, "snaptrade_age_s": None,
           "market_quotes_age_s": None, "issues": []}
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        out["status"] = "degraded"
        out["issues"].append("database not configured")
        return out
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("SELECT 1")
            out["db"] = True
            try:
                cur.execute("SELECT EXTRACT(EPOCH FROM (now() - max(last_synced_at))) "
                            "FROM snaptrade_accounts WHERE status='active' "
                            "AND account_id NOT LIKE 'demo-%'")
                r = cur.fetchone()
                if r and r[0] is not None:
                    out["snaptrade_age_s"] = int(float(r[0]))
            except Exception:
                pass
            try:
                cur.execute("SELECT EXTRACT(EPOCH FROM (now() - max(updated_at))) FROM market_quotes")
                r = cur.fetchone()
                if r and r[0] is not None:
                    out["market_quotes_age_s"] = int(float(r[0]))
            except Exception:
                pass
    except Exception as e:
        out["status"] = "degraded"
        out["issues"].append(f"db: {e!s:.120}")
        return out
    try:
        _auto_cfg = _get_automation_settings()
    except Exception:
        _auto_cfg = {}
    for job in ("daily_brief", "market_pulse", "snaptrade_sync"):
        try:
            rec = _kv_get(f"automation.last_run.{job}") or {}
        except Exception:
            rec = {}
        _enabled = bool((_auto_cfg.get(job) or {}).get("enabled"))
        out["schedulers"][job] = {"last_ts": rec.get("ts"), "ok": rec.get("ok"),
                                  "detail": (rec.get("detail") or "")[:200],
                                  "enabled": _enabled}
        # Only an ENABLED job's failure degrades health — a disabled job that
        # never ran (Alec keeps the AI jobs off) is a choice, not a problem.
        if _enabled and rec and rec.get("ok") is False:
            out["issues"].append(f"{job}: last run failed")
    # SnapTrade data older than 36h with the daily sync enabled = silently stale.
    try:
        st_enabled = _get_automation_settings().get("snaptrade_sync", {}).get("enabled")
        if st_enabled and out["snaptrade_age_s"] and out["snaptrade_age_s"] > 36 * 3600:
            out["issues"].append("snaptrade holdings stale (>36h)")
    except Exception:
        pass
    if out["issues"]:
        out["status"] = "degraded"
    return out


