def _get_benchmark_annual_from_db(benchmark_key: str, years: list) -> dict:
    """Return {year: return_pct} from the benchmark_annual_returns DB table.
    Returns only years that exist in the table."""
    if not _PSYCOPG2_OK or not os.environ.get("DATABASE_URL"):
        return {}
    try:
        conn = _fund_conn()
        with conn.cursor() as cur:
            cur.execute(
                """SELECT year, return_pct FROM benchmark_annual_returns
                    WHERE benchmark_key = %s AND year = ANY(%s)""",
                (benchmark_key, years),
            )
            return {row[0]: float(row[1]) for row in cur.fetchall()}
    except Exception:
        return {}


# YTD cache for the current (in-progress) year — 15-minute TTL so it stays fresh
# keyed by benchmark_key → (return_pct, fetched_at)
_ytd_bmark_cache: dict = {}
_YTD_BMARK_TTL = 900  # seconds


def _get_ytd_benchmark_return(benchmark_key: str) -> Optional[float]:
    """Fetch YTD return for *benchmark_key* for the current calendar year.

    Uses daily closes: first trading day of year → latest available close.
    Results are cached for 15 minutes. Returns None if yfinance unavailable
    or the fetch fails.
    """
    import datetime as _dt
    if not _YFINANCE_OK:
        return None
    defn = _BENCHMARK_DEFS.get(benchmark_key)
    if not defn:
        return None

    now = time.time()
    cached = _ytd_bmark_cache.get(benchmark_key)
    if cached and (now - cached[1]) < _YTD_BMARK_TTL:
        return cached[0]

    year = _dt.date.today().year
    start_of_year = f"{year}-01-01"
    total_w, total_r = 0.0, 0.0
    for ticker, weight in defn["tickers"]:
        try:
            hist = _builder_call_timeout(
                lambda tk=ticker: yf.Ticker(tk).history(start=start_of_year, interval="1d"),
                8.0, None)
            if hist is None or hist.empty:
                continue
            first_close = float(hist["Close"].iloc[0])
            last_close  = float(hist["Close"].iloc[-1])
            ytd = (last_close / first_close - 1) * 100
            total_r += ytd * weight
            total_w += weight
        except Exception:
            continue

    if total_w > 0:
        result = round(total_r / total_w, 2)
        _ytd_bmark_cache[benchmark_key] = (result, now)
        return result
    return None


def _get_benchmark_annual(benchmark_key: str, years: list) -> dict:
    """Return {year: return_pct} for the given benchmark and years.

    Strategy (Option C hybrid):
      - Historical years (≤ 2025): DB first (curated/verified data seeded at startup),
        falls back to in-memory curated dict if DB unavailable.
      - Current year (2026): YTD from daily closes (first trading day → latest),
        cached for 15 minutes so the column stays fresh without hammering Yahoo.
    """
    if not years:
        return {}
    defn = _BENCHMARK_DEFS.get(benchmark_key)
    if not defn:
        return {}

    import datetime as _dt
    current_year = _dt.date.today().year
    HISTORICAL_CUTOFF = current_year - 1  # everything before this year is historical

    historical_years = [yr for yr in years if yr <= HISTORICAL_CUTOFF]
    live_years       = [yr for yr in years if yr >  HISTORICAL_CUTOFF]

    result: dict[int, float] = {}

    # ── Historical: DB → in-memory curated fallback ───────────────────────────
    if historical_years:
        db_result = _get_benchmark_annual_from_db(benchmark_key, historical_years)
        result.update(db_result)
        curated = _CURATED_BENCHMARK_RETURNS.get(benchmark_key, {})
        for yr in historical_years:
            if yr not in result and yr in curated:
                result[yr] = curated[yr][0]

    # ── Live: YTD daily-close calculation for the current year ────────────────
    for yr in live_years:
        ytd = _get_ytd_benchmark_return(benchmark_key)
        if ytd is not None:
            result[yr] = ytd

    return result


@app.get("/api/market/spy-ytd")
def get_spy_ytd():
    """Return S&P 500 (SPY) year-to-date return % in real-time from Yahoo Finance.

    Cached for 15 minutes so rapid page reloads don't hammer Yahoo.
    Returns:
        ytd_pct     — YTD return as a decimal percentage (e.g. -4.37)
        first_close — SPY closing price on the first trading day of the year
        last_close  — SPY closing price on the most recent trading day
        as_of       — date string of the last_close bar (YYYY-MM-DD)
    """
    import datetime as _dt

    now = time.time()
    cached = _spy_ytd_cache.get("ts")
    if cached and (now - cached) < _SPY_YTD_TTL:
        return {k: v for k, v in _spy_ytd_cache.items() if k != "ts"}

    if not _YFINANCE_OK:
        raise HTTPException(status_code=503, detail="yfinance not installed on this server")

    try:
        start_of_year = _dt.date(_dt.date.today().year, 1, 1).isoformat()
        hist = _builder_call_timeout(
            lambda: yf.Ticker("SPY").history(start=start_of_year, interval="1d"),
            8.0, None)
        if hist is None or hist.empty:
            raise ValueError("Empty history returned for SPY")
        first_close = float(hist["Close"].iloc[0])
        last_close  = float(hist["Close"].iloc[-1])
        ytd_pct     = round((last_close / first_close - 1) * 100, 2)
        as_of       = str(hist.index[-1].date())
        result = {
            "ytd_pct":     ytd_pct,
            "first_close": round(first_close, 2),
            "last_close":  round(last_close, 2),
            "as_of":       as_of,
        }
        _spy_ytd_cache.update({**result, "ts": now})
        return result
    except HTTPException:
        raise
    except Exception as exc:
        # Return stale cache if available rather than erroring
        if cached:
            return {k: v for k, v in _spy_ytd_cache.items() if k != "ts"}
        raise HTTPException(status_code=503, detail=f"SPY YTD fetch failed: {exc}")


@app.get("/api/benchmark-annual")
def get_benchmark_annual(key: str = "sp500", years: str = ""):
    """Return stored annual returns for *key* benchmark for the given *years*.

    Query params:
      key   — benchmark key (sp500 | dow30 | nasdaq | msci_world | bonds | 60_40 | 85_15)
      years — comma-separated list of years, e.g. "2020,2021,2022"

    Returns:
      { ok: true, key, label, returns: { "2020": 18.40, "2021": 28.71, ... } }

    Historical years (≤ 2025) are served from the DB (curated data seeded at startup).
    2026+ are fetched live from yfinance and cached for the process lifetime.
    No auth required — this is public index data.
    """
    if key not in _BENCHMARK_DEFS:
        raise HTTPException(400, f"Unknown benchmark key: {key}")

    try:
        year_list = [int(y.strip()) for y in years.split(",") if y.strip().isdigit()]
    except Exception:
        year_list = []

    if not year_list:
        raise HTTPException(400, "Provide at least one year via ?years=2020,2021,...")

    returns_map = _get_benchmark_annual(key, year_list)
    return {
        "ok":      True,
        "key":     key,
        "label":   _BENCHMARK_DEFS[key]["label"],
        "returns": {str(yr): v for yr, v in returns_map.items()},
    }


# ── Per-ticker sector + recent headline (for rebalance table columns) ─────────
_ticker_meta_cache: dict[str, dict] = {}   # ticker → {"sector", "industry", "recent_dev", "ts"}
_TICKER_META_TTL = 900                     # 15 min — same as price/SPY caches


_STOCK_INFO_CACHE: dict[str, tuple[float, dict]] = {}


@app.get("/api/stock-info/{ticker}")
def get_stock_info(ticker: str):
    """FREE (zero-LLM) one-stop stock snapshot for the positions expander:
    quote + meta + 52-week stats + latest-fiscal-year fundamentals + derived
    valuation ratios + saved-report pointer. Everything comes from the local
    market-data store and company_financials — no external calls, no tokens.
    Cached 120s per ticker."""
    tk = (ticker or "").strip().upper()
    if not tk or len(tk) > 12:
        raise HTTPException(status_code=422, detail="Invalid ticker")
    hit = _STOCK_INFO_CACHE.get(tk)
    if hit and time.time() - hit[0] < 120:
        return hit[1]
    out: dict = {"ticker": tk}
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return out
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            alias = _resolve_ticker_alias(tk)
            cur.execute("SELECT price, prev_close, pct_change, realized_vol, updated_at "
                        "FROM market_quotes WHERE symbol IN (%s, %s) "
                        "ORDER BY updated_at DESC LIMIT 1", (tk, alias))
            q = cur.fetchone()
            if q:
                out["quote"] = {
                    "price": q["price"], "prev_close": q["prev_close"],
                    "pct_change": q["pct_change"], "realized_vol": q["realized_vol"],
                    "as_of": q["updated_at"].isoformat() if q["updated_at"] else None,
                }
            cur.execute("SELECT name, sector, industry, analyst_target "
                        "FROM security_meta WHERE symbol IN (%s, %s) LIMIT 1", (tk, alias))
            m = cur.fetchone()
            if m:
                out["meta"] = dict(m)
            # 52-week stats + weekly sparkline from the price store.
            cur.execute("""
                SELECT d, close FROM price_history
                 WHERE symbol IN (%s, %s) AND d >= (CURRENT_DATE - INTERVAL '370 days')
                 ORDER BY d
            """, (tk, alias))
            bars = [(r["d"], float(r["close"])) for r in cur.fetchall() if r["close"] is not None]
            if bars:
                closes = [c for _, c in bars]
                px_now = (out.get("quote") or {}).get("price") or closes[-1]
                jan1 = [c for (d, c) in bars if d.month == 1 and d.year == datetime.utcnow().year]
                out["range52w"] = {
                    "high": round(max(closes), 2), "low": round(min(closes), 2),
                    "off_high_pct": round((px_now / max(closes) - 1) * 100, 2) if max(closes) else None,
                    "ytd_pct": round((px_now / jan1[0] - 1) * 100, 2) if jan1 and jan1[0] else None,
                    "one_year_pct": round((px_now / closes[0] - 1) * 100, 2) if closes[0] else None,
                }
                # ~weekly points for a small sparkline
                step = max(1, len(bars) // 52)
                out["sparkline"] = [{"d": d.isoformat(), "c": round(c, 2)}
                                    for d, c in bars[::step]][-60:]
            # Latest fiscal-year fundamentals (+ derived ratios).
            cur.execute("""
                SELECT fy, period_end, revenue, net_income, ebitda, diluted_eps,
                       free_cash_flow, operating_cash_flow, gross_margin,
                       operating_margin, net_margin, total_debt, cash,
                       shares_outstanding, stockholders_equity, entity_name
                  FROM company_financials
                 WHERE ticker = %s AND period_type = 'annual'
                 ORDER BY period_end DESC LIMIT 1
            """, (tk,))
            f = cur.fetchone()
            if f:
                fin = {k: (float(v) if isinstance(v, (int, float)) or
                           (v is not None and str(v).replace('.', '', 1).replace('-', '', 1).isdigit())
                           else v) for k, v in dict(f).items()}
                for k in ("revenue", "net_income", "ebitda", "free_cash_flow",
                          "operating_cash_flow", "total_debt", "cash",
                          "shares_outstanding", "stockholders_equity", "diluted_eps",
                          "gross_margin", "operating_margin", "net_margin"):
                    try:
                        fin[k] = float(f[k]) if f[k] is not None else None
                    except (TypeError, ValueError):
                        fin[k] = None
                out["financials"] = fin
                px = (out.get("quote") or {}).get("price")
                sh = fin.get("shares_outstanding")
                eps = fin.get("diluted_eps")
                if px and sh:
                    mcap = px * sh
                    out["derived"] = {
                        "market_cap": round(mcap, 0),
                        "pe": round(px / eps, 1) if eps else None,
                        "fcf_yield_pct": (round(fin["free_cash_flow"] / mcap * 100, 2)
                                          if fin.get("free_cash_flow") else None),
                        "net_cash": (round(fin["cash"] - fin["total_debt"], 0)
                                     if fin.get("cash") is not None and fin.get("total_debt") is not None
                                     else None),
                        "debt_to_equity": (round(fin["total_debt"] / fin["stockholders_equity"], 2)
                                           if fin.get("total_debt") and fin.get("stockholders_equity")
                                           else None),
                    }
            # Saved-report pointer — UI links ONLY when one exists.
            cur.execute("""
                SELECT generated_at, rating, price_target, upside_pct
                  FROM analyst_reports
                 WHERE ticker = %s AND archived IS NOT TRUE AND report_md IS NOT NULL
            """, (tk,))
            r = cur.fetchone()
            out["saved_report"] = ({
                "exists": True,
                "generated_at": r["generated_at"].isoformat() if r["generated_at"] else None,
                "rating": r["rating"],
                "price_target": float(r["price_target"]) if r["price_target"] is not None else None,
                "upside_pct": float(r["upside_pct"]) if r["upside_pct"] is not None else None,
            } if r else {"exists": False})
    except Exception as e:
        out["warning"] = str(e)[:160]

    # Free live enrichment (Yahoo via existing helpers) when local store is thin.
    # Still zero LLM tokens — used by top-bar ticker lookup for any symbol.
    need_quote = not (out.get("quote") or {}).get("price")
    need_meta = not (out.get("meta") or {}).get("name")
    if need_quote or need_meta:
        try:
            if need_quote:
                snap = analyst.fetch_market_snapshot(_resolve_ticker_alias(tk)) or {}
                if snap.get("price") is not None:
                    out["quote"] = {
                        "price": snap.get("price"),
                        "prev_close": snap.get("prev_close") or snap.get("previous_close"),
                        "pct_change": snap.get("pct_change"),
                        "realized_vol": (out.get("quote") or {}).get("realized_vol"),
                        "as_of": _pacific_time_str(),
                        "live": True,
                    }
                    out["live_source"] = "yahoo"
            if need_meta and yf is not None:
                info = _builder_call_timeout(
                    lambda: getattr(yf.Ticker(_resolve_ticker_alias(tk)), "info", {}) or {},
                    8.0, {}) or {}
                name = info.get("longName") or info.get("shortName")
                if name or info.get("sector") or info.get("industry"):
                    out["meta"] = {
                        "name": name or tk,
                        "sector": info.get("sector"),
                        "industry": info.get("industry"),
                        "analyst_target": info.get("targetMeanPrice"),
                    }
                if not out.get("derived"):
                    mcap = info.get("marketCap")
                    pe = info.get("trailingPE") or info.get("forwardPE")
                    if mcap or pe:
                        out["derived"] = {
                            "market_cap": float(mcap) if mcap else None,
                            "pe": round(float(pe), 1) if pe else None,
                            "fcf_yield_pct": None,
                            "net_cash": None,
                            "debt_to_equity": info.get("debtToEquity"),
                        }
                # 52w from live info when store empty
                if not out.get("range52w"):
                    hi = info.get("fiftyTwoWeekHigh")
                    lo = info.get("fiftyTwoWeekLow")
                    px = (out.get("quote") or {}).get("price")
                    if hi and lo:
                        out["range52w"] = {
                            "high": float(hi), "low": float(lo),
                            "off_high_pct": (round((px / float(hi) - 1) * 100, 2)
                                             if px and hi else None),
                            "ytd_pct": None,
                            "one_year_pct": None,
                        }
        except Exception as e:
            out["live_warning"] = str(e)[:120]
    if "saved_report" not in out:
        out["saved_report"] = {"exists": False}
    out["free"] = True
    out["token_cost"] = 0
    _STOCK_INFO_CACHE[tk] = (time.time(), out)
    if len(_STOCK_INFO_CACHE) > 400:
        _STOCK_INFO_CACHE.pop(next(iter(_STOCK_INFO_CACHE)), None)
    return out


@app.get("/api/market/ticker-meta/{ticker}")
def get_ticker_meta(ticker: str):
    """Return sector, industry, and most-recent news headline for *ticker*.

    Cached for 15 minutes.  Used by the rebalance table to fill the
    Category and Recent Development columns via async client-side injection.

    Returns:
        sector     — e.g. "Technology"
        industry   — e.g. "Semiconductors"
        recent_dev — title of the most-recent Yahoo Finance news item, or ""
    """
    t = ticker.strip().upper()
    now = time.time()
    cached = _ticker_meta_cache.get(t)
    if cached and (now - cached["ts"]) < _TICKER_META_TTL:
        return {k: v for k, v in cached.items() if k != "ts"}

    # Sector / industry — analyst module has a robust multi-fallback implementation
    try:
        sector, industry = analyst.fetch_sector_and_industry(t)
    except Exception:
        sector, industry = "Unknown", "Unknown"

    # Most-recent news headline via yfinance
    recent_dev = ""
    news_list: list[dict] = []
    if _YFINANCE_OK:
        try:
            news_items = _builder_call_timeout(lambda: yf.Ticker(t).news or [], 8.0, []) or []
            for item in news_items[:8]:        # fetch up to 8, keep best 5
                # yfinance ≥ 0.2.x wraps fields inside "content" sub-dict
                content = item.get("content") or {}
                title = (
                    item.get("title") or content.get("title") or ""
                ).strip()
                summary = (
                    item.get("summary") or item.get("description")
                    or content.get("summary") or content.get("description") or ""
                ).strip()
                publisher = (
                    item.get("publisher")
                    or (content.get("provider") or {}).get("displayName", "")
                ).strip()
                url = (
                    item.get("link") or item.get("url")
                    or (content.get("canonicalUrl") or {}).get("url", "")
                ).strip()
                pub_ts = item.get("providerPublishTime") or None
                if not title:
                    continue
                news_list.append({
                    "title":     title,
                    "summary":   summary,   # full, untruncated
                    "publisher": publisher,
                    "url":       url,
                    "pub_ts":    pub_ts,    # Unix timestamp or None
                })
                if len(news_list) >= 5:
                    break

            # Compact inline string for the table cell (2 stories, short excerpt)
            snippets: list[str] = []
            for story in news_list[:2]:
                text = story["title"]
                if story["summary"] and story["summary"].lower() != story["title"].lower():
                    first = story["summary"].split(".")[0].strip()
                    excerpt = first if len(first) <= 120 else first[:117] + "…"
                    if excerpt:
                        text += " — " + excerpt
                if story["publisher"]:
                    text += f"  ({story['publisher']})"
                snippets.append(text)
            recent_dev = "  ·  ".join(snippets)
        except Exception:
            pass

    result = {
        "sector":     sector,
        "industry":   industry,
        "recent_dev": recent_dev,   # compact string for the inline cell
        "news":       news_list,    # structured array for the expanded modal
    }
    _ticker_meta_cache[t] = {**result, "ts": now}
    return result


# ── Idea Generator — surface movers ≥ threshold% from user's universe ─────────
# Sources: watchlist ∪ open positions ∪ saved-report tickers.
# Classifies each mover into earnings_today | sector_move | news | unknown.
# Caches per-(user, threshold) for 5 min so repeated tab visits don't refetch.
_IDEA_FEED_CACHE: dict[tuple, dict] = {}   # (lp_id, threshold, limit) → {data, ts}
# Keep short — movers use batch_quotes; long TTL served phantom ±% after quote bugs.
_IDEA_FEED_TTL    = 90                     # seconds
# Show ALL movers, but only EAGERLY enrich (sector + news) the top N by magnitude
# so a big-move day can't fire dozens of slow per-ticker news fetches in the
# request path (the cloud-IP hang trap). Movers beyond the cap still appear;
# their news loads lazily on row-expand via /api/news.
_IDEA_ENRICH_CAP  = 25

_SECTOR_ETF_MAP = {
    "Technology":             "XLK",
    "Energy":                 "XLE",
    "Financial Services":     "XLF",
    "Financial":              "XLF",
    "Financials":             "XLF",
    "Healthcare":             "XLV",
    "Health Care":            "XLV",
    "Consumer Cyclical":      "XLY",
    "Consumer Discretionary": "XLY",
    "Consumer Defensive":     "XLP",
    "Consumer Staples":       "XLP",
    "Industrials":            "XLI",
    "Utilities":              "XLU",
    "Real Estate":            "XLRE",
    "Communication Services": "XLC",
    "Basic Materials":        "XLB",
    "Materials":              "XLB",
}


@app.post("/api/v2/research/prioritize")
def research_prioritize(request: Request, top_n: int = 5):
    """Grok 4.5 pre-screen (Option C — hybrid universe).

    Universe = (today's movers from idea-feed) ∪ (ALL saved-report tickers).
    Each candidate is tagged with a bucket signal that the screener uses
    to balance its picks:
      • bucket='active' → moved ≥2.5% today (action-biased)
      • bucket='stale'  → no big move + last_report_at > 14 days
                          (refresh candidate, not action)
      • bucket='fresh'  → no big move + last_report_at ≤ 14 days
                          (deprioritized — recently analyzed, quiet today)

    Grok 4.5 returns picks ideally mixing buckets so the UI gets a balanced
    "what to refresh / what to react to" list.

    Cost: small structured JSON call (no live search). Override model via
    GROK_SCREEN_MODEL env (default grok-4.5).
    """
    claims = _claims_or_401(request)
    lp_id = claims.get("lp_id") or claims.get("email") or "anon"

    # 1) Movers from idea-feed (the "active" bucket source)
    try:
        feed = research_idea_feed(request, threshold=2.5, limit=80, force=False)
    except Exception as e:
        return JSONResponse({"ok": False, "error": f"universe build failed: {e!s:.200}"},
                            status_code=500)
    movers = (feed or {}).get("movers") or []
    movers_by_tk = {m.get("ticker"): m for m in movers if m.get("ticker")}

    # 2) ALL saved reports (the "stale"/"fresh" bucket source)
    all_reports: list[dict] = []
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT ticker, generated_at, last_attempt_at,
                                      report_date, rating, price_target, upside_pct
                               FROM analyst_reports
                               WHERE archived IS NOT TRUE
                               ORDER BY generated_at DESC""")
                all_reports = cur.fetchall() or []
        except Exception as _e:
            print(f"⚠️ [prioritize] reports query failed: {_e!s:.120}", flush=True)
    reports_by_tk = {r["ticker"]: r for r in all_reports}

    # 3) Build the merged candidate list (deduped by ticker)
    candidate_tickers: set[str] = set(movers_by_tk.keys()) | set(reports_by_tk.keys())
    from datetime import datetime as _dt, timezone as _tz
    now_utc = _dt.now(_tz.utc)

    candidates = []
    for tk in candidate_tickers:
        m   = movers_by_tk.get(tk) or {}
        rep = reports_by_tk.get(tk) or {}

        # Compute report age in days (None if no report)
        gen_at = rep.get("generated_at")
        age_days = None
        if gen_at:
            try:
                if hasattr(gen_at, "tzinfo") and gen_at.tzinfo is None:
                    gen_at = gen_at.replace(tzinfo=_tz.utc)
                age_days = max(0, int((now_utc - gen_at).total_seconds() // 86400))
            except Exception:
                age_days = None

        pct = m.get("pct_change") if m else None
        is_mover = pct is not None and abs(pct) >= 2.5

        # Bucket classification
        if is_mover:
            bucket = "active"
        elif age_days is not None and age_days > 14:
            bucket = "stale"
        else:
            bucket = "fresh"

        candidates.append({
            "ticker":               tk,
            "bucket":               bucket,    # ← key signal for the screener
            "name":                 m.get("name"),
            "sector":               m.get("sector"),
            "pct_change_today":     pct,
            "sector_etf_change":    m.get("sector_etf_change"),
            "reason_class":         m.get("reason_class"),
            "headline_count":       len(m.get("news") or []),
            "top_headline":         ((m.get("news") or [{}])[0] or {}).get("title"),
            "last_report_at":       gen_at.isoformat() if gen_at else None,
            "report_age_days":      age_days,
            "rating":               rep.get("rating"),
            "upside_pct":           float(rep["upside_pct"]) if rep.get("upside_pct") is not None else None,
        })

    if not candidates:
        return {"ok": True, "picks": [], "skipped": [],
                "note": "Nothing in universe — no movers and no saved reports."}

    # Cap considered set to keep input cheap (Grok 4.5 structured triage;
    # going past 100 tickers makes the input prompt bloat without much picking benefit)
    candidates.sort(key=lambda c: (
        0 if c["bucket"] == "active" else
        1 if c["bucket"] == "stale" else
        2,
        -abs(c["pct_change_today"] or 0),
        -(c["report_age_days"] or 0),
    ))
    candidates = candidates[:100]
    bucket_counts = {b: sum(1 for c in candidates if c["bucket"] == b)
                     for b in ("active", "stale", "fresh")}

    _screen_model = getattr(analyst, "GROK_SCREEN_MODEL", None) or "grok-4.5"
    print(f"🎯 [prioritize {lp_id}] {len(candidates)} candidates "
          f"(active={bucket_counts['active']} stale={bucket_counts['stale']} fresh={bucket_counts['fresh']}) → {_screen_model}", flush=True)

    result = analyst.screen_universe(candidates, top_n=top_n)
    if not result.get("ok"):
        return JSONResponse({"ok": False, "error": result.get("error", "screen failed")},
                            status_code=500)
    return {
        "ok":            True,
        "model":         result.get("model"),
        "picks":         result["picks"],
        "skipped":       result["skipped"],
        "considered":    len(candidates),
        "bucket_counts": bucket_counts,
    }


_MARKET_MOVERS_CACHE: dict = {"ts": 0.0, "data": None}
_MARKET_MOVERS_TTL = 180   # 3 min — Yahoo screeners, bounds the request rate


@app.get("/api/market/movers")
def market_movers(request: Request, limit: int = 12, min_price: float = 3.0):
    """The biggest BROAD-MARKET movers today (Yahoo gainers/losers/most-active
    screeners) — ranked by absolute % move, penny stocks filtered. Powers the
    'Today's Movers' card. Cached 3 min. No LLM, no key."""
    _claims_or_401(request)
    now = time.time()
    c = _MARKET_MOVERS_CACHE
    if c["data"] is None or (now - c["ts"]) >= _MARKET_MOVERS_TTL:
        try:
            import market_data as _md
            rows = _md.yahoo_market_movers(min_price=min_price) or []
        except Exception as e:
            return {"ok": False, "movers": [], "error": f"{e!s:.160}"}
        rows.sort(key=lambda m: abs(m.get("pct_change") or 0.0), reverse=True)
        c["data"] = rows
        c["ts"] = now
    return {"ok": True, "as_of": _pacific_time_str(),
            "movers": (c["data"] or [])[: int(limit)]}


@app.get("/api/v2/research/idea-feed")
def research_idea_feed(request: Request, threshold: float = 4.0, limit: int = 60, force: bool = False):
    """Return today's notable movers from the user's universe.

    Universe = watchlist ∪ open positions (tax_lots) ∪ saved-report subjects.
    A mover is any ticker with |today's pct_change| ≥ `threshold` (default 4%).
    Each mover is enriched with:
      • sector and sector-ETF comparison (XLK/XLE/...)
      • headline news items (up to 5 from Yahoo via yfinance)
      • reason_class: 'sector_move' | 'news' | 'unknown'
      • source labels: where it came from in the universe
    """
    claims = _claims_or_401(request)
    lp_id   = claims.get("lp_id") or claims.get("email") or "anon"
    role    = claims.get("role", "lp")
    is_priv = role in ("gp", "admin")

    # Cache key includes the request shape; user-scoped to be safe.
    cache_key = (str(lp_id), float(threshold), int(limit), is_priv)
    cached = _IDEA_FEED_CACHE.get(cache_key)
    # ?force=true bypasses the in-memory TTL cache so the user's manual
    # refresh button actually pulls fresh quotes + news.
    if not force and cached and (time.time() - cached["ts"]) < _IDEA_FEED_TTL:
        return cached["data"]
    if force:
        # Drop stale idea + quote cache so refresh re-pulls live prices
        _IDEA_FEED_CACHE.pop(cache_key, None)
        try:
            # Clear in-process quote cache for a clean re-fetch
            for k in list(_QUOTE_CACHE.keys()):
                _QUOTE_CACHE.pop(k, None)
        except Exception:
            pass
        print(f"[idea-feed] force=true → bypassing caches for {lp_id}", flush=True)

    # ── 1. Build universe ─────────────────────────────────────────────────────
    universe: set[str] = set()
    sources: dict[str, set] = {}

    def _add(tk: str, src: str) -> None:
        if not tk:
            return
        tk = tk.strip().upper().rstrip("*")
        if not tk or not re.fullmatch(r"[A-Z0-9.\-]+", tk):
            return
        universe.add(tk)
        sources.setdefault(tk, set()).add(src)

    # 1a. Watchlist
    try:
        if lp_id and lp_id != "anon":
            for tk in (_wl_get_db(lp_id) or []):
                _add(tk, "watchlist")
    except Exception as _e:
        print(f"[idea-feed] watchlist fetch failed: {_e}")

    # 1b. Saved-report tickers
    try:
        if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("""
                    SELECT DISTINCT ticker FROM analyst_reports
                     WHERE archived IS NOT TRUE
                """)
                for row in cur.fetchall():
                    _add(row[0], "report")
    except Exception as _e:
        print(f"[idea-feed] reports fetch failed: {_e}")

    # 1b2. Daily Brief tickers (from the morning Grok scan) — surfaces names
    # you don't track yet but the brief flagged as worth a look. Tagged with
    # source 'daily_brief' so Prioritize can recognize them as discovery.
    try:
        brief_payload = _kv_get("daily_brief.latest") or {}
        for tk in (brief_payload.get("tickers") or [])[:20]:
            _add(tk, "daily_brief")
    except Exception as _e:
        print(f"[idea-feed] daily-brief fetch failed: {_e}")

    # 1c. Open positions (managed accounts + LP funds — both live in tax_lots)
    try:
        if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""
                    SELECT DISTINCT s.symbol
                      FROM tax_lots tl
                      JOIN securities s ON s.id = tl.security_id
                      JOIN funds      f ON f.id = tl.fund_id
                     WHERE f.status     != 'closed'
                       AND tl.closed_at  IS NULL
                       AND tl.quantity   > 0
                       AND s.asset_class != 'cash'
                """)
                for r in cur.fetchall():
                    _add(r["symbol"] or "", "position")
    except Exception as _e:
        print(f"[idea-feed] positions fetch failed: {_e}")

    if not universe:
        out = {"movers": [], "universe_size": 0, "as_of": _pacific_time_str(),
               "threshold": threshold, "note": "Universe is empty — add to "
                                                "watchlist, save a report, or upload positions."}
        _IDEA_FEED_CACHE[cache_key] = {"data": out, "ts": time.time()}
        return out

    # ── 2. Batch live quotes (price + pct_change) ─────────────────────────────
    try:
        quotes = batch_quotes(",".join(sorted(universe))) or {}
    except Exception as _e:
        return {"movers": [], "universe_size": len(universe),
                "as_of": _pacific_time_str(),
                "error": f"quote fetch failed: {_e}"}

    # ── 3. Movers ≥ |threshold|% — YOUR universe only (watchlist / saved reports
    # / positions). The broad-market biggest movers live on the 'Today's Movers'
    # card instead, so the Idea Generator stays focused on names DGA cares about. ─
    raw_movers: list[dict] = []
    for tk in universe:
        q = quotes.get(tk) or {}
        pct = q.get("pct_change")
        prc = q.get("price")
        if pct is None or prc is None:
            continue
        try:
            pct_f = float(pct)
        except Exception:
            continue
        if abs(pct_f) < float(threshold):
            continue
        raw_movers.append({
            "ticker":     tk,
            "price":      float(prc),
            "pct_change": round(pct_f, 4),
            "abs_change": round(float(prc) * pct_f / 100.0, 2) if prc else None,
            "sources":    sorted(sources.get(tk, ())),
        })

    raw_movers.sort(key=lambda m: abs(m["pct_change"]), reverse=True)
    movers = raw_movers[: int(limit)]

    if not movers:
        out = {"movers": [], "universe_size": len(universe),
               "as_of": _pacific_time_str(), "threshold": threshold,
               "note": f"No tickers moved ≥ ±{threshold}% today in your universe of "
                       f"{len(universe)} symbols."}
        _IDEA_FEED_CACHE[cache_key] = {"data": out, "ts": time.time()}
        return out

    # ── 4. Sector-ETF batch quote (one call covers all 11 sectors) ────────────
    sector_etf_set = set(_SECTOR_ETF_MAP.values())
    try:
        etf_quotes = batch_quotes(",".join(sorted(sector_etf_set))) or {}
    except Exception:
        etf_quotes = {}

    # ── 5. Per-mover enrichment: sector + news + reason classification ────────
    # Defaults for EVERY mover so the full list renders. We only eagerly enrich
    # the top _IDEA_ENRICH_CAP by magnitude (bounds request-path network); the
    # rest keep these defaults and lazy-load news on expand.
    for m in movers:
        m.setdefault("sector", "Unknown")
        m.setdefault("industry", "")
        m.setdefault("news", [])
        m.setdefault("sector_etf", None)
        m.setdefault("sector_pct_change", None)
        m.setdefault("reason_class", "unknown")
        m.setdefault("reason_text", "")
    for m in movers[:_IDEA_ENRICH_CAP]:
        try:
            meta = get_ticker_meta(m["ticker"])   # cached 15 min via _ticker_meta_cache
        except Exception:
            meta = {}
        sector = (meta.get("sector") or "Unknown").strip()
        m["sector"]   = sector
        m["industry"] = meta.get("industry") or ""
        m["news"]     = (meta.get("news") or [])[:5]

        # Sector ETF comparison
        etf = _SECTOR_ETF_MAP.get(sector)
        etf_pct = None
        if etf:
            etf_pct = (etf_quotes.get(etf) or {}).get("pct_change")
            if etf_pct is not None:
                try:
                    etf_pct = float(etf_pct)
                except Exception:
                    etf_pct = None
        m["sector_etf"]        = etf
        m["sector_pct_change"] = round(etf_pct, 4) if etf_pct is not None else None

        # Classify
        reason_class = "unknown"
        reason_text  = ""
        # Sector move: ETF also moved same direction with ≥ 1.5% magnitude
        if (etf_pct is not None
                and abs(etf_pct) >= 1.5
                and (m["pct_change"] * etf_pct) > 0):
            reason_class = "sector_move"
            direction = "tailwind" if m["pct_change"] > 0 else "headwind"
            reason_text = f"{sector} sector {direction} ({etf}: {etf_pct:+.2f}%)"
        elif m["news"]:
            reason_class = "news"
            reason_text  = (m["news"][0].get("title") or "")[:160]
        m["reason_class"] = reason_class
        m["reason_text"]  = reason_text

    out = {
        "movers":        movers,
        "universe_size": len(universe),
        "as_of":         _pacific_time_str(),
        "threshold":     threshold,
        "ttl_seconds":   _IDEA_FEED_TTL,
    }
    _IDEA_FEED_CACHE[cache_key] = {"data": out, "ts": time.time()}
    return out


# ──────────────────────────────────────────────────────────────────────────────
# Builder — sector-weighted basket allocator from saved-report candidates
# ──────────────────────────────────────────────────────────────────────────────
# Candidates come from analyst_reports (must have price_target + upside_pct).
# Sectors come from _ticker_meta_cache (yfinance, 15-min TTL).
# Allocates each user-specified sector weight to the top N candidates within
# that sector, weighted by expected return (with per-stock cap).

_BUILDER_CANDIDATES_CACHE: dict = {"data": None, "ts": 0}
_BUILDER_CANDIDATES_TTL   = 600   # 10 min
_BUILDER_CANDIDATES_DIAG: dict = {}   # last-run diagnostics, surfaced in the API


def _builder_classify_sector(raw_sector: str) -> str:
    """Map yfinance sector strings to canonical labels used by the UI.

    Yahoo uses variations like 'Technology', 'Financial Services', 'Healthcare';
    we normalize so the user's sector weights match candidates predictably.

    Unknown / blank → 'Other' so those candidates aren't silently dropped
    from the Builder pool — they roll up into a selectable 'Other' bucket
    the user can include in any basket allocation.
    """
    if not raw_sector or raw_sector.strip() in ("", "Unknown", "—"):
        return "Other"
    s = raw_sector.strip()
    # Canonicalize a few known variants
    SYN = {
        "Financial Services":  "Financials",
        "Financial":           "Financials",
        "Health Care":         "Healthcare",
        "Consumer Discretionary": "Consumer Cyclical",
        "Consumer Staples":    "Consumer Defensive",
        "Materials":           "Basic Materials",
    }
    return SYN.get(s, s)


# Process-global sector cache so a ticker is resolved at most once per process.
# "" = negative cache (resolved to nothing — don't retry this process).
_BUILDER_SECTOR_CACHE: dict = {}
_BUILDER_SECTOR_RESOLVE_CAP = 40   # max SIC resolves per BACKGROUND run (off the
                                   # request path); persisted so it's a one-time
                                   # cost — a couple Refresh clicks warm the universe
_BUILDER_EDGAR_ID = [False]        # whether edgar set_identity has been called

# Tickers the last pool build couldn't sector from the store, awaiting the
# BACKGROUND resolver (kicked by ?fresh=1). The request path NEVER resolves
# inline — that timed the whole pool out on the cloud IP.
_BUILDER_UNRESOLVED: set = set()
_BUILDER_BG_RESOLVING = [False]    # re-entrancy guard for the background resolver


def _sic_to_sector(s: int):
    """Map an SEC SIC code to a canonical Builder sector. Coarse but real —
    enough to bucket a candidate correctly for sector-weighted allocation."""
    if   100  <= s <= 999:  return "Consumer Defensive"      # agriculture
    elif 1000 <= s <= 1299: return "Basic Materials"         # metal mining
    elif 1300 <= s <= 1399: return "Energy"                  # oil & gas extraction
    elif 1400 <= s <= 1499: return "Basic Materials"         # nonmetallic mining
    elif 1500 <= s <= 1799: return "Industrials"             # construction
    elif 2000 <= s <= 2199: return "Consumer Defensive"      # food & beverage
    elif 2200 <= s <= 2399: return "Consumer Cyclical"       # textiles/apparel
    elif 2400 <= s <= 2599: return "Consumer Cyclical"       # lumber/furniture
    elif 2600 <= s <= 2699: return "Basic Materials"         # paper
    elif 2700 <= s <= 2799: return "Communication Services"  # publishing
    elif 2800 <= s <= 2829: return "Basic Materials"         # industrial chemicals
    elif 2830 <= s <= 2836: return "Healthcare"              # drugs/biotech
    elif 2840 <= s <= 2844: return "Consumer Defensive"      # soap/detergent/cosmetics (PG, CL, EL)
    elif 2845 <= s <= 2899: return "Basic Materials"         # other chemicals
    elif 2900 <= s <= 2999: return "Energy"                  # petroleum refining
    elif 3000 <= s <= 3299: return "Consumer Cyclical"       # rubber/plastics/glass
    elif 3300 <= s <= 3399: return "Basic Materials"         # primary metals
    elif 3400 <= s <= 3569: return "Industrials"             # metal products/machinery
    elif 3570 <= s <= 3579: return "Technology"              # computers
    elif 3580 <= s <= 3669: return "Industrials"             # industrial/electrical
    elif 3670 <= s <= 3699: return "Technology"              # electronics/semiconductors
    elif 3700 <= s <= 3799: return "Consumer Cyclical"       # motor vehicles/aerospace
    elif 3800 <= s <= 3879: return "Healthcare"              # medical/measuring instruments
    elif 3880 <= s <= 3999: return "Industrials"
    elif 4000 <= s <= 4799: return "Industrials"             # transportation
    elif 4800 <= s <= 4899: return "Communication Services"  # telecom
    elif 4900 <= s <= 4999: return "Utilities"
    elif 5000 <= s <= 5199: return "Industrials"             # wholesale
    elif 5200 <= s <= 5299: return "Consumer Cyclical"       # building materials/hardware retail
    elif 5300 <= s <= 5399: return "Consumer Defensive"      # variety/general merch (WMT, TGT, DG)
    elif 5400 <= s <= 5499: return "Consumer Defensive"      # food stores (grocery)
    elif 5500 <= s <= 5899: return "Consumer Cyclical"       # auto/apparel/furniture/dining retail
    elif s == 5912:         return "Consumer Defensive"      # drug stores / pharmacies
    elif 5900 <= s <= 5999: return "Consumer Cyclical"       # other retail
    elif 6000 <= s <= 6199: return "Financials"              # banks
    elif 6200 <= s <= 6299: return "Financials"              # securities/brokers
    elif 6320 <= s <= 6329: return "Healthcare"              # health insurers (UNH, health plans)
    elif 6300 <= s <= 6499: return "Financials"              # insurance (life/P&C/etc.)
    elif 6500 <= s <= 6599: return "Real Estate"
    elif s == 6798:         return "Real Estate"             # REITs
    elif 6700 <= s <= 6799: return "Financials"              # holding/investment
    elif 7000 <= s <= 7299: return "Consumer Cyclical"       # hotels/personal services
    elif 7300 <= s <= 7369: return "Industrials"             # business services
    elif 7370 <= s <= 7379: return "Technology"              # software/data processing
    elif 7380 <= s <= 7399: return "Industrials"
    elif 7400 <= s <= 7999: return "Consumer Cyclical"       # services/entertainment
    elif 8000 <= s <= 8099: return "Healthcare"              # health services
    elif 8100 <= s <= 8999: return "Industrials"             # professional services
    return None


def _builder_resolve_sector_live(tk: str):
    """Resolve a canonical sector for a ticker via the SEC SIC code (EDGAR) —
    FAST (~0.3s) and un-throttled (NOT Yahoo, which hangs on the cloud IP and
    used to time this out and empty the whole pool). Sets the process cache.
    Returns (sector, None) or (None, None). Caller checks cache + budget first
    and hard-times this with _builder_call_timeout."""
    if not _BUILDER_EDGAR_ID[0]:
        try:
            ua = analyst.get_sec_user_agent()
            if not ua:
                _BUILDER_SECTOR_CACHE[tk] = ""
                return None, None
            from edgar import set_identity
            set_identity(ua)
            _BUILDER_EDGAR_ID[0] = True
        except Exception as e:
            print(f"[builder] edgar set_identity failed: {e!s:.100}", flush=True)
            _BUILDER_SECTOR_CACHE[tk] = ""
            return None, None
    try:
        from edgar import Company
        sic = Company(tk).sic
        sec = _sic_to_sector(int(sic)) if sic is not None else None
    except Exception as e:
        print(f"[builder] resolve_sector(SIC) failed {tk}: {e!s:.100}", flush=True)
        _BUILDER_SECTOR_CACHE[tk] = ""
        return None, None
    if sec:
        _BUILDER_SECTOR_CACHE[tk] = sec
        return sec, None
    _BUILDER_SECTOR_CACHE[tk] = ""
    return None, None


# ── Sector-resolve JOB ────────────────────────────────────────────────────
# A status-tracked background job that resolves EVERY unresolved candidate's
# sector via EDGAR SIC and persists it to security_meta — runs to COMPLETION
# (no per-run cap) in a daemon thread, persisting + committing one ticker at a
# time so progress is durable and visible. The pool's Refresh button starts it
# and polls the status, then reloads candidates. This replaces the old capped,
# fire-and-forget resolver that left most names stuck in "Other".
_BUILDER_RESOLVE_JOB = {
    "running": False, "total": 0, "done": 0, "resolved": 0, "failed": 0,
    "started_at": 0.0, "finished_at": 0.0,
}
_BUILDER_RESOLVE_LOCK = threading.Lock()


def _builder_unresolved_tickers() -> list[str]:
    """Candidate tickers that currently land in 'Other'/'Unknown' — i.e. have no
    real sector in the store yet. Pure-DB (uses the fast _builder_fetch_candidates)."""
    try:
        cands = _builder_fetch_candidates()
    except Exception:
        cands = []
    return sorted({c["ticker"] for c in cands
                   if (c.get("sector") or "Other") in ("Other", "Unknown")})


def _builder_resolve_sectors_worker(tickers: list[str]):
    """Resolve + persist each ticker's sector via EDGAR SIC. One commit per
    ticker so a mid-job Refresh sees partial progress. Never raises."""
    conn = None
    try:
        if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
            try:
                conn = _fund_conn()
            except Exception as e:
                print(f"[builder] resolve-job: no DB conn: {e!s:.120}", flush=True)
        for tk in tickers:
            try:
                sec, ind = _builder_resolve_sector_live(tk)   # always hits EDGAR (no neg-cache skip)
                if sec and conn is not None:
                    with conn.cursor() as cur:
                        _store_meta(cur, tk, {"sector": sec, "industry": ind, "name": None})
                    conn.commit()
                    _BUILDER_RESOLVE_JOB["resolved"] += 1
                elif not sec:
                    _BUILDER_RESOLVE_JOB["failed"] += 1
            except Exception as e:
                print(f"[builder] resolve-job {tk} failed: {e!s:.120}", flush=True)
                _BUILDER_RESOLVE_JOB["failed"] += 1
            finally:
                _BUILDER_RESOLVE_JOB["done"] += 1
    finally:
        if conn is not None:
            try: conn.close()
            except Exception: pass
        _BUILDER_RESOLVE_JOB["running"] = False
        _BUILDER_RESOLVE_JOB["finished_at"] = time.time()
        # Bust the candidates cache so the next load reflects the new sectors.
        _BUILDER_CANDIDATES_CACHE["data"] = None
        _BUILDER_CANDIDATES_CACHE["ts"] = 0
        print(f"[builder] resolve-job done: {_BUILDER_RESOLVE_JOB['resolved']} resolved, "
              f"{_BUILDER_RESOLVE_JOB['failed']} failed", flush=True)


# Words that match the ticker-shaped regex but are clearly financial jargon,
# not actual stock symbols. Filter applied during comp extraction to keep noise
# out of the Builder candidate pool.
_TICKER_BLACKLIST = {
    # Roles / acronyms
    "CEO","CFO","COO","CIO","CTO","CMO","CRO","CSO","CDO","ESG","IPO","M&A",
    "OEM","B2B","B2C","SDK","API","CRM","ERP","SAAS","DTC","FDA","SEC","NYSE",
    # Financial metrics / accounting
    "EPS","ROIC","ROE","ROA","ROCE","EBIT","EBITDA","DCF","NPV","IRR","FCF",
    "OCF","CAPEX","OPEX","WACC","TAM","SAM","SOM","GMV","ARR","MRR","LTV",
    "CAC","COGS","SGA","D&A","P&L","BS","CF","YTD","YOY","QOQ","MOM","HOH",
    "TTM","NTM","LTM","FY","FQ","H1","H2","Q1","Q2","Q3","Q4","FY1","FY2",
    "BPS","PBV","PEG","PSR","DPS","BVPS","CAGR","NIM","NPL","CET1",
    # Currencies / units
    "USD","EUR","GBP","JPY","CNY","CAD","AUD","CHF","SEK","NOK","DKK","INR",
    "BRL","MXN","RUB","ZAR","HKD","SGD","KRW","TRY","ARS","NZD",
    # Common all-caps words that show up in DGA reports
    "BUY","SELL","HOLD","ADD","TRIM","RATING","TARGET","PRICE","UPSIDE",
    "DOWNSIDE","BASE","BULL","BEAR","VERDICT","SUMMARY","SECTION","CHART",
    "TABLE","COMP","COMPS","PEER","PEERS","INDUSTRY","SECTOR","INDEX","NA",
    "NM","TBD","ETA","FYI","DGA","LP","GP","AI","ML","IT","HQ","CO","INC",
    "LLC","LP","ETC","RE","SE","CO","AS","IS","BE","OF","TO","IN","ON","BY",
    "AT","NO","OK","TY","HR","PR","UI","UX","KPI","SAM","ROIC","FY23","FY24",
    "FY25","FY26","FY27","Q126","Q226","Q326","Q426","H125","H225",
    # Rating buckets we use
    "STRONG","CONVICTION","PICK","OVERWEIGHT","UNDERWEIGHT","NEUTRAL",
}

def _extract_ticker_candidates_from_md(md: str) -> list[str]:
    """Regex-extract things that LOOK like tickers from a DGA report.

    Scans for 1-5 uppercase letters, optionally with .X suffix (BRK.B style),
    then filters against the financial-jargon blacklist above. Doesn't
    validate against yfinance here — caller does that step lazily, with
    caching, to amortize the cost.
    """
    if not md:
        return []
    # Word boundary + 1-5 uppercase letters, optional .X class share suffix
    raw = re.findall(r"\b([A-Z]{1,5}(?:\.[A-Z])?)\b", md)
    out, seen = [], set()
    for tk in raw:
        if tk in _TICKER_BLACKLIST:
            continue
        if tk in seen:
            continue
        # Pure all-caps strings of length 1 are almost never tickers in context
        if len(tk) == 1:
            continue
        seen.add(tk)
        out.append(tk)
    return out


# NOTE: comp validation used to live here (_is_real_ticker → yf.Ticker().fast_info
# + _builder_extract_comps_for_report). REMOVED — those live yfinance calls in the
# request path were the recurring "empty candidate pool" bug: on a cold process
# they fired hundreds of fast_info calls that stalled on the cloud IP and blew the
# endpoint's time cap. Comp extraction is now regex-only (in _builder_fetch_
# candidates), and comps are validated by store membership (a real analyst_target),
# not by a live call. See [[cloud-ip-yfinance-fragility]].


def _builder_call_timeout(fn, timeout: float, default=None):
    """Run fn() in a worker thread, returning `default` if it errors or exceeds
    `timeout` seconds. Keeps slow/blocking yfinance scrapes (which can hang from
    a rate-limited cloud IP) from stalling the whole Builder request. Uses
    shutdown(wait=False) so a still-hung call never blocks us on exit."""
    import concurrent.futures as _cf
    ex = _cf.ThreadPoolExecutor(max_workers=1)
    fut = ex.submit(fn)
    try:
        return fut.result(timeout=timeout)
    except Exception:
        return default
    finally:
        ex.shutdown(wait=False)


def _builder_fetch_candidates() -> list[dict]:
    """Return list of Builder candidates: saved-report subjects PLUS comp
    tickers extracted from those reports' markdown.

    Schema: [{ticker, name, sector, rating, price_target, upside_pct,
              current_price, generated_at, source}].

    Where `source` is:
      • 'report' — the ticker is the subject of a saved DGA report
                   (has explicit price_target + upside_pct)
      • 'comp'   — the ticker was mentioned as a comparable in another
                   report's comp table; we derive upside_pct from
                   yfinance analyst targetMeanPrice when available
    """
    now = time.time()
    if (_BUILDER_CANDIDATES_CACHE["data"] is not None
            and (now - _BUILDER_CANDIDATES_CACHE["ts"]) < _BUILDER_CANDIDATES_TTL):
        _BUILDER_CANDIDATES_DIAG.update(cache_hit=True, returned=len(_BUILDER_CANDIDATES_CACHE["data"]))
        return _BUILDER_CANDIDATES_CACHE["data"]

    _BUILDER_CANDIDATES_DIAG.clear()
    _BUILDER_CANDIDATES_DIAG.update(cache_hit=False, db_url_set=bool(os.environ.get("DATABASE_URL")))

    deadline = now + 9.0   # (no live calls remain; kept for the degraded-cache note)

    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        _BUILDER_CANDIDATES_DIAG.update(error="DB unavailable (no DATABASE_URL / psycopg2)")
        return []

    # ── 1. Pull report subjects. STRICT: explicit target + upside. If that
    #     matches nothing, RELAX to target-only (upside is computed from the
    #     live/stored price below) so the pool isn't empty just because a report
    #     stored a price target but no upside_pct.
    strict_sql = """
        SELECT ticker, rating, price_target, upside_pct, generated_at, report_md,
               claude_price_target, claude_upside_pct, claude_rating
          FROM analyst_reports
         WHERE archived IS NOT TRUE
           AND (price_target IS NOT NULL OR claude_price_target IS NOT NULL)
           AND (upside_pct   IS NOT NULL OR claude_upside_pct   IS NOT NULL)
         ORDER BY COALESCE(LEAST(upside_pct, claude_upside_pct),
                           upside_pct, claude_upside_pct) DESC NULLS LAST
    """
    # EVERY saved report is Builder-eligible (Alec's rule) — a report whose
    # target didn't extract still names a researched stock. Targets/upside
    # stay NULL on those rows; the construct allocator median-fills for
    # EV-weighting and equal-weighting never needed them at all.
    all_sql = """
        SELECT ticker, rating, price_target, upside_pct, generated_at, report_md,
               claude_price_target, claude_upside_pct, claude_rating
          FROM analyst_reports
         WHERE archived IS NOT TRUE AND report_md IS NOT NULL
         ORDER BY COALESCE(LEAST(upside_pct, claude_upside_pct),
                           upside_pct, claude_upside_pct) DESC NULLS LAST
    """
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("SELECT COUNT(*) AS n FROM analyst_reports WHERE archived IS NOT TRUE")
            total_reports = (cur.fetchone() or {}).get("n", 0)
            cur.execute(strict_sql)
            strict_n = len(cur.fetchall() or [])
            cur.execute(all_sql)
            rows = cur.fetchall() or []
            _BUILDER_CANDIDATES_DIAG.update(total_unarchived=total_reports,
                                            strict_rows=strict_n, used_rows=len(rows),
                                            no_target_rows=len(rows) - strict_n)
    except Exception as e:
        print(f"[builder] candidates query failed: {e!s:.200}", flush=True)
        _BUILDER_CANDIDATES_DIAG.update(error=f"query failed: {e!s:.150}")
        return []

    print(f"[builder] reports unarchived={_BUILDER_CANDIDATES_DIAG.get('total_unarchived')} "
          f"strict={_BUILDER_CANDIDATES_DIAG.get('strict_rows')} "
          f"used={_BUILDER_CANDIDATES_DIAG.get('used_rows')}", flush=True)
    if not rows:
        _BUILDER_CANDIDATES_DIAG.update(error="no non-archived saved reports")
        return []

    # ── 2. Walk each report and extract comp tickers from the markdown ───
    #     REGEX-ONLY → ZERO network. We do NOT yfinance-validate comps here:
    #     _builder_extract_comps_for_report() called _is_real_ticker() →
    #     yf.Ticker().fast_info, firing HUNDREDS of live calls on a cold process
    #     (66 reports × ≤25 tickers). On the rate-limited cloud IP those stall
    #     and blow the endpoint's 12s cap → the function is killed before it
    #     returns → EMPTY pool. Garbage symbols are filtered downstream instead:
    #     a comp only survives the build loop if the STORE has an analyst_target
    #     for it (real, synced tickers), so no live validation is needed.
    comp_universe: dict[str, str] = {}   # ticker → first-report-ticker that mentioned it
    own_tickers: set[str] = set()
    _COMP_CAP = 150                       # bound the store lookup IN-list
    for r in rows:
        tk = (r["ticker"] or "").strip().upper()
        if not tk: continue
        own_tickers.add(tk)
        md = r.get("report_md") or ""
        if not md: continue
        try:
            for c in _extract_ticker_candidates_from_md(md)[:25]:
                if c not in comp_universe and c not in own_tickers:
                    comp_universe[c] = tk
                    if len(comp_universe) >= _COMP_CAP:
                        break
        except Exception as _e:
            print(f"[builder] comp extract failed for {tk}: {_e!s:.120}")
        if len(comp_universe) >= _COMP_CAP:
            break
    # Comps that are ALSO report subjects: drop from the comp universe
    for tk in own_tickers:
        comp_universe.pop(tk, None)
    print(f"[builder] candidate pool: {len(own_tickers)} report subjects + "
          f"{len(comp_universe)} comp tickers (validated)")

    # ── 3. Quotes + meta for the whole universe: PURELY from the persisted store.
    #     NO live calls in this request path — a live batch_quotes for 100+
    #     un-synced tickers (18s) blew past the endpoint's 12s cap and left the
    #     pool EMPTY. Report subjects always appear regardless (their targets
    #     come from analyst_reports); sectors/prices fill in from the store, which
    #     the market autosync keeps fresh.
    all_tickers = list(own_tickers) + list(comp_universe.keys())
    try:
        quotes = _db_quotes(all_tickers) if callable(globals().get("_db_quotes")) else {}
    except Exception as _e:
        print(f"[builder] _db_quotes failed: {_e!s:.120}", flush=True)
        quotes = {}
    try:
        db_meta = _db_meta(all_tickers) if callable(globals().get("_db_meta")) else {}
    except Exception as _e:
        print(f"[builder] _db_meta failed: {_e!s:.120}", flush=True)
        db_meta = {}

    # ── 4. Build candidate dicts for report subjects ─────────────────────
    out: list[dict] = []
    for r in rows:
        try:
            tk = (r["ticker"] or "").strip().upper()
            if not tk:
                continue
            sector_raw, name = "Unknown", tk
            dm = db_meta.get(tk)
            if dm and dm.get("sector"):
                sector_raw, name = dm["sector"], (dm.get("name") or tk)
            elif dm and dm.get("name"):
                name = dm["name"]
            # PURE-DB request path — ZERO live network calls (any sync resolve, even
            # EDGAR, can blow the time cap on the cloud IP and empty the whole pool).
            # Use the in-process sector cache if present; the STORE is filled by the
            # background resolver (kicked by Refresh) + the 10-min autosync.
            if sector_raw == "Unknown" and _BUILDER_SECTOR_CACHE.get(tk):
                sector_raw = _BUILDER_SECTOR_CACHE[tk]
            if sector_raw == "Unknown" and tk not in _BUILDER_SECTOR_CACHE:
                _BUILDER_UNRESOLVED.add(tk)   # queue for the background resolver
            sector = _builder_classify_sector(sector_raw)
            q = quotes.get(tk) or {}
            # Conservative (less-aggressive) target/upside when both LLMs ran.
            pt_g = float(r["price_target"])         if r["price_target"]         is not None else None
            pt_c = float(r["claude_price_target"])  if r["claude_price_target"]  is not None else None
            up_g = float(r["upside_pct"])           if r["upside_pct"]           is not None else None
            up_c = float(r["claude_upside_pct"])    if r["claude_upside_pct"]    is not None else None
            eff_pt = min(pt_g, pt_c) if (pt_g is not None and pt_c is not None) else (pt_g if pt_g is not None else pt_c)
            eff_up = min(up_g, up_c) if (up_g is not None and up_c is not None) else (up_g if up_g is not None else up_c)
            # If upside wasn't stored, derive it from the target + current price.
            if eff_up is None and eff_pt and q.get("price"):
                try:
                    _px = float(q["price"])
                    if _px > 0:
                        eff_up = round((eff_pt - _px) / _px * 100, 2)
                except Exception:
                    pass
            providers = []
            if pt_g is not None: providers.append("grok")
            if pt_c is not None: providers.append("claude")
            _gen = r["generated_at"]
            out.append({
                "ticker":        tk,
                "name":          name,
                "sector":        sector,
                "sector_raw":    sector_raw,
                "rating":        r["rating"] or r.get("claude_rating"),
                "price_target":  eff_pt,
                "upside_pct":    eff_up,
                "current_price": float(q.get("price")) if q.get("price") is not None else None,
                "day_pct":       float(q.get("pct_change")) if q.get("pct_change") is not None else None,
                "generated_at":  _gen.isoformat() if hasattr(_gen, "isoformat") else (str(_gen) if _gen else None),
                "source":        "report",
                "from_report":   None,
                "providers":     providers,
                "grok_target":   pt_g, "claude_target": pt_c,
            })
        except Exception as _e:
            _BUILDER_CANDIDATES_DIAG.setdefault("row_errors", []).append(
                f"{(r.get('ticker') or '?')}: {type(_e).__name__}: {_e!s:.80}")
            continue

    # ── 5. Build candidate dicts for comp tickers ────────────────────────
    # For comps, derive upside_pct from yfinance analyst targetMeanPrice
    # when available. If neither current price nor target is known, skip
    # the comp (no signal for the EV-weighted allocator).
    for tk, source_report in list(comp_universe.items())[:60]:
        try:
            sector_raw, name = "Unknown", tk
            dm = db_meta.get(tk)
            if dm and dm.get("sector"):
                sector_raw, name = dm["sector"], (dm.get("name") or tk)
            elif dm and dm.get("name"):
                name = dm["name"]
            if sector_raw == "Unknown" and _BUILDER_SECTOR_CACHE.get(tk):
                sector_raw = _BUILDER_SECTOR_CACHE[tk]
            if sector_raw == "Unknown" and tk not in _BUILDER_SECTOR_CACHE:
                _BUILDER_UNRESOLVED.add(tk)   # queue for the background resolver
            sector = _builder_classify_sector(sector_raw)

            q = quotes.get(tk) or {}
            cur_price = float(q.get("price")) if q.get("price") is not None else None

            target = None
            dm_target = (dm or {}).get("analyst_target")
            if dm_target:
                target = float(dm_target)

            upside = None
            if target is not None and cur_price and cur_price > 0:
                upside = round((target - cur_price) / cur_price * 100, 2)

            # Skip comps with no usable signal (no target AND no upside)
            if upside is None:
                continue

            out.append({
                "ticker":        tk,
                "name":          name,
                "sector":        sector,
                "sector_raw":    sector_raw,
                "rating":        None,
                "price_target":  target,
                "upside_pct":    upside,
                "current_price": cur_price,
                "day_pct":       float(q.get("pct_change")) if q.get("pct_change") is not None else None,
                "generated_at":  None,
                "source":        "comp",
                "from_report":   source_report,
            })
        except Exception as _e:
            _BUILDER_CANDIDATES_DIAG.setdefault("row_errors", []).append(
                f"comp {tk}: {type(_e).__name__}: {_e!s:.80}")
            continue

    _BUILDER_CANDIDATES_DIAG.update(returned=len(out),
                                    unknown_sector=sum(1 for c in out if c.get("sector") == "Unknown"),
                                    other_sector=sum(1 for c in out if c.get("sector") == "Other"),
                                    bg_queue=len(_BUILDER_UNRESOLVED))
    # NEVER cache an empty result — always retry next call so a transient miss
    # can't get stuck for the 10-min TTL.
    if out:
        _BUILDER_CANDIDATES_CACHE["data"] = out
        _BUILDER_CANDIDATES_CACHE["ts"]   = now
    print(f"[builder] returning {len(out)} candidates "
          f"({_BUILDER_CANDIDATES_DIAG.get('unknown_sector')} Unknown sector)", flush=True)
    return out


@app.get("/api/v2/builder/candidates")
def builder_candidates(request: Request, fresh: int = 0):
    """Return all eligible Builder candidates with sector + EV.

    Response: {
      candidates: [...],
      by_sector:  {sector: [tickers...]},
      sectors:    [{name, count, median_upside_pct}, ...]
    }
    `fresh=1` (the pool's Refresh button) busts the 10-min cache. Sector
    resolution is a SEPARATE job (POST /api/v2/builder/resolve-sectors) the UI
    drives explicitly; this endpoint stays PURE-DB (zero network) and instant.
    """
    _cl = _claims_or_401(request)
    if _cl.get("demo_mode"):
        return _demo_builder_candidates()
    if fresh:
        _BUILDER_CANDIDATES_CACHE["data"] = None
        _BUILDER_CANDIDATES_CACHE["ts"] = 0
    # Hard cap so the endpoint can NEVER hang — the fetch is PURE-DB (no live
    # network calls), so 12s is comfortable. Covers a stalled DB connection
    # (_fund_conn over the SSH tunnel). On timeout, serve whatever's cached (else
    # empty) so the UI resolves instead of spinning forever.
    cands = _builder_call_timeout(_builder_fetch_candidates, 12.0,
                                  _BUILDER_CANDIDATES_CACHE.get("data") or [])
    by_sector: dict[str, list[str]] = {}
    upside_by_sec: dict[str, list[float]] = {}
    for c in cands:
        by_sector.setdefault(c["sector"], []).append(c["ticker"])
        if c["upside_pct"] is not None:
            upside_by_sec.setdefault(c["sector"], []).append(c["upside_pct"])
    sectors = []
    for s, tks in sorted(by_sector.items(), key=lambda kv: -len(kv[1])):
        ups = upside_by_sec.get(s) or []
        median_up = sorted(ups)[len(ups) // 2] if ups else None
        sectors.append({
            "name":              s,
            "count":             len(tks),
            "median_upside_pct": round(median_up, 2) if median_up is not None else None,
        })
    return {
        "candidates": cands,
        "by_sector":  by_sector,
        "sectors":    sectors,
        "total":      len(cands),
        "diagnostics": dict(_BUILDER_CANDIDATES_DIAG),
    }


@app.post("/api/v2/builder/resolve-sectors")
def builder_resolve_sectors(request: Request):
    """Start the sector-resolve job: EDGAR-SIC-resolve EVERY candidate currently
    in 'Other'/'Unknown' and persist to the store, so they become eligible for
    sector-weighted allocation. Runs to completion in a daemon thread (off the
    request path); the UI polls GET for progress, then reloads candidates.
    Returns the job status immediately."""
    _claims_or_401(request)
    with _BUILDER_RESOLVE_LOCK:
        if _BUILDER_RESOLVE_JOB["running"]:
            return {**_BUILDER_RESOLVE_JOB, "already_running": True}
        tickers = _builder_unresolved_tickers()
        _BUILDER_RESOLVE_JOB.update(running=bool(tickers), total=len(tickers),
                                    done=0, resolved=0, failed=0,
                                    started_at=time.time(), finished_at=0.0)
        if not tickers:
            _BUILDER_RESOLVE_JOB["finished_at"] = time.time()
            return dict(_BUILDER_RESOLVE_JOB)
        threading.Thread(target=_builder_resolve_sectors_worker,
                         args=(tickers,), daemon=True).start()
    print(f"[builder] resolve-job started for {len(tickers)} tickers", flush=True)
    return dict(_BUILDER_RESOLVE_JOB)


@app.get("/api/v2/builder/resolve-sectors")
def builder_resolve_sectors_status(request: Request):
    """Poll the sector-resolve job status."""
    _claims_or_401(request)
    return dict(_BUILDER_RESOLVE_JOB)


class BuilderAllocateRequest(BaseModel):
    sector_weights:        dict          # {sector_name: pct}; values should roughly sum to 100
    basket_size:           float = 1_000_000
    method:                str   = "ev_weighted"   # 'ev_weighted' | 'equal'
    max_per_stock_pct:     float = 15.0
    max_stocks_per_sector: int   = 6
    redistribute_empty:    bool  = True            # if a sector has no candidates, push its weight into the others
    softmax_temperature:   float = 1.0             # for ev_weighted; >1 flattens, <1 sharpens


class BuilderConstructRequest(BaseModel):
    tickers: list[str]                      # selected pool (from /candidates)
    basket_size: float = 100_000.0
    method: str = "equal"                   # equal | ev_weighted | rating_weighted
    max_per_stock_pct: float = 10.0         # cap vs basket
    max_per_sector_pct: float = 0.0         # 0 = no sector cap
    softmax_temperature: float = 1.0        # ev_weighted spread control


@app.post("/api/v2/builder/construct")
def builder_construct(request: Request, body: BuilderConstructRequest):
    """Pool-first Builder: the user picks tickers (default = ALL saved
    reports), a weighting method, and caps — no sector-weight form required.

    Methods:
      equal           — 1/N across the pool
      ev_weighted     — softmax(upside / T); tickers with no stored upside get
                        the POOL MEDIAN upside so research without an
                        extractable target is never dropped
      rating_weighted — Buy-family 1.5× · Hold 1.0× · Sell-family 0.4× ·
                        unrated 1.0×, normalized

    Caps run after weighting: per-stock cap (vs basket) then optional
    per-sector cap, trimmed pro-rata and redistributed (3 passes — converges
    for any sane caps). Shares are floored at store prices; the remainder is
    reported as residual cash. Zero LLM calls, pure DB."""
    _cl_c = _claims_or_401(request)
    _demo_pool = _demo_builder_candidates()["candidates"] if _cl_c.get("demo_mode") else None
    picks = [t.strip().upper() for t in (body.tickers or []) if t and t.strip()]
    if not picks:
        raise HTTPException(400, "tickers is required — select at least one saved-report stock")
    basket = max(0.0, float(body.basket_size or 0))
    method = body.method if body.method in ("equal", "ev_weighted", "rating_weighted") else "equal"
    cap_stock  = max(0.0, min(100.0, float(body.max_per_stock_pct or 0))) / 100.0
    cap_sector = max(0.0, min(100.0, float(body.max_per_sector_pct or 0))) / 100.0
    temp = max(0.1, float(body.softmax_temperature or 1.0))

    by_tk = {c["ticker"]: c for c in (_demo_pool if _demo_pool is not None
                                      else _builder_fetch_candidates())}
    rows = [by_tk[t] for t in picks if t in by_tk]
    missing = [t for t in picks if t not in by_tk]
    if not rows:
        raise HTTPException(400, "None of the selected tickers are in the candidate pool.")

    ups = [c["upside_pct"] for c in rows if c.get("upside_pct") is not None]
    median_up = sorted(ups)[len(ups) // 2] if ups else 0.0

    def _rating_mult(rt: str | None) -> float:
        r = (rt or "").strip().upper()
        if any(k in r for k in ("BUY", "OVERWEIGHT", "OUTPERFORM", "ACCUMULATE")):
            return 1.5
        if any(k in r for k in ("SELL", "UNDERWEIGHT", "UNDERPERFORM", "REDUCE")):
            return 0.4
        return 1.0

    import math as _math
    if method == "equal":
        raw = {c["ticker"]: 1.0 for c in rows}
    elif method == "rating_weighted":
        raw = {c["ticker"]: _rating_mult(c.get("rating")) for c in rows}
    else:  # ev_weighted
        raw = {}
        for c in rows:
            up = c["upside_pct"] if c.get("upside_pct") is not None else median_up
            raw[c["ticker"]] = _math.exp(max(-200.0, min(200.0, up / (10.0 * temp))))
    tot = sum(raw.values()) or 1.0
    w = {t: v / tot for t, v in raw.items()}

    sec_of = {c["ticker"]: (c.get("sector") or "Unknown") for c in rows}
    for _ in range(3):
        # per-stock cap
        if cap_stock > 0:
            over = {t: v - cap_stock for t, v in w.items() if v > cap_stock}
            if over:
                spill = sum(over.values())
                for t in over:
                    w[t] = cap_stock
                room = {t: v for t, v in w.items() if t not in over and v < cap_stock}
                rt = sum(room.values())
                for t in room:
                    w[t] += spill * (room[t] / rt) if rt else 0.0
        # per-sector cap
        if cap_sector > 0:
            sec_tot: dict[str, float] = {}
            for t, v in w.items():
                sec_tot[sec_of[t]] = sec_tot.get(sec_of[t], 0.0) + v
            over_secs = {s: v - cap_sector for s, v in sec_tot.items() if v > cap_sector}
            if over_secs:
                spill = sum(over_secs.values())
                for s, ov in over_secs.items():
                    scale = cap_sector / sec_tot[s]
                    for t in w:
                        if sec_of[t] == s:
                            w[t] *= scale
                room = {t: v for t, v in w.items()
                        if sec_of[t] not in over_secs}
                rt = sum(room.values())
                for t in room:
                    w[t] += spill * (room[t] / rt) if rt else 0.0

    out_rows, alloc_total = [], 0.0
    for c in sorted(rows, key=lambda x: -w.get(x["ticker"], 0)):
        t = c["ticker"]
        wt = w.get(t, 0.0)
        px = c.get("current_price")
        dollars = basket * wt
        shares = int(dollars / px) if px and px > 0 else None
        actual = (shares * px) if shares is not None else dollars
        alloc_total += actual
        out_rows.append({
            "ticker": t, "name": c.get("name"), "sector": sec_of[t],
            "weight_pct": round(wt * 100, 2),
            "dollars": round(dollars, 2),
            "shares": shares,
            "actual_dollars": round(actual, 2),
            "price": px,
            "rating": c.get("rating"),
            "upside_pct": c.get("upside_pct"),
            "upside_filled": c.get("upside_pct") is None and method == "ev_weighted",
        })
    sec_break: dict[str, float] = {}
    for r in out_rows:
        sec_break[r["sector"]] = sec_break.get(r["sector"], 0.0) + r["weight_pct"]
    exp_ups = [(r["upside_pct"] if r["upside_pct"] is not None else median_up) * r["weight_pct"] / 100.0
               for r in out_rows]
    return {
        "rows": out_rows,
        "summary": {
            "positions": len(out_rows),
            "basket_size": basket,
            "allocated": round(alloc_total, 2),
            "residual_cash": round(basket - alloc_total, 2),
            "expected_upside_pct": round(sum(exp_ups), 2) if ups else None,
            "median_upside_fill": round(median_up, 2) if ups else None,
            "method": method,
            "sector_breakdown": {s: round(v, 2) for s, v in
                                 sorted(sec_break.items(), key=lambda kv: -kv[1])},
        },
        "missing_from_pool": missing,
    }


@app.post("/api/v2/builder/allocate")
def builder_allocate(request: Request, body: BuilderAllocateRequest):
    """Run the sector-weighted allocator and return a built basket.

    Algorithm per sector:
      1. Filter candidates matching this sector.
      2. Sort by upside_pct DESC; keep top `max_stocks_per_sector`.
      3. Distribute the sector's weight using:
           ev_weighted: softmax(upside_pct / temperature)
           equal      : uniform weight
      4. Apply per-stock cap: if any stock exceeds max_per_stock_pct of the
         BASKET (not the sector), trim and redistribute the excess to the
         other stocks in that sector pro-rata.
    Empty sectors:
      • If `redistribute_empty`, the missing weight is redistributed pro-rata
        across sectors that DO have candidates.
      • Otherwise, the weight is left unallocated (reported in summary).
    """
    _claims_or_401(request)

    if not body.sector_weights:
        raise HTTPException(400, "sector_weights is required")
    basket = max(0.0, float(body.basket_size or 0))
    max_stock_frac  = max(0.0, min(100.0, float(body.max_per_stock_pct))) / 100.0
    max_per_sector  = max(1, int(body.max_stocks_per_sector or 6))
    method          = body.method if body.method in ("ev_weighted", "equal") else "ev_weighted"
    softmax_T       = max(0.1, float(body.softmax_temperature or 1.0))

    # Normalize input weights to sum 1.0
    raw = {_builder_classify_sector(k): float(v) for k, v in body.sector_weights.items() if float(v) > 0}
    total = sum(raw.values())
    if total <= 0:
        raise HTTPException(400, "sector_weights must sum to a positive value")
    sec_weight = {s: w / total for s, w in raw.items()}   # fractions

    cands = _builder_fetch_candidates()

    # Bucket candidates by sector and prune to top N by upside
    cands_by_sec: dict[str, list[dict]] = {}
    for c in cands:
        if c["upside_pct"] is None:
            continue
        cands_by_sec.setdefault(c["sector"], []).append(c)
    for s in cands_by_sec:
        cands_by_sec[s].sort(key=lambda x: x["upside_pct"] or -999, reverse=True)
        cands_by_sec[s] = cands_by_sec[s][:max_per_sector]

    # Identify empty target sectors
    empty_targets = [s for s in sec_weight if not cands_by_sec.get(s)]
    funded_targets = [s for s in sec_weight if cands_by_sec.get(s)]
    warnings: list[str] = []
    unallocated_frac = 0.0

    if empty_targets:
        empty_sum = sum(sec_weight[s] for s in empty_targets)
        if body.redistribute_empty and funded_targets:
            funded_sum = sum(sec_weight[s] for s in funded_targets) or 1.0
            for s in funded_targets:
                sec_weight[s] += empty_sum * (sec_weight[s] / funded_sum)
            warnings.append(f"Sectors with no candidates ({', '.join(empty_targets)}) — "
                            f"{empty_sum*100:.1f}% redistributed across {len(funded_targets)} funded sectors")
        else:
            unallocated_frac += empty_sum
            warnings.append(f"Sectors with no candidates: {', '.join(empty_targets)} "
                            f"({empty_sum*100:.1f}% left unallocated)")
        for s in empty_targets:
            sec_weight.pop(s, None)

    # ── Per-sector allocation ─────────────────────────────────────────────────
    def _allocate_within_sector(sec_cands: list[dict], sector_frac: float) -> list[dict]:
        n = len(sec_cands)
        if n == 0 or sector_frac <= 0:
            return []
        # Compute initial weights of stocks WITHIN the sector (sum to 1)
        if method == "equal":
            w = [1.0 / n] * n
        else:
            import math as _m
            ups = [(c["upside_pct"] or 0.0) / softmax_T for c in sec_cands]
            if not ups:
                w = [1.0 / n] * n
            else:
                m_max = max(ups)
                exps = [_m.exp(u - m_max) for u in ups]  # numerical stability
                z = sum(exps) or 1.0
                w = [e / z for e in exps]
        # Translate to basket-fractions
        stock_frac = [wi * sector_frac for wi in w]

        # Enforce per-stock cap (in BASKET units, not sector units).
        # Iteratively: any stock above cap is trimmed to cap; excess spread
        # proportionally to the others. Stop when no caps are breached or
        # all eligible stocks are at the cap.
        cap = max_stock_frac
        if cap > 0 and cap < 1.0:
            for _it in range(20):
                over = [(i, sf - cap) for i, sf in enumerate(stock_frac) if sf > cap + 1e-9]
                if not over:
                    break
                excess = sum(o[1] for o in over)
                for i, _ in over:
                    stock_frac[i] = cap
                # Recipients: stocks below cap
                below = [i for i, sf in enumerate(stock_frac) if sf < cap - 1e-9]
                if not below:
                    # All capped — excess becomes sector-level slack (rare)
                    break
                room = sum(cap - stock_frac[i] for i in below) or 1.0
                for i in below:
                    delta = excess * ((cap - stock_frac[i]) / room)
                    stock_frac[i] = min(cap, stock_frac[i] + delta)

        out_rows = []
        for c, frac in zip(sec_cands, stock_frac):
            if frac <= 1e-9:
                continue
            out_rows.append({
                "ticker":        c["ticker"],
                "name":          c["name"],
                "weight_pct":    round(frac * 100.0, 3),
                "dollars":       round(frac * basket, 2) if basket else None,
                "upside_pct":    c["upside_pct"],
                "price_target":  c["price_target"],
                "current_price": c["current_price"],
                "rating":        c["rating"],
                "source":        c.get("source", "report"),
                "from_report":   c.get("from_report"),
            })
        return out_rows

    sectors_out = []
    grand_alloc = 0.0
    total_expected = 0.0
    total_positions = 0
    for s, frac in sec_weight.items():
        positions = _allocate_within_sector(cands_by_sec.get(s, []), frac)
        sec_alloc = sum(p["weight_pct"] for p in positions) / 100.0
        # Weighted expected return for the sector
        sec_exp = sum((p["weight_pct"] or 0) * (p["upside_pct"] or 0)
                      for p in positions) / 100.0
        grand_alloc += sec_alloc
        total_expected += sec_exp
        total_positions += len(positions)
        sectors_out.append({
            "sector":               s,
            "target_weight_pct":    round(frac * 100.0, 3),
            "allocated_weight_pct": round(sec_alloc * 100.0, 3),
            "allocated_dollars":    round(sec_alloc * basket, 2) if basket else None,
            "candidates_available": len(cands_by_sec.get(s, [])),
            "positions":            positions,
            "weighted_expected_return_pct":
                round(sec_exp / (sec_alloc * 100.0) * 100.0, 2)
                if sec_alloc > 0 else None,
        })

    # Sort sectors by allocated weight desc for display
    sectors_out.sort(key=lambda x: -x["allocated_weight_pct"])

    return {
        "basket_size":           basket,
        "method":                method,
        "max_per_stock_pct":     body.max_per_stock_pct,
        "max_stocks_per_sector": max_per_sector,
        "sectors":               sectors_out,
        "summary": {
            "total_positions":            total_positions,
            "sectors_funded":             len([s for s in sectors_out if s["positions"]]),
            "total_allocated_pct":        round(grand_alloc * 100.0, 3),
            "unallocated_pct":            round(unallocated_frac * 100.0, 3),
            "projected_return_pct":       round(total_expected, 2),  # already weighted by basket-fraction
            "warnings":                   warnings,
        },
    }


# ──────────────────────────────────────────────────────────────────────────────
# Builder — saved scenarios (per-user, kv_store backed)
# ──────────────────────────────────────────────────────────────────────────────
# Each saved scenario captures:
#   • The Build request (sector_weights, basket_size, method, ...)
#   • The result (sectors[] with positions, summary)
#   • A user-given name + auto timestamp
# Stored under kv_store key `builder:scenarios:{lp_id}` as a list. Bounded at
# 50 scenarios per user (oldest auto-pruned on save).

_BUILDER_SCENARIO_KEY_PREFIX = "builder:scenarios:"
_BUILDER_SCENARIO_LIMIT      = 50


def _builder_scenarios_key(lp_id: str) -> str:
    return _BUILDER_SCENARIO_KEY_PREFIX + str(lp_id)


def _builder_load_scenarios(lp_id: str) -> list[dict]:
    raw = _kv_get(_builder_scenarios_key(lp_id))
    if not raw or not isinstance(raw, list):
        return []
    return raw


def _builder_save_scenarios(lp_id: str, scenarios: list[dict]) -> bool:
    return _kv_put(_builder_scenarios_key(lp_id), scenarios)


class BuilderSaveScenarioRequest(BaseModel):
    name:    str | None = None
    request: dict
    result:  dict


@app.post("/api/v2/builder/scenarios")
def builder_save_scenario(request: Request, body: BuilderSaveScenarioRequest):
    """Persist a built basket as a named scenario for later review.
    Returns the saved scenario with its server-generated id + created_at."""
    claims = _claims_or_401(request)
    lp_id = str(claims.get("lp_id") or claims.get("email") or "anon")
    if not body.request or not body.result:
        raise HTTPException(400, "request and result are required")

    sc_id = str(uuid.uuid4())
    now_iso = datetime.utcnow().isoformat()
    # Derive a default name when not provided: '60% Tech · 20% Energy · …'
    name = (body.name or "").strip()
    if not name:
        sw = body.request.get("sector_weights") or {}
        if isinstance(sw, dict) and sw:
            parts = [f"{int(round(float(v)))}% {k}" for k, v in sw.items() if float(v) > 0]
            name = " · ".join(parts[:4]) or "Basket"
        else:
            name = f"Basket {now_iso[:10]}"

    scenario = {
        "id":         sc_id,
        "name":       name[:120],
        "created_at": now_iso,
        "request":    body.request,
        "result":     body.result,
        "watchlist_synced": False,
    }
    existing = _builder_load_scenarios(lp_id)
    existing.insert(0, scenario)        # newest first
    if len(existing) > _BUILDER_SCENARIO_LIMIT:
        existing = existing[:_BUILDER_SCENARIO_LIMIT]
    if not _builder_save_scenarios(lp_id, existing):
        raise HTTPException(500, "Could not persist scenario (kv_store unavailable)")
    return scenario


@app.get("/api/v2/builder/scenarios")
def builder_list_scenarios(request: Request):
    """Return all saved scenarios for the current user, newest first."""
    claims = _claims_or_401(request)
    lp_id = str(claims.get("lp_id") or claims.get("email") or "anon")
    return {"scenarios": _builder_load_scenarios(lp_id)}


@app.delete("/api/v2/builder/scenarios/{scenario_id}")
def builder_delete_scenario(scenario_id: str, request: Request):
    """Remove one saved scenario."""
    claims = _claims_or_401(request)
    lp_id = str(claims.get("lp_id") or claims.get("email") or "anon")
    existing = _builder_load_scenarios(lp_id)
    kept = [s for s in existing if s.get("id") != scenario_id]
    if len(kept) == len(existing):
        raise HTTPException(404, "Scenario not found")
    _builder_save_scenarios(lp_id, kept)
    return {"ok": True}


@app.post("/api/v2/builder/scenarios/{scenario_id}/to-watchlist")
def builder_scenario_to_watchlist(scenario_id: str, request: Request):
    """Add every ticker from the scenario's allocation to the user's watchlist
    so the basket can be followed over time using the existing watchlist
    mechanics. Idempotent — tickers already on the watchlist stay there.
    Returns the watchlist after the merge + how many were newly added.
    """
    claims = _claims_or_401(request)
    lp_id = str(claims.get("lp_id") or claims.get("email") or "anon")
    existing = _builder_load_scenarios(lp_id)
    scenario = next((s for s in existing if s.get("id") == scenario_id), None)
    if scenario is None:
        raise HTTPException(404, "Scenario not found")

    # Walk the scenario's result.sectors → positions → ticker
    sectors = ((scenario.get("result") or {}).get("sectors") or [])
    tickers: list[str] = []
    for s in sectors:
        for p in (s.get("positions") or []):
            tk = (p.get("ticker") or "").strip().upper()
            if tk:
                tickers.append(tk)
    # Dedup while preserving order (largest-weight first, since sectors are
    # already weight-sorted and positions are EV-sorted within sector)
    seen, ordered = set(), []
    for tk in tickers:
        if tk not in seen:
            seen.add(tk); ordered.append(tk)

    if not ordered:
        raise HTTPException(422, "Scenario has no positions to add")

    _watchlist_migrate_legacy_once()
    before = set(_wl_get_db(lp_id) or [])
    added: list[str] = []
    for tk in ordered:
        if not re.fullmatch(r"[A-Z0-9.\-]+", tk):
            continue
        if tk in before:
            continue
        try:
            _wl_add_db(lp_id, tk)
            added.append(tk)
        except Exception as _e:
            print(f"[builder→watchlist] could not add {tk}: {_e!s:.120}")

    # Mark scenario as synced and bump it back to the top of the list
    scenario["watchlist_synced"]    = True
    scenario["watchlist_synced_at"] = datetime.utcnow().isoformat()
    new_list = [scenario] + [s for s in existing if s.get("id") != scenario_id]
    _builder_save_scenarios(lp_id, new_list)

    return {
        "ok":           True,
        "added":        added,
        "added_count":  len(added),
        "total_in_basket": len(ordered),
        "watchlist":    _wl_get_db(lp_id),
    }


# ──────────────────────────────────────────────────────────────────────────────
# LLM Lab — A/B vote tracking + aggregate leaderboard
# ──────────────────────────────────────────────────────────────────────────────
# Per-user vote log under kv_store key 'lab:votes:{lp_id}'. Each vote ties to
# a (ticker, grok_generated_at, alt_generated_at) tuple so re-runs produce a
# fresh comparison ID and don't conflate old votes with new outputs.

_LAB_VOTES_KEY_PREFIX = "lab:votes:"
_LAB_VOTE_LIMIT       = 500   # per user; oldest auto-pruned


def _lab_votes_key(lp_id: str) -> str:
    return _LAB_VOTES_KEY_PREFIX + str(lp_id)


def _lab_load_votes(lp_id: str) -> list[dict]:
    raw = _kv_get(_lab_votes_key(lp_id))
    return raw if isinstance(raw, list) else []


def _lab_save_votes(lp_id: str, votes: list[dict]) -> bool:
    return _kv_put(_lab_votes_key(lp_id), votes)


class LabVoteRequest(BaseModel):
    ticker:    str
    winner:    str           # 'grok' | 'claude' | 'tie'
    note:      str | None = None
    grok_target:   float | None = None
    claude_target: float | None = None
    grok_upside:   float | None = None
    claude_upside: float | None = None


@app.post("/api/v2/lab/vote")
def lab_vote(request: Request, body: LabVoteRequest):
    """Record a comparison vote: which model produced the better report."""
    claims = _claims_or_401(request)
    lp_id = str(claims.get("lp_id") or claims.get("email") or "anon")
    tk = (body.ticker or "").strip().upper()
    if not tk:
        raise HTTPException(400, "ticker is required")
    if body.winner not in ("grok", "claude", "tie"):
        raise HTTPException(400, "winner must be 'grok' | 'claude' | 'tie'")

    vote = {
        "id":             str(uuid.uuid4()),
        "ticker":         tk,
        "winner":         body.winner,
        "note":           (body.note or "")[:500],
        "grok_target":    body.grok_target,
        "claude_target":  body.claude_target,
        "grok_upside":    body.grok_upside,
        "claude_upside":  body.claude_upside,
        "voted_at":       datetime.utcnow().isoformat(),
    }
    votes = _lab_load_votes(lp_id)
    # Replace any previous vote for the same ticker (latest wins)
    votes = [v for v in votes if v.get("ticker") != tk]
    votes.insert(0, vote)
    if len(votes) > _LAB_VOTE_LIMIT:
        votes = votes[:_LAB_VOTE_LIMIT]
    _lab_save_votes(lp_id, votes)
    return vote


@app.get("/api/v2/lab/votes")
def lab_list_votes(request: Request):
    """Return all votes (newest first) for the current user."""
    claims = _claims_or_401(request)
    lp_id = str(claims.get("lp_id") or claims.get("email") or "anon")
    return {"votes": _lab_load_votes(lp_id)}


@app.delete("/api/v2/lab/votes/{vote_id}")
def lab_delete_vote(vote_id: str, request: Request):
    """Remove a single vote."""
    claims = _claims_or_401(request)
    lp_id = str(claims.get("lp_id") or claims.get("email") or "anon")
    votes = _lab_load_votes(lp_id)
    kept  = [v for v in votes if v.get("id") != vote_id]
    if len(kept) == len(votes):
        raise HTTPException(404, "Vote not found")
    _lab_save_votes(lp_id, kept)
    return {"ok": True}


@app.get("/api/v2/lab/stats")
def lab_stats(request: Request):
    """Aggregate stats across all votes for the leaderboard.

    Returns: {
      total, grok_wins, claude_wins, ties, grok_win_pct, claude_win_pct,
      avg_target_delta_pct      — (claude - grok) / grok × 100,  if both targets known
      avg_upside_delta_pct      — claude_upside - grok_upside,    if both known
      target_delta_sign         — 'claude_higher' | 'grok_higher' | 'even'
      upside_delta_sign         — same
      by_ticker:  [{ticker, winner, note, ...}]
    }
    """
    claims = _claims_or_401(request)
    lp_id = str(claims.get("lp_id") or claims.get("email") or "anon")
    votes = _lab_load_votes(lp_id)
    total = len(votes)
    if total == 0:
        return {"total": 0, "grok_wins": 0, "claude_wins": 0, "ties": 0,
                "grok_win_pct": 0, "claude_win_pct": 0, "tie_pct": 0,
                "avg_target_delta_pct": None, "avg_upside_delta_pct": None,
                "target_delta_sign": None, "upside_delta_sign": None,
                "by_ticker": []}

    g = sum(1 for v in votes if v.get("winner") == "grok")
    c = sum(1 for v in votes if v.get("winner") == "claude")
    t = sum(1 for v in votes if v.get("winner") == "tie")

    # Target delta: %% change from grok target → claude target (only votes with both)
    deltas_pct: list[float] = []
    upside_deltas: list[float] = []
    for v in votes:
        gt, ct = v.get("grok_target"), v.get("claude_target")
        if gt and ct and float(gt) != 0:
            deltas_pct.append((float(ct) - float(gt)) / float(gt) * 100.0)
        gu, cu = v.get("grok_upside"), v.get("claude_upside")
        if gu is not None and cu is not None:
            upside_deltas.append(float(cu) - float(gu))

    avg_t = (sum(deltas_pct) / len(deltas_pct)) if deltas_pct else None
    avg_u = (sum(upside_deltas) / len(upside_deltas)) if upside_deltas else None

    def _sign(x):
        if x is None: return None
        if x > 1:  return "claude_higher"
        if x < -1: return "grok_higher"
        return "even"

    return {
        "total":               total,
        "grok_wins":           g,
        "claude_wins":         c,
        "ties":                t,
        "grok_win_pct":        round(g / total * 100, 1),
        "claude_win_pct":      round(c / total * 100, 1),
        "tie_pct":             round(t / total * 100, 1),
        "avg_target_delta_pct": round(avg_t, 2) if avg_t is not None else None,
        "avg_upside_delta_pct": round(avg_u, 2) if avg_u is not None else None,
        "target_delta_sign":    _sign(avg_t),
        "upside_delta_sign":    _sign(avg_u),
        "by_ticker":            votes[:50],   # cap response size
    }


@app.delete("/api/cache")
def clear_local_cache():
    """Delete all locally-cached _DGA_Report.md files from /stocks.

    Dropbox / Drive files are NOT touched — only this server instance's
    local copy is cleared. After the user deletes files from Dropbox,
    calling this endpoint ensures the Research tab reflects the true state
    instead of showing stale reports that were hydrated at startup.
    """
    cleared: list[str] = []
    for md in analyst.STOCKS_FOLDER.glob("*_DGA_Report.md"):
        try:
            md.unlink()
            cleared.append(md.name.replace("_DGA_Report.md", ""))
        except OSError:
            pass
    return {"cleared": cleared, "count": len(cleared)}


@app.post("/api/reports/{ticker}/refresh-data")
def refresh_ticker_data(ticker: str, request: Request,
                        background_tasks: BackgroundTasks):
    """Wipe cached SEC + user_msg + market data for `ticker` and kick off a
    fresh Grok analyze. Use this when a saved report has empty financial
    tables — the cached extract was bad, and reuse_user_msg keeps serving
    it to every downstream LLM run.

    Side effects:
      • Deletes {ticker}_xbrl_extract.json, {ticker}_user_msg.txt,
        {ticker}_market_snapshot.json, and stock-financials/{ticker}/*
      • Triggers a fresh /api/analyze with llm_provider='grok'
        (Claude can be re-compared after the new user_msg lands)
      • Returns the new job_id so the UI can poll progress

    The next 🔬 Compare / 🔬 LLM Lab run on this ticker will see the
    refreshed data automatically (they reuse_user_msg from the new cache).
    """
    _claims_or_401(request)
    tk = (ticker or "").strip().upper()
    if not tk or not tk.replace(".", "").replace("-", "").isalnum() or len(tk) > 12:
        raise HTTPException(status_code=422, detail="Invalid ticker")

    cleared: list[str] = []
    folder = analyst.STOCKS_FOLDER
    # Files to wipe — these are what reuse_user_msg picks up
    cache_files = [
        folder / f"{tk}_xbrl_extract.json",
        folder / f"{tk}_user_msg.txt",
        folder / f"{tk}_market_snapshot.json",
    ]
    for path in cache_files:
        if path.exists():
            try:
                path.unlink()
                cleared.append(path.name)
            except OSError:
                pass
    # Also wipe the downloaded Excel workbooks so pull_sec_financials gets
    # the latest filings (Tesla, etc. publish new 10-Qs that the cached
    # workbooks won't reflect)
    try:
        fin_dir = analyst.STOCKS_FOLDER.parent / "stock-financials" / tk
        if fin_dir.exists():
            import shutil
            shutil.rmtree(fin_dir)
            cleared.append(f"stock-financials/{tk}/*")
    except Exception as _e:
        print(f"[refresh-data] could not wipe stock-financials/{tk}: {_e}")

    # Kick off a fresh Grok analyze (no reuse_user_msg)
    job_id  = str(uuid.uuid4())
    now_iso = datetime.utcnow().isoformat()
    with _jobs_lock:
        _jobs[job_id] = {
            "job_id": job_id, "ticker": tk, "status": "queued",
            "created_at": now_iso, "error": None, "result": None,
            "llm_provider": "grok",
            "progress": {"step": "queued", "pct": 0.0,
                          "label": f"Queued — fresh data refresh for {tk}"},
        }
    _save_job_index_entry(job_id, {"ticker": tk, "type": "refresh",
                                    "created_at": now_iso})
    background_tasks.add_task(_run_analysis, job_id, tk, False, "grok")
    return {
        "ok":      True,
        "cleared": cleared,
        "job_id":  job_id,
        "message": f"Wiped {len(cleared)} cached file(s). Fresh Grok analysis queued — "
                   f"poll /api/jobs/{job_id} for status.",
    }


@app.delete("/api/report/{ticker}")
def delete_report(ticker: str):
    """Delete the locally-cached report files for a single ticker.

    Removes the .md, .docx, and .pptx files from /stocks for *ticker*.
    Dropbox / Drive copies are NOT touched — only this server instance's
    local cache is cleared. The next portfolio or analysis run will
    re-hydrate or regenerate as needed.
    """
    ticker = ticker.strip().upper()
    folder = analyst.STOCKS_FOLDER
    targets = [
        folder / f"{ticker}_DGA_Report.md",
        folder / f"{ticker}_DGA_Report.docx",
        folder / f"{ticker}_DGA_Presentation.pptx",
    ]
    cleared: list[str] = []
    for path in targets:
        if path.exists():
            try:
                path.unlink()
                cleared.append(path.name)
            except OSError:
                pass
    if not cleared:
        raise HTTPException(status_code=404, detail=f"No cached files found for {ticker}")
    return {"ticker": ticker, "cleared": cleared, "count": len(cleared)}


# In-memory summary cache, keyed by md_file.stat().st_mtime_ns. Avoids
# re-parsing the same markdown on every /api/reports call. Capped implicitly
# by the number of tickers a user has cached locally.
_summary_cache: dict[str, dict] = {}


_REPORT_DATE_RE = re.compile(
    r"^\s*\**\s*DGA\s+CAPITAL\s+RESEARCH\s*\**\s*[|:\-—–]\s*(.{4,60}?)\s*\**\s*$",
    re.IGNORECASE | re.MULTILINE,
)
_REPORT_DATE_RE_ALT = re.compile(
    r"^\s*DATE\s*:\s*(.{4,60}?)\s*$",
    re.IGNORECASE | re.MULTILINE,
)


def _extract_report_date(md: str) -> str | None:
    """Pull the analyst's stated 'as-of' date from a DGA report header.

    Matches:
      '**DGA CAPITAL RESEARCH** | April 19, 2026'
      'DGA CAPITAL RESEARCH: 2026-05-22'
      '## DGA Capital Research — May 22, 2026'
    Falls back to a 'DATE: ...' line if no header match.
    Returns the raw date string (display-as-is) or None.
    """
    if not md:
        return None
    # Only scan the first ~2000 chars to keep it cheap on big reports
    head = md[:2000]
    m = _REPORT_DATE_RE.search(head)
    if m:
        d = _clean_report_date(m.group(1))
        if d and len(d) <= 50:
            return d
    m2 = _REPORT_DATE_RE_ALT.search(head)
    if m2:
        d = _clean_report_date(m2.group(1))
        if d and len(d) <= 50:
            return d
    return None


def _clean_report_date(raw: str) -> str:
    """Strip markdown + leading emoji/symbol junk that leaks from report
    headers. e.g. '⚡ **May 22, 2026**' → 'May 22, 2026'. We strip any
    leading run of non-alphanumerics (emoji, asterisks, spaces, pipes) and
    trailing asterisks/punctuation, then collapse whitespace."""
    if not raw:
        return ""
    d = raw.strip()
    d = re.sub(r"^[\W_]+", "", d)        # leading emoji/**/| etc.
    d = re.sub(r"[*\s.,;:|]+$", "", d)   # trailing markdown/punctuation
    d = re.sub(r"\s+", " ", d).strip()
    return d


def _db_upsert_report(
    ticker: str,
    md_text: str,
    summary: dict,
    has_docx: bool,
    has_pptx: bool,
    gamma_url: str | None = None,
    pptx_stale: bool | None = None,
    provider: str = "grok",
) -> None:
    """Upsert one analyst report row into PostgreSQL.

    provider:
      • 'grok'   — writes report_md / generated_at / rating / price_target /
                   upside_pct (the canonical columns; default)
      • 'claude' — writes report_md_claude / claude_generated_at /
                   claude_rating / claude_price_target / claude_upside_pct
                   alongside the existing Grok columns (which stay intact)

    pptx_stale:
      • None   — preserve existing value (don't touch the column)
      • True   — mark deck as old/stale (report rerun without Gamma)
      • False  — deck regenerated alongside the report (in sync)

    Entirely wrapped in try/except — never raises, so a DB failure never
    affects the job result or any calling code.
    """
    if not _PSYCOPG2_OK or not os.environ.get("DATABASE_URL"):
        return
    # Pull the report-header date once — surfaces under the ticker in Saved
    # Reports so the user sees the analyst's as-of date, not the DB upload time.
    report_date = _extract_report_date(md_text)
    # Defensive: ensure all schema columns this function references actually
    # exist before INSERT. Earlier deploys may have missed a column ADD,
    # leaving the INSERT to fail silently with 'column does not exist'.
    try:
        _ensure_analyst_reports_table_schema()
    except Exception:
        pass
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            # ── Claude path: only touches the *_claude columns ──────────
            if provider == "claude":
                cur.execute("""
                    INSERT INTO analyst_reports
                        (ticker, generated_at, report_md, has_docx, has_pptx,
                         report_md_claude, claude_generated_at, claude_report_date,
                         claude_rating, claude_price_target, claude_upside_pct,
                         last_attempt_at, last_attempt_status, last_attempt_error)
                    VALUES (%s, NOW(), '', FALSE, FALSE,
                            %s, NOW(), %s, %s, %s, %s,
                            NOW(), 'success', NULL)
                    ON CONFLICT (ticker) DO UPDATE SET
                        report_md_claude    = EXCLUDED.report_md_claude,
                        claude_generated_at = NOW(),
                        claude_report_date  = EXCLUDED.claude_report_date,
                        claude_rating       = EXCLUDED.claude_rating,
                        claude_price_target = EXCLUDED.claude_price_target,
                        claude_upside_pct   = EXCLUDED.claude_upside_pct,
                        archived            = FALSE,
                        last_attempt_at     = NOW(),
                        last_attempt_status = 'success',
                        last_attempt_error  = NULL
                """, (
                    ticker, md_text, report_date,
                    summary.get("rating"), summary.get("price_target"),
                    summary.get("upside_pct"),
                ))
                return

            # ── Grok path (existing behavior) ──────────────────────────
            if pptx_stale is None:
                # Path A: do not touch pptx_stale
                cur.execute("""
                    INSERT INTO analyst_reports
                        (ticker, generated_at, report_md, has_docx, has_pptx,
                         rating, price_target, upside_pct, gamma_url, report_date,
                         last_attempt_at, last_attempt_status, last_attempt_error)
                    VALUES (%s, NOW(), %s, %s, %s, %s, %s, %s, %s, %s,
                            NOW(), 'success', NULL)
                    ON CONFLICT (ticker) DO UPDATE SET
                        generated_at        = NOW(),
                        report_md           = EXCLUDED.report_md,
                        has_docx            = EXCLUDED.has_docx,
                        has_pptx            = EXCLUDED.has_pptx,
                        rating              = EXCLUDED.rating,
                        price_target        = EXCLUDED.price_target,
                        upside_pct          = EXCLUDED.upside_pct,
                        gamma_url           = EXCLUDED.gamma_url,
                        report_date         = EXCLUDED.report_date,
                        archived            = FALSE,
                        last_attempt_at     = NOW(),
                        last_attempt_status = 'success',
                        last_attempt_error  = NULL
                """, (
                    ticker, md_text, has_docx, has_pptx,
                    summary.get("rating"), summary.get("price_target"),
                    summary.get("upside_pct"), gamma_url, report_date,
                ))
            else:
                # Path B: explicitly set pptx_stale
                cur.execute("""
                    INSERT INTO analyst_reports
                        (ticker, generated_at, report_md, has_docx, has_pptx,
                         rating, price_target, upside_pct, gamma_url, pptx_stale, report_date,
                         last_attempt_at, last_attempt_status, last_attempt_error)
                    VALUES (%s, NOW(), %s, %s, %s, %s, %s, %s, %s, %s, %s,
                            NOW(), 'success', NULL)
                    ON CONFLICT (ticker) DO UPDATE SET
                        generated_at        = NOW(),
                        report_md           = EXCLUDED.report_md,
                        has_docx            = EXCLUDED.has_docx,
                        has_pptx            = EXCLUDED.has_pptx,
                        rating              = EXCLUDED.rating,
                        price_target        = EXCLUDED.price_target,
                        upside_pct          = EXCLUDED.upside_pct,
                        gamma_url           = EXCLUDED.gamma_url,
                        pptx_stale          = EXCLUDED.pptx_stale,
                        report_date         = EXCLUDED.report_date,
                        archived            = FALSE,
                        last_attempt_at     = NOW(),
                        last_attempt_status = 'success',
                        last_attempt_error  = NULL
                """, (
                    ticker, md_text, has_docx, has_pptx,
                    summary.get("rating"), summary.get("price_target"),
                    summary.get("upside_pct"), gamma_url, bool(pptx_stale), report_date,
                ))
    except Exception as _e:
        # LOUD log — easy to grep in Railway logs. Previous version used
        # a vague 'non-fatal' message that buried real schema errors.
        err_str = str(_e)
        is_schema = ("does not exist" in err_str or "column" in err_str.lower())
        prefix = "❌❌❌ SCHEMA-MISSING" if is_schema else "❌ DB-WRITE-FAILED"
        print(f"{prefix} _db_upsert_report({ticker}/{provider}): {err_str!s:.500}", flush=True)
        # On a schema error, force-run the table migration NOW and retry once.
        # The migration is idempotent and cheap; if the column truly was missing
        # this rescues the persist instead of dropping the report.
        if is_schema:
            try:
                _ensure_analyst_reports_table_schema(force=True)
                # Retry — call ourselves with the same args
                return _db_upsert_report(
                    ticker, md_text, summary,
                    has_docx=has_docx, has_pptx=has_pptx,
                    gamma_url=gamma_url, pptx_stale=pptx_stale,
                    provider=provider,
                )
            except Exception as _e2:
                print(f"❌❌❌ retry after schema-fix ALSO failed for {ticker}: {_e2!s:.300}", flush=True)


def _db_record_attempt_failure(ticker: str, error: str) -> None:
    """Mark the most-recent analyze attempt as FAILED for `ticker`.

    Only updates the attempt tracking columns; leaves the existing
    successful report (report_md, generated_at, etc.) untouched so the
    user can still open the old report and see exactly which day's data
    they're looking at while knowing the last refresh failed.

    If no row exists yet for this ticker (failure on first-ever attempt),
    we still create one with empty report fields so the UI can surface
    the failure in the saved-reports list.
    """
    if not _PSYCOPG2_OK or not os.environ.get("DATABASE_URL"):
        return
    err_short = (error or "")[:500]
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                INSERT INTO analyst_reports
                    (ticker, generated_at, report_md, has_docx, has_pptx,
                     last_attempt_at, last_attempt_status, last_attempt_error)
                VALUES (%s, NOW(), '', FALSE, FALSE,
                        NOW(), 'failed', %s)
                ON CONFLICT (ticker) DO UPDATE SET
                    last_attempt_at     = NOW(),
                    last_attempt_status = 'failed',
                    last_attempt_error  = EXCLUDED.last_attempt_error
            """, (ticker, err_short))
    except Exception as _e:
        print(f"[analyst_reports] failure-record failed for {ticker} (non-fatal): {_e!s:.200}")


def _extract_summary_cached(md_file: Path) -> dict:
    """Return {rating, price_target, upside_pct} for a saved report.

    Parsing happens once per (ticker, mtime) pair — re-running an analysis
    bumps mtime which invalidates the cache. We only read the first 12KB
    of the file because every field extract_summary_from_report cares about
    is in the report header / summary table.
    """
    try:
        key = f"{md_file.name}:{md_file.stat().st_mtime_ns}"
    except OSError:
        return {}
    cached = _summary_cache.get(key)
    if cached is not None:
        return cached
    try:
        with open(md_file, "rb") as fh:
            head = fh.read(12 * 1024).decode("utf-8", errors="replace")
        full = analyst.extract_summary_from_report(head)
    except Exception:  # noqa: BLE001
        full = {}
    summary = {
        "rating":        full.get("rating"),
        "price_target":  full.get("price_target"),
        "current_price": full.get("current_price"),
        "upside_pct":    full.get("upside_pct"),
    }
    _summary_cache[key] = summary
    return summary


@app.delete("/api/reports/{ticker}")
def delete_report(ticker: str):
    """Archive a saved report: marks DB row archived=TRUE, moves local files to archive folder.

    The report is NOT permanently deleted — it can be restored from Settings.
    Archived tickers are excluded from list_reports() and hydration so they
    never reappear after a Railway redeploy.
    """
    ticker = ticker.strip().upper()
    archived_db = False
    archived_files = []

    # Mark archived in PostgreSQL (do NOT delete the row — needed for restore)
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute(
                    "UPDATE analyst_reports SET archived = TRUE WHERE ticker = %s",
                    (ticker,)
                )
            archived_db = True
        except Exception as _e:
            print(f"[archive_report] DB update failed for {ticker}: {_e}")

    # Move local files to stocks/archive/ folder instead of deleting
    folder  = analyst.STOCKS_FOLDER
    archive = folder / "archive"
    archive.mkdir(exist_ok=True)
    for suffix in ("_DGA_Report.md", "_DGA_Report.docx", "_DGA_Presentation.pptx"):
        p = folder / f"{ticker}{suffix}"
        if p.exists():
            try:
                p.rename(archive / p.name)
                archived_files.append(suffix)
            except Exception as _e:
                print(f"[archive_report] could not move {p.name}: {_e}")

    # Remove from Market Pulse kv_store so it disappears from the pulse panel
    try:
        pulse = _kv_get("scan.pulse") or {}
        if ticker in pulse:
            pulse.pop(ticker)
            _kv_put("scan.pulse", pulse)
    except Exception:
        pass

    return {"ok": True, "ticker": ticker, "archived_db": archived_db, "archived_files": archived_files}


@app.get("/api/reports/archived")
def list_archived_reports():
    """Return all tickers that have been archived (removed from Saved Reports)."""
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""
                    SELECT ticker, generated_at, rating, price_target, upside_pct
                    FROM analyst_reports
                    WHERE archived = TRUE
                    ORDER BY generated_at DESC
                """)
                rows = cur.fetchall()
            return [
                {
                    "ticker":       r["ticker"],
                    "generated_at": r["generated_at"].isoformat() if r["generated_at"] else None,
                    "rating":       r["rating"],
                    "price_target": float(r["price_target"]) if r["price_target"] else None,
                    "upside_pct":   float(r["upside_pct"])   if r["upside_pct"]   else None,
                }
                for r in rows
            ]
        except Exception as _e:
            print(f"[archived_reports] DB query failed: {_e}")
    return []


@app.post("/api/reports/{ticker}/restore")
def restore_report(ticker: str):
    """Restore an archived report back to active Saved Reports."""
    ticker = ticker.strip().upper()
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute(
                    "UPDATE analyst_reports SET archived = FALSE WHERE ticker = %s",
                    (ticker,)
                )
        except Exception as _e:
            raise HTTPException(status_code=500, detail=f"DB restore failed: {_e}")

    # Move local files back from archive/ to stocks/
    folder  = analyst.STOCKS_FOLDER
    archive = folder / "archive"
    for suffix in ("_DGA_Report.md", "_DGA_Report.docx", "_DGA_Presentation.pptx"):
        p = archive / f"{ticker}{suffix}"
        if p.exists():
            try:
                p.rename(folder / p.name)
            except Exception as _e:
                print(f"[restore_report] could not move {p.name}: {_e}")

    return {"ok": True, "ticker": ticker}


@app.post("/api/reports/restore-all")
def restore_all_reports():
    """Restore ALL archived reports back to active Saved Reports."""
    restored = []
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("SELECT ticker FROM analyst_reports WHERE archived = TRUE")
                tickers = [r[0] for r in cur.fetchall()]
                cur.execute("UPDATE analyst_reports SET archived = FALSE WHERE archived = TRUE")
        except Exception as _e:
            raise HTTPException(status_code=500, detail=f"DB restore-all failed: {_e}")
    else:
        tickers = []

    # Move all archived local files back
    folder  = analyst.STOCKS_FOLDER
    archive = folder / "archive"
    for ticker in tickers:
        for suffix in ("_DGA_Report.md", "_DGA_Report.docx", "_DGA_Presentation.pptx"):
            p = archive / f"{ticker}{suffix}"
            if p.exists():
                try:
                    p.rename(folder / p.name)
                    restored.append(ticker)
                except Exception:
                    pass

    return {"ok": True, "restored": list(set(restored))}


def _backfill_report_dates() -> None:
    """One-shot lazy backfill: extract the in-report date from any existing
    rows where report_date / claude_report_date is NULL. Reads the stored
    report_md / report_md_claude column, runs _extract_report_date(), updates
    the row. Idempotent — only touches rows with NULL date fields.

    Runs inside list_reports so the user never has to wait for a separate
    migration; first call after deploy backfills everything, subsequent
    calls are no-ops because all rows have dates set.
    """
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            # Grok dates
            cur.execute("""
                SELECT ticker, report_md FROM analyst_reports
                 WHERE report_date IS NULL AND report_md IS NOT NULL AND report_md != ''
                 LIMIT 200
            """)
            grok_rows = cur.fetchall()
            for row in grok_rows:
                d = _extract_report_date(row["report_md"] or "")
                if d:
                    try:
                        cur.execute(
                            "UPDATE analyst_reports SET report_date = %s WHERE ticker = %s",
                            (d, row["ticker"]),
                        )
                    except Exception:
                        pass
            # Claude dates
            cur.execute("""
                SELECT ticker, report_md_claude FROM analyst_reports
                 WHERE claude_report_date IS NULL AND report_md_claude IS NOT NULL AND report_md_claude != ''
                 LIMIT 200
            """)
            claude_rows = cur.fetchall()
            for row in claude_rows:
                d = _extract_report_date(row["report_md_claude"] or "")
                if d:
                    try:
                        cur.execute(
                            "UPDATE analyst_reports SET claude_report_date = %s WHERE ticker = %s",
                            (d, row["ticker"]),
                        )
                    except Exception:
                        pass
            if grok_rows or claude_rows:
                print(f"[backfill] report dates filled — {len(grok_rows)} grok + {len(claude_rows)} claude")
    except Exception as _e:
        print(f"[backfill] error: {_e!s:.120}")


def _hydrate_orphaned_grok_reports() -> None:
    """One-shot: backfill any DGA Grok report that's missing from the DB.

    Sources scanned, in order:
      1. Local /stocks/{TICKER}_DGA_Report.md files
      2. Dropbox folder listing — recovers reports whose local file was
         wiped by a Railway dyno restart (the original failure mode for
         the user's INTC report). Calls list_dropbox_report_tickers().

    For each candidate ticker NOT already in analyst_reports.report_md,
    pulls the markdown (disk → Dropbox → Drive → Sheets) and persists via
    _db_upsert_report(provider='grok'). Idempotent: rows with non-empty
    report_md are skipped.
    """
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    folder = analyst.STOCKS_FOLDER

    # ── Source 1: local disk ───────────────────────────────────────────
    local_tickers: set[str] = set()
    try:
        for p in folder.glob("*_DGA_Report.md"):
            if p.name.endswith("_DGA_Report_claude.md"):
                continue
            tk = p.name.replace("_DGA_Report.md", "").upper()
            if tk:
                local_tickers.add(tk)
    except Exception:
        pass

    # ── Source 2: Dropbox listing (RECOVERY for Railway-wiped /stocks) ─
    dropbox_grok: set[str] = set()
    try:
        listings = analyst.list_dropbox_report_tickers()
        dropbox_grok = set(listings.get("grok") or [])
        if dropbox_grok and not local_tickers:
            print(f"[hydrate] /stocks empty; found {len(dropbox_grok)} Grok report(s) in Dropbox", flush=True)
    except Exception as _e:
        print(f"[hydrate] dropbox listing failed: {_e!s:.120}", flush=True)

    candidates = local_tickers | dropbox_grok
    if not candidates:
        return

    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            for tk in candidates:
                # Skip if DB already has Grok content
                cur.execute("""SELECT report_md FROM analyst_reports
                               WHERE ticker = %s""", (tk,))
                row = cur.fetchone()
                if row and (row["report_md"] or "").strip():
                    continue
                # Pull text — disk first, then Drive/Dropbox/Sheets
                text = ""
                local_path = folder / f"{tk}_DGA_Report.md"
                if local_path.exists():
                    try: text = local_path.read_text()
                    except Exception: pass
                if not text or len(text) < 200:
                    try:
                        text = analyst.fetch_report_from_drive(tk, provider="grok") or ""
                    except Exception: pass
                if not text or len(text) < 200:
                    print(f"[hydrate] could not source Grok report for {tk} (no disk + no Drive)", flush=True)
                    continue
                try:
                    summary = analyst.extract_summary_from_report(text) or {}
                    has_docx = (folder / f"{tk}_DGA_Report.docx").exists()
                    has_pptx = (folder / f"{tk}_DGA_Presentation.pptx").exists()
                    _db_upsert_report(
                        tk, text, summary,
                        has_docx=has_docx, has_pptx=has_pptx, gamma_url=None,
                        pptx_stale=None, provider="grok",
                    )
                    src = "disk" if local_path.exists() else "Dropbox"
                    print(f"✅ [hydrate] backfilled Grok report for {tk} from {src} ({len(text):,} chars)", flush=True)
                except Exception as _e:
                    print(f"❌ [hydrate] grok failed for {tk}: {_e!s:.200}", flush=True)
    except Exception as _e:
        print(f"❌ [hydrate] grok outer error: {_e!s:.200}", flush=True)


def _hydrate_orphaned_claude_reports() -> None:
    """One-shot: backfill any DGA Claude report that's missing from the DB.

    Sources scanned, in order:
      1. Local /stocks/{TICKER}_DGA_Report_claude.md files
      2. Dropbox folder listing — recovers reports whose local file was
         wiped by a Railway dyno restart (the original failure mode for
         the user's INTC Claude report). Calls list_dropbox_report_tickers().

    For each candidate ticker whose claude_generated_at is NULL (or
    claude_report_md is empty), pulls the markdown (disk → Dropbox) and
    persists via _db_upsert_report(provider='claude'). Idempotent.
    """
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    folder = analyst.STOCKS_FOLDER

    # ── Source 1: local disk ───────────────────────────────────────────
    local_tickers: set[str] = set()
    try:
        for p in folder.glob("*_DGA_Report_claude.md"):
            tk = p.name.replace("_DGA_Report_claude.md", "").upper()
            if tk:
                local_tickers.add(tk)
    except Exception:
        pass

    # ── Source 2: Dropbox listing (RECOVERY for Railway-wiped /stocks) ─
    dropbox_claude: set[str] = set()
    try:
        listings = analyst.list_dropbox_report_tickers()
        dropbox_claude = set(listings.get("claude") or [])
        if dropbox_claude and not local_tickers:
            print(f"[hydrate] /stocks empty; found {len(dropbox_claude)} Claude report(s) in Dropbox", flush=True)
    except Exception as _e:
        print(f"[hydrate] dropbox listing failed: {_e!s:.120}", flush=True)

    candidates = local_tickers | dropbox_claude
    if not candidates:
        return

    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            for tk in candidates:
                # Skip if DB already has Claude content
                cur.execute("""SELECT claude_generated_at, report_md_claude
                               FROM analyst_reports WHERE ticker = %s""", (tk,))
                row = cur.fetchone()
                if row and row.get("claude_generated_at") and (row.get("report_md_claude") or "").strip():
                    continue
                # Pull text — disk first, then Dropbox
                text = ""
                local_path = folder / f"{tk}_DGA_Report_claude.md"
                if local_path.exists():
                    try: text = local_path.read_text()
                    except Exception: pass
                if not text or len(text) < 200:
                    try:
                        text = analyst.fetch_report_from_drive(tk, provider="claude") or ""
                    except Exception: pass
                if not text or len(text) < 200:
                    print(f"[hydrate] could not source Claude report for {tk} (no disk + no Dropbox)", flush=True)
                    continue
                try:
                    summary = analyst.extract_summary_from_report(text) or {}
                    _db_upsert_report(
                        tk, text, summary,
                        has_docx=False, has_pptx=False, gamma_url=None,
                        pptx_stale=None, provider="claude",
                    )
                    src = "disk" if local_path.exists() else "Dropbox"
                    print(f"✅ [hydrate] backfilled Claude report for {tk} from {src} ({len(text):,} chars)", flush=True)
                except Exception as _e:
                    print(f"❌ [hydrate] claude failed for {tk}: {_e!s:.200}", flush=True)
    except Exception as _e:
        print(f"❌ [hydrate] claude outer error: {_e!s:.200}", flush=True)


def _parse_report_date_ts(val) -> float:
    """Parse report as-of strings ('May 22, 2026') or datetimes → epoch seconds.

    Returns 0 when unparseable. Used to sort Saved Reports by content freshness.
    """
    if val is None or val == "":
        return 0.0
    if hasattr(val, "timestamp"):
        try:
            return float(val.timestamp())
        except Exception:
            return 0.0
    s = str(val).strip()
    if not s:
        return 0.0
    # ISO first
    try:
        iso = s.replace("Z", "+00:00")
        return datetime.fromisoformat(iso).timestamp()
    except Exception:
        pass
    # Common narrative headers: "May 22, 2026" / "May 8, 2026"
    for fmt in ("%B %d, %Y", "%b %d, %Y", "%B %d %Y", "%Y-%m-%d", "%m/%d/%Y"):
        try:
            return datetime.strptime(s, fmt).timestamp()
        except Exception:
            continue
    return 0.0


def _report_freshness_key(row: dict) -> tuple:
    """Sort key for saved reports — freshest content first.

    Prefer the report's *as-of* date (what the analysis covers). Pipeline
    ``generated_at`` is often bulk-stamped by hydration (same second for every
    row) so it is only a fallback when no as-of exists. Rows *with* an as-of
    always rank above rows without one, so bulk stamps don't float empty
    as-of rows to the top.
    """
    content = 0.0
    for k in ("report_date", "claude_report_date"):
        content = max(content, _parse_report_date_ts(row.get(k)))
    if content > 0:
        return (1, content)
    gen = 0.0
    for k in ("claude_generated_at", "generated_at", "last_attempt_at"):
        v = row.get(k)
        if v is None:
            continue
        if hasattr(v, "timestamp"):
            try:
                gen = max(gen, float(v.timestamp()))
            except Exception:
                pass
        else:
            gen = max(gen, _parse_report_date_ts(v))
    return (0, gen)


@app.get("/api/reports")
def list_reports(request: Request = None):
    if request is not None and _request_is_demo(request):
        rows = _kv_get("demo.reports") or []
        demo = [{k: v for k, v in r.items() if k != "report_md"} for r in rows]
        demo.sort(key=_report_freshness_key, reverse=True)
        return demo
    """Return all tickers that have saved reports.

    Each entry now includes an extracted summary (`rating`, `price_target`,
    `upside_pct`) so the Research tab can show a target-vs-price chip in
    the saved-reports list without an extra API round-trip per row.

    Primary source: PostgreSQL `analyst_reports` table (survives Railway redeploys).
    Fallback: filesystem glob of *_DGA_Report.md files.
    """
    # Defensive: ensure all schema columns this endpoint references actually
    # exist before SELECT. Without this, a missed migration on Railway means
    # the SELECT fails → silent fallback to empty filesystem → user sees
    # NO reports even though they exist in the DB.
    try:
        _ensure_analyst_reports_table_schema()
    except Exception:
        pass

    # Lazy one-shot: hydrate any orphaned Grok reports — the typical case
    # is a Grok analysis whose file made it to disk + Drive but whose DB
    # upsert silently failed for any reason. Without this, the user sees
    # the file in Dropbox but nothing in Saved Reports.
    try:
        _hydrate_orphaned_grok_reports()
    except Exception:
        pass
    # Same for orphaned Claude reports (Compare / LLM Lab side artifacts).
    try:
        _hydrate_orphaned_claude_reports()
    except Exception:
        pass
    # Lazy one-shot: backfill report_date / claude_report_date for existing
    # rows that predate the schema migration (extracts from stored markdown).
    try:
        _backfill_report_dates()
    except Exception:
        pass

    # ── Primary: PostgreSQL ──────────────────────────────────────────────────
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""
                    SELECT ticker, generated_at, has_docx, has_pptx,
                           rating, price_target, upside_pct, gamma_url,
                           COALESCE(pptx_stale, FALSE) AS pptx_stale,
                           last_attempt_at, last_attempt_status, last_attempt_error,
                           claude_generated_at, claude_rating,
                           claude_price_target, claude_upside_pct,
                           report_date, claude_report_date
                    FROM analyst_reports
                    WHERE archived IS NOT TRUE
                    ORDER BY GREATEST(
                      COALESCE(generated_at, TIMESTAMP '1970-01-01'),
                      COALESCE(claude_generated_at, TIMESTAMP '1970-01-01'),
                      COALESCE(last_attempt_at, TIMESTAMP '1970-01-01')
                    ) DESC NULLS LAST
                """)
                rows = cur.fetchall()
            if rows:
                out = []
                for r in rows:
                    # Detect which providers have a report
                    # Detect provider presence by timestamp only — requiring
                    # price_target made Claude reports invisible whenever the
                    # extractor's regex couldn't find one (different formatting
                    # from Grok). The pill should always appear so the user
                    # can click in and read the report regardless.
                    has_grok   = bool(r["generated_at"])
                    has_claude = bool(r["claude_generated_at"])
                    providers = []
                    if has_grok:   providers.append("grok")
                    if has_claude: providers.append("claude")
                    provider_badge = "BOTH" if (has_grok and has_claude) else (
                        "CLAUDE" if has_claude else ("GROK" if has_grok else "—"))

                    # Effective (less aggressive) price target / upside for
                    # downstream EV math (Builder, rebalance, etc.). When both
                    # providers have a target, take the LOWER of the two —
                    # that's the conservative read. When only one has data,
                    # use it directly.
                    pt_g  = float(r["price_target"])         if r["price_target"]         is not None else None
                    pt_c  = float(r["claude_price_target"])  if r["claude_price_target"]  is not None else None
                    up_g  = float(r["upside_pct"])           if r["upside_pct"]           is not None else None
                    up_c  = float(r["claude_upside_pct"])    if r["claude_upside_pct"]    is not None else None
                    if pt_g is not None and pt_c is not None:
                        eff_pt = min(pt_g, pt_c)
                    else:
                        eff_pt = pt_g if pt_g is not None else pt_c
                    if up_g is not None and up_c is not None:
                        eff_up = min(up_g, up_c)
                    else:
                        eff_up = up_g if up_g is not None else up_c

                    out.append({
                        "ticker":              r["ticker"],
                        "generated_at":        r["generated_at"].isoformat() if r["generated_at"] else None,
                        "has_docx":            r["has_docx"],
                        "has_pptx":            r["has_pptx"],
                        "pptx_stale":          bool(r["pptx_stale"]),
                        "gamma_url":           r["gamma_url"],
                        "rating":              r["rating"],
                        # Backward-compat: price_target / upside_pct EXPOSE the
                        # effective (conservative) values now. Existing UI
                        # using these fields gets the safer number for free.
                        "price_target":        eff_pt,
                        "upside_pct":          eff_up,
                        "grok_price_target":   pt_g,
                        "grok_upside_pct":     up_g,
                        "claude_price_target": pt_c,
                        "claude_upside_pct":   up_c,
                        "claude_generated_at": r["claude_generated_at"].isoformat() if r["claude_generated_at"] else None,
                        "claude_rating":       r["claude_rating"],
                        "providers":           providers,
                        "provider_badge":      provider_badge,
                        # As-of dates pulled from each LLM's report header
                        # ('DGA CAPITAL RESEARCH | May 22, 2026'). These are
                        # what the user sees under the ticker — distinct from
                        # generated_at (DB upload time).
                        "report_date":         r.get("report_date"),
                        "claude_report_date":  r.get("claude_report_date"),
                        "current_price":       None,
                        "last_attempt_at":     r["last_attempt_at"].isoformat() if r.get("last_attempt_at") else None,
                        "last_attempt_status": r.get("last_attempt_status"),
                        "last_attempt_error":  r.get("last_attempt_error"),
                    })
                # Freshest content first (as-of date), not bulk hydration stamp.
                out.sort(key=_report_freshness_key, reverse=True)
                return out
        except Exception as _e:
            print(f"[analyst_reports] list_reports DB query failed (falling back): {_e!s:.200}")

    # ── Fallback: filesystem glob ────────────────────────────────────────────
    folder = analyst.STOCKS_FOLDER
    try:
        gamma_idx = analyst._load_gamma_index()
    except Exception:
        gamma_idx = {}
    reports = []
    for md_file in sorted(folder.glob("*_DGA_Report.md"), key=lambda p: p.stat().st_mtime, reverse=True):
        ticker = md_file.name.replace("_DGA_Report.md", "")
        has_docx = (folder / f"{ticker}_DGA_Report.docx").exists()
        has_pptx = (folder / f"{ticker}_DGA_Presentation.pptx").exists()
        gamma_entry = gamma_idx.get(ticker) or {}
        summary = _extract_summary_cached(md_file)
        reports.append({
            "ticker": ticker,
            "generated_at": datetime.utcfromtimestamp(md_file.stat().st_mtime).isoformat(),
            "has_docx": has_docx,
            "has_pptx": has_pptx,
            "gamma_url": gamma_entry.get("gamma_url"),
            # Extracted summary fields (may be None for older reports without
            # the standard header).
            "rating":        summary.get("rating"),
            "price_target":  summary.get("price_target"),
            "current_price": summary.get("current_price"),
            "upside_pct":    summary.get("upside_pct"),
            "report_date":   summary.get("report_date") or summary.get("as_of"),
        })
    reports.sort(key=_report_freshness_key, reverse=True)
    return reports


