class WatchlistUpdate(BaseModel):
    tickers: list[str]


# NOTE (ui334): the legacy file-based GET /api/watchlist and
# DELETE /api/watchlist/{ticker} routes that lived here were SHADOWED by the
# v2 DB-backed routes registered earlier (first match wins) — dead code,
# removed. PUT (replace-all) and POST /{ticker} are kept for the legacy
# /app/ shell, still writing the JSON file.
@app.put("/api/watchlist")
def set_watchlist(body: WatchlistUpdate):
    """Replace the entire legacy file watchlist (legacy /app/ shell only)."""
    clean = [t.strip().upper() for t in body.tickers if t.strip()]
    analyst.save_watchlist(clean)
    return {"tickers": analyst.load_watchlist()}


@app.post("/api/watchlist/{ticker}")
def add_watchlist_ticker(ticker: str):
    """Add a single ticker to the legacy file watchlist (legacy /app/ shell)."""
    t = ticker.strip().upper()
    if not t or not t.replace(".", "").isalnum() or len(t) > 10:
        raise HTTPException(status_code=422, detail="Invalid ticker")
    tickers = analyst.add_to_watchlist(t)
    return {"tickers": tickers}


def _all_watchlist_tickers() -> list:
    """Union of the DB watchlists (what the terminal UI writes) and the legacy
    JSON-file list (what pre-v2 tooling wrote). The options-scan and
    market-store universes used to read ONLY the file — tickers added in the
    UI never entered the wheel scan or the quote store."""
    out = []
    try:
        out.extend(analyst.load_watchlist() or [])
    except Exception:
        pass
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            _demo_uids = list((_demo_registry() or {}).get("user_ids") or [])
            with _fund_conn() as conn, conn.cursor() as cur:
                # Exclude demo users' watchlist rows — the real scan universe
                # must never absorb demo-only tickers.
                if _demo_uids:
                    cur.execute("SELECT DISTINCT ticker FROM watchlists "
                                "WHERE lp_id <> ALL(%s)", (_demo_uids,))
                else:
                    cur.execute("SELECT DISTINCT ticker FROM watchlists")
                out.extend(r[0] for r in cur.fetchall())
        except Exception as e:
            print(f"[watchlist] union read failed: {e!s:.120}", flush=True)
    seen, uniq = set(), []
    for t in out:
        t = (t or "").strip().upper()
        if t and t not in seen:
            seen.add(t)
            uniq.append(t)
    return uniq


# ---------------------------------------------------------------------------
# Scan job worker
# ---------------------------------------------------------------------------

def _run_scan(job_id: str, tickers: list[str]) -> None:
    with _sjobs_lock:
        _sjobs[job_id]["status"] = "running"

    completed: dict[str, Any] = {}

    def on_progress(ticker: str, result: dict) -> None:
        with _sjobs_lock:
            _sjobs[job_id]["results"][ticker] = result
            _sjobs[job_id]["tickers_done"] = list(_sjobs[job_id]["results"].keys())
        # Stream each result immediately into scan.pulse so Market Pulse
        # updates ticker-by-ticker without waiting for the full scan to finish.
        try:
            scanned_at = datetime.utcnow().isoformat()
            pulse = _kv_get("scan.pulse") or {}
            pulse[ticker] = dict(result, _scanned_at=scanned_at)
            _kv_put("scan.pulse", pulse)
        except Exception as _pe:
            print(f"[scan] streaming kv persist failed for {ticker}: {_pe}")

    # Cancellation predicate — checked between tickers by analyst.run_portfolio_scan.
    # The in-flight Grok call (if any) completes naturally; we just don't
    # start the next one. xAI charges for any call we already initiated.
    def _is_cancelled() -> bool:
        with _sjobs_lock:
            j = _sjobs.get(job_id) or {}
            return bool(j.get("cancel_requested"))

    try:
        final = analyst.run_portfolio_scan(
            tickers, on_progress=on_progress, verbose=True,
            is_cancelled=_is_cancelled,
        )
        with _sjobs_lock:
            _sjobs[job_id]["status"] = "cancelled" if final.get("cancelled") else "done"
            _sjobs[job_id]["results"] = final["results"]
            _sjobs[job_id]["scanned_at"] = final["scanned_at"]
            _sjobs[job_id]["tickers_done"] = list(final["results"].keys())
        # Merge new results into the persistent kv_store blob so Market Pulse
        # retains results for tickers NOT in this scan (per-ticker persistence).
        try:
            existing = _kv_get("scan.pulse") or {}
            merged = dict(existing)
            for tk, res in final["results"].items():
                merged[tk] = dict(res, _scanned_at=final["scanned_at"])
            _kv_put("scan.pulse", merged)
        except Exception as _ke:
            print(f"[scan] kv persist failed (non-fatal): {_ke}")
    except BaseException as exc:  # noqa: BLE001
        tb = traceback.format_exc()
        print(f"\n❌ Scan job {job_id} CRASHED:\n{tb}", flush=True)
        with _sjobs_lock:
            _sjobs[job_id]["status"] = "failed"
            _sjobs[job_id]["error"] = str(exc)


