@app.get("/api/scan/latest")
def get_latest_scan(request: Request = None):
    if request is not None and _request_is_demo(request):
        return _kv_get("demo.samples.pulse") or {"exists": False}
    """Return the merged per-ticker scan pulse (persists across deploys).

    Primary source: kv_store 'scan.pulse' dict (per-ticker, survives redeploys).
    Each ticker entry keeps its own _scanned_at so results persist until that
    specific ticker is re-scanned.
    Fallback: legacy scan_results.json on disk.
    """
    # Primary: kv_store merged pulse
    pulse = _kv_get("scan.pulse")
    if pulse and isinstance(pulse, dict):
        # Find newest individual scan timestamp for display
        timestamps = [v.get("_scanned_at") for v in pulse.values() if isinstance(v, dict) and v.get("_scanned_at")]
        scanned_at = max(timestamps) if timestamps else None
        return {
            "exists": True,
            "scanned_at": scanned_at,
            "results": pulse,
        }
    # Fallback: legacy disk file
    path = analyst.SCAN_RESULTS_FILE
    if not path.exists():
        return {"exists": False}
    try:
        data = json.loads(path.read_text())
        data["exists"] = True
        return data
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Could not read scan results: {exc}")


@app.get("/api/scan/{job_id}")
def get_scan_status(job_id: str, request: Request = None):
    """Poll a running or completed scan job."""
    if job_id == "demo-scan" or (request is not None and _request_is_demo(request)):
        pulse = _kv_get("demo.samples.pulse") or {}
        res = pulse.get("results") or {}
        return {"job_id": "demo-scan", "status": "done",
                "tickers": list(res), "tickers_done": list(res),
                "results": res, "scanned_at": pulse.get("scanned_at"), "error": None}
    with _sjobs_lock:
        job = _sjobs.get(job_id)
    if not job:
        raise HTTPException(status_code=404, detail="Scan job not found")
    return job


