@app.get("/api/scan/preview")
def scan_preview(threshold: float = 2.5, source: str = "reports"):
    """Preview what a bulk scan would do BEFORE the user clicks Scan.

    source: 'reports' = saved-report tickers (current Scan All button source)
            'market'  = Market Scan list

    Returns:
      { ok, source, threshold,
        total_universe: int,
        movers: [{ticker, pct_change, price}],   // only mover tickers
        movers_count: int,
        est_cost_low_usd: float,   // mover-only cost
        est_cost_high_usd: float,
        all_cost_low_usd: float,   // "scan everything" cost
        all_cost_high_usd: float }
    """
    # Per-call Grok pricing — sticky empirical bounds (incl. live search add-on)
    PER_TICKER_LOW, PER_TICKER_HIGH = 0.04, 0.06

    # Source the universe
    universe: list[str] = []
    if source == "reports":
        if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
            try:
                with _fund_conn() as conn, conn.cursor() as cur:
                    cur.execute("""SELECT ticker FROM analyst_reports
                                   WHERE archived IS NOT TRUE
                                   ORDER BY generated_at DESC""")
                    universe = [r[0] for r in cur.fetchall() if r and r[0]]
            except Exception as _e:
                print(f"[scan/preview] DB query failed: {_e}")
    elif source == "market":
        universe = _get_market_scan_tickers()
    universe = _filter_scan_tickers(universe)

    if not universe:
        return {"ok": True, "source": source, "threshold": threshold,
                "total_universe": 0, "movers": [], "movers_count": 0,
                "est_cost_low_usd": 0, "est_cost_high_usd": 0,
                "all_cost_low_usd": 0, "all_cost_high_usd": 0}

    # Pull quotes for each ticker (fast — yfinance batch under the hood)
    movers: list[dict] = []
    for tk in universe:
        try:
            snap = analyst.fetch_market_snapshot(tk)
            price, prev = snap.get("price"), snap.get("previous_close")
            if price is None or not prev or prev == 0:
                continue
            pct = (price - prev) / prev * 100
            if abs(pct) >= threshold:
                movers.append({
                    "ticker":     tk,
                    "pct_change": round(pct, 2),
                    "price":      round(float(price), 2),
                })
        except Exception:
            pass

    movers.sort(key=lambda m: abs(m["pct_change"]), reverse=True)
    n_movers, n_all = len(movers), len(universe)
    return {
        "ok": True,
        "source":         source,
        "threshold":      threshold,
        "total_universe": n_all,
        "movers":         movers,
        "movers_count":   n_movers,
        "est_cost_low_usd":  round(n_movers * PER_TICKER_LOW,  2),
        "est_cost_high_usd": round(n_movers * PER_TICKER_HIGH, 2),
        "all_cost_low_usd":  round(n_all    * PER_TICKER_LOW,  2),
        "all_cost_high_usd": round(n_all    * PER_TICKER_HIGH, 2),
    }


@app.post("/api/scan/reports")
def start_reports_scan(background_tasks: BackgroundTasks, threshold: float = 0.0):
    """Kick off a live-search scan for tickers in the analyst_reports table.

    threshold > 0  → scan ONLY tickers whose today's |pct_change| ≥ threshold
                     (cheap mover-only mode — recommended default 2.5)
    threshold == 0 → scan ALL saved-report tickers (legacy "scan everything",
                     billed accordingly — confirm the cost with the user first)
    """
    # Collect tickers from DB first, filesystem fallback
    tickers = []
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("SELECT ticker FROM analyst_reports WHERE archived IS NOT TRUE ORDER BY generated_at DESC")
                tickers = [row[0] for row in cur.fetchall()]
        except Exception as _e:
            print(f"[scan/reports] DB query failed: {_e}")
    if not tickers:
        # Filesystem fallback
        tickers = [p.name.replace("_DGA_Report.md", "")
                   for p in analyst.STOCKS_FOLDER.glob("*_DGA_Report.md")]
    tickers = _filter_scan_tickers(tickers)
    if not tickers:
        raise HTTPException(status_code=422, detail="No saved reports to scan")

    # Mover-only filter — saves ~90% of cost on quiet days
    if threshold and threshold > 0:
        all_tickers = list(tickers)
        kept = []
        for tk in all_tickers:
            try:
                snap = analyst.fetch_market_snapshot(tk)
                price, prev = snap.get("price"), snap.get("previous_close")
                if price is not None and prev and prev != 0:
                    pct = abs((price - prev) / prev * 100)
                    if pct >= threshold:
                        kept.append(tk)
            except Exception:
                pass   # don't fail the whole scan because one quote failed
        print(f"[scan/reports] threshold={threshold}% filter: {len(kept)}/{len(all_tickers)} tickers qualify", flush=True)
        tickers = kept
        if not tickers:
            raise HTTPException(
                status_code=422,
                detail=f"No saved-report tickers moved ≥{threshold}% today — nothing to scan.",
            )

    job_id = str(uuid.uuid4())
    now = datetime.utcnow().isoformat()
    with _sjobs_lock:
        _sjobs[job_id] = {
            "job_id": job_id,
            "status": "queued",
            "created_at": now,
            "tickers": tickers,
            "tickers_done": [],
            "results": {},
            "scanned_at": None,
            "error": None,
            "cancel_requested": False,
        }
    background_tasks.add_task(_run_scan, job_id, tickers)
    return _sjobs[job_id]


@app.post("/api/scan/reports/{job_id}/cancel")
def cancel_reports_scan(job_id: str):
    """Request cancellation of an in-flight Saved-Reports scan.

    Takes effect AFTER the in-flight ticker completes — the current Grok
    call (already billed) finishes naturally and the scan exits before
    starting the next one. Saves remaining cost.
    """
    with _sjobs_lock:
        j = _sjobs.get(job_id)
        if not j:
            raise HTTPException(status_code=404, detail="Scan job not found")
        if j.get("status") not in ("queued", "running"):
            return {"ok": False, "message": f"Job is not running (status: {j.get('status')})."}
        j["cancel_requested"] = True
        done = len(j.get("tickers_done") or [])
        total = len(j.get("tickers") or [])
    return {
        "ok": True,
        "message": f"Cancel requested — will stop after current ticker. {done}/{total} done so far.",
    }


# Batch-quote and per-ticker-price cache are now unified in _QUOTE_CACHE above.
# (Previously _batch_quote_cache cached per frozenset(syms); now each symbol
# is cached individually so any call that fetches AAPL warms the cache for
# every other endpoint that later needs AAPL within _QUOTE_TTL seconds.)

# ── Tiingo fallback price source ──────────────────────────────────────────────
# Used when Yahoo returns no data (rate-limited or delisted warning).
# Free tier: real-time IEX prices for US equities, up to 500 req/hr.
# Set TIINGO_API_KEY env var in Railway to enable.
# Register free at https://www.tiingo.com/
def _tiingo_batch(syms: list[str]) -> dict[str, dict]:
    """Fetch {sym: {price, pct_change}} from Tiingo IEX for the given symbols.

    Returns an empty dict if TIINGO_API_KEY is not set or the request fails.
    Tiingo uses the same ticker format as Yahoo for most US equities,
    but prefers lowercase. Symbols are upper-cased in the response map.
    """
    key = os.environ.get("TIINGO_API_KEY", "").strip()
    if not key or not syms:
        return {}
    try:
        import requests as _rq
        # Apply the alias map — Tiingo used to be queried with RAW Fidelity
        # symbols, so "BRKB" priced a different listing entirely ($183 while
        # BRK-B traded ~$506 — the ANAT-IRA incident) and "NLYPRF" returned
        # nothing. Query aliased, answer keyed by the ORIGINAL symbol.
        alias_of = {s: _resolve_ticker_alias(s) for s in syms}
        orig_of = {}
        for o, a in alias_of.items():
            orig_of.setdefault(a.upper(), o.upper())
        tickers_param = ",".join(a.lower() for a in alias_of.values())
        resp = _rq.get(
            "https://api.tiingo.com/iex",
            params={"tickers": tickers_param, "token": key},
            headers={"Content-Type": "application/json"},
            timeout=10,
        )
        if not resp.ok:
            print(f"[tiingo] HTTP {resp.status_code}: {resp.text[:120]}")
            return {}
        rows = resp.json()
        out: dict[str, dict] = {}
        for row in rows:
            sym = (row.get("ticker") or "").upper()
            sym = orig_of.get(sym, sym)
            last       = row.get("last") or row.get("tngoLast")
            prev_close = row.get("prevClose")
            if last is None:
                continue
            pct = ((last - prev_close) / prev_close * 100) if prev_close else None
            out[sym] = {"price": float(last), "pct_change": pct}
        return out
    except Exception as _e:
        print(f"[tiingo] batch failed: {_e}")
        return {}


def _tiingo_single(sym: str) -> dict:
    """Fetch one ticker from Tiingo. Returns {} on miss."""
    result = _tiingo_batch([sym])
    return result.get(sym.upper(), {})

@app.get("/api/quotes")
def batch_quotes(tickers: str = ""):
    """Return {symbol: {price, pct_change}} for a comma-separated ticker list.

    Cascade (cache-miss only) — free sources only (no Tradier):
      1. In-process cache (short TTL)
      2. market_data.get_quotes — Yahoo chart (+ optional Tiingo)
      3. Yahoo chart HTTP (per symbol) — regularMarketPrice / previousClose
      4. yfinance download with safe multi-index extraction
      5. Tiingo (if TIINGO_API_KEY set)
      6. market_quotes store (as_of stamped)

    Day % uses official previous_close vs last when the source provides it.
    """
    originals = [t.strip().upper().rstrip("*") for t in tickers.split(",") if t.strip()][:100]
    if not originals:
        return {}

    # NOTE: _SCAN_EXCLUDE is intentionally NOT applied here — batch_quotes() is
    # a price-only function. Tickers excluded from AI scanning still have real
    # prices and must appear in the live portfolio / watchlist.
    null_row: dict = {"price": None, "pct_change": None}
    result: dict = {}

    # ── Per-ticker cache check ────────────────────────────────────────────────
    now    = time.time()
    misses: list = []
    for sym in originals:
        entry = _QUOTE_CACHE.get(sym)
        if entry and (now - entry["_ts"]) < _QUOTE_TTL and entry.get("price") is not None:
            result[sym] = {"price": entry["price"], "pct_change": entry.get("pct_change")}
            if entry.get("as_of"):
                result[sym]["as_of"] = entry["as_of"]
        else:
            misses.append(sym)

    if not misses:
        return result

    def _pct_from(price, prev):
        try:
            if price is None or prev in (None, 0):
                return None
            return (float(price) - float(prev)) / float(prev) * 100.0
        except (TypeError, ValueError):
            return None

    def _accept(sym: str, price, pct=None, prev=None, source: str = "", as_of=None):
        if price is None:
            return
        try:
            price = float(price)
        except (TypeError, ValueError):
            return
        if price != price:  # NaN
            return
        if pct is None and prev is not None:
            pct = _pct_from(price, prev)
        row = {"price": price, "pct_change": pct}
        if as_of:
            row["as_of"] = as_of
        if source:
            row["source"] = source
        result[sym] = row
        _QUOTE_CACHE[sym] = {**row, "_ts": now}

    # ── 1) Same path as /api/quote/{ticker}: yfinance fast_info (correct prev) ─
    # Parallelized; this is what the report header uses and matches Yahoo Finance.
    if misses and _YFINANCE_OK:
        try:
            from concurrent.futures import ThreadPoolExecutor, as_completed
            def _snap_one(orig: str):
                ysym = _resolve_ticker_alias(orig)
                try:
                    snap = analyst.fetch_market_snapshot(ysym) or {}
                    return orig, snap
                except Exception as e:
                    return orig, {"error": str(e)[:80]}

            with ThreadPoolExecutor(max_workers=min(12, max(2, len(misses)))) as pool:
                futs = {pool.submit(_snap_one, o): o for o in misses}
                for fut in as_completed(futs, timeout=14):
                    try:
                        orig, snap = fut.result()
                    except Exception:
                        continue
                    px = snap.get("price")
                    prev = snap.get("previous_close")
                    pct = snap.get("pct_change")
                    if pct is None:
                        pct = _pct_from(px, prev)
                    if px is not None:
                        _accept(orig, px, pct, prev,
                                source=snap.get("source") or "fast_info")
            misses = [s for s in misses if s not in result or result[s].get("price") is None]
        except Exception as e:
            print(f"[batch_quotes] fast_info batch failed: {e!s:.140}", flush=True)

    # ── 2) market_data Yahoo chart / Tiingo (fixed prev-close priority) ───────
    if misses:
        try:
            import market_data as _md
            ymap = {orig: _resolve_ticker_alias(orig) for orig in misses}
            rev: dict = {}
            for orig, ysym in ymap.items():
                rev.setdefault(ysym, []).append(orig)
            mdq = _md.get_quotes(list(rev.keys())) or {}
            for ysym, q in mdq.items():
                px = q.get("price")
                prev = q.get("prev_close")
                pct = q.get("pct_change")
                if pct is None:
                    pct = _pct_from(px, prev)
                for orig in rev.get(ysym, [ysym]):
                    if orig in misses:
                        _accept(orig, px, pct, prev, source=q.get("source") or "yahoo-chart")
            misses = [s for s in misses if s not in result or result[s].get("price") is None]
        except Exception as e:
            print(f"[batch_quotes] market_data failed: {e!s:.140}", flush=True)

    # ── 3) Yahoo chart HTTP fallback ──────────────────────────────────────────
    if misses:
        try:
            import urllib.request as _urlreq
            still = []
            for orig in misses:
                ysym = _resolve_ticker_alias(orig)
                try:
                    url = (f"https://query1.finance.yahoo.com/v8/finance/chart/{ysym}"
                           f"?range=5d&interval=1d")
                    req = _urlreq.Request(
                        url, headers={"User-Agent": "Mozilla/5.0 DGACapital/1.0"})
                    with _urlreq.urlopen(req, timeout=6) as resp:
                        data = json.loads(resp.read().decode("utf-8", "replace"))
                    res0 = ((data.get("chart") or {}).get("result") or [None])[0]
                    if not res0:
                        still.append(orig)
                        continue
                    meta = res0.get("meta") or {}
                    px = (meta.get("regularMarketPrice")
                          or meta.get("postMarketPrice")
                          or meta.get("preMarketPrice"))
                    # Official prev close first — chartPreviousClose is often wrong
                    prev = (meta.get("previousClose")
                            or meta.get("regularMarketPreviousClose")
                            or meta.get("chartPreviousClose"))
                    if px is None:
                        closes = ((res0.get("indicators") or {}).get("quote") or [{}])[0].get("close") or []
                        closes = [c for c in closes if c is not None]
                        if closes:
                            px = closes[-1]
                            if prev is None and len(closes) >= 2:
                                prev = closes[-2]
                    if px is None:
                        still.append(orig)
                        continue
                    _accept(orig, px, None, prev, source="yahoo-chart")
                except Exception:
                    still.append(orig)
            misses = still
        except Exception as e:
            print(f"[batch_quotes] yahoo-chart path failed: {e!s:.120}", flush=True)

    # ── 4) yfinance download (last resort for multi) ──────────────────────────
    if misses and _YFINANCE_OK:
        ymap = {}
        yahoo_syms = []
        seen_y = set()
        for orig in misses:
            ysym = _resolve_ticker_alias(orig)
            ymap.setdefault(ysym, []).append(orig)
            if ysym not in seen_y:
                seen_y.add(ysym)
                yahoo_syms.append(ysym)
        try:
            import yfinance as _yf
            data = _builder_call_timeout(
                lambda: _yf.download(
                    yahoo_syms, period="5d", auto_adjust=True,
                    progress=False, group_by="column", threads=False),
                10.0, None)
            if data is not None and len(getattr(data, "columns", [])) > 0:
                def _closes_for(ysym: str):
                    # group_by=column → ('Close', TICKER) or flat Close for n=1
                    try:
                        if len(yahoo_syms) == 1:
                            return data["Close"].dropna()
                        if hasattr(data.columns, "levels"):
                            # MultiIndex: try Close then ticker
                            try:
                                return data["Close"][ysym].dropna()
                            except Exception:
                                return data[(ysym, "Close")].dropna()
                        return data[ysym]["Close"].dropna()
                    except Exception:
                        return None

                for ysym, origs in ymap.items():
                    closes = _closes_for(ysym)
                    if closes is None or len(closes) == 0:
                        continue
                    price = float(closes.iloc[-1])
                    prev = float(closes.iloc[-2]) if len(closes) >= 2 else None
                    for orig in origs:
                        if orig in misses:
                            _accept(orig, price, None, prev, source="yfinance")
                misses = [s for s in misses if s not in result or result[s].get("price") is None]
        except Exception as _e:
            print(f"[batch_quotes] yf.download failed: {_e}", flush=True)

    # ── 5) Tiingo ─────────────────────────────────────────────────────────────
    if misses:
        try:
            tiingo_data = _tiingo_batch(misses) or {}
            for orig, q in tiingo_data.items():
                if q.get("price") is not None:
                    _accept(orig, q.get("price"), q.get("pct_change"),
                            source="tiingo")
            misses = [s for s in misses if s not in result or result[s].get("price") is None]
        except Exception as e:
            print(f"[batch_quotes] tiingo failed: {e!s:.120}", flush=True)

    # ── 6) Fresh store (≤90s) then any-age store ──────────────────────────────
    if misses:
        try:
            db_fn = globals().get("_db_quotes")
            db_fresh = db_fn(misses, max_age_s=90) if callable(db_fn) else {}
        except Exception as e:
            print(f"[batch_quotes] db_quotes fresh failed: {e!s:.120}", flush=True)
            db_fresh = {}
        for sym, dq in (db_fresh or {}).items():
            if dq and dq.get("price") is not None:
                _accept(sym, dq["price"], dq.get("pct_change"),
                        source="store-fresh", as_of=dq.get("as_of"))
        misses = [s for s in misses if s not in result or result[s].get("price") is None]

    if misses:
        try:
            db_fn = globals().get("_db_quotes")
            db_any = db_fn(misses) if callable(db_fn) else {}
        except Exception as e:
            print(f"[batch_quotes] db_quotes any-age failed: {e!s:.120}", flush=True)
            db_any = {}
        for sym, dq in (db_any or {}).items():
            if dq and dq.get("price") is not None:
                _accept(sym, dq["price"], dq.get("pct_change"),
                        source="store", as_of=dq.get("as_of"))
                print(f"[quotes] {sym}: live miss → store as_of {dq.get('as_of')}", flush=True)
        misses = [s for s in misses if s not in result or result[s].get("price") is None]

    # Fill remaining with nulls (short negative cache)
    for sym in originals:
        if sym not in result:
            result[sym] = dict(null_row)
            _QUOTE_CACHE[sym] = {**null_row, "_ts": now - _QUOTE_TTL + 45}

    return result


# ---------------------------------------------------------------------------
# Intelligence — macro → sector → company idea generation
# ---------------------------------------------------------------------------

def _run_intelligence(job_id: str, sector: str) -> None:
    with _ijobs_lock:
        _ijobs[job_id]["status"] = "running"
    try:
        result = analyst.run_market_intelligence(sector)
        with _ijobs_lock:
            _ijobs[job_id]["status"] = "done" if result.get("ok") else "failed"
            _ijobs[job_id]["result"] = result
            if not result.get("ok"):
                _ijobs[job_id]["error"] = result.get("error", "Unknown error")
        # Persist the latest successful run to Postgres so /api/intelligence/latest
        # survives Railway redeploys (file in STOCKS_FOLDER is ephemeral).
        if result.get("ok"):
            try:
                _kv_put("intelligence.latest", {
                    **result,
                    "completed_at": datetime.utcnow().isoformat() + "Z",
                    "sector": sector,
                })
            except Exception as _e:
                print(f"[intelligence] kv_put failed: {_e}")
    except BaseException as exc:  # noqa: BLE001
        tb = traceback.format_exc()
        print(f"\n❌ Intelligence job {job_id} CRASHED:\n{tb}", flush=True)
        with _ijobs_lock:
            _ijobs[job_id]["status"] = "failed"
            _ijobs[job_id]["error"] = str(exc)


@app.post("/api/intelligence")
def start_intelligence(req: IntelligenceRequest, background_tasks: BackgroundTasks):
    """Start a market intelligence run for the given sector focus."""
    sector = (req.sector or "Tech").strip()
    job_id = str(uuid.uuid4())
    now = datetime.utcnow().isoformat()
    with _ijobs_lock:
        _ijobs[job_id] = {
            "job_id": job_id,
            "status": "queued",
            "created_at": now,
            "sector": sector,
            "result": None,
            "error": None,
        }
    background_tasks.add_task(_run_intelligence, job_id, sector)
    return _ijobs[job_id]


@app.get("/api/intelligence/latest")
def get_latest_intelligence():
    """Return the most-recently-completed intelligence run.

    PRIMARY: kv_store row `intelligence.latest` (Postgres — survives deploys).
    FALLBACK: legacy intelligence.json on disk for local-only runs that
    pre-date the DB migration.
    """
    payload = _kv_get("intelligence.latest")
    if payload is not None:
        payload["exists"] = True
        return payload
    path = analyst.INTEL_FILE
    if not path.exists():
        return {"exists": False}
    try:
        data = json.loads(path.read_text())
        data["exists"] = True
        # Opportunistic backfill so the next deploy doesn't have to re-read disk
        _kv_put("intelligence.latest", data)
        return data
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Could not read intelligence: {exc}")


@app.get("/api/intelligence/{job_id}")
def get_intelligence_status(job_id: str):
    """Poll a running or completed intelligence job."""
    with _ijobs_lock:
        job = _ijobs.get(job_id)
    if not job:
        raise HTTPException(status_code=404, detail="Intelligence job not found")
    return job


# ---------------------------------------------------------------------------
# Daily Brief — Goldman-style PM morning note (Grok 4.x w/ live X + web)
# ---------------------------------------------------------------------------

def _dga_book_tickers(limit: int = 80) -> list[str]:
    """The firm's 'book' for the Daily Pulse — open positions across all live
    funds + saved-report names. Lets the brief lead with the live X read on the
    tickers DGA actually holds and follows. Firm-wide (no lp_id needed)."""
    tks: list[str] = []
    seen: set[str] = set()

    def _add(t):
        t = (t or "").strip().upper().rstrip("*")
        if t and re.fullmatch(r"[A-Z0-9.\-]+", t) and t not in seen:
            seen.add(t)
            tks.append(t)

    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("""SELECT DISTINCT s.symbol FROM tax_lots tl
                                 JOIN securities s ON s.id = tl.security_id
                                 JOIN funds f ON f.id = tl.fund_id
                                WHERE f.status != 'closed' AND tl.closed_at IS NULL
                                  AND tl.quantity > 0 AND s.asset_class != 'cash'""")
                for r in cur.fetchall():
                    _add(r[0])
                cur.execute("SELECT DISTINCT ticker FROM analyst_reports WHERE archived IS NOT TRUE")
                for r in cur.fetchall():
                    _add(r[0])
        except Exception as e:
            print(f"[daily_brief] book gather failed: {e!s:.140}", flush=True)
    return tks[:limit]


def _run_daily_brief(job_id: str) -> None:
    with _bjobs_lock:
        _bjobs[job_id]["status"] = "running"
    try:
        # Option 4: when volume LLM is on, attach free Market Wire + Fund Filings
        # so the cheap model has ground truth without Grok live-search spend.
        evidence = ""
        try:
            if analyst.volume_llm_enabled():
                evidence = _volume_evidence_pack("anon")
        except Exception as _e:
            print(f"[daily_brief] evidence pack: {_e!s:.120}", flush=True)
        result = analyst.run_daily_brief(
            book_tickers=_dga_book_tickers(),
            evidence_context=evidence,
        )
        with _bjobs_lock:
            _bjobs[job_id]["status"] = "done" if result.get("ok") else "failed"
            _bjobs[job_id]["result"] = result
            if not result.get("ok"):
                _bjobs[job_id]["error"] = result.get("error", "Unknown error")
        if result.get("ok"):
            try:
                _kv_put("daily_brief.latest", {
                    **result,
                    "completed_at": _now_pacific().isoformat(),
                    "generated_at": _now_pacific().isoformat(),
                })
            except Exception as _e:
                print(f"[daily_brief] kv_put failed: {_e}")
    except BaseException as exc:  # noqa: BLE001
        tb = traceback.format_exc()
        print(f"\n❌ Daily Brief job {job_id} CRASHED:\n{tb}", flush=True)
        with _bjobs_lock:
            _bjobs[job_id]["status"] = "failed"
            _bjobs[job_id]["error"] = str(exc)


@app.post("/api/daily-brief")
def start_daily_brief(background_tasks: BackgroundTasks, request: Request = None):
    """Start PM morning brief. Volume LLM when Option 4 enabled; else Grok+live."""
    if request is not None and _request_is_demo(request):
        return {"job_id": "demo-brief", "status": "done"}
    job_id = str(uuid.uuid4())
    now = _now_pacific().isoformat()
    with _bjobs_lock:
        _bjobs[job_id] = {
            "job_id": job_id,
            "status": "queued",
            "created_at": now,
            "result": None,
            "error": None,
        }
    background_tasks.add_task(_run_daily_brief, job_id)
    return _bjobs[job_id]


@app.get("/api/daily-brief/latest")
def get_latest_daily_brief(request: Request = None):
    if request is not None and _request_is_demo(request):
        return _kv_get("demo.samples.daily_brief") or {"exists": False}
    """Return the most-recently-completed daily brief.

    PRIMARY: kv_store row `daily_brief.latest` (Postgres — survives deploys).
    FALLBACK: legacy daily_brief.json on disk.
    """
    payload = _kv_get("daily_brief.latest")
    if payload is not None:
        payload["exists"] = True
        return payload
    path = analyst.DAILY_BRIEF_FILE
    if not path.exists():
        return {"exists": False}
    try:
        data = json.loads(path.read_text())
        data["exists"] = True
        _kv_put("daily_brief.latest", data)
        return data
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Could not read daily brief: {exc}")


@app.get("/api/daily-brief/{job_id}")
def get_daily_brief_status(job_id: str, request: Request = None):
    """Poll a running or completed daily-brief job."""
    if job_id == "demo-brief" or (request is not None and _request_is_demo(request)):
        s = _kv_get("demo.samples.daily_brief") or {}
        return {"job_id": "demo-brief", "status": "done",
                "markdown": s.get("markdown"), "generated_at": s.get("generated_at"),
                "error": None}
    with _bjobs_lock:
        job = _bjobs.get(job_id)
    if not job:
        raise HTTPException(status_code=404, detail="Daily brief job not found")
    return job


