# ── Automation settings (stored in kv_store) ─────────────────────────────────
_DEFAULT_AUTOMATION: dict = {
    "daily_brief":  {"enabled": True,  "hour": 8, "minute": 0},
    "market_pulse": {"enabled": True,  "hour": 8, "minute": 15},
    # Pre-market pull of SnapTrade (Fidelity) holdings → tax_lots, plus daily
    # balance snapshots, activity ingest and balance-history rebuild — the
    # hands-off replacement for the manual CSV imports. On by default; a saved
    # automation.settings override (the UI toggle) still wins.
    "snaptrade_sync": {"enabled": True, "hour": 6, "minute": 0},
    # Nightly: SEC refresh for FOLLOWED names only (saved reports + watchlist).
    # Insert-only new periods — does not overwrite. Free, tiny set, low Railway cost.
    "fin_nightly": {"enabled": True, "hour": 2, "minute": 30},
    # Monthly: light refresh of the REST of company_financials (oldest first).
    # day = day-of-month (1–28). Insert-only. Off-hours, small budget.
    "fin_monthly": {"enabled": True, "hour": 3, "minute": 15, "day": 1},
    # Legacy key — maps to fin_nightly for older clients; prefer fin_nightly.
    "fin_overnight": {"enabled": True, "hour": 2, "minute": 30},
    # Continuous full-US backfill supervisor — OFF by default (expensive / noisy).
    "fin_us_backfill": {"enabled": False},
}

def _get_automation_settings() -> dict:
    saved = _kv_get("automation.settings") or {}
    result = {}
    for job, defaults in _DEFAULT_AUTOMATION.items():
        result[job] = {**defaults, **(saved.get(job) or {})}
    return result

def _secs_until(hour: int, minute: int, pacific_offset=None) -> float:
    """Seconds until the next occurrence of HH:MM Pacific."""
    now = _now_pacific()
    target = now.replace(hour=hour, minute=minute, second=0, microsecond=0)
    if now >= target:
        target += timedelta(days=1)
    return (target - now).total_seconds()


def _secs_until_dom(day: int, hour: int, minute: int) -> float:
    """Seconds until next day-of-month at HH:MM Pacific (day clamped 1–28)."""
    day = max(1, min(int(day or 1), 28))
    hour = max(0, min(int(hour or 0), 23))
    minute = max(0, min(int(minute or 0), 59))
    now = _now_pacific()
    # Walk forward at most ~32 days to hit the next matching DOM.
    for i in range(0, 40):
        cand = (now + timedelta(days=i)).replace(
            hour=hour, minute=minute, second=0, microsecond=0)
        if cand.day == day and cand > now:
            return (cand - now).total_seconds()
    # Fallback: ~30 days
    return float(30 * 86400)

def _automation_record_run(job: str, ok, detail: str = "") -> None:
    """Persist per-scheduler run status so the UI / health endpoint can show it.
    ok=None means "started/claimed" — written BEFORE a catch-up run so a deploy
    that kills the job mid-flight doesn't make the next boot re-launch it.
    (Without the claim, ~15 deploys in one day re-fired the daily brief and a
    full market-pulse AI scan on every restart — constant background load.)"""
    try:
        _kv_put(f"automation.last_run.{job}",
                {"ts": datetime.utcnow().isoformat(),
                 "ok": (None if ok is None else bool(ok)),
                 "detail": str(detail)[:400]})
    except Exception:
        pass


_CATCHUP_DONE: dict = {}   # {job: pacific-date-str} — in-process once-a-day guard


def _automation_needs_catchup(job: str, hour: int, minute: int) -> bool:
    """True when today's scheduled run was missed — e.g. a Railway deploy
    restarted the process across the run time (the sleep-until-target pattern
    has no memory). The worker then runs once immediately instead of silently
    skipping the day. The in-process _CATCHUP_DONE guard means a failing
    kv write (DB down) can't turn this into a run-the-job-every-loop cycle."""
    try:
        now_p = _now_pacific()
        today_key = now_p.date().isoformat()
        if _CATCHUP_DONE.get(job) == today_key:
            return False
        if (now_p.hour, now_p.minute) < (int(hour), int(minute)):
            return False   # scheduled time not reached yet — don't set the flag
        _CATCHUP_DONE[job] = today_key   # one evaluation past the gate per day
        rec = _kv_get(f"automation.last_run.{job}") or {}
        last_day = (rec.get("ts") or "")[:10]
        # last_run ts is UTC; a morning-Pacific run lands on the same UTC
        # calendar day, so a plain date compare is a safe once-a-day guard.
        return last_day != today_key
    except Exception:
        return False


@app.get("/api/automation/settings")
def get_automation_settings_endpoint():
    settings = _get_automation_settings()
    now_pac = _now_pacific()
    # Annotate each job with seconds_until_next so the UI can show "next in Xh"
    for job, cfg in settings.items():
        if cfg["enabled"]:
            secs = _secs_until(cfg["hour"], cfg["minute"])
            cfg["next_run_secs"] = round(secs)
        else:
            cfg["next_run_secs"] = None
        try:
            cfg["last_run"] = _kv_get(f"automation.last_run.{job}") or None
        except Exception:
            cfg["last_run"] = None
    return settings

@app.post("/api/automation/settings")
def save_automation_settings_endpoint(request: Request):
    body = _request_json_sync(request)
    current = _get_automation_settings()
    for job in ("daily_brief", "market_pulse", "snaptrade_sync",
                "fin_nightly", "fin_monthly", "fin_overnight", "fin_us_backfill"):
        if job in body and isinstance(body[job], dict):
            patch = body[job]
            if "enabled" in patch:
                current[job]["enabled"] = bool(patch["enabled"])
            if "hour" in patch:
                current[job]["hour"] = max(0, min(23, int(patch["hour"])))
            if "minute" in patch:
                current[job]["minute"] = max(0, min(59, int(patch["minute"])))
            if "day" in patch and job == "fin_monthly":
                current[job]["day"] = max(1, min(28, int(patch["day"])))
            # Keep legacy fin_overnight aligned with fin_nightly when either is patched
            if job == "fin_nightly":
                lo = dict(current.get("fin_overnight") or {})
                if "enabled" in patch:
                    lo["enabled"] = bool(patch["enabled"])
                if "hour" in patch:
                    lo["hour"] = current[job]["hour"]
                if "minute" in patch:
                    lo["minute"] = current[job]["minute"]
                current["fin_overnight"] = lo
    _kv_put("automation.settings", current)
    print(f"[automation] settings updated: {current}")
    return current


# ── Auto-schedule daily brief every morning (time from automation.settings) ───
def _auto_daily_brief_worker() -> None:
    """Daemon thread: fires run_daily_brief() daily at the configured Pacific time."""
    import time as _time
    while True:
        try:
            cfg = _get_automation_settings().get("daily_brief", _DEFAULT_AUTOMATION["daily_brief"])
            if not cfg.get("enabled", True):
                # Disabled — sleep 1h then re-check in case user re-enables
                print("[daily-brief-scheduler] disabled — sleeping 1h")
                _time.sleep(3600)
                continue
            h, m = cfg["hour"], cfg["minute"]
            # NO deploy-restart catch-up here: the daily brief is an AI job
            # that COSTS MONEY — it runs ONLY at its scheduled time. (The
            # catch-up briefly added in ui335 re-fired it on every deploy;
            # auto-recovery is reserved for the free, data-only SnapTrade sync.)
            wait_secs = _secs_until(h, m)
            print(f"[daily-brief-scheduler] next run at {h:02d}:{m:02d} Pacific — sleeping {wait_secs/3600:.1f}h")
            _time.sleep(wait_secs)
            # Re-check enabled after waking (user may have disabled while sleeping)
            cfg2 = _get_automation_settings().get("daily_brief", {})
            if not cfg2.get("enabled", True):
                print("[daily-brief-scheduler] disabled after wake — skipping")
                continue
            print(f"[daily-brief-scheduler] {h:02d}:{m:02d} Pacific — running daily brief…")
            # Same call as the manual endpoint — includes the GP's book tickers.
            # Volume mode attaches free evidence; rollback uses Grok+live.
            _ev = ""
            try:
                if analyst.volume_llm_enabled():
                    _ev = _volume_evidence_pack("anon")
            except Exception:
                pass
            analyst.run_daily_brief(book_tickers=_dga_book_tickers(), evidence_context=_ev)
            # Persist to kv_store so the UI picks it up
            try:
                brief = analyst.DAILY_BRIEF_FILE
                if brief.exists():
                    import json as _json
                    data = _json.loads(brief.read_text())
                    _kv_put("daily_brief.latest", data)
            except Exception as _e:
                print(f"[daily-brief-scheduler] kv persist failed: {_e}")
            _automation_record_run("daily_brief", True, "ok")
        except Exception as _e:
            print(f"[daily-brief-scheduler] error (retrying in 1h): {_e}")
            _automation_record_run("daily_brief", False, str(_e))
            import time as _time2
            _time2.sleep(3600)

threading.Thread(target=_auto_daily_brief_worker, daemon=True, name="daily-brief-scheduler").start()

# ── Auto-scan all saved reports into Market Pulse (time from automation.settings)
def _auto_market_pulse_worker() -> None:
    """Daemon: scans all saved-report tickers at the configured Pacific time."""
    import time as _time
    while True:
        try:
            cfg = _get_automation_settings().get("market_pulse", _DEFAULT_AUTOMATION["market_pulse"])
            if not cfg.get("enabled", True):
                print("[pulse-scheduler] disabled — sleeping 1h")
                _time.sleep(3600)
                continue
            h, m = cfg["hour"], cfg["minute"]
            # NO deploy-restart catch-up: the pulse scan is an AI job that
            # COSTS MONEY — scheduled time only, never auto-relaunched.
            wait_secs = _secs_until(h, m)
            print(f"[pulse-scheduler] next run at {h:02d}:{m:02d} Pacific — sleeping {wait_secs/3600:.1f}h")
            _time.sleep(wait_secs)
            cfg2 = _get_automation_settings().get("market_pulse", {})
            if not cfg2.get("enabled", True):
                print("[pulse-scheduler] disabled after wake — skipping")
                continue
            print(f"[pulse-scheduler] {h:02d}:{m:02d} Pacific — running market pulse scan on saved reports…")
            # Collect tickers from DB
            tickers = []
            if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
                try:
                    with _fund_conn() as conn, conn.cursor() as cur:
                        cur.execute("SELECT ticker FROM analyst_reports WHERE archived IS NOT TRUE ORDER BY generated_at DESC")
                        tickers = [r[0] for r in cur.fetchall()]
                except Exception as _e:
                    print(f"[pulse-scheduler] DB query failed: {_e}")
            tickers = _filter_scan_tickers(tickers)
            if not tickers:
                print("[pulse-scheduler] no tickers to scan — skipping")
                continue
            print(f"[pulse-scheduler] scanning {len(tickers)} tickers…")
            job_id = str(uuid.uuid4())
            with _sjobs_lock:
                _sjobs[job_id] = {
                    "job_id": job_id, "status": "queued", "created_at": datetime.utcnow().isoformat(),
                    "tickers": tickers, "tickers_done": [], "results": {}, "scanned_at": None, "error": None,
                }
            _run_scan(job_id, tickers)   # blocking — intentional (runs in its own thread)
            print(f"[pulse-scheduler] scan complete — {len(tickers)} tickers merged into Market Pulse")
            _automation_record_run("market_pulse", True, f"{len(tickers)} tickers")
        except Exception as _e:
            import time as _t2
            print(f"[pulse-scheduler] error (retrying in 1h): {_e}")
            _automation_record_run("market_pulse", False, str(_e))
            _t2.sleep(3600)

threading.Thread(target=_auto_market_pulse_worker, daemon=True, name="pulse-scheduler").start()


# ── Auto-sync SnapTrade (Fidelity) holdings pre-market (time from automation.settings)
def _auto_snaptrade_sync_worker() -> None:
    """Daemon: pulls SnapTrade holdings → tax_lots daily at the configured Pacific
    time. Opt-in (disabled by default); runs the same logic as the ↻ Sync button."""
    import time as _time
    while True:
        try:
            cfg = _get_automation_settings().get("snaptrade_sync", _DEFAULT_AUTOMATION["snaptrade_sync"])
            if not cfg.get("enabled", False):
                _time.sleep(3600)
                continue
            h, m = cfg["hour"], cfg["minute"]
            if _automation_needs_catchup("snaptrade_sync", h, m):
                print("[snaptrade-scheduler] missed today's run — catching up now")
                _automation_record_run("snaptrade_sync", None, "catch-up started")
            else:
                wait_secs = _secs_until(h, m)
                print(f"[snaptrade-scheduler] next run at {h:02d}:{m:02d} Pacific — sleeping {wait_secs/3600:.1f}h")
                _time.sleep(wait_secs)
                cfg2 = _get_automation_settings().get("snaptrade_sync", {})
                if not cfg2.get("enabled", False):
                    print("[snaptrade-scheduler] disabled after wake — skipping")
                    continue
            if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
                print("[snaptrade-scheduler] no database — skipping")
                continue
            print(f"[snaptrade-scheduler] {h:02d}:{m:02d} Pacific — syncing SnapTrade holdings…")
            res = _snaptrade_run_sync()
            n_err = len(res.get('errors', []))
            n_ok  = len(res.get('synced', []))
            print(f"[snaptrade-scheduler] synced {n_ok} account(s), "
                  f"pushed {len(res.get('lots_written',[]))} fund(s); "
                  f"{n_err} error(s)")
            # ok = CORE success (accounts synced). Per-account warnings used to
            # flip the whole run to "failed" on the Data Health card even when
            # positions/activities landed fine — warnings go in detail instead.
            _automation_record_run(
                "snaptrade_sync", n_ok > 0,
                (f"{n_ok} accounts" + (f" · {n_err} warning(s): "
                    + json.dumps(res.get("errors", []))[:280] if n_err else ""))
                if n_ok else json.dumps(res.get("errors", []))[:400])
        except Exception as _e:
            import time as _t2
            print(f"[snaptrade-scheduler] error (retrying in 1h): {_e}")
            _automation_record_run("snaptrade_sync", False, str(_e))
            _t2.sleep(3600)

threading.Thread(target=_auto_snaptrade_sync_worker, daemon=True, name="snaptrade-scheduler").start()


# ---------------------------------------------------------------------------
# Fund Admin — read-only endpoints (queries Railway Postgres via psycopg2)
# ---------------------------------------------------------------------------
try:
    import psycopg2
    from psycopg2.extras import RealDictCursor as _RealDictCursor
    _PSYCOPG2_OK = True
except ImportError:
    _PSYCOPG2_OK = False

# ── Connection pool ──────────────────────────────────────────────────────────
# _fund_conn() used to do psycopg2.connect() per call (217 call sites — a full
# TCP+TLS handshake to Railway Postgres each time, ~50-150ms). The pool makes
# checkout ~free. _PooledConn keeps the EXACT semantics call sites rely on:
# conn.close() (or GC of the proxy) releases back to the pool; `with conn:`
# still commits/rollbacks without releasing, matching psycopg2.
_FUND_POOL = None
_FUND_POOL_LOCK = threading.Lock()


def _get_fund_pool():
    global _FUND_POOL
    if _FUND_POOL is None:
        with _FUND_POOL_LOCK:
            if _FUND_POOL is None:
                from psycopg2 import pool as _pgpool
                _FUND_POOL = _pgpool.ThreadedConnectionPool(
                    1, 10, os.environ["DATABASE_URL"],
                    keepalives=1, keepalives_idle=30,
                    keepalives_interval=10, keepalives_count=3)
    return _FUND_POOL


class _PooledConn:
    """Proxy over a pooled psycopg2 connection.

    close() returns the connection to the pool (after rolling back any open
    transaction and resetting autocommit) instead of really closing it, so
    every existing call site — explicit conn.close(), try/finally, and the
    many `with _fund_conn() as conn` blocks that rely on GC — keeps working
    unchanged. __del__ releases too, matching the old close-on-GC behavior.
    """
    __slots__ = ("_conn", "_released")

    def __init__(self, conn):
        object.__setattr__(self, "_conn", conn)
        object.__setattr__(self, "_released", False)

    def close(self):
        if self._released:
            return
        object.__setattr__(self, "_released", True)
        pool = _FUND_POOL
        try:
            if pool is None or self._conn.closed:
                try:
                    self._conn.close()
                except Exception:
                    pass
                if pool is not None:
                    try:
                        pool.putconn(self._conn, close=True)
                    except Exception:
                        pass
                return
            try:
                if not self._conn.autocommit:
                    self._conn.rollback()
                self._conn.autocommit = False
            except Exception:
                pool.putconn(self._conn, close=True)
                return
            pool.putconn(self._conn)
        except Exception:
            try:
                self._conn.close()
            except Exception:
                pass

    def __enter__(self):
        self._conn.__enter__()
        return self

    def __exit__(self, *exc):
        # psycopg2 semantics: commit/rollback but do NOT close — several call
        # sites keep using the conn after a `with conn:` block.
        return self._conn.__exit__(*exc)

    def __getattr__(self, name):
        return getattr(self._conn, name)

    def __setattr__(self, name, value):
        setattr(self._conn, name, value)

    def __del__(self):
        try:
            self.close()
        except Exception:
            pass


def _fund_conn():
    if not _PSYCOPG2_OK:
        raise HTTPException(status_code=503, detail="psycopg2 not installed")
    url = os.environ.get("DATABASE_URL")
    if not url:
        raise HTTPException(status_code=503, detail="DATABASE_URL not configured")
    # Ensure self-migrations have run before the first real query.
    # Cheap no-op after the first successful run (guarded by _MIGRATIONS_APPLIED).
    try:
        _apply_self_migrations()
    except Exception:
        pass
    # Pooled path with a liveness probe (a server-closed idle conn is retried
    # once); any pool failure falls back to a direct connect — never worse
    # than the old behavior.
    try:
        pool = _get_fund_pool()
        for _attempt in (1, 2):
            raw = pool.getconn()
            try:
                with raw.cursor() as _c:
                    _c.execute("SELECT 1")
                raw.rollback()
                return _PooledConn(raw)
            except Exception:
                try:
                    pool.putconn(raw, close=True)
                except Exception:
                    pass
    except Exception as e:
        print(f"[db-pool] falling back to direct connect: {e!s:.120}", flush=True)
    try:
        return psycopg2.connect(url)
    except Exception as e:
        raise HTTPException(status_code=503, detail=f"Fund DB unavailable: {e}")



def _db_quotes(symbols, max_age_s=None) -> dict:
    """{SYM: {price, pct_change, as_of?}} from market_quotes store.

    Always defined on the server module (not only after financials domain mount)
    so /api/quotes, watchlist, fund positions, and mobile never NameError when
    the domain mount is late or fails. Financials body may re-bind the same name.
    """
    syms = [s.strip().upper() for s in (symbols or []) if s and str(s).strip()]
    if not syms:
        return {}
    if not globals().get("_PSYCOPG2_OK") or not os.environ.get("DATABASE_URL"):
        return {}
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            if max_age_s is not None:
                cur.execute("""SELECT symbol, price, pct_change, updated_at FROM market_quotes
                                WHERE symbol = ANY(%s)
                                  AND updated_at > now() - (%s || ' seconds')::interval""",
                            (syms, str(int(max_age_s))))
            else:
                cur.execute("SELECT symbol, price, pct_change, updated_at FROM market_quotes "
                            "WHERE symbol = ANY(%s)", (syms,))
            return {r["symbol"]: {"price": r["price"], "pct_change": r["pct_change"],
                                  "as_of": r["updated_at"].isoformat() if r.get("updated_at") else None}
                    for r in (cur.fetchall() or []) if r.get("price") is not None}
    except Exception as e:
        print(f"[market] db_quotes failed: {e!s:.120}", flush=True)
        return {}


def _db_meta(symbols) -> dict:
    """{SYM: {name, sector, industry, ...}} from security_meta — always available."""
    syms = [s.strip().upper() for s in (symbols or []) if s and str(s).strip()]
    if not syms:
        return {}
    if not globals().get("_PSYCOPG2_OK") or not os.environ.get("DATABASE_URL"):
        return {}
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""SELECT symbol, name, sector, industry, analyst_target
                             FROM security_meta WHERE symbol = ANY(%s)""", (syms,))
            return {r["symbol"]: dict(r) for r in (cur.fetchall() or []) if r.get("symbol")}
    except Exception as e:
        print(f"[market] db_meta failed: {e!s:.120}", flush=True)
        return {}


def _ddl_once(fn):
    """Run a DDL ensure-table function only once per process.

    The `_ensure_*` functions are idempotent, but several sat on hot request
    paths executing CREATE TABLE + ALTERs (5-10 extra round-trips + catalog
    locks) on EVERY call — e.g. the quarterly-letter read path. First
    completed call wins; a process restart naturally retries, so a transient
    first-call failure can't permanently skip the DDL across deploys.
    """
    import functools
    state = {"done": False}

    @functools.wraps(fn)
    def wrapper(*a, **k):
        if state["done"]:
            return
        r = fn(*a, **k)
        state["done"] = True
        return r
    return wrapper


# ---------------------------------------------------------------------------
# Idempotent self-applying migrations.
# Each ALTER uses IF NOT EXISTS so it's safe to run on every startup.
# Failures are logged but don't crash the app.
# ---------------------------------------------------------------------------
_MIGRATIONS_APPLIED = False

# ---------------------------------------------------------------------------
# SQL statement splitter — handles dollar-quoted strings ($$...$$, $tag$...$tag$)
# so we can split a .sql migration file into individual statements.
# ---------------------------------------------------------------------------
def _iter_sql_statements(sql: str):
    """Yield individual SQL statements, properly handling $$ dollar-quoted blocks."""
    buf: list[str] = []
    dollar_tag: str | None = None
    i = 0
    n = len(sql)
    while i < n:
        # Skip single-line comments outside dollar quotes
        if dollar_tag is None and sql[i] == '-' and i + 1 < n and sql[i + 1] == '-':
            while i < n and sql[i] != '\n':
                i += 1
            continue
        # Detect dollar-quote open / close
        if sql[i] == '$':
            j = sql.find('$', i + 1)
            if j >= 0:
                tag = sql[i: j + 1]
                if dollar_tag is None:
                    # Opening a dollar-quote block
                    dollar_tag = tag
                    buf.append(tag)
                    i = j + 1
                    continue
                elif tag == dollar_tag:
                    # Closing the dollar-quote block
                    buf.append(tag)
                    dollar_tag = None
                    i = j + 1
                    continue
        # Statement terminator (only outside dollar quotes)
        if dollar_tag is None and sql[i] == ';':
            stmt = ''.join(buf).strip()
            if stmt and not stmt.startswith('--'):
                yield stmt
            buf = []
            i += 1
            continue
        buf.append(sql[i])
        i += 1
    # Trailing statement (no trailing semicolon)
    stmt = ''.join(buf).strip()
    if stmt and not stmt.startswith('--'):
        yield stmt


def _exec_sql_file(conn, path: Path) -> tuple[int, int]:
    """Execute every statement in *path* against *conn*.

    Returns (ok_count, err_count). Errors are logged but do not abort the run
    so we get as many tables created as possible even if, e.g., an extension
    isn't available.
    """
    try:
        sql = path.read_text(encoding='utf-8')
    except Exception as e:
        print(f"[migration] cannot read {path.name}: {e}")
        return 0, 1

    ok = err = 0
    for stmt in _iter_sql_statements(sql):
        # Skip pure comment blocks
        stripped = '\n'.join(
            line for line in stmt.splitlines()
            if not line.strip().startswith('--')
        ).strip()
        if not stripped:
            continue
        try:
            with conn.cursor() as cur:
                cur.execute(stripped)
            conn.commit()
            ok += 1
        except Exception as e:
            conn.rollback()
            err += 1
            print(f"[migration] non-fatal ({path.name}): {e!s:.120}")
    print(f"[migration] {path.name}: {ok} ok, {err} errors")
    return ok, err


