# Money-market / cash tickers to exclude from equity rebalance
_CASH_TICKERS = {"SPAXX", "FDRXX", "FDLXX", "FZFXX", "FZDXX", "SPRXX", "VMFXX"}

def _is_cash_ticker(sym: str) -> bool:
    """Return True if this ticker is cash/money-market, a bond CUSIP, or ignored.
    All of these should be excluded from equity rebalance calculations.
    """
    clean = sym.rstrip("*").upper()
    if clean in _CASH_TICKERS:
        return True
    # Bond CUSIPs (start with digit) and ignored tickers (portfolio names etc.)
    if _is_bond_cusip(clean) or _ticker_should_ignore(clean):
        return True
    return False


# ── Runtime ticker alias/ignore management ────────────────────────────────────

@app.get("/api/v2/admin/ticker-map")
def get_ticker_map(request: Request):
    """Return current alias + ignore dictionaries. GP-only."""
    _require_fund_token(request)
    return {
        "aliases": _TICKER_ALIASES,
        "ignore":  _TICKER_IGNORE,
        "bonds_auto_detected": "Any ticker whose first character (after stripping $) is a digit",
    }


class TickerAliasRequest(BaseModel):
    source: str   # e.g. "BRKB"
    target: str   # e.g. "BRK-B"

class TickerIgnoreRequest(BaseModel):
    ticker: str   # e.g. "EM50"
    reason: str = "user_added"

@app.post("/api/v2/admin/ticker-map/alias")
def add_ticker_alias(body: TickerAliasRequest, request: Request):
    """Add a runtime alias (e.g. BRKB → BRK-B). Persists for the life of the process."""
    _require_fund_token(request)
    src = body.source.strip().upper()
    tgt = body.target.strip().upper()
    if not src or not tgt:
        raise HTTPException(status_code=422, detail="source and target required")
    _TICKER_ALIASES[src] = tgt
    # Flush unified quote cache for this symbol so it re-resolves immediately.
    _QUOTE_CACHE.pop(src, None)
    print(f"[ticker-map] alias added: {src} → {tgt}")
    return {"ok": True, "alias": {src: tgt}}

@app.post("/api/v2/admin/ticker-map/ignore")
def add_ticker_ignore(body: TickerIgnoreRequest, request: Request):
    """Add a ticker to the ignore list (portfolio names, phantom rows, etc.)."""
    _require_fund_token(request)
    sym = body.ticker.strip().upper()
    if not sym:
        raise HTTPException(status_code=422, detail="ticker required")
    _TICKER_IGNORE[sym] = body.reason
    _QUOTE_CACHE.pop(sym, None)
    print(f"[ticker-map] ignore added: {sym} ({body.reason})")
    return {"ok": True, "ignored": sym, "reason": body.reason}


def _force_ipv4_connect(hostname: str, port: int, timeout: int = 20):
    """Resolve hostname to an IPv4 address and return a connected socket.

    Railway containers sometimes default to IPv6 which either has no route
    (Errno 101 ENETUNREACH) or hits Cloudflare IP bans. Forcing AF_INET
    ensures we always go out on the IPv4 path.
    """
    import socket
    addrs = socket.getaddrinfo(hostname, port, socket.AF_INET, socket.SOCK_STREAM)
    if not addrs:
        raise OSError(f"No IPv4 address found for {hostname}")
    ipv4_addr = addrs[0][4]          # (ip, port) tuple
    sock = socket.create_connection(ipv4_addr, timeout=timeout)
    return sock, ipv4_addr[0]


def _send_via_gmail(to_addr: str, subject: str, html_body: str) -> dict:
    """Send HTML email via Gmail SMTP, forcing IPv4 to avoid Railway's IPv6 routing gaps."""
    import smtplib, ssl, socket
    from email.mime.multipart import MIMEMultipart
    from email.mime.text import MIMEText

    gmail_user = os.environ.get("GMAIL_USER", "")
    gmail_pwd  = os.environ.get("GMAIL_APP_PASSWORD", "")
    if not gmail_user or not gmail_pwd:
        return {"ok": False, "error": "GMAIL_USER or GMAIL_APP_PASSWORD not set"}

    from_addr = f"DGA Capital Reports <{gmail_user}>"
    msg = MIMEMultipart("alternative")
    msg["Subject"] = subject
    msg["From"]    = from_addr
    msg["To"]      = to_addr
    msg.attach(MIMEText(html_body, "html"))

    smtp_host = "smtp.gmail.com"
    last_err  = None

    # Try port 587 (STARTTLS) then 465 (SSL), both forced to IPv4
    for port, use_ssl in [(587, False), (465, True)]:
        try:
            raw_sock, ipv4 = _force_ipv4_connect(smtp_host, port)
            ctx = ssl.create_default_context()
            if use_ssl:
                ssl_sock = ctx.wrap_socket(raw_sock, server_hostname=smtp_host)
                smtp = smtplib.SMTP_SSL.__new__(smtplib.SMTP_SSL)
                smtplib.SMTP.__init__(smtp, timeout=20)
                smtp.sock = ssl_sock
                smtp.file = ssl_sock.makefile("rb")
                smtp._tls_established = True
                smtp.ehlo(smtp_host)
            else:
                smtp = smtplib.SMTP.__new__(smtplib.SMTP)
                smtplib.SMTP.__init__(smtp, timeout=20)
                smtp.sock = raw_sock
                smtp.file = raw_sock.makefile("rb")
                smtp.ehlo(smtp_host)
                smtp.starttls(context=ctx)
                smtp.ehlo(smtp_host)
            smtp.login(gmail_user, gmail_pwd)
            smtp.sendmail(gmail_user, [to_addr], msg.as_string())
            smtp.quit()
            return {"ok": True, "transport": f"gmail_smtp:{port}", "ipv4": ipv4,
                    "sent_to": to_addr, "from": from_addr}
        except smtplib.SMTPAuthenticationError as e:
            # Auth error is definitive — no point trying the other port
            return {"ok": False,
                    "error": f"Gmail auth failed (port {port}): generate an App Password at "
                             "myaccount.google.com → Security → App passwords. "
                             f"Detail: {e}"}
        except OSError as e:
            last_err = f"port {port}: {e}"
        except Exception as e:
            last_err = f"port {port}: {e}"

    return {"ok": False, "error": f"Gmail SMTP failed on all ports — {last_err}"}


def _send_via_resend(to_addr: str, subject: str, html_body: str) -> dict:
    """Send HTML email via Resend REST API, forcing IPv4 to avoid Cloudflare 1010 on IPv6."""
    import http.client, ssl, socket

    resend_key  = os.environ.get("RESEND_API_KEY", "")
    resend_from = os.environ.get("RESEND_FROM", "") or "DGA Capital <reports@dgacapital.com>"
    if not resend_key:
        return {"ok": False, "error": "RESEND_API_KEY not set"}

    payload = json.dumps({
        "from": resend_from, "to": [to_addr],
        "subject": subject, "html": html_body,
    }).encode()

    api_host = "api.resend.com"
    try:
        # Force IPv4 — Cloudflare 1010 is typically an IPv6 ASN block
        raw_sock, ipv4 = _force_ipv4_connect(api_host, 443)
        ctx = ssl.create_default_context()
        ssl_sock = ctx.wrap_socket(raw_sock, server_hostname=api_host)

        # Reuse HTTPSConnection but inject our pre-connected socket
        conn = http.client.HTTPSConnection(api_host, 443, timeout=20)
        conn.sock = ssl_sock

        conn.request("POST", "/emails", body=payload, headers={
            "Authorization":  f"Bearer {resend_key}",
            "Content-Type":   "application/json",
            "User-Agent":     "DGA-Capital-Server/1.0",
            "Accept":         "application/json",
        })
        resp      = conn.getresponse()
        resp_body = resp.read().decode("utf-8", "replace")

        if resp.status >= 400:
            hint = ""
            if resp.status == 403:
                hint = (" — Still getting Cloudflare 1010 even on IPv4 "
                        f"({ipv4}). The current Railway container's IPv4 may also be "
                        "blocked. Re-deploy on Railway to get a fresh IP, or set "
                        "RESEND_FROM and try again.")
            elif resp.status == 401:
                hint = " — API key invalid or revoked."
            elif resp.status == 422:
                hint = " — Invalid from/to address."
            return {"ok": False,
                    "error": f"Resend HTTP {resp.status}: {resp_body[:300]}{hint}",
                    "ipv4": ipv4}
        return {"ok": True, "transport": "resend", "ipv4": ipv4,
                "sent_to": to_addr, "from": resend_from}

    except OSError as e:
        return {"ok": False, "error": f"Network error reaching Resend (IPv4): {e}"}
    except Exception as e:
        return {"ok": False, "error": f"Resend request failed: {e}"}


def _send_simple_email(to_addr: str, subject: str, html_body: str) -> dict:
    """Send HTML email. Both transports now force IPv4 to fix Railway's IPv6 routing gaps.
    Tries Resend first (original working path), falls back to Gmail SMTP."""
    resend_key = os.environ.get("RESEND_API_KEY", "")
    gmail_user = os.environ.get("GMAIL_USER", "")
    gmail_pwd  = os.environ.get("GMAIL_APP_PASSWORD", "")

    if resend_key:
        result = _send_via_resend(to_addr, subject, html_body)
        if result["ok"]:
            return result
        print(f"[email] Resend failed ({result.get('error')}), trying Gmail SMTP…")

    if gmail_user and gmail_pwd:
        return _send_via_gmail(to_addr, subject, html_body)

    return {"ok": False, "error": "No email transport configured (need RESEND_API_KEY or GMAIL_USER+GMAIL_APP_PASSWORD)"}


def _render_report_pdf(html: str) -> bytes:
    """Convert a report HTML string to PDF bytes using WeasyPrint."""
    from weasyprint import HTML as _WP_HTML
    return _WP_HTML(string=html).write_pdf()


def _send_email_with_pdf_attachment(
    to_addr: str,
    subject: str,
    text_html: str,
    pdf_bytes: bytes,
    pdf_filename: str = "quarterly_report.pdf",
) -> dict:
    """Send an email with a PDF file attached. Tries Resend then Gmail SMTP."""
    import base64 as _b64
    resend_key = os.environ.get("RESEND_API_KEY", "")
    gmail_user = os.environ.get("GMAIL_USER", "")
    gmail_pwd  = os.environ.get("GMAIL_APP_PASSWORD", "")

    if resend_key:
        result = _send_via_resend_with_attachment(
            to_addr, subject, text_html, pdf_bytes, pdf_filename)
        if result["ok"]:
            return result
        print(f"[email] Resend attachment failed ({result.get('error')}), trying Gmail SMTP…")

    if gmail_user and gmail_pwd:
        return _send_via_gmail_with_attachment(
            to_addr, subject, text_html, pdf_bytes, pdf_filename)

    return {"ok": False, "error": "No email transport configured"}


def _send_via_resend_with_attachment(
    to_addr: str,
    subject: str,
    html_body: str,
    pdf_bytes: bytes,
    pdf_filename: str,
) -> dict:
    """Resend REST API — email with PDF attachment."""
    import http.client, ssl, socket, base64 as _b64

    resend_key  = os.environ.get("RESEND_API_KEY", "")
    resend_from = os.environ.get("RESEND_FROM", "") or "DGA Capital <reports@dgacapital.com>"
    if not resend_key:
        return {"ok": False, "error": "RESEND_API_KEY not set"}

    payload = json.dumps({
        "from":    resend_from,
        "to":      [to_addr],
        "subject": subject,
        "html":    html_body,
        "attachments": [{
            "filename": pdf_filename,
            "content":  _b64.b64encode(pdf_bytes).decode("ascii"),
        }],
    }).encode()

    api_host = "api.resend.com"
    try:
        raw_sock, ipv4 = _force_ipv4_connect(api_host, 443)
        ctx      = ssl.create_default_context()
        ssl_sock = ctx.wrap_socket(raw_sock, server_hostname=api_host)
        conn     = http.client.HTTPSConnection(api_host, 443, timeout=30)
        conn.sock = ssl_sock
        conn.request("POST", "/emails", body=payload, headers={
            "Authorization": f"Bearer {resend_key}",
            "Content-Type":  "application/json",
            "User-Agent":    "DGA-Capital-Server/1.0",
            "Accept":        "application/json",
        })
        resp      = conn.getresponse()
        resp_body = resp.read().decode("utf-8", "replace")
        if resp.status >= 400:
            return {"ok": False, "error": f"Resend HTTP {resp.status}: {resp_body[:300]}", "ipv4": ipv4}
        return {"ok": True, "transport": "resend+pdf", "ipv4": ipv4, "sent_to": to_addr}
    except OSError as e:
        return {"ok": False, "error": f"Network error: {e}"}
    except Exception as e:
        return {"ok": False, "error": f"Resend attachment request failed: {e}"}


def _send_via_gmail_with_attachment(
    to_addr: str,
    subject: str,
    html_body: str,
    pdf_bytes: bytes,
    pdf_filename: str,
) -> dict:
    """Gmail SMTP — email with PDF attachment."""
    import smtplib, ssl, socket
    from email.mime.multipart import MIMEMultipart
    from email.mime.text import MIMEText
    from email.mime.base import MIMEBase
    from email import encoders

    gmail_user = os.environ.get("GMAIL_USER", "")
    gmail_pwd  = os.environ.get("GMAIL_APP_PASSWORD", "")
    if not gmail_user or not gmail_pwd:
        return {"ok": False, "error": "GMAIL_USER or GMAIL_APP_PASSWORD not set"}

    from_addr = f"DGA Capital Reports <{gmail_user}>"
    msg = MIMEMultipart("mixed")
    msg["Subject"] = subject
    msg["From"]    = from_addr
    msg["To"]      = to_addr

    # HTML body part
    msg.attach(MIMEText(html_body, "html"))

    # PDF attachment
    part = MIMEBase("application", "pdf")
    part.set_payload(pdf_bytes)
    encoders.encode_base64(part)
    part.add_header("Content-Disposition", f'attachment; filename="{pdf_filename}"')
    msg.attach(part)

    smtp_host = "smtp.gmail.com"
    last_err  = None
    for port, use_ssl in [(587, False), (465, True)]:
        try:
            raw_sock, ipv4 = _force_ipv4_connect(smtp_host, port)
            ctx = ssl.create_default_context()
            if use_ssl:
                ssl_sock = ctx.wrap_socket(raw_sock, server_hostname=smtp_host)
                smtp = smtplib.SMTP_SSL.__new__(smtplib.SMTP_SSL)
                smtplib.SMTP.__init__(smtp, timeout=30)
                smtp.sock = ssl_sock
                smtp.file = ssl_sock.makefile("rb")
                smtp._tls_established = True
                smtp.ehlo(smtp_host)
            else:
                smtp = smtplib.SMTP.__new__(smtplib.SMTP)
                smtplib.SMTP.__init__(smtp, timeout=30)
                smtp.sock = raw_sock
                smtp.file = raw_sock.makefile("rb")
                smtp.ehlo(smtp_host)
                smtp.starttls(context=ctx)
                smtp.ehlo(smtp_host)
            smtp.login(gmail_user, gmail_pwd)
            smtp.sendmail(gmail_user, [to_addr], msg.as_string())
            smtp.quit()
            return {"ok": True, "transport": f"gmail_smtp+pdf:{port}", "ipv4": ipv4, "sent_to": to_addr}
        except smtplib.SMTPAuthenticationError as e:
            return {"ok": False, "error": f"Gmail auth failed: {e}"}
        except OSError as e:
            last_err = f"port {port}: {e}"
        except Exception as e:
            last_err = f"port {port}: {e}"

    return {"ok": False, "error": f"Gmail SMTP failed — {last_err}"}


@app.get("/api/v2/gp/email-diag")
def email_diag(request: Request):
    """Diagnose email transport — checks Resend API key, verified domains, and SMTP config.
    Returns a full diagnostic report so we know exactly what to fix."""
    claims = getattr(request.state, "auth_claims", None)
    if not claims or claims.get("role") not in ("gp", "admin"):
        _require_fund_token(request)

    import urllib.request as _urlreq, urllib.error as _urlerr

    result: dict = {}

    # 1. Environment variables (masked)
    resend_key        = os.environ.get("RESEND_API_KEY", "")
    resend_from       = os.environ.get("RESEND_FROM", "")
    resend_acct_email = os.environ.get("RESEND_ACCOUNT_EMAIL", "")
    gmail_user        = os.environ.get("GMAIL_USER", "")
    gmail_pwd         = os.environ.get("GMAIL_APP_PASSWORD", "")

    result["env"] = {
        "RESEND_API_KEY":       f"set ({resend_key[:6]}...)" if resend_key else "NOT SET",
        "RESEND_FROM":          resend_from or "NOT SET (defaults to onboarding@resend.dev)",
        "RESEND_ACCOUNT_EMAIL": resend_acct_email or "NOT SET — set this to your Resend signup email for test-mode sending",
        "GMAIL_USER":           gmail_user or "NOT SET",
        "GMAIL_APP_PASSWORD":   "set" if gmail_pwd else "NOT SET",
    }

    test_to = resend_acct_email or (claims.get("email", "") if claims else "")

    # 2. Resend API test (forced IPv4 — fixes Cloudflare 1010 on IPv6)
    if resend_key:
        result["resend_test"] = _send_via_resend(
            test_to or gmail_user or "test@dgacapital.com",
            "[DGA diag] Resend API test",
            "<p>Resend transport test from Railway (IPv4-forced).</p>",
        )
    else:
        result["resend_test"] = {"skipped": "RESEND_API_KEY not set"}

    # 3. Gmail SMTP test (forced IPv4 — fixes ENETUNREACH on IPv6)
    if gmail_user and gmail_pwd:
        result["gmail_test"] = _send_via_gmail(
            test_to or gmail_user,
            "[DGA diag] Gmail SMTP test",
            "<p>Gmail SMTP transport test from Railway (IPv4-forced).</p>",
        )
    else:
        result["gmail_test"] = {"skipped": "GMAIL_USER or GMAIL_APP_PASSWORD not set"}

    # 4. Diagnosis
    resend_ok = result["resend_test"].get("ok", False)
    gmail_ok  = result["gmail_test"].get("ok", False)

    if resend_ok:
        result["active_transport"] = "resend"
        result["status"] = "✅ Resend is working (IPv4) — report emails will use Resend"
    elif gmail_ok:
        result["active_transport"] = "gmail_smtp"
        result["status"] = "✅ Gmail SMTP is working (IPv4) — report emails will fall back to Gmail"
    else:
        result["active_transport"] = "none"
        result["status"] = "❌ Both transports failed — see notes below"

    resend_err = result["resend_test"].get("error", "")
    gmail_err  = result["gmail_test"].get("error", "")
    notes = []
    if "1010" in resend_err and "IPv4" in resend_err:
        notes.append(
            "Resend: still 1010 even on IPv4 — this specific Railway container's IP is "
            "on Cloudflare's blocklist. Re-deploy on Railway (Settings → Deploy → Redeploy) "
            "to get a fresh IP assignment. If it keeps happening, set RESEND_FROM in Railway "
            "env vars and open a ticket with Resend support."
        )
    elif "1010" in resend_err:
        notes.append("Resend: IPv4 forcing is now in place — if 1010 persists, redeploy on Railway.")
    if "unreachable" in gmail_err.lower() or "101" in gmail_err:
        notes.append(
            "Gmail: ENETUNREACH on both ports suggests Railway is restricting outbound "
            "SMTP (25/465/587). This is uncommon on Railway — try redeploying. "
            "If it persists, use Resend as the primary path."
        )
    if "auth" in gmail_err.lower():
        notes.append(
            "Gmail auth error: GMAIL_APP_PASSWORD must be a Gmail App Password, not your "
            "regular Google password. Generate one at "
            "myaccount.google.com → Security → App passwords."
        )
    if not resend_from:
        notes.append(
            "RESEND_FROM is not set — Resend will try to send from onboarding@resend.dev "
            "which is only allowed for Resend's own account email. "
            "Set RESEND_FROM=DGA Capital <reports@dgacapital.com> in Railway env vars."
        )
    result["notes"] = notes
    return result


@app.post("/api/v2/gp/email-test")
def email_test_send(request: Request):
    """Send a quick test email to verify Resend is working end-to-end.
    Body: { "to": "user@example.com" }   (required)
    Returns the raw result from _send_simple_email so the caller sees
    exactly what Resend replied."""
    claims = getattr(request.state, "auth_claims", None)
    if not claims or claims.get("role") not in ("gp", "admin"):
        raise HTTPException(status_code=403, detail="GP access required")
    try:
        body_raw = _request_body_sync(request)
        body_json = json.loads(body_raw) if body_raw else {}
    except Exception:
        body_json = {}
    to_addr = (body_json.get("to") or "").strip()
    if not to_addr or "@" not in to_addr:
        raise HTTPException(status_code=422, detail="Provide a valid 'to' email address in the request body")

    resend_key  = os.environ.get("RESEND_API_KEY", "")
    resend_from = os.environ.get("RESEND_FROM", "") or "DGA Capital <reports@dgacapital.com>"

    html_body = f"""
<!DOCTYPE html><html><body style="font-family:sans-serif;padding:32px;background:#f0f4f8;">
  <div style="max-width:480px;margin:0 auto;background:#fff;border-radius:12px;padding:28px;
              box-shadow:0 4px 20px rgba(0,0,0,0.10);border-top:4px solid #5BB8D4;">
    <img src="https://portfolio.dgacapital.com/web/assets/dga_logo.png"
         style="height:36px;margin-bottom:20px;" alt="DGA Capital" onerror="this.style.display='none'">
    <h2 style="color:#0A1628;margin:0 0 8px;">✅ Email Transport Working</h2>
    <p style="color:#475569;font-size:14px;margin:0 0 16px;">
      This is a test email from the DGA Capital GP Portal.<br>
      Sent via Resend from <strong>{resend_from}</strong>.
    </p>
    <hr style="border:none;border-top:1px solid #e2e8f0;margin:16px 0;">
    <p style="color:#94a3b8;font-size:11px;margin:0;">
      Sent {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC &mdash; DGA Capital GP Portal
    </p>
  </div>
</body></html>"""

    result = _send_simple_email(to_addr, "[DGA] Email test — GP Portal", html_body)
    # Always return 200 so the UI gets the full result dict (ok + error detail)
    result["to"]   = to_addr
    result["from"] = resend_from
    result["key_set"] = bool(resend_key)
    return result


@app.get("/api/v2/gp/fund/{fund_id}/rebalance")
def get_account_rebalance(fund_id: str, request: Request):
    """Return the persisted rebalance result for a managed account."""
    _require_fund_token(request)
    result = _kv_get(f"rebalance.account.{fund_id}")
    if result is None:
        return {"ok": False, "detail": "No rebalance yet"}
    return result


@app.post("/api/v2/gp/fund/{fund_id}/rebalance")
def run_account_rebalance(fund_id: str, request: Request):
    """Run a fresh portfolio rebalance for a managed account and persist results."""
    claims = getattr(request.state, "auth_claims", None)
    if not claims or claims.get("role") not in ("gp", "admin"):
        _require_fund_token(request)  # fall back to legacy fund token

    if not _PSYCOPG2_OK:
        raise HTTPException(status_code=503, detail="Database not available")

    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            # 1. Resolve fund id
            fid = _resolve_fund_id(cur, fund_id)

            # 2. Load open positions from tax_lots
            cur.execute("""
                SELECT s.symbol,
                       SUM(tl.quantity) AS qty,
                       SUM(tl.quantity * tl.cost_basis_per_unit) AS cost
                  FROM tax_lots tl
                  JOIN securities s ON s.id = tl.security_id
                 WHERE tl.fund_id = %s AND tl.closed_at IS NULL
                 GROUP BY s.symbol
            """, (fid,))
            lot_rows = cur.fetchall()

            if not lot_rows:
                raise HTTPException(status_code=422, detail="No open positions found for this fund")

            # 3. Fetch live prices
            all_syms = [r["symbol"] for r in lot_rows if r["symbol"]]
            prices = _fetch_prices(all_syms)

            # Compute total MV (all positions including cash)
            total_mv_all = 0.0
            pos_map = {}  # symbol -> {qty, cost, price, mv}
            for r in lot_rows:
                sym = r["symbol"]
                qty = float(r["qty"] or 0)
                cost = float(r["cost"] or 0)
                price = prices.get(sym)
                mv = qty * price if price else cost
                total_mv_all += mv
                pos_map[sym] = {"qty": qty, "cost": cost, "price": price, "mv": mv}

            # 4. Filter to equity tickers only
            equity_syms = [s for s in all_syms if not _is_cash_ticker(s)]

            total_equity_mv = sum(pos_map[s]["mv"] for s in equity_syms if s in pos_map)
            if total_equity_mv <= 0:
                total_equity_mv = max(sum(pos_map[s]["cost"] for s in equity_syms if s in pos_map), 1.0)

            # 5. Look up research reports from saved markdown files in STOCKS_FOLDER.
            #    Falls back to Hold/0 upside when no report exists for a ticker.
            reports_folder = analyst.STOCKS_FOLDER
            ticker_results = []
            for sym in equity_syms:
                md_path = reports_folder / f"{sym}_DGA_Report.md"
                summary_dict: dict = {}
                if md_path.exists():
                    try:
                        raw_summary = _extract_summary_cached(md_path)
                        if raw_summary:
                            summary_dict = {
                                "rating":       raw_summary.get("rating") or "Hold",
                                "price_target": raw_summary.get("price_target"),
                                "upside_pct":   raw_summary.get("upside_pct") or 0,
                            }
                    except Exception:
                        pass

                ticker_results.append({
                    "ticker": sym,
                    "ok": True,
                    "summary": summary_dict or {"rating": "Hold", "price_target": None, "upside_pct": 0},
                    "sector":   "Unknown",
                    "industry": "Unknown",
                })

            if not ticker_results:
                raise HTTPException(status_code=422, detail="No equity positions found to rebalance")

            # 6. Compute rebalance (uses "current" strategy = keep all positions)
            try:
                rebalance = analyst.compute_rebalance(ticker_results, strategy="current")
            except Exception as exc:
                raise HTTPException(status_code=500, detail=f"compute_rebalance failed: {exc}")

            weights = rebalance.get("weights", {})  # {ticker: fraction 0-1}
            reb_rows = rebalance.get("rows", [])

            # Build a lookup from compute_rebalance rows
            reb_lookup = {r["ticker"]: r for r in reb_rows}

            # 7. Build result rows
            result_rows = []
            current_ev = 0.0
            suggested_ev = 0.0

            for sym in equity_syms:
                pm = pos_map.get(sym, {})
                cur_pct = (pm.get("mv", 0) / total_equity_mv * 100) if total_equity_mv > 0 else 0
                sug_frac = weights.get(sym, 0)
                sug_pct = sug_frac * 100

                reb = reb_lookup.get(sym, {})
                rating = reb.get("rating") or (ticker_results[equity_syms.index(sym)].get("summary") or {}).get("rating") or "Hold"
                upside_pct = reb.get("upside_pct")
                if upside_pct is None:
                    upside_pct = (ticker_results[equity_syms.index(sym)].get("summary") or {}).get("upside_pct") or 0
                score = float(reb.get("score") or 0)
                sec = reb.get("sector") or ticker_results[equity_syms.index(sym)].get("sector") or "Unknown"

                current_ev  += (cur_pct / 100) * float(upside_pct)
                suggested_ev += sug_frac * float(upside_pct)

                # Action determination
                diff = sug_pct - cur_pct
                if diff > 1.5:
                    action = "BUY MORE"
                elif diff < -1.5:
                    action = "TRIM"
                else:
                    action = "HOLD"

                # Shares calculation
                _price = pm.get("price") or 0
                if not _price and pm.get("qty", 0) > 0:
                    _price = pm.get("cost", 0) / pm["qty"]  # fallback to avg cost
                _current_qty  = pm.get("qty", 0)
                _current_mv   = pm.get("mv", 0)
                _suggested_mv = sug_frac * total_equity_mv
                _delta_mv     = _suggested_mv - _current_mv
                _shares_delta = round(_delta_mv / _price, 2) if _price > 0 else None
                _new_qty      = round(_current_qty + _shares_delta, 2) if _shares_delta is not None else None

                result_rows.append({
                    "ticker":        sym,
                    "name":          sym,  # no name in tax_lots directly
                    "current_pct":   round(cur_pct, 2),
                    "suggested_pct": round(sug_pct, 2),
                    "rating":        rating,
                    "upside_pct":    round(float(upside_pct), 2),
                    "score":         round(score, 4),
                    "sector":        sec,
                    "action":        action,
                    "current_qty":   round(_current_qty, 4),
                    "price":         round(_price, 4) if _price else None,
                    "shares_delta":  _shares_delta,
                    "new_qty":       _new_qty,
                })

            # EV = weighted-average upside across equity positions
            # current_ev  = Σ (cur_pct/100 × upside_pct)  — e.g. 15.3% allocation × 18.5% upside
            # suggested_ev = Σ (sug_frac × upside_pct)     — already a fraction (0–1)
            result = {
                "ok":               True,
                "fund_id":          fund_id,
                "run_at":           datetime.utcnow().isoformat() + "Z",
                "strategy":         "current",
                "total_equity_mv":  round(total_equity_mv, 2),
                "rows":             result_rows,
                "current_ev":       round(current_ev, 2),
                "suggested_ev":     round(suggested_ev, 2),
                "positions_count":  len(lot_rows),
                "equity_count":     len(equity_syms),
            }

            # 8. Persist and flush cache
            _kv_put(f"rebalance.account.{fund_id}", result)
            _invalidate_user_cache()

            return result
    finally:
        conn.close()


@app.post("/api/v2/gp/fund/{fund_id}/rebalance/email")
def email_account_rebalance(fund_id: str, request: Request):
    """Email the rebalance summary for a managed account to a specified address."""
    claims = getattr(request.state, "auth_claims", None)
    if not claims or claims.get("role") not in ("gp", "admin"):
        _require_fund_token(request)

    # Load persisted rebalance
    data = _kv_get(f"rebalance.account.{fund_id}")
    if not data or not data.get("ok"):
        raise HTTPException(status_code=404, detail="No rebalance found — run one first")

    # Determine recipient — prefer explicitly provided address from request body
    to_addr = ""
    try:
        body_raw = _request_body_sync(request)
        if body_raw:
            body_json = json.loads(body_raw)
            to_addr = (body_json.get("to") or "").strip()
    except Exception:
        pass
    # Fall back to GP's auth email
    if not to_addr and claims:
        to_addr = claims.get("email", "")
    if not to_addr or "@" not in to_addr:
        raise HTTPException(status_code=422, detail="Provide a valid recipient email address")

    run_date = data.get("run_at", "")[:10] if data.get("run_at") else "—"
    evImprove = (data.get("suggested_ev") or 0) - (data.get("current_ev") or 0)
    evSign = "+" if evImprove >= 0 else ""
    sug_ev_color = "#22c55e" if evImprove >= 0 else "#ef4444"

    rows_html = ""
    for row in sorted(data.get("rows", []), key=lambda r: -(r.get("suggested_pct") or 0)):
        diff = (row.get("suggested_pct") or 0) - (row.get("current_pct") or 0)
        diff_str = f"+{diff:.1f}%" if diff > 0.1 else (f"{diff:.1f}%" if diff < -0.1 else "—")
        diff_color = "#22c55e" if diff > 0.5 else ("#ef4444" if diff < -0.5 else "#8899aa")
        upside = row.get("upside_pct") or 0
        upside_sign = "+" if upside >= 0 else ""
        sd = row.get("shares_delta")
        if sd is not None and abs(sd) >= 0.01:
            shares_str = f"+{sd:.2f}" if sd > 0 else f"{sd:.2f}"
            shares_color = "#22c55e" if sd > 0 else "#ef4444"
        else:
            shares_str = "—"
            shares_color = "#6688aa"
        rows_html += (
            f"<tr style='border-bottom:1px solid #2a3a4a;'>"
            f"<td style='padding:6px 10px;font-weight:bold;color:#5bb8d4;'>{row.get('ticker','')}</td>"
            f"<td style='padding:6px 10px;text-align:right;'>{row.get('rating','—')}</td>"
            f"<td style='padding:6px 10px;text-align:right;'>{upside_sign}{upside:.1f}%</td>"
            f"<td style='padding:6px 10px;text-align:right;'>{(row.get('current_pct') or 0):.1f}%</td>"
            f"<td style='padding:6px 10px;text-align:right;'>{(row.get('suggested_pct') or 0):.1f}%</td>"
            f"<td style='padding:6px 10px;text-align:right;color:{diff_color};'>{diff_str}</td>"
            f"<td style='padding:6px 10px;text-align:right;'>{row.get('action','—')}</td>"
            f"<td style='padding:6px 10px;text-align:right;font-weight:bold;color:{shares_color};'>{shares_str}</td>"
            f"</tr>"
        )

    html_body = f"""
<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#0a1628;color:#c0d0e0;margin:0;padding:24px;">
  <div style="max-width:700px;margin:0 auto;">
    <h1 style="color:#5bb8d4;font-size:20px;margin-bottom:4px;">Portfolio Rebalance Summary</h1>
    <p style="color:#6688aa;font-size:13px;margin-top:0;">Fund {fund_id} &mdash; Run {run_date}</p>

    <div style="display:flex;gap:24px;margin:20px 0;flex-wrap:wrap;">
      <div style="text-align:center;background:#112233;padding:16px 24px;border-radius:8px;">
        <div style="font-size:11px;color:#6688aa;font-weight:bold;margin-bottom:6px;">CURRENT EV</div>
        <div style="font-size:28px;font-weight:bold;color:#8899aa;">{(data.get('current_ev') or 0):.1f}%</div>
        <div style="font-size:11px;color:#445566;">wtd avg upside</div>
      </div>
      <div style="display:flex;align-items:center;font-size:28px;color:#5bb8d4;">→</div>
      <div style="text-align:center;background:#112233;padding:16px 24px;border-radius:8px;">
        <div style="font-size:11px;color:#6688aa;font-weight:bold;margin-bottom:6px;">SUGGESTED EV</div>
        <div style="font-size:28px;font-weight:bold;color:{sug_ev_color};">{(data.get('suggested_ev') or 0):.1f}%</div>
        <div style="font-size:11px;color:#445566;">wtd avg upside</div>
      </div>
      <div style="display:flex;align-items:center;">
        <span style="background:rgba(34,197,94,0.15);color:#22c55e;padding:8px 16px;border-radius:6px;font-size:14px;font-weight:bold;">
          {evSign}{evImprove:.1f}% EV improvement
        </span>
      </div>
    </div>

    <table style="width:100%;border-collapse:collapse;background:#112233;border-radius:8px;overflow:hidden;">
      <thead>
        <tr style="background:#1a3050;">
          <th style="padding:8px 10px;text-align:left;color:#8899aa;font-size:11px;">TICKER</th>
          <th style="padding:8px 10px;text-align:right;color:#8899aa;font-size:11px;">RATING</th>
          <th style="padding:8px 10px;text-align:right;color:#8899aa;font-size:11px;">UPSIDE</th>
          <th style="padding:8px 10px;text-align:right;color:#8899aa;font-size:11px;">CURRENT %</th>
          <th style="padding:8px 10px;text-align:right;color:#8899aa;font-size:11px;">SUGGESTED %</th>
          <th style="padding:8px 10px;text-align:right;color:#8899aa;font-size:11px;">CHANGE</th>
          <th style="padding:8px 10px;text-align:right;color:#8899aa;font-size:11px;">ACTION</th>
          <th style="padding:8px 10px;text-align:right;color:#8899aa;font-size:11px;">SHARES</th>
        </tr>
      </thead>
      <tbody>
        {rows_html}
      </tbody>
    </table>

    <p style="font-size:11px;color:#445566;margin-top:20px;">
      Generated by DGA Capital GP Portal &mdash; {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC
    </p>
  </div>
</body>
</html>"""

    subject = f"[DGA] Portfolio Rebalance — Fund {fund_id} — {run_date}"
    result = _send_simple_email(to_addr, subject, html_body)
    if not result.get("ok"):
        raise HTTPException(status_code=500, detail=result.get("error", "Email failed"))
    return result


@app.get("/api/fund/activity")
def fund_activity(request: Request, fund_id: str = None):
    _require_fund_token(request)
    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)
            cur.execute("""
                SELECT
                    t.id, t.effective_date, t.category, t.description, t.posted_at,
                    COALESCE(SUM(tl.debit),  0) AS total_debit,
                    COALESCE(SUM(tl.credit), 0) AS total_credit
                  FROM transactions t
                  JOIN transaction_lines tl ON tl.transaction_id = t.id
                 WHERE t.fund_id = %s
                 GROUP BY t.id, t.effective_date, t.category, t.description, t.posted_at
                 ORDER BY t.posted_at DESC
                 LIMIT 25
            """, (fid,))
            rows = cur.fetchall()
            return [{
                "id":             str(r["id"]),
                "effective_date": str(r["effective_date"]),
                "category":       r["category"],
                "description":    r["description"],
                "posted_at":      r["posted_at"].isoformat() if r["posted_at"] else None,
                "amount":         max(float(r["total_debit"]), float(r["total_credit"])),
            } for r in rows]
    finally:
        conn.close()


@app.get("/api/fund/waterfall")
def fund_waterfall(request: Request, fund_id: str = None):
    """GP carry / LP waterfall — high-watermark model.

    Carry model:
      • The hurdle ($100 K/yr fixed) is a per-year GATE: if the year's gross
        profit exceeds the hurdle, the GP is entitled to carry.
      • Carry amount  = (year_end_NAV − high_watermark) × carry_pct (25 %).
      • High-watermark starts at  contributions + hurdle  (inception year),
        then advances to the highest end-NAV ever recorded.
      • HWM only moves up; years where end_NAV < HWM earn zero carry even if
        the year was profitable.
      • All carry is rolled into GP fractional equity (never paid out as cash),
        so the GP's dollar stake = accum_fraction × current_NAV at any moment.

    Data source priority:
      1. fund_annual_snapshots (exact year-by-year actuals — preferred)
      2. Approximation from contribution + current NAV (shows warning)
    """
    _require_fund_token(request)
    # 25s response cache — waterfall is identical for any caller of the same fund
    cache_key = ("fund_waterfall", "fund", str(fund_id or ""))
    _cached = _user_cache_get(cache_key)
    if _cached is not None:
        return _cached
    _t0 = time.time()
    from datetime import date as _date
    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)

            cur.execute("""
                SELECT inception_date, carry_pct, hurdle_pct,
                       COALESCE(catch_up_pct, 1.0) AS catch_up_pct
                  FROM funds WHERE id = %s
            """, (fid,))
            fund        = dict(cur.fetchone())
            inception   = fund["inception_date"]
            carry_pct   = float(fund["carry_pct"])
            hurdle_pct  = float(fund["hurdle_pct"])
            catch_up    = float(fund["catch_up_pct"])
            today       = _date.today()

            # ── Check for annual snapshots ────────────────────────────────
            has_snapshots = False
            annual_rows   = []
            try:
                cur.execute("""
                    SELECT year, start_nav, end_nav, contributions,
                           hurdle_amount, gross_profit, carry_earned,
                           carry_paid, carry_rolled, gp_equity_end, notes
                      FROM fund_annual_snapshots
                     WHERE fund_id = %s
                     ORDER BY year ASC
                """, (fid,))
                annual_rows = [dict(r) for r in cur.fetchall()]
                has_snapshots = len(annual_rows) > 0
            except Exception:
                pass  # table doesn't exist yet

            # ── LP commitments ────────────────────────────────────────────
            cur.execute("""
                SELECT COALESCE(SUM(c.commitment_amount), 0) AS total
                  FROM commitments c JOIN lps l ON l.id = c.lp_id
                 WHERE l.fund_id = %s AND c.superseded_by IS NULL
            """, (fid,))
            contributions = float(cur.fetchone()["total"])

            cur.execute("""
                SELECT l.legal_name,
                       COALESCE(SUM(c.commitment_amount), 0) AS commitment
                  FROM lps l
                  LEFT JOIN commitments c ON c.lp_id = l.id AND c.superseded_by IS NULL
                 WHERE l.fund_id = %s AND l.status = 'active'
                 GROUP BY l.id, l.legal_name
                HAVING COALESCE(SUM(c.commitment_amount), 0) > 0
                 ORDER BY COALESCE(SUM(c.commitment_amount), 0) DESC
            """, (fid,))
            lp_rows = cur.fetchall()

            # NAV = live market value of all open positions
            nav = _fund_market_nav(cur, fid)

            if has_snapshots:
                # ── Exact annual calculation from year-by-year snapshots ─────
                #
                # GP equity model: carry is issued as fractional ownership each
                # year carry is earned.  The GP's dollar stake at any date is:
                #   gp_equity = accum_fraction × current_NAV
                # (co-investment: the stake moves with NAV, not a fixed dollar).
                #
                # High-watermark:
                #   HWM_initial = contributions + hurdle_amount  (inception gate)
                #   HWM advances to end_NAV whenever end_NAV > HWM
                #
                annual_hurdle_fixed = float(annual_rows[0]["hurdle_amount"])   # $100 K
                last_row            = annual_rows[-1]
                last_year           = last_row["year"]
                last_end_nav        = float(last_row["end_nav"])
                last_gp_equity      = float(last_row["gp_equity_end"])
                last_accum_frac     = last_gp_equity / last_end_nav if last_end_nav else 0.0

                years_since         = (today - inception).days / 365.25
                total_gain          = nav - contributions

                # ── Reconstruct HWM per row for the year-by-year table ───────
                # HWM_initial = first year start_nav + hurdle  (= 2,000,000 + 100,000 = 2,100,000)
                # Using start_nav (total fund including GP) rather than LP contributions alone.
                hwm = float(annual_rows[0]["start_nav"]) + annual_hurdle_fixed   # inception gate
                snapshot_rows_out = []
                hwm_at_end = hwm  # tracks the running HWM
                for r in annual_rows:
                    end_nav_r  = float(r["end_nav"])
                    gp_eq_r    = float(r["gp_equity_end"])
                    accum_frac_r = gp_eq_r / end_nav_r if end_nav_r else 0.0
                    row_hwm    = hwm  # HWM at start of this year (threshold to exceed)
                    snapshot_rows_out.append({
                        "year":             r["year"],
                        "start_nav":        float(r["start_nav"]),
                        "end_nav":          end_nav_r,
                        "gross_profit":     float(r["gross_profit"]),
                        "hurdle_amount":    float(r["hurdle_amount"]),
                        "carry_earned":     float(r["carry_earned"]),
                        "gp_equity_end":    round(gp_eq_r, 2),
                        "accum_gp_pct":     round(accum_frac_r * 100, 4),
                        "hwm_threshold":    round(row_hwm, 2),
                    })
                    if end_nav_r > hwm:
                        hwm = end_nav_r
                hwm_at_end = hwm   # current HWM after all completed years

                # ── Current year (partial) carry estimate ────────────────────
                # HWM = hwm_at_end (highest end_NAV in recorded history)
                # New carry is earned only if nav > HWM AND gain > pro-rata hurdle
                cur_year_days      = (today - _date(last_year + 1, 1, 1)).days
                cur_year_frac      = max(0.0, cur_year_days / 365.25)
                cur_year_hurdle    = annual_hurdle_fixed * cur_year_frac
                cur_year_gain      = nav - last_end_nav
                cur_year_new_carry = 0.0
                if cur_year_gain > cur_year_hurdle and nav > hwm_at_end:
                    cur_year_new_carry = (nav - hwm_at_end) * carry_pct

                # ── GP equity at current NAV ──────────────────────────────────
                # Base: last accum fraction × current NAV (stake moves with NAV)
                # Plus: any new carry earned in partial current year
                gp_equity_base   = last_accum_frac * nav
                gp_accrued_carry = gp_equity_base + cur_year_new_carry
                gp_equity_pct    = (gp_accrued_carry / nav * 100) if nav else 0.0
                lp_nav_after_carry = nav - gp_accrued_carry

                # ── Carry history summary ─────────────────────────────────────
                total_carry_earned = sum(float(r["carry_earned"]) for r in annual_rows)
                carry_years        = [r["year"] for r in annual_rows if float(r["carry_earned"]) > 0]
                hurdle_cleared     = len(carry_years) > 0

                per_lp = []
                for row in lp_rows:
                    commitment = float(row["commitment"])
                    share      = commitment / contributions if contributions else 0
                    per_lp.append({
                        "legal_name":      row["legal_name"],
                        "commitment":      commitment,
                        "share_pct":       round(share * 100, 4),
                        "carry_charge":    round(gp_accrued_carry * share, 2),
                        "nav_after_carry": round(lp_nav_after_carry * share, 2),
                    })

                result = {
                    "as_of":                 today.isoformat(),
                    "inception_date":        str(inception),
                    "data_source":           "annual_snapshots",
                    "years_since_inception": round(years_since, 2),
                    "nav":                   round(nav, 2),
                    "contributions":         round(contributions, 2),
                    "total_gain":            round(total_gain, 2),
                    "hurdle_pct":            hurdle_pct,
                    "carry_pct":             carry_pct,
                    "catch_up_pct":          catch_up,
                    # Waterfall summary
                    "hurdle_cleared":        hurdle_cleared,
                    "carry_years":           carry_years,
                    "high_watermark":        round(hwm_at_end, 2),
                    "total_carry_earned_hist": round(total_carry_earned, 2),
                    "gp_accrued_carry":      round(gp_accrued_carry, 2),
                    "gp_equity_pct":         round(gp_equity_pct, 4),
                    "lp_nav_after_carry":    round(lp_nav_after_carry, 2),
                    # Current-year estimates
                    "cur_year_gain":         round(cur_year_gain, 2),
                    "cur_year_hurdle":       round(cur_year_hurdle, 2),
                    "cur_year_new_carry":    round(cur_year_new_carry, 2),
                    # Year-by-year table
                    "annual_snapshots":      snapshot_rows_out,
                    "per_lp":                per_lp,
                }
                print(f"[perf] fund_waterfall {str(fund_id or '')[:8]} {time.time()-_t0:.2f}s (snapshots path)")
                _user_cache_put(cache_key, result)
                return result

            else:
                # ── Approximation (no annual snapshots yet) ───────────────
                # Annual hurdle: each year the fund must return hurdle_pct on
                # starting NAV before carry applies.  Without year-by-year data
                # we approximate using simple annual hurdle on contributions.
                years           = (today - inception).days / 365.25
                total_gain      = nav - contributions
                annual_hurdle_amount = contributions * hurdle_pct
                # Simple sum: hurdle_pct × contributions × years (not compound)
                cumulative_hurdle = annual_hurdle_amount * years
                hurdle_cleared  = total_gain >= cumulative_hurdle
                carry_pool      = max(0.0, total_gain - cumulative_hurdle)
                gp_carry        = carry_pool * carry_pct if hurdle_cleared else 0.0
                lp_net          = total_gain - gp_carry

                per_lp = []
                for row in lp_rows:
                    commitment = float(row["commitment"])
                    share      = commitment / contributions if contributions else 0
                    per_lp.append({
                        "legal_name":      row["legal_name"],
                        "commitment":      commitment,
                        "share_pct":       round(share * 100, 4),
                        "carry_charge":    round(gp_carry * share, 2),
                        "net_gain":        round(lp_net * share, 2),
                        "nav_after_carry": round(commitment + lp_net * share, 2),
                    })

                result = {
                    "as_of":                today.isoformat(),
                    "inception_date":       str(inception),
                    "data_source":          "approximation",
                    "data_source_warning":  "Annual snapshots not yet entered. Figures are approximate — provide year-end NAVs for exact calculation.",
                    "years_since_inception":round(years, 2),
                    "nav":                  round(nav, 2),
                    "contributions":        round(contributions, 2),
                    "total_gain":           round(total_gain, 2),
                    "hurdle_pct":           hurdle_pct,
                    "carry_pct":            carry_pct,
                    "annual_hurdle_amount": round(annual_hurdle_amount, 2),
                    "cumulative_hurdle":    round(cumulative_hurdle, 2),
                    "hurdle_cleared":       hurdle_cleared,
                    "carry_pool":           round(carry_pool, 2),
                    "gp_accrued_carry":     round(gp_carry, 2),
                    "lp_net_gain":          round(lp_net, 2),
                    "lp_nav_after_carry":   round(contributions + lp_net, 2),
                    "annual_snapshots":     [],
                    "per_lp":               per_lp,
                }
                print(f"[perf] fund_waterfall {str(fund_id or '')[:8]} {time.time()-_t0:.2f}s (approx path)")
                _user_cache_put(cache_key, result)
                return result
    finally:
        conn.close()


# ---------------------------------------------------------------------------
# Fund Admin — management endpoints (create, import positions, import cap table)
# ---------------------------------------------------------------------------

def _seed_coa_for_fund(cur, fund_id: str) -> None:
    """Insert the standard chart-of-accounts for a new fund (idempotent)."""
    cur.execute("SELECT COUNT(*) AS n FROM accounts WHERE fund_id = %s", (fund_id,))
    if cur.fetchone()["n"] > 0:
        return  # already seeded
    for code, name, atype in _FUND_COA:
        cur.execute("""
            INSERT INTO accounts (fund_id, code, name, type)
            VALUES (%s, %s, %s, %s)
            ON CONFLICT (fund_id, code) DO NOTHING
        """, (fund_id, code, name, atype))


@app.post("/api/fund/admin/create")
def fund_admin_create(request: Request, body: CreateFundRequest):
    """Create a new fund + seed its chart of accounts.
    Idempotent on short_name — re-calling with the same short_name updates
    the fund name but does not touch the CoA."""
    _require_fund_token(request)

    # Force-run migration up-front (creates tables if missing, fixes fund_type column).
    # If startup failed to migrate (e.g. DB wasn't ready yet), this gives it a
    # second chance right before the first fund creation.
    _apply_self_migrations()

    # Normalize the inception date — accept "2017", "2017-1-1", "2017-01-01"
    inc = (body.inception_date or '').strip()
    if re.fullmatch(r'\d{4}', inc):
        inc = f"{inc}-01-01"
    else:
        m = re.fullmatch(r'(\d{4})-(\d{1,2})-(\d{1,2})', inc)
        if m:
            inc = f"{m.group(1)}-{int(m.group(2)):02d}-{int(m.group(3)):02d}"
    if not re.fullmatch(r'\d{4}-\d{2}-\d{2}', inc):
        raise HTTPException(400, f"Invalid inception_date {body.inception_date!r} — use YYYY-MM-DD")

    fy_end = body.fiscal_year_end
    if not fy_end:
        fy_end = f"{inc[:4]}-12-31"
    ftype = body.fund_type if body.fund_type in ('lp_fund', 'managed_account') else 'lp_fund'

    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            try:
                cur.execute("""
                    INSERT INTO funds (
                        name, short_name, structure, domicile, base_ccy,
                        inception_date, fiscal_year_end,
                        mgmt_fee_pct, mgmt_fee_basis, mgmt_fee_freq,
                        carry_pct, hurdle_pct, catch_up_pct,
                        max_lps, status, fund_type
                    ) VALUES (
                        %s, %s, '3c1', 'DE', 'USD',
                        %s, %s,
                        %s, 'committed', 'quarterly',
                        %s, %s, 1.00,
                        99, 'open', %s
                    )
                    ON CONFLICT (short_name) DO UPDATE
                        SET name      = EXCLUDED.name,
                            fund_type = EXCLUDED.fund_type,
                            updated_at = NOW()
                    RETURNING id
                """, (body.name, body.short_name, inc, fy_end,
                      body.mgmt_fee_pct, body.carry_pct, body.hurdle_pct, ftype))
            except Exception as e:
                # Most likely causes:
                #   A) fund_type column missing — fall back to no-fund_type INSERT
                #   B) Table doesn't exist — re-raise with informative message
                conn.rollback()
                msg = str(e).lower()
                if 'does not exist' in msg or 'relation' in msg:
                    raise HTTPException(500,
                        f"Database table missing — schema may not have been created: {e}")
                if 'fund_type' in msg or 'column' in msg:
                    cur.execute("""
                        INSERT INTO funds (
                            name, short_name, structure, domicile, base_ccy,
                            inception_date, fiscal_year_end,
                            mgmt_fee_pct, mgmt_fee_basis, mgmt_fee_freq,
                            carry_pct, hurdle_pct, catch_up_pct,
                            max_lps, status
                        ) VALUES (
                            %s, %s, '3c1', 'DE', 'USD',
                            %s, %s,
                            %s, 'committed', 'quarterly',
                            %s, %s, 1.00,
                            99, 'open'
                        )
                        ON CONFLICT (short_name) DO UPDATE
                            SET name = EXCLUDED.name,
                                updated_at = NOW()
                        RETURNING id
                    """, (body.name, body.short_name, inc, fy_end,
                          body.mgmt_fee_pct, body.carry_pct, body.hurdle_pct))
                else:
                    raise HTTPException(500, f"Insert failed: {e}")

            row = cur.fetchone()
            if not row:
                raise HTTPException(500, "Insert returned no row")
            fid = str(row["id"])
            _seed_coa_for_fund(cur, fid)
        conn.commit()
        return {"fund_id": fid, "name": body.name, "short_name": body.short_name,
                "fund_type": ftype}
    except HTTPException:
        raise
    except Exception as e:
        conn.rollback()
        raise HTTPException(500, f"Create fund failed: {e}")
    finally:
        conn.close()


@app.post("/api/fund/import-positions")
def fund_import_positions(
    request: Request,
    fund_id: str = Form(None),
    file: UploadFile = File(...),
):
    """Upload a Fidelity Account Positions CSV (or XLSX) to refresh the
    fund's open tax-lot positions.

    Flow:
     1. Parse CSV → list of {symbol, name, qty, avg_cost, last_price, ...}
     2. Upsert securities records
     3. Close all existing open lots (without a hard delete — immutable ledger)
     4. Create a single 'adjustment' transaction with balanced double-entry:
          Dr. 1100 Securities at Cost  (one line per security)
          Dr. 1030 Cash — Money Market (for MM positions)
          Cr. 3000 Capital — GP        (single balancing credit)
     5. Insert new tax_lots pointing at that transaction
    """
    _require_fund_token(request)
    raw = file.file.read()
    # Handle both CSV and XLSX uploads
    if (file.filename or '').lower().endswith(('.xlsx', '.xls')):
        if not _OPENPYXL_OK:
            raise HTTPException(400, "openpyxl not installed — upload a .csv file")
        wb = openpyxl.load_workbook(io.BytesIO(raw), read_only=True, data_only=True)
        ws = wb.active
        header = [str(c.value or '').strip() for c in next(ws.iter_rows())]
        lines  = [header] + [
            [str(c.value or '').strip() for c in row] for row in ws.iter_rows(min_row=2)
        ]
        content = '\n'.join(','.join(r) for r in lines)
    else:
        content = raw.decode('utf-8', errors='replace')

    positions = _parse_fidelity_csv(content)
    if not positions:
        raise HTTPException(400, "No valid positions found in file. "
            "Expected a Fidelity Account Positions CSV export.")

    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)

            # ── Fetch CoA accounts ─────────────────────────────────────────
            cur.execute("""
                SELECT code, id FROM accounts
                 WHERE fund_id = %s AND code IN ('1020','1030','1100','3000')
            """, (fid,))
            acct_map = {r["code"]: str(r["id"]) for r in cur.fetchall()}
            sec_acct  = acct_map.get("1100")
            mm_acct   = acct_map.get("1030") or acct_map.get("1020")
            cap_acct  = acct_map.get("3000")
            if not sec_acct or not cap_acct:
                raise HTTPException(500, "Chart of accounts not found — "
                    "run /api/fund/admin/create first")

            # ── Upsert securities ─────────────────────────────────────────
            sec_ids = {}
            for p in positions:
                sym = p["symbol"]
                is_cash = bool(p["is_cash"])
                cur.execute("""
                    INSERT INTO securities (symbol, name, asset_class, is_public)
                    VALUES (%s, %s, %s, %s)
                    ON CONFLICT (symbol) DO UPDATE
                        SET name        = EXCLUDED.name,
                            asset_class = EXCLUDED.asset_class,
                            is_public   = EXCLUDED.is_public
                    RETURNING id
                """, (sym, p["name"] or sym,
                      "cash" if is_cash else "equity",
                      not is_cash))  # is_public=TRUE for equities, FALSE for cash
                sec_ids[sym] = str(cur.fetchone()["id"])

            # ── Close all existing open lots ──────────────────────────────
            cur.execute("""
                UPDATE tax_lots SET closed_at = NOW()
                 WHERE fund_id = %s AND closed_at IS NULL
            """, (fid,))

            # ── Create balancing adjustment transaction ────────────────────
            today = datetime.utcnow().date().isoformat()
            cur.execute("""
                INSERT INTO transactions
                    (fund_id, effective_date, category, description)
                VALUES (%s, %s, 'adjustment', 'Position import from Fidelity CSV')
                RETURNING id
            """, (fid, today))
            txn_id = str(cur.fetchone()["id"])

            # Build lines: one Dr per position, one Cr total
            total_cost = 0.0
            line_num   = 1
            for p in positions:
                cost = float(p["cost_basis"])
                if cost <= 0:
                    continue
                total_cost += cost
                acct = mm_acct if p["is_cash"] else sec_acct
                if not acct:
                    continue
                cur.execute("""
                    INSERT INTO transaction_lines
                        (transaction_id, line_number, account_id, debit, security_id)
                    VALUES (%s, %s, %s, %s, %s)
                """, (txn_id, line_num, acct, round(cost, 4),
                      sec_ids.get(p["symbol"])))
                line_num += 1

            # Balancing credit to Capital — GP
            if total_cost > 0:
                cur.execute("""
                    INSERT INTO transaction_lines
                        (transaction_id, line_number, account_id, credit)
                    VALUES (%s, %s, %s, %s)
                """, (txn_id, line_num, cap_acct, round(total_cost, 4)))

            # ── Insert new tax_lots ───────────────────────────────────────
            for p in positions:
                cur.execute("""
                    INSERT INTO tax_lots
                        (fund_id, security_id, acquired_at,
                         quantity, cost_basis_per_unit, open_transaction_id)
                    VALUES (%s, %s, NOW(), %s, %s, %s)
                """, (fid, sec_ids[p["symbol"]],
                      float(p["quantity"]),
                      float(p["avg_cost"]) if p["avg_cost"] else 0.0,
                      txn_id))

        conn.commit()

        # Fetch prices for imported symbols
        symbols = [p["symbol"] for p in positions if not p["is_cash"]]
        prices  = _fetch_prices(symbols)
        market_value = sum(
            float(p["quantity"]) * (prices.get(p["symbol"]) or float(p.get("last_price") or 0))
            for p in positions
        )

        return {
            "fund_id":            fid,
            "imported":           len(positions),
            "positions_imported": len(positions),
            "market_value_total": round(market_value, 2),
            "message": f"Successfully imported {len(positions)} position lots.",
        }
    finally:
        conn.close()


@app.post("/api/fund/import-captable")
def fund_import_captable(
    request: Request,
    fund_id: str = Form(None),
    file: UploadFile = File(...),
):
    """Upload a cap-table CSV or XLSX to set/update LP records and commitments.

    Expected columns (case-insensitive):
        LP Name, Commitment Amount, Entity Type (opt), Effective Date (opt)

    On re-upload, existing LPs are matched by legal_name (case-insensitive).
    New commitments supersede the previous commitment for each LP.
    """
    _require_fund_token(request)
    raw  = file.file.read()
    rows, economics, fund_estab_year = _parse_captable(raw, file.filename or '')
    if not rows:
        raise HTTPException(400, "No valid LP rows found in file. "
            "Expected a column containing 'LP Name' and contribution amounts "
            "(either a 'Commitment Amount' column or year columns like '2024', '2025').")
    # Also parse annual NAV rows from the same file (waterfall data)
    nav_rows = _parse_annual_nav(raw, file.filename or '')

    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)

            # Look up CoA accounts needed for contribution journal entries
            cur.execute("""
                SELECT code, id FROM accounts
                 WHERE fund_id = %s AND code IN ('1020','1010','3100','3000')
            """, (fid,))
            acct_map = {r["code"]: str(r["id"]) for r in cur.fetchall()}
            cash_acct = acct_map.get("1020") or acct_map.get("1010")
            lp_cap_acct = acct_map.get("3100")  # Capital — LP

            # ── Wipe existing LP + commitment rows for this fund ─────────────
            # Delete in dependency order (children before parents) to avoid FK
            # violations. Only touch tables that the cap-table import owns.
            # Nullable lp_id references (transaction_lines, accounts, users)
            # are NULLed rather than deleted so those rows are preserved.
            cur.execute("""
                UPDATE transaction_lines SET lp_id = NULL
                 WHERE lp_id IN (SELECT id FROM lps WHERE fund_id = %s)
            """, (fid,))
            cur.execute("""
                UPDATE accounts SET lp_id = NULL
                 WHERE lp_id IN (SELECT id FROM lps WHERE fund_id = %s)
            """, (fid,))
            cur.execute("""
                UPDATE users SET lp_id = NULL
                 WHERE lp_id IN (SELECT id FROM lps WHERE fund_id = %s)
            """, (fid,))
            # Delete leaf tables with NOT NULL lp_id FK (deepest first)
            for tbl in ("lp_statements", "carry_allocations",
                        "mgmt_fee_allocations", "nav_snapshot_lp",
                        "distribution_allocations", "capital_call_allocations",
                        "lp_annual_snapshots"):
                cur.execute(
                    f"DELETE FROM {tbl} WHERE lp_id IN "
                    f"(SELECT id FROM lps WHERE fund_id = %s)",
                    (fid,)
                )
            # commitments has its own fund_id — delete directly
            cur.execute("DELETE FROM commitments WHERE fund_id = %s", (fid,))
            # Now lps has no remaining FK children — safe to delete
            cur.execute("DELETE FROM lps WHERE fund_id = %s", (fid,))

            # ── Insert fresh LP rows ──────────────────────────────────────────
            imported = 0
            for row in rows:
                commitment = float(row["commitment"])
                eff_date   = row["effective_date"]

                cur.execute("""
                    INSERT INTO lps (fund_id, legal_name, entity_type,
                                     accred_type, status)
                    VALUES (%s, %s, %s, 'net_worth', 'active')
                    RETURNING id
                """, (fid, row["legal_name"], row["entity_type"]))
                r = cur.fetchone()
                if not r:
                    continue
                lp_id = str(r["id"])

                # ── Commitment ────────────────────────────────────────────────
                cur.execute("""
                    INSERT INTO commitments
                        (lp_id, fund_id, commitment_amount, effective_date)
                    VALUES (%s, %s, %s, %s)
                """, (lp_id, fid, commitment, eff_date))

                # ── Capital contribution journal entry ────────────────────────
                if cash_acct and lp_cap_acct and commitment > 0:
                    cur.execute("""
                        INSERT INTO transactions
                            (fund_id, effective_date, category, description)
                        VALUES (%s, %s, 'contribution', %s)
                        RETURNING id
                    """, (fid, eff_date,
                          f"Capital contribution — {row['legal_name']}"))
                    txn_id = str(cur.fetchone()["id"])
                    cur.execute("""
                        INSERT INTO transaction_lines
                            (transaction_id, line_number, account_id, debit)
                        VALUES (%s, 1, %s, %s)
                    """, (txn_id, cash_acct, round(commitment, 4)))
                    cur.execute("""
                        INSERT INTO transaction_lines
                            (transaction_id, line_number, account_id, credit)
                        VALUES (%s, 2, %s, %s)
                    """, (txn_id, lp_cap_acct, round(commitment, 4)))

                imported += 1

            # ── Apply fund economics + Fund Established date ─────────────────
            econ_applied = {}
            fund_updates = []
            fund_vals    = []
            for col, key in [
                ("mgmt_fee_pct", "mgmt_fee_pct"),
                ("carry_pct",    "carry_pct"),
                ("hurdle_pct",   "hurdle_pct"),
            ]:
                if key in economics:
                    fund_updates.append(f"{col} = %s")
                    fund_vals.append(economics[key])
                    econ_applied[key] = economics[key]
            if fund_estab_year:
                fund_updates.append("inception_date = %s")
                fund_vals.append(f"{fund_estab_year}-01-01")
            if fund_updates:
                fund_vals.append(fid)
                cur.execute(
                    f"UPDATE funds SET {', '.join(fund_updates)} WHERE id = %s",
                    fund_vals,
                )

            # ── Import annual NAV rows (waterfall) ───────────────────────────
            nav_imported = 0
            for r in nav_rows:
                cur.execute("""
                    INSERT INTO fund_annual_snapshots
                        (fund_id, year, start_nav, end_nav, contributions,
                         hurdle_amount, gross_profit, carry_earned,
                         carry_paid, carry_rolled, gp_equity_end)
                    VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
                    ON CONFLICT (fund_id, year) DO UPDATE
                        SET start_nav      = EXCLUDED.start_nav,
                            end_nav        = EXCLUDED.end_nav,
                            contributions  = EXCLUDED.contributions,
                            hurdle_amount  = EXCLUDED.hurdle_amount,
                            gross_profit   = EXCLUDED.gross_profit,
                            carry_earned   = EXCLUDED.carry_earned,
                            carry_paid     = EXCLUDED.carry_paid,
                            carry_rolled   = EXCLUDED.carry_rolled,
                            gp_equity_end  = EXCLUDED.gp_equity_end,
                            updated_at     = NOW()
                """, (fid, r['year'], r['start_nav'], r['end_nav'],
                      r['contributions'], r['hurdle_amount'], r['gross_profit'],
                      r['carry_earned'], r['carry_paid'], r['carry_rolled'],
                      r['gp_equity_end']))
                nav_imported += 1

        conn.commit()
        year_note = ""
        contrib_years = [r["contribution_year"] for r in rows if r.get("contribution_year")]
        if contrib_years:
            year_note = f" (contributions from {min(contrib_years)}–{max(contrib_years)})"
        resp: dict = {
            "fund_id":           fid,
            "imported":          imported,
            "lps_imported":      imported,
            "nav_rows_imported": nav_imported,
            "message":           f"Imported {imported} LP record(s){year_note}.",
        }
        if nav_imported:
            resp["message"] += f" {nav_imported} annual NAV rows loaded."
        if fund_estab_year:
            resp["message"] += f" Fund established {fund_estab_year}."
        if econ_applied:
            resp["economics_applied"] = econ_applied
            parts = []
            if "mgmt_fee_pct" in econ_applied:
                parts.append(f"mgmt fee {econ_applied['mgmt_fee_pct']*100:.2f}%")
            if "carry_pct" in econ_applied:
                parts.append(f"carry {econ_applied['carry_pct']*100:.0f}%")
            if "hurdle_pct" in econ_applied:
                parts.append(f"hurdle {econ_applied['hurdle_pct']*100:.0f}%")
            resp["message"] += f" Fund economics updated: {', '.join(parts)}."
        return resp
    finally:
        conn.close()


# ---------------------------------------------------------------------------
# Annual NAV import — populates fund_annual_snapshots for waterfall display
# ---------------------------------------------------------------------------

def _parse_annual_nav(content: bytes, filename: str) -> list:
    """Parse an annual NAV / waterfall spreadsheet.

    Expected columns (detected by header keyword matching):
        Year | Jan 1 NAV | Dec 31 NAV | Contributions | Hurdle Amount |
        Carry Owed | GP Equity Allocated | LP Allocations | … |
        accum GP equity in fund

    Returns list of dicts matching fund_annual_snapshots columns.
    Rows without a valid Dec 31 NAV (e.g. current partial year) are skipped.
    """
    fname_lower = (filename or '').lower()
    if fname_lower.endswith(('.xlsx', '.xls')):
        if not _OPENPYXL_OK:
            raise HTTPException(400, "openpyxl not installed — upload a CSV instead")
        wb  = openpyxl.load_workbook(io.BytesIO(content), read_only=True, data_only=True)
        ws  = wb.active
        raw = [[str(c.value if c.value is not None else '').strip() for c in row]
               for row in ws.iter_rows()]
    else:
        text = content.decode('utf-8', errors='replace')
        raw  = [[cell.strip() for cell in row] for row in csv.reader(io.StringIO(text))]

    if not raw:
        return []

    def _pm(s):
        """Parse money string: '$1,474,741' or '-' → float (dash / blank → 0)."""
        s2 = str(s or '').replace('$', '').replace(',', '').strip()
        if s2 in ('', '-', '—', 'None'):
            return 0.0
        try:
            return float(s2)
        except (ValueError, TypeError):
            return None

    def _pct_val(s):
        """Parse percent string '13.37%' or '0.1337' → fraction 0–1, or None."""
        s2 = str(s or '').strip()
        # Strip everything after a space (e.g. "0.08% EM: 99.02%" → "0.08%")
        s2 = s2.split()[0] if s2 else ''
        s2 = s2.replace('%', '').strip()
        try:
            v = float(s2)
            return v / 100.0 if v > 1 else v   # "13.37" → 0.1337; "0.1337" → 0.001337?
            # Heuristic: values > 1 are already percent form
        except (ValueError, TypeError):
            return None

    # ── Locate the header row (col A = "year") ───────────────────────────────
    header_idx = None
    for i, row in enumerate(raw):
        if row and str(row[0]).strip().lower() == 'year':
            header_idx = i
            break

    if header_idx is None:
        return []

    header = [str(c).lower().strip() for c in raw[header_idx]]

    def _find_col(*kws):
        for kw in kws:
            for j, h in enumerate(header):
                if kw in h:
                    return j
        return None

    c_start  = _find_col('jan 1', 'jan1', 'start nav', 'beginning') or 1
    c_end    = _find_col('dec 31', 'dec31', 'end nav', 'ending')    or 2
    c_contr  = _find_col('contribution')                             or 3
    c_hurdle = _find_col('hurdle amount', 'hurdle')                  or 4
    c_carry  = _find_col('carry owed', 'carry earned', 'carry')      or 5
    c_accum  = _find_col('accum gp', 'accumulated gp', 'accum gp equity')

    # accum GP column is often the last column (J = index 9 in typical layout)
    if c_accum is None:
        c_accum = max(9, len(header) - 1)

    out = []
    for row in raw[header_idx + 1:]:
        if not row or not str(row[0]).strip():
            continue
        try:
            year = int(float(str(row[0]).strip()))
        except (ValueError, TypeError):
            continue
        if year < 2000 or year > 2099:
            continue

        start_nav = _pm(row[c_start]  if c_start  < len(row) else '') or 0.0
        end_nav   = _pm(row[c_end]    if c_end    < len(row) else '')
        contrib   = _pm(row[c_contr]  if c_contr  < len(row) else '') or 0.0
        hurdle    = _pm(row[c_hurdle] if c_hurdle < len(row) else '') or 0.0
        carry     = _pm(row[c_carry]  if c_carry  < len(row) else '') or 0.0
        accum_raw = row[c_accum]      if c_accum  < len(row) else ''

        # Skip partial / current year rows (no Dec 31 NAV yet)
        if end_nav is None or end_nav <= 0:
            continue

        accum_pct    = _pct_val(accum_raw)
        gp_equity_end = round(accum_pct * end_nav, 2) if accum_pct is not None else 0.0
        gross_profit  = round(end_nav - start_nav - contrib, 2)

        out.append({
            'year':          year,
            'start_nav':     round(start_nav, 2),
            'end_nav':       round(end_nav,   2),
            'contributions': round(contrib,   2),
            'hurdle_amount': round(hurdle,    2),
            'gross_profit':  gross_profit,
            'carry_earned':  round(carry,     2),
            'carry_paid':    0.0,
            'carry_rolled':  round(carry,     2),
            'gp_equity_end': gp_equity_end,
        })

    return out


@app.post("/api/fund/import-annual-nav")
def fund_import_annual_nav(
    request: Request,
    fund_id: str = Form(None),
    file: UploadFile = File(...),
):
    """SINGLE LP-FUND ADMIN UPLOAD. Parses one spreadsheet that contains:
      • Year-by-year NAV / hurdle / carry / GP equity rows  → fund_annual_snapshots
      • LP roster + initial contributions                   → lps + commitments
      • Economics ("0/25, 5% hurdle")                        → funds.mgmt_fee_pct, carry_pct, hurdle_pct
      • "Fund Established | <year>"                          → funds.inception_date

    Everything is keyword-detected; rows can be in any order. Re-uploading
    safely overwrites all four destinations.
    """
    _require_fund_token(request)
    raw       = file.file.read()
    nav_rows  = _parse_annual_nav(raw, file.filename or '')
    lp_rows, economics, fund_estab_year = _parse_captable(raw, file.filename or '')

    if not nav_rows and not lp_rows:
        raise HTTPException(400,
            "No valid data found. Expected the annual NAV worksheet to contain "
            "either a 'Year | Jan 1 NAV | Dec 31 NAV | …' header block, or an "
            "'LP Name | <partners…>' / 'initial contribution | <amounts…>' block, "
            "or both.")

    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)

            # ── 1. LP roster + commitments (only if present in the file) ─────
            lp_imported = 0
            if lp_rows:
                # Wipe existing LPs/commitments — fresh import is the contract.
                cur.execute("""
                    DELETE FROM transaction_lines
                     WHERE transaction_id IN (
                         SELECT id FROM transactions
                          WHERE fund_id = %s AND category = 'contribution')
                """, (fid,))
                cur.execute("DELETE FROM transactions WHERE fund_id = %s AND category = 'contribution'", (fid,))
                cur.execute("DELETE FROM commitments WHERE fund_id = %s", (fid,))
                cur.execute("DELETE FROM lps WHERE fund_id = %s", (fid,))
                for row in lp_rows:
                    cur.execute("""
                        INSERT INTO lps (fund_id, legal_name, entity_type, accred_type, status)
                        VALUES (%s, %s, %s, 'net_worth', 'active')
                        RETURNING id
                    """, (fid, row["legal_name"], row.get("entity_type", "individual")))
                    r2 = cur.fetchone()
                    if not r2: continue
                    cur.execute("""
                        INSERT INTO commitments (lp_id, fund_id, commitment_amount, effective_date)
                        VALUES (%s, %s, %s, %s)
                    """, (str(r2["id"]), fid, float(row["commitment"]), row["effective_date"]))
                    lp_imported += 1

            # ── 2. Fund economics + inception (only if present in file) ──────
            econ_applied = {}
            updates, vals = [], []
            for col, key in [("mgmt_fee_pct", "mgmt_fee_pct"),
                             ("carry_pct",    "carry_pct"),
                             ("hurdle_pct",   "hurdle_pct")]:
                if key in economics:
                    updates.append(f"{col} = %s")
                    vals.append(economics[key])
                    econ_applied[key] = economics[key]
            if fund_estab_year:
                updates.append("inception_date = %s")
                vals.append(f"{fund_estab_year}-01-01")
            if updates:
                vals.append(fid)
                cur.execute(f"UPDATE funds SET {', '.join(updates)} WHERE id = %s", vals)

            # ── 3. Year-by-year NAV snapshots (only if present in file) ──────
            nav_imported = 0
            for r in nav_rows:
                cur.execute("""
                    INSERT INTO fund_annual_snapshots
                        (fund_id, year, start_nav, end_nav, contributions,
                         hurdle_amount, gross_profit, carry_earned,
                         carry_paid, carry_rolled, gp_equity_end)
                    VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
                    ON CONFLICT (fund_id, year) DO UPDATE
                        SET start_nav      = EXCLUDED.start_nav,
                            end_nav        = EXCLUDED.end_nav,
                            contributions  = EXCLUDED.contributions,
                            hurdle_amount  = EXCLUDED.hurdle_amount,
                            gross_profit   = EXCLUDED.gross_profit,
                            carry_earned   = EXCLUDED.carry_earned,
                            carry_paid     = EXCLUDED.carry_paid,
                            carry_rolled   = EXCLUDED.carry_rolled,
                            gp_equity_end  = EXCLUDED.gp_equity_end,
                            updated_at     = NOW()
                """, (fid, r['year'], r['start_nav'], r['end_nav'],
                      r['contributions'], r['hurdle_amount'], r['gross_profit'],
                      r['carry_earned'], r['carry_paid'], r['carry_rolled'],
                      r['gp_equity_end']))
                nav_imported += 1

        conn.commit()
        years = sorted(r['year'] for r in nav_rows) if nav_rows else []
        parts = []
        if lp_imported:   parts.append(f"{lp_imported} LP{'s' if lp_imported != 1 else ''}")
        if nav_imported:  parts.append(f"{nav_imported} annual NAV row{'s' if nav_imported != 1 else ''} ({min(years)}–{max(years)})")
        if econ_applied:  parts.append("economics")
        if fund_estab_year: parts.append(f"inception {fund_estab_year}")
        return {
            "fund_id":       fid,
            "nav_imported":  nav_imported,
            "lp_imported":   lp_imported,
            "economics":     econ_applied,
            "inception_year": fund_estab_year,
            "years":         years,
            "message":       "Imported " + ", ".join(parts) + "." if parts else "Nothing imported.",
        }
    finally:
        conn.close()


# ─────────────────────────────────────────────────────────────────────────────
# Benchmark monthly closes — for overlay on managed-account balance chart
# Supports SPY (default) and any other ETF/index the UI requests.
# ─────────────────────────────────────────────────────────────────────────────
_bench_monthly_cache: dict = {}   # keyed by ticker symbol

_ALLOWED_BENCH = {"SPY", "QQQ", "DIA", "URTH", "EFA", "AGG",
                  "IWM", "VTI", "GLD", "TLT", "VNQ", "VXUS"}

@app.get("/api/market/spy-monthly")
def get_spy_monthly(ticker: str = "SPY"):
    """Return month-end closes for the requested benchmark ticker for the
    current calendar year, indexed to the first trading day's close.
    Cached 15 min per ticker. Defaults to SPY."""
    sym = (ticker or "SPY").upper().strip()
    if sym not in _ALLOWED_BENCH:
        sym = "SPY"
    import time as _time
    now    = _time.time()
    cached = _bench_monthly_cache.get(sym, {})
    if cached.get("ts") and (now - cached["ts"]) < 900:
        return {k: v for k, v in cached.items() if k != "ts"}
    try:
        import yfinance as yf
        from datetime import date as _date
        start = f"{_date.today().year}-01-01"
        hist  = _builder_call_timeout(
            lambda: yf.Ticker(sym).history(start=start, interval="1d"), 8.0, None)
        if hist is None or hist.empty:
            raise ValueError(f"Empty history for {sym}")
        first_close = float(hist.iloc[0]["Close"])
        monthly = hist.resample("ME").last().dropna(subset=["Close"])
        points = []
        for ts, row in monthly.iterrows():
            close = float(row["Close"])
            points.append({
                "month":   ts.strftime("%Y-%m"),
                "close":   round(close, 2),
                "ytd_pct": round((close / first_close - 1.0) * 100, 4),
                "norm":    round(close / first_close, 6),
            })
        result = {"ticker": sym, "first_close": round(first_close, 2), "points": points}
        _bench_monthly_cache[sym] = {**result, "ts": now}
        return result
    except Exception as exc:
        if _bench_monthly_cache.get(sym):
            return {k: v for k, v in _bench_monthly_cache[sym].items() if k != "ts"}
        # Legacy fallback key for old _spy_monthly_cache callers
        raise HTTPException(status_code=503, detail=f"{sym} monthly fetch failed: {exc}")


def get_spy_monthly_data():
    """Internal helper — returns SPY monthly dict (same shape as the endpoint)."""
    try:
        import yfinance as yf
        from datetime import date as _date
        now = __import__("time").time()
        cached = _bench_monthly_cache.get("SPY", {})
        if cached.get("ts") and (now - cached["ts"]) < 900:
            return {k: v for k, v in cached.items() if k != "ts"}
        sym = "SPY"
        start = f"{_date.today().year}-01-01"
        hist  = _builder_call_timeout(
            lambda: yf.Ticker(sym).history(start=start, interval="1d"), 8.0, None)
        if hist is None or hist.empty:
            raise ValueError("Empty SPY history")
        first_close = float(hist.iloc[0]["Close"])
        monthly = hist.resample("ME").last().dropna(subset=["Close"])
        points = []
        for ts, row in monthly.iterrows():
            close = float(row["Close"])
            points.append({
                "month":   ts.strftime("%Y-%m"),
                "close":   round(close, 2),
                "ytd_pct": round((close / first_close - 1.0) * 100, 4),
                "norm":    round(close / first_close, 6),
            })
        result = {"ticker": sym, "first_close": round(first_close, 2), "points": points}
        _bench_monthly_cache[sym] = {**result, "ts": now}
        return result
    except Exception:
        return None


def _account_overview_from_balance(records: list) -> dict | None:
    """Single source of truth for a managed account's YTD overview, computed
    purely from the parsed Fidelity Balance-Detail records (output of
    _parse_balance_history_csv).

    One CSV in → the complete result_json the account-detail page consumes. This
    replaces the fragile 3-file Modified-Dietz path (positions + activity +
    monthly-perf) that produced sign-flipped returns when the three files were
    out of sync. The balance CSV is internally consistent — its monthly gains
    reconcile exactly to Fidelity's reported totals — so every figure below ties
    out to the statement.

    Returns the dict stored as managed_account_ytd_cache.result_json, or None.

    Figures (all for the latest year present in the data = "YTD"):
      • twrr_return_pct  — Portfolio Return (time-weighted): chained monthly
                            returns, transfer/inception months skipped. Headline.
      • md_return_pct    — Modified Dietz over the whole window.
      • xirr_return_pct  — Personal Return (money-weighted, period MWRR ≈ Dietz).
      • begin/end/flows/gain, plus the monthly chart series + SPY overlay.
    """
    import datetime as _dt
    if not records:
        return None
    years = sorted({r["year"] for r in records})
    cur_year = years[-1]
    ytd  = sorted([r for r in records if r["year"] == cur_year], key=lambda r: r["month"])
    if not ytd:
        return None
    live = [r for r in ytd if not r.get("skip")]   # exclude custodial-transfer months

    # Beginning balance: first YTD month's open. Inception-safe — if the account
    # opened this year (beg == 0), use that month's deposits as the start capital.
    begin = float(ytd[0].get("beg_balance") or 0.0)
    if begin == 0.0:
        begin = float(ytd[0].get("deposits") or 0.0)
    end = float(ytd[-1].get("end_balance") or 0.0)

    deposits    = round(sum(float(r.get("deposits")    or 0.0) for r in ytd), 2)
    withdrawals = round(sum(float(r.get("withdrawals") or 0.0) for r in ytd), 2)
    net_flow    = round(deposits - withdrawals, 2)
    gain        = round(end - begin - net_flow, 2)   # ties to Fidelity's total

    # TWRR — chain each month's (already Modified-Dietz) return, skip transfers.
    tw = 1.0
    for r in live:
        tw *= (1.0 + float(r.get("return_pct") or 0.0) / 100.0)
    twrr = round((tw - 1.0) * 100.0, 4)

    # Period MWRR (money-weighted) = Modified Dietz across the whole YTD window,
    # flows weighted by mid-month. Same time window as TWRR so the two compare.
    period_start = _dt.date(cur_year, 1, 1)
    today = _dt.date.today()
    cd = max(1, (today - period_start).days)
    weighted = 0.0
    for r in ytd:
        mf = float(r.get("deposits") or 0.0) - float(r.get("withdrawals") or 0.0)
        if mf == 0.0:
            continue
        try:
            mid = _dt.date(cur_year, int(r["month"]), 15)
            weighted += mf * (cd - max(0, (mid - period_start).days)) / cd
        except Exception:
            continue
    denom = begin + weighted
    mwrr  = round(gain / denom * 100.0, 4) if denom > 0 else twrr

    _MN = {1:'Jan',2:'Feb',3:'Mar',4:'Apr',5:'May',6:'Jun',
           7:'Jul',8:'Aug',9:'Sep',10:'Oct',11:'Nov',12:'Dec'}
    mc_monthly = [
        {
            "label":       _MN.get(r["month"], r["label"]),
            "month":       r["month"],
            "return_pct":  r["return_pct"],
            "beg_balance": float(r.get("beg_balance") or 0.0),
            "end_balance": r["end_balance"],
            "start_value": float(r.get("beg_balance") or 0.0),
            "end_value":   r["end_balance"],
            "market_change": float(r.get("market_change") or 0.0),
            "skip":        r.get("skip", False),
            "exact":       True,
            "perf_detail": {
                "deposits":    r.get("deposits",    0.0),
                "withdrawals": r.get("withdrawals", 0.0),
                "net_flow":    float(r.get("deposits", 0.0)) - float(r.get("withdrawals", 0.0)),
            },
        }
        for r in ytd
    ]

    payload = {
        "twrr_return_pct":       twrr,
        "md_return_pct":         mwrr,
        "xirr_return_pct":       mwrr,
        "begin_value":           round(begin, 2),
        "end_value":             round(end, 2),
        "ytd_beg_balance":       round(begin, 2),
        "ytd_total_deposits":    deposits,
        "ytd_total_withdrawals": withdrawals,
        "net_external_flows":    net_flow,
        "investment_gain":       gain,
        "year":                  cur_year,
        "monthly_chart":         {"monthly": mc_monthly},
        "source":                "balance_history_csv",
    }

    # Attach the SPY (benchmark) overlay so the chart line + alpha tile render.
    # Best-effort: never let a benchmark fetch failure block the import.
    try:
        payload["spy_monthly"] = get_spy_monthly_data()
    except Exception:
        payload["spy_monthly"] = None
    return payload


# ─────────────────────────────────────────────────────────────────────────────
@app.post("/api/fund/{fund_id}/import-balance-history")
def fund_import_balance_history(
    fund_id: str,
    request: Request,
    file: UploadFile = File(...),
):
    _require_fund_token(request)
    raw = file.file.read()
    text = raw.decode('utf-8', errors='replace')
    records = _parse_balance_history_csv(text)
    if not records:
        raise HTTPException(400, "No valid monthly rows found in file.")
    # Derive the COMPLETE YTD overview from this single CSV — one authoritative
    # computation (TWRR + Modified Dietz + flows + monthly chart + SPY overlay),
    # internally consistent and reconciling to Fidelity's totals. This is the one
    # source of truth for the account overview; it intentionally overwrites any
    # stale value left by the legacy 3-file ytd-run path.
    result_json = _account_overview_from_balance(records)
    if not result_json:
        raise HTTPException(400, "Could not derive YTD figures from the file.")
    ytd_pct = result_json["twrr_return_pct"]   # headline = time-weighted return
    nav     = result_json["end_value"]

    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)
            cur.execute("""
                INSERT INTO account_balance_history (fund_id, data_json, updated_at)
                VALUES (%s, %s, now())
                ON CONFLICT (fund_id) DO UPDATE
                  SET data_json = EXCLUDED.data_json, updated_at = now()
            """, (fid, json.dumps(records)))
            cur.execute("""
                INSERT INTO managed_account_ytd_cache (fund_id, nav, ytd_pct, result_json, updated_at)
                VALUES (%s, %s, %s, %s, now())
                ON CONFLICT (fund_id) DO UPDATE
                  SET nav = EXCLUDED.nav, ytd_pct = EXCLUDED.ytd_pct,
                      result_json = EXCLUDED.result_json, updated_at = now()
            """, (fid, nav, ytd_pct, json.dumps(result_json)))
            # The CSV overwrite is authoritative — but if SnapTrade snapshots
            # extend past the CSV's last month, re-append those live months now
            # instead of waiting for the next sync. Best-effort behind a
            # savepoint so a failure can't poison the import's transaction.
            try:
                cur.execute("SAVEPOINT snap_rebuild")
                _bh = _snaptrade_rebuild_balance_history(cur, fid)
                cur.execute("RELEASE SAVEPOINT snap_rebuild")
                # Keep the success toast in step with what the page will render.
                if _bh and _bh.get("ytd_pct") is not None:
                    ytd_pct = float(_bh["ytd_pct"])
                if _bh and _bh.get("nav"):
                    nav = _bh["nav"]
            except Exception as _e:
                try:
                    cur.execute("ROLLBACK TO SAVEPOINT snap_rebuild")
                except Exception:
                    pass
                print(f"[snaptrade] post-CSV history rebuild skipped: {_e!s:.120}", flush=True)
        conn.commit()
    finally:
        conn.close()
    ytd_sign = "+" if ytd_pct >= 0 else ""
    return {
        "ok": True, "months": len(records),
        "range": f"{records[0]['label']} – {records[-1]['label']}",
        "ytd_pct": ytd_pct, "ytd_label": f"{ytd_sign}{ytd_pct:.2f}%",
    }


@app.get("/api/fund/{fund_id}/balance-history")
def fund_balance_history(fund_id: str, request: Request):
    # GPs and LPs (viewing their own accounts) are both allowed.
    claims = getattr(request.state, 'auth_claims', None)
    if not claims:
        _require_fund_token(request)  # legacy fund token fallback
    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)
            cur.execute(
                "SELECT data_json, updated_at FROM account_balance_history WHERE fund_id = %s",
                (fid,)
            )
            row = cur.fetchone()
    finally:
        conn.close()

    if not row:
        return {"ok": False, "monthly": [], "quarterly": [], "annual": [], "updated_at": None}

    monthly = json.loads(row["data_json"])
    updated_at = row["updated_at"].isoformat() if row["updated_at"] else None

    def chain_returns(pts):
        result = 1.0
        for p in pts:
            if p.get("skip"):
                continue
            result *= (1 + p["return_pct"] / 100)
        return round((result - 1) * 100, 4)

    # Compute running cash-only balance for each monthly period.
    # cash_only = what the balance would be with 0% investment return:
    # starts at initial beg_balance, then each period adds net deposits only.
    cash_only_running = 0.0
    for p in monthly:
        if cash_only_running == 0.0 and p.get("beg_balance"):
            cash_only_running = float(p["beg_balance"])
        net = float(p.get("deposits") or 0) - float(p.get("withdrawals") or 0)
        cash_only_running += net
        p["cash_only_balance"] = round(cash_only_running, 2)

    def _inception_beg(pts):
        """Return the correct beginning balance for a group of monthly records.
        For inception periods (first month has beg=0), use the gross deposits
        from that first month as the starting capital — that is what the investor
        committed to the account.  This prevents '—' in the BEG VALUE column and
        enables a meaningful return calculation for the opening year/quarter."""
        first_beg = float(pts[0].get("beg_balance") or 0)
        if first_beg != 0:
            return first_beg
        # Inception: account opened this period — use initial deposit as proxy
        first_dep = float(pts[0].get("deposits") or 0)
        return round(first_dep, 2) if first_dep else 0.0

    def _inception_month(pts):
        """Return the calendar month number of the inception month when
        beg_balance is 0 (i.e. the account did not start on Jan 1), else None."""
        if float(pts[0].get("beg_balance") or 0) == 0 and float(pts[0].get("deposits") or 0) > 0:
            return int(pts[0]["month"])
        return None

    quarterly = []
    for (yr, q), grp in groupby(monthly, key=lambda r: (r["year"], (r["month"] - 1) // 3 + 1)):
        pts = list(grp)
        quarterly.append({
            "year": yr, "quarter": q,
            "label": f"Q{q} {yr}",
            "beg_balance":       _inception_beg(pts),
            "end_balance":       pts[-1]["end_balance"],
            "cash_only_balance": pts[-1].get("cash_only_balance"),
            "deposits":          round(sum(float(p.get("deposits") or 0) for p in pts), 2),
            "withdrawals":       round(sum(float(p.get("withdrawals") or 0) for p in pts), 2),
            "return_pct":        chain_returns(pts),
            "inception_month":   _inception_month(pts),
        })

    # Load fund display settings (benchmark choice set by GP)
    fund_settings  = _load_fund_settings(fid)
    benchmark_key  = fund_settings.get("benchmark", "sp500")
    benchmark_defn = _BENCHMARK_DEFS.get(benchmark_key, _BENCHMARK_DEFS["sp500"])
    benchmark_label = benchmark_defn["label"]

    # Fetch benchmark annual returns for all years in history
    years = sorted({p["year"] for p in monthly}) if monthly else []
    bmark_annual: dict[int, float] = _get_benchmark_annual(benchmark_key, years)

    # Manual overrides take precedence over Modified Dietz calculation
    manual_returns = _load_manual_annual_returns(fid)

    _MONTH_ABBR = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]

    annual = []
    for yr, grp in groupby(monthly, key=lambda r: r["year"]):
        pts = list(grp)
        bmark_ret   = bmark_annual.get(yr)
        port_ret    = manual_returns.get(yr) if yr in manual_returns else chain_returns(pts)
        inc_month   = _inception_month(pts)   # int 1-12 if inception year, else None
        # Label: "2025 (Oct–Dec)" for partial inception years so the GP sees the true period
        if inc_month and pts[-1]["month"] < 12:
            span_label = f"{_MONTH_ABBR[inc_month-1]}–{_MONTH_ABBR[pts[-1]['month']-1]}"
            year_label = f"{yr} ({span_label})"
        elif inc_month:
            year_label = f"{yr} ({_MONTH_ABBR[inc_month-1]}–Dec)"
        else:
            year_label = str(yr)
        annual.append({
            "year":                 yr,
            "label":                year_label,
            "beg_balance":          _inception_beg(pts),
            "end_balance":          pts[-1]["end_balance"],
            "cash_only_balance":    pts[-1].get("cash_only_balance"),
            "deposits":             round(sum(float(p.get("deposits") or 0) for p in pts), 2),
            "withdrawals":          round(sum(float(p.get("withdrawals") or 0) for p in pts), 2),
            "return_pct":           port_ret,
            "benchmark_return_pct": bmark_ret,
            "alpha":                round(port_ret - bmark_ret, 2) if bmark_ret is not None else None,
            "return_source":        "manual" if yr in manual_returns else "computed",
            "inception_month":      inc_month,   # None for full years
            "data_months":          len([p for p in pts if not p.get("skip")]),  # actual months in this year
        })

    return {
        "ok":             True,
        "monthly":        monthly,
        "quarterly":      quarterly,
        "annual":         annual,
        "benchmark_key":  benchmark_key,
        "benchmark_label": benchmark_label,
        "period":         fund_settings.get("period", "all"),
        "updated_at":     updated_at,
    }


# Managed-account YTD calc — server-side wrapper that runs the existing
# unified Modified Dietz + attribution + monthly-balance computation,
# overlays the SPY benchmark series, and persists everything to the cache.
# ─────────────────────────────────────────────────────────────────────────────
@app.post("/api/fund/account/{fund_id}/ytd-run")
def fund_account_ytd_run(
    fund_id: str,
    request: Request,
    positions_file:    UploadFile     = File(...),
    activity_file:     UploadFile     = File(...),
    monthly_perf_file: UploadFile     = File(None),
    begin_value:       float | None   = Form(None),
):
    """Run YTD for a managed account from 3 Fidelity CSVs, attach SPY
    benchmark, persist to managed_account_ytd_cache, return the merged
    result."""
    _require_fund_token(request)

    try:
        pos_text = (positions_file.file.read()).decode("utf-8", errors="replace")
        act_text = (activity_file.file.read()).decode("utf-8", errors="replace")
    except Exception as exc:
        raise HTTPException(422, f"Could not read Fidelity files: {exc}")

    mp_text = None
    if monthly_perf_file and monthly_perf_file.filename:
        try:
            mp_text = (monthly_perf_file.file.read()).decode("utf-8", errors="replace")
        except Exception as exc:
            raise HTTPException(422, f"Could not read monthly performance file: {exc}")

    # ── Auto-fill begin_value from stored baseline when not supplied ───────────
    # IMPORTANT: only fall back to the saved baseline when NO monthly-performance
    # CSV was uploaded. The Balance & Income Detail CSV carries Fidelity's exact
    # Jan-1 balance (months[0].start), which is authoritative; a stale/incorrect
    # saved baseline must NOT override it (that produced impossible Modified-Dietz
    # returns like -200% while TWRR, chained from the same CSV, stayed correct).
    baseline_used = False
    if begin_value is None and not (mp_text and mp_text.strip()):
        import json as _json_bv
        _bv_conn = _fund_conn()
        try:
            with _bv_conn.cursor(cursor_factory=_RealDictCursor) as _bv_cur:
                _bv_fid = _resolve_fund_id(_bv_cur, fund_id)
                _bv_cur.execute("""
                    SELECT jan1_balance FROM account_ytd_baseline
                     WHERE fund_id = %s
                     ORDER BY year DESC LIMIT 1
                """, (_bv_fid,))
                _bv_row = _bv_cur.fetchone()
                if _bv_row:
                    begin_value  = float(_bv_row["jan1_balance"])
                    baseline_used = True
        except Exception:
            pass   # table may not exist yet; non-fatal
        finally:
            _bv_conn.close()

    try:
        result = analyst.compute_unified_ytd(
            pos_text, act_text, begin_value, monthly_perf_text=mp_text,
        )
    except Exception as exc:
        raise HTTPException(500, f"YTD computation failed: {exc}\n\n{traceback.format_exc()}")

    if not result.get("ok"):
        raise HTTPException(422, result.get("error", "YTD computation returned no data"))

    # Attach SPY benchmark for chart overlay
    try:
        spy = get_spy_monthly_data()
        result["spy_monthly"] = spy
    except Exception:
        result["spy_monthly"] = None

    # Persist into managed_account_ytd_cache.
    # Headline metric is ALWAYS TWRR when available — the balance-CSV import
    # and the SnapTrade rebuild both write TWRR, and this path used to write
    # Modified Dietz, so the same ytd_pct field silently flipped definition
    # depending on which writer ran last.
    nav     = result.get("end_value") or result.get("end_nav") or 0.0
    ytd_pct = (result.get("twrr_return_pct")
               if result.get("twrr_return_pct") is not None
               else (result.get("md_return_pct") or result.get("ytd_pct")
                     or result.get("modified_dietz") or 0.0))
    import json as _json
    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            # Resolve fund ID
            fid = _resolve_fund_id(cur, fund_id)

            # ── Preserve the Balance-Detail CSV as the single source of truth ──
            # If the account overview was already computed from the authoritative
            # Balance & Income Detail CSV (import-balance-history), this run keeps
            # those return / NAV / monthly-chart numbers and only OVERLAYS its
            # attribution + cash-flow detail. Positions+Activity must never flip
            # the headline YTD return — that is what produced the wrong figure.
            cur.execute("SELECT result_json FROM managed_account_ytd_cache "
                        "WHERE fund_id = %s", (fid,))
            _ex_row = cur.fetchone()
            _existing = None
            if _ex_row and _ex_row.get("result_json"):
                _existing = (_ex_row["result_json"] if isinstance(_ex_row["result_json"], dict)
                             else _json.loads(_ex_row["result_json"]))
            if _existing and _existing.get("source") in ("balance_history_csv",
                                                         "balance_history_snaptrade"):
                _AUTH = ("twrr_return_pct", "md_return_pct", "xirr_return_pct",
                         "begin_value", "end_value", "ytd_beg_balance",
                         "ytd_total_deposits", "ytd_total_withdrawals",
                         "net_external_flows", "investment_gain",
                         "monthly_chart", "spy_monthly", "year", "source")
                for _k in _AUTH:
                    if _k in _existing:
                        result[_k] = _existing[_k]
                nav     = _existing.get("end_value") or nav
                ytd_pct = (_existing.get("twrr_return_pct")
                           if _existing.get("twrr_return_pct") is not None else ytd_pct)

            cur.execute("""
                INSERT INTO managed_account_ytd_cache
                       (fund_id, nav, ytd_pct, result_json, updated_at)
                VALUES (%s, %s, %s, %s, now())
                ON CONFLICT (fund_id) DO UPDATE
                   SET nav         = EXCLUDED.nav,
                       ytd_pct     = EXCLUDED.ytd_pct,
                       result_json = EXCLUDED.result_json,
                       updated_at  = now()
            """, (fid, float(nav), float(ytd_pct), _json.dumps(result)))

            # Also sync positions into tax_lots so the Positions panel is populated.
            # Ensure CoA exists (managed accounts created via v2 API may not have it).
            _pos_sync_ok = False
            _pos_sync_msg = "No positions file provided"
            try:
                _seed_coa_for_fund(cur, fid)
                positions_parsed = _parse_fidelity_csv(pos_text)
                if not positions_parsed:
                    _pos_sync_msg = "Positions CSV parsed 0 rows — check file format"
                if positions_parsed:
                    # Ensure COA exists (backfill accounts created before seeding was wired)
                    _seed_coa_for_fund(cur, fid)
                    # Fetch CoA account IDs
                    cur.execute("""
                        SELECT code, id FROM accounts
                         WHERE fund_id = %s AND code IN ('1020','1030','1100','3000')
                    """, (fid,))
                    acct_map  = {r["code"]: str(r["id"]) for r in cur.fetchall()}
                    sec_acct  = acct_map.get("1100")
                    mm_acct   = acct_map.get("1030") or acct_map.get("1020")
                    cap_acct  = acct_map.get("3000")

                    if sec_acct and cap_acct:
                        # Upsert securities — update asset_class and is_public on conflict
                        # so pre-existing rows with wrong values get corrected.
                        sec_ids = {}
                        for p in positions_parsed:
                            _is_cash = bool(p["is_cash"])
                            cur.execute("""
                                INSERT INTO securities (symbol, name, asset_class, is_public)
                                VALUES (%s, %s, %s, %s)
                                ON CONFLICT (symbol) DO UPDATE
                                    SET name        = EXCLUDED.name,
                                        asset_class = EXCLUDED.asset_class,
                                        is_public   = EXCLUDED.is_public
                                RETURNING id
                            """, (p["symbol"], p["name"] or p["symbol"],
                                  "cash" if _is_cash else "equity",
                                  not _is_cash))  # is_public=TRUE for equities
                            sec_ids[p["symbol"]] = str(cur.fetchone()["id"])

                        # Close existing open lots
                        cur.execute("""
                            UPDATE tax_lots SET closed_at = NOW()
                             WHERE fund_id = %s AND closed_at IS NULL
                        """, (fid,))

                        # Create adjustment transaction
                        today_iso = datetime.utcnow().date().isoformat()
                        cur.execute("""
                            INSERT INTO transactions
                                (fund_id, effective_date, category, description)
                            VALUES (%s, %s, 'adjustment', 'Position import from YTD run')
                            RETURNING id
                        """, (fid, today_iso))
                        txn_id = str(cur.fetchone()["id"])

                        # Transaction lines (Dr positions, Cr capital)
                        total_cost_lots = 0.0
                        ln = 1
                        for p in positions_parsed:
                            cost = float(p["cost_basis"] or 0)
                            if cost <= 0:
                                continue
                            total_cost_lots += cost
                            acct = mm_acct if p["is_cash"] else sec_acct
                            if not acct:
                                continue
                            cur.execute("""
                                INSERT INTO transaction_lines
                                    (transaction_id, line_number, account_id, debit, security_id)
                                VALUES (%s, %s, %s, %s, %s)
                            """, (txn_id, ln, acct, round(cost, 4),
                                  sec_ids.get(p["symbol"])))
                            ln += 1
                        if total_cost_lots > 0:
                            cur.execute("""
                                INSERT INTO transaction_lines
                                    (transaction_id, line_number, account_id, credit)
                                VALUES (%s, %s, %s, %s)
                            """, (txn_id, ln, cap_acct, round(total_cost_lots, 4)))

                        # Insert tax lots
                        for p in positions_parsed:
                            cur.execute("""
                                INSERT INTO tax_lots
                                    (fund_id, security_id, acquired_at,
                                     quantity, cost_basis_per_unit, open_transaction_id)
                                VALUES (%s, %s, NOW(), %s, %s, %s)
                            """, (fid, sec_ids[p["symbol"]],
                                  float(p["quantity"]),
                                  float(p["avg_cost"]) if p["avg_cost"] else 0.0,
                                  txn_id))
                        _pos_sync_ok  = True
                        _pos_sync_msg = f"{len(positions_parsed)} positions synced to tax_lots"
            except Exception as _pos_exc:
                # Non-fatal: YTD data was already saved; positions sync is best-effort
                _pos_sync_msg = f"positions sync failed: {str(_pos_exc)[:200]}"
                print(f"⚠️  positions sync failed for {fund_id}: {_pos_exc}")

            # NOTE: The monthly_perf_file (YTD Balance Detail CSV) is intentionally
            # NOT written to account_balance_history here.  That table is the
            # all-time chart's source of truth and must only be populated by the
            # dedicated "Upload to All-Time Chart" endpoint
            # (POST /api/fund/{fund_id}/import-balance-history).
            # Writing a YTD-only file here would overwrite multi-year all-time
            # data with just the current year's months.

        conn.commit()
    finally:
        conn.close()

    result["positions_sync_ok"]  = _pos_sync_ok
    result["positions_sync_msg"] = _pos_sync_msg
    result["baseline_used"]      = baseline_used   # True when jan1_balance was auto-read from DB
    return result


# ---------------------------------------------------------------------------
# Fund administration — delete
# ---------------------------------------------------------------------------

def _safe_delete(cur, sql: str, params: tuple) -> None:
    """Execute a DELETE inside a savepoint.

    Silently skips if the table (or a referenced table in a subquery) does not
    exist — psycopg2 puts the SQLSTATE code on exc.pgcode, NOT in str(exc), so
    we check that attribute directly.

    SQLSTATE codes we treat as non-fatal:
      42P01 — undefined_table
      42703 — undefined_column
    All other exceptions are re-raised so real errors surface to the caller.
    """
    _SKIP_CODES = ("42P01", "42703")
    cur.execute("SAVEPOINT _del_sp")
    try:
        cur.execute(sql, params)
        cur.execute("RELEASE SAVEPOINT _del_sp")
    except Exception as exc:
        cur.execute("ROLLBACK TO SAVEPOINT _del_sp")
        pgcode = getattr(exc, "pgcode", "") or ""
        if pgcode not in _SKIP_CODES:
            raise  # real error — bubble up with full context


@app.delete("/api/fund/admin/delete")
def fund_admin_delete(request: Request, fund_id: str):
    """Permanently delete a fund and ALL its associated data.

    Requires the x-delete-password header to match the FUND_DELETE_PASSWORD
    environment variable.  If FUND_DELETE_PASSWORD is not set the endpoint
    is disabled (returns 503).
    """
    _require_fund_token(request)

    # ── Verify FUND_DELETE_PASSWORD ──────────────────────────────────────────
    required_pw = os.environ.get("FUND_DELETE_PASSWORD", "").strip()
    if not required_pw:
        raise HTTPException(
            status_code=503,
            detail="FUND_DELETE_PASSWORD is not configured on this server.",
        )
    submitted_pw = request.headers.get("x-delete-password", "").strip()
    if not hmac.compare_digest(submitted_pw, required_pw):
        raise HTTPException(status_code=403, detail="Incorrect delete password.")

    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)
            cur.execute("SELECT name FROM funds WHERE id = %s", (fid,))
            row = cur.fetchone()
            if not row:
                raise HTTPException(404, "Fund not found")
            name = row["name"]

            # ── 1. Grandchild rows (FK → non-funds parent) ────────────────────
            _safe_delete(cur, """
                DELETE FROM transaction_lines
                 WHERE transaction_id IN (
                       SELECT id FROM transactions WHERE fund_id = %s)
            """, (fid,))
            _safe_delete(cur, """
                DELETE FROM capital_call_allocations
                 WHERE capital_call_id IN (
                       SELECT id FROM capital_calls WHERE fund_id = %s)
            """, (fid,))
            _safe_delete(cur, """
                DELETE FROM distribution_allocations
                 WHERE distribution_id IN (
                       SELECT id FROM distributions WHERE fund_id = %s)
            """, (fid,))
            _safe_delete(cur, """
                DELETE FROM nav_snapshot_lp
                 WHERE snapshot_id IN (
                       SELECT id FROM nav_snapshots WHERE fund_id = %s)
            """, (fid,))
            _safe_delete(cur, """
                DELETE FROM carry_allocations
                 WHERE carry_run_id IN (
                       SELECT id FROM carry_runs WHERE fund_id = %s)
            """, (fid,))
            _safe_delete(cur, """
                DELETE FROM mgmt_fee_allocations
                 WHERE mgmt_fee_run_id IN (
                       SELECT id FROM mgmt_fee_runs WHERE fund_id = %s)
            """, (fid,))
            _safe_delete(cur, """
                DELETE FROM commitments
                 WHERE lp_id IN (SELECT id FROM lps WHERE fund_id = %s)
            """, (fid,))
            _safe_delete(cur, """
                DELETE FROM lp_statements
                 WHERE lp_id IN (SELECT id FROM lps WHERE fund_id = %s)
            """, (fid,))

            # ── 2. Direct fund_id children (order matters for remaining FKs) ──
            for tbl in (
                "transactions",
                "capital_calls",
                "distributions",
                "nav_snapshots",
                "carry_runs",
                "mgmt_fee_runs",
                "lps",
                "tax_lots",
                "accounts",
                "managed_account_ytd_cache",
                "audit_log",
            ):
                _safe_delete(cur, f"DELETE FROM {tbl} WHERE fund_id = %s", (fid,))  # noqa: S608

            # ── 3. Finally remove the fund itself ─────────────────────────────
            cur.execute("DELETE FROM funds WHERE id = %s", (fid,))
        conn.commit()
        return {"deleted": fid, "name": name}
    except HTTPException:
        raise
    except Exception as exc:
        try:
            conn.rollback()
        except Exception:
            pass
        raise HTTPException(
            status_code=500,
            detail=f"Delete failed: {type(exc).__name__}: {exc}",
        )
    finally:
        conn.close()


