# ---------------------------------------------------------------------------
# YTD Baseline — save / retrieve per-account Jan-1 starting balance
# ---------------------------------------------------------------------------

@app.post("/api/fund/account/{fund_id}/set-ytd-baseline")
def set_ytd_baseline(
    fund_id:  str,
    request:  Request,
    year:     int    = Form(...),
    jan1_balance: float = Form(...),
    flows_json:   str  = Form("[]"),   # JSON-encoded list of cash-flow dicts
    notes:    str      = Form(""),
):
    """Store (or overwrite) the Jan 1 beginning balance and historical cash
    flows for a managed account for a given year.

    After the first merge run the user clicks "Set as YTD Baseline" in the
    UI.  The endpoint stores the data so that future YTD uploads can auto-fill
    the beginning balance without the user typing it each time.
    """
    _require_fund_token(request)
    import json as _json
    try:
        flows = _json.loads(flows_json)
        if not isinstance(flows, list):
            raise ValueError("flows_json must be a JSON array")
    except Exception as exc:
        raise HTTPException(422, f"Invalid flows_json: {exc}")

    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)
            _ensure_ytd_baseline_table(conn)   # idempotent — creates if missing
            cur.execute("""
                INSERT INTO account_ytd_baseline
                       (fund_id, year, jan1_balance, historical_flows, notes, created_at, updated_at)
                VALUES (%s, %s, %s, %s::jsonb, %s, now(), now())
                ON CONFLICT (fund_id, year) DO UPDATE
                   SET jan1_balance     = EXCLUDED.jan1_balance,
                       historical_flows = EXCLUDED.historical_flows,
                       notes            = EXCLUDED.notes,
                       updated_at       = now()
            """, (fid, year, jan1_balance, _json.dumps(flows), notes.strip() or None))
        conn.commit()
    except Exception as exc:
        raise HTTPException(500, f"Could not save YTD baseline: {exc}")
    finally:
        conn.close()

    return {
        "ok":           True,
        "fund_id":      fund_id,
        "year":         year,
        "jan1_balance": jan1_balance,
        "flows_stored": len(flows),
        "notes":        notes.strip() or None,
    }


@app.get("/api/fund/account/{fund_id}/ytd-baseline")
def get_ytd_baseline(
    fund_id: str,
    request: Request,
    year:    int | None = None,
):
    """Return the stored YTD baseline for a managed account.

    If `year` is omitted, returns the most-recent year stored.
    Returns 404 if no baseline has been saved yet.
    """
    _require_fund_token(request)
    import json as _json
    conn = _fund_conn()
    try:
        with conn.cursor(cursor_factory=_RealDictCursor) as cur:
            fid = _resolve_fund_id(cur, fund_id)
            if year:
                cur.execute("""
                    SELECT year, jan1_balance, historical_flows, notes, updated_at
                      FROM account_ytd_baseline
                     WHERE fund_id = %s AND year = %s
                """, (fid, year))
            else:
                cur.execute("""
                    SELECT year, jan1_balance, historical_flows, notes, updated_at
                      FROM account_ytd_baseline
                     WHERE fund_id = %s
                     ORDER BY year DESC
                     LIMIT 1
                """, (fid,))
            row = cur.fetchone()
    except Exception as exc:
        raise HTTPException(500, f"Could not read YTD baseline: {exc}")
    finally:
        conn.close()

    if not row:
        raise HTTPException(404, "No YTD baseline stored for this account.")

    flows = row["historical_flows"]
    if isinstance(flows, str):
        try:
            flows = _json.loads(flows)
        except Exception:
            flows = []

    return {
        "ok":           True,
        "fund_id":      fund_id,
        "year":         row["year"],
        "jan1_balance": float(row["jan1_balance"]),
        "flows":        flows,
        "notes":        row["notes"],
        "updated_at":   row["updated_at"].isoformat() if row["updated_at"] else None,
    }


@app.post("/api/fund/merge-balance-history")
def merge_balance_history(
    request: Request,
    file1: UploadFile = File(...),
    file2: UploadFile = File(...),
):
    """Parse two Fidelity Investment Income & Balance Detail CSVs and return
    a merged CSV where overlapping months are summed field-by-field."""
    _require_fund_token(request)
    t1 = (file1.file.read()).decode("utf-8", errors="replace")
    t2 = (file2.file.read()).decode("utf-8", errors="replace")
    r1 = _parse_balance_history_csv(t1)
    r2 = _parse_balance_history_csv(t2)
    if not r1 and not r2:
        raise HTTPException(400, "No valid monthly rows found in either file.")
    map1 = {(r["year"], r["month"]): r for r in r1}
    map2 = {(r["year"], r["month"]): r for r in r2}
    SUM_FIELDS = ("beg_balance", "end_balance", "market_change",
                  "dividends", "interest", "deposits", "withdrawals", "fees")
    merged = []
    for key in sorted(set(map1) | set(map2), reverse=True):
        a, b = map1.get(key), map2.get(key)
        if a and b:
            row = {"label": a["label"], "year": a["year"], "month": a["month"]}
            for f in SUM_FIELDS:
                row[f] = (a.get(f) or 0.0) + (b.get(f) or 0.0)
        else:
            src = a or b
            row = {f: src.get(f, 0.0) for f in ("label", "year", "month") + SUM_FIELDS}
        merged.append(row)

    def _fm(v):
        return f'-${abs(v):,.2f}' if v < 0 else f'${v:,.2f}'

    lines = [
        "Investment income Export",
        '"Income For: COMBINED"',
        f'"Investment income - ({merged[-1]["label"]} - {merged[0]["label"]})"',
        '"Monthly","Beginning balance","Market change","Dividends","Interest","Deposits","Withdrawals","Net advisory fees","Ending balance"',
    ]
    for r in merged:
        lines.append(",".join([
            f'"{r["label"]}"', f'"{_fm(r["beg_balance"])}"',
            f'"{_fm(r["market_change"])}"', f'"{_fm(r["dividends"])}"',
            f'"{_fm(r["interest"])}"', f'"{_fm(r["deposits"])}"',
            f'"{_fm(r["withdrawals"])}"', f'"{_fm(r["fees"])}"',
            f'"{_fm(r["end_balance"])}"',
        ]))
    from fastapi.responses import Response as _Resp
    return _Resp(
        content="\n".join(lines),
        media_type="text/csv",
        headers={"Content-Disposition": 'attachment; filename="merged_balance_history.csv"'},
    )


