# ── DGA Memos (PDF-export of podcast scripts) ─────────────────────────
@_ddl_once
def _ensure_dga_memos_table() -> None:
    """Create dga_memos table — DGA Capital memos generated from podcast
    scripts. Idempotent."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    # Step 1: CREATE TABLE + INDEXES (one transaction, must succeed together)
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            try:
                cur.execute("CREATE EXTENSION IF NOT EXISTS pgcrypto")
            except Exception: conn.rollback()
            cur.execute("""
                CREATE TABLE IF NOT EXISTS dga_memos (
                    id              TEXT PRIMARY KEY,
                    source_job_key  TEXT NOT NULL,
                    source_format   TEXT,
                    episode_title   TEXT,
                    assigned_fund_id TEXT,
                    gp_memo         TEXT,
                    script_json     JSONB,
                    pdf_bytes       BYTEA,
                    generated_by    TEXT,
                    generated_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
                    last_sent_to    TEXT,
                    last_sent_at    TIMESTAMPTZ,
                    archived        BOOLEAN NOT NULL DEFAULT FALSE
                )
            """)
            cur.execute("CREATE INDEX IF NOT EXISTS dga_memos_fund_idx ON dga_memos(assigned_fund_id)")
            cur.execute("CREATE INDEX IF NOT EXISTS dga_memos_gen_idx  ON dga_memos(generated_at DESC)")
            conn.commit()
    except Exception as e:
        print(f"❌ _ensure_dga_memos_table CREATE failed: {e!s:.300}", flush=True)
        return  # Without the table, the ALTERs below would also fail

    # Step 2: Idempotent migration for any pre-existing UUID-typed columns.
    # Each ALTER runs in its OWN connection so a failure (e.g. column already
    # TEXT) doesn't poison subsequent ones.
    for alter in (
        "ALTER TABLE dga_memos ALTER COLUMN id TYPE TEXT USING id::text",
        "ALTER TABLE dga_memos ALTER COLUMN id DROP DEFAULT",
        "ALTER TABLE dga_memos ALTER COLUMN assigned_fund_id TYPE TEXT USING assigned_fund_id::text",
        "ALTER TABLE dga_memos ALTER COLUMN assigned_fund_id DROP DEFAULT",
    ):
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute(alter)
                conn.commit()
        except Exception as e:
            # Most failures are "cannot cast" or "column is not of type X" —
            # both no-op cases. Log once for visibility.
            es = str(e)[:120]
            if "already" not in es and "does not exist" not in es:
                print(f"⚠️ dga_memos ALTER skipped: {alter[-60:]!r} → {es}", flush=True)


def _content_disposition(disposition: str, filename: str) -> str:
    """Build an RFC 6266 / RFC 5987 safe Content-Disposition header value.

    HTTP header values are encoded latin-1 by the ASGI server, so any non-
    latin-1 character in the filename (e.g. an em-dash '—' U+2014 in a memo
    title) raises UnicodeEncodeError → HTTP 500. We emit BOTH an ASCII-only
    `filename=` fallback (for ancient clients) and a UTF-8 `filename*=` per
    RFC 5987 so modern browsers show the real title.
    """
    import urllib.parse as _up
    # ASCII fallback: drop anything outside latin-1, collapse to safe chars.
    ascii_name = filename.encode("ascii", "ignore").decode("ascii") or "document"
    ascii_name = ascii_name.replace('"', "").replace("\\", "")
    utf8_name = _up.quote(filename, safe="")
    return (f"{disposition}; filename=\"{ascii_name}\"; "
            f"filename*=UTF-8''{utf8_name}")


def _memo_md_inline(text: str) -> str:
    """Convert inline markdown in a memo line to reportlab markup. Escapes HTML
    first, then applies bold/italic/code/links so `**x**`, `*x*`, `` `x` `` and
    [t](url) render properly instead of showing raw markdown characters."""
    import html as _h
    s = _h.escape(text or "")
    s = re.sub(r"`([^`]+)`", r'<font face="Courier">\1</font>', s)
    s = re.sub(r"\*\*(.+?)\*\*", r"<b>\1</b>", s)
    s = re.sub(r"__(.+?)__", r"<b>\1</b>", s)
    s = re.sub(r"(?<![\*\w])\*(?!\s)(.+?)(?<!\s)\*(?![\*\w])", r"<i>\1</i>", s)
    s = re.sub(r"\[([^\]]+)\]\((https?://[^)\s]+)\)", r'<a href="\2" color="#1565c0">\1</a>', s)
    # any leftover stray markdown bullets/markers at line start
    return s


def _memo_md_flowables(md_text: str, S: dict) -> list:
    """Parse a markdown body into reportlab flowables: headings, bullet &
    numbered lists, horizontal rules, GFM pipe TABLES, and paragraphs — with
    inline formatting. S is a dict of ParagraphStyles: body, h2, h3, bullet,
    tcell, thead, plus numeric 'width' (content width in points)."""
    from reportlab.platypus import Paragraph, HRFlowable, Table, TableStyle
    from reportlab.lib import colors as _c
    NAVY = _c.HexColor("#0A1628")
    ZEBRA = _c.HexColor("#f1f5f9")
    GRID = _c.HexColor("#e2e8f0")
    out, para_buf, bullet_buf, num_buf = [], [], [], []
    lines = (md_text or "").replace("\r\n", "\n").split("\n")

    def flush_para():
        if para_buf:
            txt = " ".join(x.strip() for x in para_buf).strip()
            if txt:
                out.append(Paragraph(_memo_md_inline(txt), S["body"]))
            para_buf.clear()

    def flush_bullets():
        for b in bullet_buf:
            out.append(Paragraph("•&nbsp;&nbsp;" + _memo_md_inline(b), S["bullet"]))
        bullet_buf.clear()

    def flush_nums():
        for i, b in enumerate(num_buf, 1):
            out.append(Paragraph(f"<b>{i}.</b>&nbsp;&nbsp;" + _memo_md_inline(b), S["bullet"]))
        num_buf.clear()

    def flush_all():
        flush_para(); flush_bullets(); flush_nums()

    def _split_row(r):
        return [c.strip() for c in re.sub(r"^\s*\|", "", re.sub(r"\|\s*$", "", r)).split("|")]

    i = 0
    while i < len(lines):
        raw = lines[i]
        st = raw.strip()
        # GFM table: a header row with '|' followed by a |---|---| separator
        if "|" in st and i + 1 < len(lines) and re.match(r"^\s*\|?[\s:|-]*-[\s:|-]*\|[\s:|-]*$", lines[i + 1]):
            flush_all()
            heads = _split_row(st)
            ncol = len(heads)
            i += 2
            rows = []
            while i < len(lines) and "|" in lines[i] and lines[i].strip():
                cells = _split_row(lines[i])
                cells = (cells + [""] * ncol)[:ncol]   # pad/truncate to header width
                rows.append(cells)
                i += 1
            data = [[Paragraph(_memo_md_inline(h), S["thead"]) for h in heads]]
            for r in rows:
                data.append([Paragraph(_memo_md_inline(c), S["tcell"]) for c in r])
            width = float(S.get("width") or 460)
            col_w = [width / ncol] * ncol
            tbl = Table(data, colWidths=col_w, repeatRows=1)
            tbl.setStyle(TableStyle([
                ("BACKGROUND", (0, 0), (-1, 0), NAVY),
                ("VALIGN", (0, 0), (-1, -1), "TOP"),
                ("LEFTPADDING", (0, 0), (-1, -1), 6),
                ("RIGHTPADDING", (0, 0), (-1, -1), 6),
                ("TOPPADDING", (0, 0), (-1, -1), 5),
                ("BOTTOMPADDING", (0, 0), (-1, -1), 5),
                ("ROWBACKGROUNDS", (0, 1), (-1, -1), [_c.white, ZEBRA]),
                ("LINEBELOW", (0, 0), (-1, -1), 0.4, GRID),
                ("LINEAFTER", (0, 0), (-2, -1), 0.4, GRID),
                ("BOX", (0, 0), (-1, -1), 0.5, GRID),
            ]))
            out.append(tbl)
            from reportlab.platypus import Spacer as _Sp
            out.append(_Sp(1, 8))
            continue
        if not st:
            flush_all(); i += 1; continue
        if re.match(r"^([-*_])\1{2,}$", st):                  # horizontal rule
            flush_all()
            out.append(HRFlowable(width="100%", thickness=0.5,
                                  color=_c.HexColor("#cbd5e1"), spaceBefore=5, spaceAfter=7))
            i += 1; continue
        m_h = re.match(r"^(#{1,4})\s+(.*)$", st)
        if m_h:
            flush_all()
            lvl = len(m_h.group(1))
            txt = m_h.group(2).strip().rstrip("#").strip()
            out.append(Paragraph(_memo_md_inline(txt), S["h2" if lvl <= 2 else "h3"]))
            i += 1; continue
        m_b = re.match(r"^[-*•]\s+(.*)$", st)
        if m_b:
            flush_para(); flush_nums(); bullet_buf.append(m_b.group(1).strip()); i += 1; continue
        m_n = re.match(r"^\d+[.)]\s+(.*)$", st)
        if m_n:
            flush_para(); flush_bullets(); num_buf.append(m_n.group(1).strip()); i += 1; continue
        flush_bullets(); flush_nums()
        para_buf.append(st); i += 1
    flush_all()
    return out


def _render_dga_memo_pdf(script: dict, gp_memo: str, fund_name: str | None,
                          generated_at_iso: str) -> bytes:
    """Render a DGA Capital memo PDF (reportlab platypus) with a branded logo
    letterhead. Analysis-style memos (research_memo) render their markdown body
    properly (headings/bullets/bold); podcast scripts keep speaker attribution.
    No external dependencies beyond reportlab (already installed)."""
    import io as _io
    import html as _html
    from reportlab.lib.pagesizes import letter
    from reportlab.lib.styles import ParagraphStyle
    from reportlab.lib.units import inch
    from reportlab.lib import colors
    from reportlab.platypus import (
        SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, HRFlowable, PageBreak,
        Image as _RLImage,
    )
    from reportlab.lib.enums import TA_LEFT

    NAVY = colors.HexColor("#0A1628")
    BLUE = colors.HexColor("#5BB8D4")
    AMBER_BG = colors.HexColor("#fff8e1")
    AMBER_BORDER = colors.HexColor("#f59e0b")
    GREY = colors.HexColor("#64748b")
    DARK = colors.HexColor("#1e293b")

    episode_title = script.get("episode_title") or script.get("ticker") or "DGA Memo"
    tickers = script.get("tickers") or [script.get("ticker")]
    tickers_str = ", ".join(t for t in (tickers or []) if t)[:300]
    fmt = (script.get("format") or "memo").replace("_", " ").title()
    date_str = (generated_at_iso or "")[:10]

    # Speaker display name + hex color string (used inline in Paragraph
    # markup so we keep the raw "#RRGGBB" form rather than HexColor objects)
    SPEAKER_META = {
        "opus":    ("Marc (PM)",  "#0A1628"),
        "rock":    ("Rock",       "#1565c0"),
        "claudia": ("Claudia",    "#7c3aed"),
    }
    def _sp(name):
        return SPEAKER_META.get((name or "").lower(),
                                 ((name or "Narrator").title(), "#475569"))

    # Footer with page numbers
    def _footer(canv, doc):
        canv.saveState()
        canv.setFont("Helvetica", 7.5)
        canv.setFillColor(GREY)
        canv.drawCentredString(letter[0]/2, 0.45*inch,
            f"DGA Capital · Confidential · Page {canv.getPageNumber()}")
        canv.restoreState()

    buf = _io.BytesIO()
    doc = SimpleDocTemplate(
        buf, pagesize=letter,
        leftMargin=0.85*inch, rightMargin=0.85*inch,
        topMargin=0.8*inch, bottomMargin=0.7*inch,
        title=episode_title, author="DGA Capital",
    )

    # ── Styles ────────────────────────────────────────────────────────────
    h_eyebrow = ParagraphStyle("eyebrow", fontName="Helvetica-Bold",
        fontSize=8, textColor=BLUE, spaceAfter=2, leading=10)
    h_title = ParagraphStyle("title", fontName="Helvetica-Bold",
        fontSize=19, textColor=NAVY, spaceAfter=4, leading=22)
    h_fund = ParagraphStyle("fund", fontName="Helvetica",
        fontSize=10, textColor=DARK, spaceAfter=2, leading=13)
    h_meta = ParagraphStyle("meta", fontName="Helvetica", fontSize=9,
        textColor=GREY, leading=12)
    h_section = ParagraphStyle("section", fontName="Helvetica-Bold",
        fontSize=12.5, textColor=NAVY, spaceBefore=14, spaceAfter=6, leading=15,
        borderColor=BLUE, borderWidth=0,
        borderPadding=(0, 0, 3, 0))
    p_turn = ParagraphStyle("turn", fontName="Helvetica", fontSize=10.5,
        textColor=DARK, leading=14.5, spaceAfter=4, alignment=TA_LEFT)
    p_memo = ParagraphStyle("memo", fontName="Helvetica", fontSize=10.5,
        textColor=NAVY, leading=14.5, alignment=TA_LEFT)
    p_disc = ParagraphStyle("disclaimer", fontName="Helvetica", fontSize=7.5,
        textColor=GREY, leading=10.5, spaceBefore=10)
    # Markdown body styles (for analysis-style memos)
    md_body = ParagraphStyle("md_body", fontName="Helvetica", fontSize=10.5,
        textColor=DARK, leading=15, spaceAfter=7, alignment=TA_LEFT)
    md_h2 = ParagraphStyle("md_h2", fontName="Helvetica-Bold", fontSize=12.5,
        textColor=NAVY, leading=15, spaceBefore=13, spaceAfter=5)
    md_h3 = ParagraphStyle("md_h3", fontName="Helvetica-Bold", fontSize=10.8,
        textColor=colors.HexColor("#334155"), leading=13.5, spaceBefore=9, spaceAfter=3)
    md_bullet = ParagraphStyle("md_bullet", fontName="Helvetica", fontSize=10.5,
        textColor=DARK, leading=14.5, spaceAfter=3, leftIndent=14, firstLineIndent=-10)
    md_tcell = ParagraphStyle("md_tcell", fontName="Helvetica", fontSize=8.5,
        textColor=DARK, leading=11.5)
    md_thead = ParagraphStyle("md_thead", fontName="Helvetica-Bold", fontSize=8,
        textColor=colors.white, leading=11)
    MD_STYLES = {"body": md_body, "h2": md_h2, "h3": md_h3, "bullet": md_bullet,
                 "tcell": md_tcell, "thead": md_thead, "width": doc.width}
    p_focus = ParagraphStyle("focus", fontName="Helvetica-Oblique", fontSize=9.5,
        textColor=GREY, leading=13, spaceAfter=2)

    fmt_raw = (script.get("format") or "memo").lower()
    is_analysis = fmt_raw in ("research_memo", "analysis", "strategy_memo")

    flow = []
    # ── Branded letterhead ───────────────────────────────────────────────
    try:
        _logo = BRANDING_DIR / "dga_logo.png"
        if _logo.exists():
            # Read natural dims from a probe, then pass explicit width/height to
            # the constructor — setting drawWidth/drawHeight post-construction
            # is unreliable (reportlab keeps natural size and overflows).
            _probe = _RLImage(str(_logo))
            _nw = float(getattr(_probe, "imageWidth", 0) or 649)
            _nh = float(getattr(_probe, "imageHeight", 0) or 184)
            tw = 1.9 * inch
            img = _RLImage(str(_logo), width=tw, height=tw * (_nh / _nw))
            img.hAlign = "LEFT"
            flow.append(img)
            flow.append(Spacer(1, 10))
    except Exception as _e:
        print(f"⚠️ memo logo embed skipped: {_e!s:.120}", flush=True)

    # ── Header block ─────────────────────────────────────────────────────
    flow.append(Paragraph("CONFIDENTIAL INVESTMENT MEMORANDUM", h_eyebrow))
    flow.append(Paragraph(_html.escape(episode_title), h_title))
    if fund_name:
        flow.append(Paragraph(f"Prepared for: <b>{_html.escape(fund_name)}</b>", h_fund))
    flow.append(Paragraph(
        f"{date_str} &nbsp;·&nbsp; {_html.escape(fmt)}"
        + (f" &nbsp;·&nbsp; Coverage: {_html.escape(tickers_str)}" if tickers_str else ""),
        h_meta))
    flow.append(Spacer(1, 6))
    flow.append(HRFlowable(width="100%", thickness=2, color=NAVY,
                            spaceBefore=2, spaceAfter=10))

    # ── GP Note callout ──────────────────────────────────────────────────
    if (gp_memo or "").strip():
        memo_para = Paragraph(
            f"<b><font color='#92400e' size='8'>GP NOTE</font></b><br/><br/>"
            + _html.escape(gp_memo.strip()).replace("\n", "<br/>"),
            p_memo,
        )
        tbl = Table([[memo_para]], colWidths=[doc.width])
        tbl.setStyle(TableStyle([
            ("BACKGROUND", (0,0), (-1,-1), AMBER_BG),
            ("LEFTPADDING", (0,0), (-1,-1), 12),
            ("RIGHTPADDING", (0,0), (-1,-1), 12),
            ("TOPPADDING", (0,0), (-1,-1), 10),
            ("BOTTOMPADDING", (0,0), (-1,-1), 10),
            ("LINEBEFORE", (0,0), (-1,-1), 3, AMBER_BORDER),
            ("BOX", (0,0), (-1,-1), 0.5, AMBER_BORDER),
        ]))
        flow.append(tbl)
        flow.append(Spacer(1, 12))

    # ── Body ─────────────────────────────────────────────────────────────
    if is_analysis:
        # Analysis-style memo: the body is markdown (headings, bullets, bold).
        # Render it richly, with no nonsensical speaker labels. A short
        # "research question" section becomes a focus line under the header.
        for sec in (script.get("sections") or []):
            sid = (sec.get("id") or "").lower().strip()
            turns = sec.get("turns") or []
            if not turns:
                continue
            body_md = "\n\n".join((t.get("text") or "") for t in turns).strip()
            if not body_md:
                continue
            if sid == "research_question":
                flow.append(Paragraph("FOCUS", h_eyebrow))
                flow.append(Paragraph(_memo_md_inline(body_md), p_focus))
                flow.append(Spacer(1, 8))
            else:
                flow.extend(_memo_md_flowables(body_md, MD_STYLES))
    else:
        # Podcast/dialogue memo: keep speaker-attributed turns, with inline
        # markdown so any **bold** renders rather than showing asterisks.
        for sec in (script.get("sections") or []):
            sid = (sec.get("id") or "").replace("_", " ").strip()
            title = sid.title() if sid else "Section"
            turns = sec.get("turns") or []
            if not turns:
                continue
            flow.append(Paragraph(_html.escape(title), h_section))
            flow.append(HRFlowable(width="40%", thickness=1.2, color=BLUE,
                                    spaceBefore=0, spaceAfter=6, hAlign="LEFT"))
            for t in turns:
                sp_name, sp_color_hex = _sp(t.get("speaker"))
                flow.append(Paragraph(
                    f'<b><font color="{sp_color_hex}">{_html.escape(sp_name)}:</font></b> '
                    + _memo_md_inline(t.get("text") or ""),
                    p_turn,
                ))

    # ── Disclaimer ───────────────────────────────────────────────────────
    flow.append(Spacer(1, 16))
    flow.append(HRFlowable(width="100%", thickness=0.4,
                            color=colors.HexColor("#cbd5e1"),
                            spaceBefore=4, spaceAfter=4))
    flow.append(Paragraph(
        f"<b>Disclaimer:</b> This memo is for informational and educational "
        f"purposes only and reflects views as of {date_str}. It is not "
        f"investment advice, an offer to sell, or a solicitation to buy "
        f"any security. DGA Capital is an exempt reporting adviser in "
        f"California. Holdings, opinions, and price targets discussed may "
        f"change without notice. Past performance is not indicative of "
        f"future results. The information herein is believed to be reliable "
        f"but is not guaranteed. Recipients should consult their own "
        f"financial, legal, and tax advisors before making any investment "
        f"decisions. Distribution restricted to authorized recipients only.",
        p_disc))

    doc.build(flow, onFirstPage=_footer, onLaterPages=_footer)
    return buf.getvalue()


def _render_dga_memo_html(script: dict, gp_memo: str, fund_name: str | None,
                           generated_at_iso: str) -> str:
    """Render a podcast script as a DGA Capital memo (HTML, print-friendly).
    Sections become narrative chapters; turns become attributed paragraphs.
    Kept around in case we wire WeasyPrint later — current PDF path uses
    _render_dga_memo_pdf (reportlab) which has no extra system deps.
    """
    import html as _html
    episode_title = script.get("episode_title") or script.get("ticker") or "DGA Memo"
    tickers = script.get("tickers") or [script.get("ticker")]
    tickers_str = ", ".join(t for t in (tickers or []) if t)[:300]
    fmt = (script.get("format") or "memo").replace("_", " ").title()
    date_str = (generated_at_iso or "")[:10]

    # Map speaker → display name + color
    SPEAKER_META = {
        "opus":    ("Marc (PM)",    "#0A1628"),
        "rock":    ("Rock",         "#1565c0"),
        "claudia": ("Claudia",      "#7c3aed"),
    }
    def _sp(name):
        return SPEAKER_META.get((name or "").lower(), (name.title() if name else "Narrator", "#475569"))

    sections_html = []
    for sec in (script.get("sections") or []):
        sid = (sec.get("id") or "").replace("_", " ").strip()
        # Skip technical IDs in title casing
        title = sid.title() if sid else "Section"
        turn_html = []
        for t in (sec.get("turns") or []):
            text = _html.escape(t.get("text") or "")
            sp_name, sp_color = _sp(t.get("speaker"))
            turn_html.append(
                f'<p style="margin:8px 0;line-height:1.55;font-size:11pt;">'
                f'<strong style="color:{sp_color};">{_html.escape(sp_name)}:</strong> '
                f'<span style="color:#1e293b;">{text}</span></p>'
            )
        if turn_html:
            sections_html.append(
                f'<h2 style="font-size:13pt;color:#0A1628;border-bottom:1.5px solid #5BB8D4;'
                f'padding-bottom:4px;margin-top:24px;margin-bottom:10px;letter-spacing:0.3px;">'
                f'{_html.escape(title)}</h2>'
                + "".join(turn_html)
            )

    memo_block = ""
    if (gp_memo or "").strip():
        memo_block = (
            '<div style="background:#fff8e1;border:1px solid #fde68a;border-left:4px solid #f59e0b;'
            'border-radius:6px;padding:12px 16px;margin:18px 0;">'
            '<div style="font-size:9.5pt;font-weight:800;letter-spacing:1px;color:#92400e;'
            'text-transform:uppercase;margin-bottom:6px;">GP Note</div>'
            f'<div style="font-size:11pt;color:#0A1628;line-height:1.55;white-space:pre-wrap;">'
            f'{_html.escape(gp_memo.strip())}</div></div>'
        )

    fund_line = f'<div style="font-size:10pt;color:#475569;margin-top:2px;">For: <strong>{_html.escape(fund_name)}</strong></div>' if fund_name else ""

    return f"""<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>{_html.escape(episode_title)}</title>
<style>
  @page {{ size: Letter; margin: 0.85in; @bottom-center {{ content: "DGA Capital · Confidential · Page " counter(page) " of " counter(pages); font-size: 8pt; color: #94a3b8; }} }}
  body {{ font-family: -apple-system, "Helvetica Neue", Helvetica, Arial, sans-serif; color: #1e293b; }}
  h1 {{ font-size: 20pt; color: #0A1628; margin: 0; letter-spacing: -0.4px; }}
</style></head>
<body>
  <div style="border-bottom:3px solid #0A1628;padding-bottom:10px;margin-bottom:18px;">
    <div style="display:flex;justify-content:space-between;align-items:flex-end;">
      <div>
        <div style="font-size:9pt;font-weight:800;letter-spacing:2px;color:#5BB8D4;text-transform:uppercase;">DGA Capital · Investment Memo</div>
        <h1>{_html.escape(episode_title)}</h1>
        {fund_line}
      </div>
      <div style="text-align:right;font-size:9.5pt;color:#64748b;line-height:1.5;">
        <div>{date_str}</div>
        <div style="margin-top:2px;">Format: {_html.escape(fmt)}</div>
      </div>
    </div>
    <div style="margin-top:8px;font-size:9pt;color:#64748b;">Coverage: {_html.escape(tickers_str)}</div>
  </div>
  {memo_block}
  {''.join(sections_html) or '<p style="color:#94a3b8;font-style:italic;">No sections in source script.</p>'}
  <div style="margin-top:36px;padding-top:14px;border-top:1px solid #cbd5e1;font-size:8pt;color:#94a3b8;line-height:1.5;">
    <strong style="color:#475569;">Disclaimer:</strong> This memo is for informational purposes only and reflects views as of {date_str}. It is not investment advice nor an offer to buy or sell any security. Generated from DGA Capital's internal research pipeline. Distribution is restricted to authorized recipients.
  </div>
</body></html>"""


def _load_script_by_job_key(job_key: str) -> dict | None:
    """Look up a script (and its format/title) in analyst_podcasts by ticker key."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return None
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""SELECT ticker, format, episode_title, script_json
                             FROM analyst_podcasts
                            WHERE ticker = %s
                         ORDER BY generated_at DESC LIMIT 1""", (job_key,))
            row = cur.fetchone()
            if not row: return None
            rj = row["script_json"]
            script = json.loads(rj) if isinstance(rj, str) else (rj or {})
            return {
                "ticker": row["ticker"],
                "format": row.get("format"),
                "episode_title": row.get("episode_title") or script.get("episode_title"),
                "script": script,
            }
    except Exception as e:
        print(f"⚠️ _load_script_by_job_key({job_key!r}) failed: {e!s:.150}", flush=True)
        return None


def _fund_name_lookup(fund_id: str | None) -> str | None:
    if not fund_id or not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return None
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("SELECT COALESCE(short_name, name) FROM funds WHERE id::text = %s",
                        (str(fund_id),))
            row = cur.fetchone()
            return row[0] if row else None
    except Exception:
        return None


@app.post("/api/memos/from-podcast/{job_key}")
def create_memo_from_podcast(job_key: str, request: Request):
    """Generate a DGA Capital memo PDF from a saved podcast script.

    Body: { assigned_fund_id?: uuid, gp_memo?: str }
    Returns: { ok, memo_id, episode_title, pdf_url }
    """
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    _ensure_dga_memos_table()

    try:
        body = _request_json_sync(request)
    except Exception:
        body = {}
    assigned_fund_id = (body or {}).get("assigned_fund_id") or None
    gp_memo = ((body or {}).get("gp_memo") or "").strip()

    src = _load_script_by_job_key(job_key)
    if not src or not src.get("script"):
        raise HTTPException(404, f"No podcast script found for {job_key}")

    fund_name = _fund_name_lookup(assigned_fund_id)
    from datetime import datetime as _dt, timezone as _tz
    gen_iso = _dt.now(_tz.utc).isoformat()
    try:
        pdf_bytes = _render_dga_memo_pdf(src["script"], gp_memo, fund_name, gen_iso)
    except Exception as e:
        raise HTTPException(500, f"PDF render failed: {e!s:.200}")

    import uuid as _uuid
    memo_id = str(_uuid.uuid4())
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                INSERT INTO dga_memos
                   (id, source_job_key, source_format, episode_title,
                    assigned_fund_id, gp_memo, script_json,
                    pdf_bytes, generated_by, generated_at)
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, now())
            """, (
                memo_id, job_key, src.get("format"),
                src.get("episode_title") or "DGA Memo",
                assigned_fund_id, gp_memo or None,
                json.dumps(src["script"]),
                psycopg2.Binary(pdf_bytes),
                claims.get("email") or claims.get("lp_id") or "gp",
            ))
            conn.commit()
        print(f"📄 [memo] saved id={memo_id} job_key={job_key!r} "
              f"fund={assigned_fund_id} bytes={len(pdf_bytes)}", flush=True)
    except Exception as e:
        print(f"❌ [memo] INSERT failed for {job_key!r}: {e!s:.300}", flush=True)
        raise HTTPException(500, f"DB insert failed: {e!s:.200}")

    return {
        "ok": True, "memo_id": memo_id,
        "episode_title": src.get("episode_title"),
        "assigned_fund_id": assigned_fund_id,
        "fund_name": fund_name,
        "pdf_url": f"/api/memos/{memo_id}/pdf",
        "size_bytes": len(pdf_bytes),
    }


@app.get("/api/memos/_diag")
def memos_diag(request: Request):
    """Diagnostic — confirm the dga_memos table exists, show column types,
    row count, and the most recent row's id/title. Helps debug 'memos not
    showing up' without needing Railway log access."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    _ensure_dga_memos_table()
    out: dict = {"ok": True, "claims_role": claims.get("role")}
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        out["ok"] = False; out["error"] = "no DATABASE_URL / psycopg2"; return out
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""SELECT column_name, data_type
                             FROM information_schema.columns
                            WHERE table_name = 'dga_memos'
                            ORDER BY ordinal_position""")
            out["columns"] = [dict(r) for r in cur.fetchall()]
            cur.execute("SELECT COUNT(*) AS n FROM dga_memos")
            out["row_count"] = cur.fetchone()["n"]
            cur.execute("""SELECT id, episode_title, assigned_fund_id,
                                  generated_at, octet_length(pdf_bytes) AS bytes
                             FROM dga_memos
                            ORDER BY generated_at DESC LIMIT 5""")
            rows = []
            for r in cur.fetchall():
                rows.append({**dict(r),
                             "generated_at": r["generated_at"].isoformat() if r.get("generated_at") else None})
            out["recent"] = rows
    except Exception as e:
        out["ok"] = False; out["error"] = str(e)[:300]
    return out


@app.get("/api/memos/selftest")
def memos_selftest(request: Request, download: int = 0):
    """Diagnose the memo PDF pipeline — especially logo embedding. Returns JSON
    {logo_exists, pillow, render_ok, pdf_bytes}; with ?download=1 streams a
    one-page sample memo PDF so you can visually confirm the logo renders."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    logo = BRANDING_DIR / "dga_logo.png"
    out = {"ok": True, "logo_path": str(logo), "logo_exists": logo.exists()}
    try:
        import PIL
        out["pillow"] = getattr(PIL, "__version__", "installed")
    except Exception as e:
        out["pillow"] = f"MISSING — {e!s:.80} (logo cannot embed without Pillow)"
    sample = {
        "format": "research_memo", "episode_title": "Memo Pipeline Self-Test",
        "sections": [
            {"id": "research_question", "turns": [{"speaker": "opus", "text": "Logo + table render check"}]},
            {"id": "analysis", "turns": [{"speaker": "opus", "text":
                "## Executive Summary\n\nIf you can see the **DGA Capital logo** at the top "
                "and the table below has a navy header, the pipeline is healthy.\n\n"
                "## Positions\n\n"
                "| Position | Weight | Thesis | View | Action |\n"
                "|----------|--------|--------|------|--------|\n"
                "| NVDA | 18% | AI compute leader | Demand ahead of supply | Hold |\n"
                "| INTC | 6% | Foundry optionality | Contested rating, momentum-priced | Trim |\n\n"
                "## Portfolio Actions\n\n- Trim INTC into strength\n- Maintain NVDA core\n\n"
                "## Key Risks\n\n- Concentration in AI hardware\n- Rate sensitivity"}]},
        ],
    }
    try:
        from datetime import datetime as _dt, timezone as _tz
        pdf = _render_dga_memo_pdf(sample, "", "Self-Test Fund", _dt.now(_tz.utc).isoformat())
        out["render_ok"] = True
        out["pdf_bytes"] = len(pdf)
    except Exception as e:
        out["render_ok"] = False
        out["render_error"] = str(e)[:300]
        return JSONResponse(out, status_code=500)
    if download:
        from fastapi.responses import Response as _Response
        return _Response(content=pdf, media_type="application/pdf",
                         headers={"Content-Disposition": _content_disposition("inline", "memo-selftest.pdf")})
    return out


@app.get("/api/memos")
def list_memos(request: Request, fund_id: str | None = None,
                include_archived: bool = False):
    """List all DGA memos, newest first. Optionally filter by assigned fund."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    _ensure_dga_memos_table()
    rows = []
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            where = []
            params: list = []
            if not include_archived:
                where.append("m.archived IS NOT TRUE")
            if fund_id:
                where.append("m.assigned_fund_id = %s")
                params.append(fund_id)
            where_sql = ("WHERE " + " AND ".join(where)) if where else ""
            # funds.id is UUID, m.assigned_fund_id is TEXT — cast on join side
            cur.execute(f"""
                SELECT m.id                       AS id,
                       m.source_job_key          AS source_job_key,
                       m.source_format           AS source_format,
                       m.episode_title           AS episode_title,
                       m.assigned_fund_id        AS assigned_fund_id,
                       COALESCE(f.short_name, f.name) AS fund_name,
                       m.gp_memo                 AS gp_memo,
                       m.generated_by            AS generated_by,
                       m.generated_at            AS generated_at,
                       m.last_sent_to            AS last_sent_to,
                       m.last_sent_at            AS last_sent_at,
                       octet_length(m.pdf_bytes) AS size_bytes
                  FROM dga_memos m
             LEFT JOIN funds f ON f.id::text = m.assigned_fund_id
                {where_sql}
                 ORDER BY m.generated_at DESC
                 LIMIT 200
            """, tuple(params))
            for r in cur.fetchall():
                rows.append({
                    **{k: v for k, v in r.items() if k not in ("generated_at", "last_sent_at")},
                    "generated_at": r["generated_at"].isoformat() if r.get("generated_at") else None,
                    "last_sent_at": r["last_sent_at"].isoformat() if r.get("last_sent_at") else None,
                })
    except Exception as e:
        raise HTTPException(500, f"List memos failed: {e!s:.200}")
    return {"ok": True, "memos": rows}


@app.get("/api/memos/{memo_id}/pdf")
def download_memo_pdf(memo_id: str, request: Request):
    """Stream the persisted PDF for a memo."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""SELECT pdf_bytes, episode_title
                             FROM dga_memos WHERE id = %s""", (memo_id,))
            row = cur.fetchone()
            if not row:
                raise HTTPException(404, "Memo not found")
            pdf_bytes = bytes(row[0]) if row[0] else b""
            title = (row[1] or "dga_memo").replace("/", "_")[:80]
    except HTTPException: raise
    except Exception as e:
        raise HTTPException(500, f"Fetch failed: {e!s:.200}")
    from fastapi.responses import Response as _Response
    return _Response(content=pdf_bytes, media_type="application/pdf",
                     headers={"Content-Disposition":
                              _content_disposition("inline", f"{title}.pdf")})


@app.post("/api/memos/{memo_id}/email")
def email_memo(memo_id: str, request: Request):
    """Send a memo PDF via email.
    Body: { mode: 'ad_hoc'|'lp_list', to_addr?, subject?, body_html? }
    mode='lp_list' sends one email per active LP in the assigned fund.
    """
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    try:
        body = _request_json_sync(request)
    except Exception:
        body = {}
    mode      = (body or {}).get("mode") or "ad_hoc"
    to_addr   = ((body or {}).get("to_addr") or "").strip()
    subject_in = ((body or {}).get("subject") or "").strip()
    body_html  = ((body or {}).get("body_html") or "").strip()

    # Load memo
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""SELECT id::text, episode_title, gp_memo,
                                  pdf_bytes, assigned_fund_id::text AS fund_id
                             FROM dga_memos WHERE id = %s""", (memo_id,))
            memo = cur.fetchone()
    except Exception as e:
        raise HTTPException(500, f"Fetch failed: {e!s:.200}")
    if not memo:
        raise HTTPException(404, "Memo not found")
    pdf_bytes = bytes(memo["pdf_bytes"]) if memo.get("pdf_bytes") else b""
    if not pdf_bytes:
        raise HTTPException(500, "Memo has no stored PDF")

    subject = subject_in or f"DGA Capital · {memo['episode_title']}"
    filename = (memo["episode_title"] or "dga_memo").replace("/", "_")[:80] + ".pdf"
    default_html = body_html or f"""
<html><body style="font-family:-apple-system,sans-serif;color:#1e293b;">
  <p>Please find attached our latest DGA Capital memo: <strong>{memo['episode_title']}</strong>.</p>
  {('<p style="background:#fff8e1;padding:10px 14px;border-left:3px solid #f59e0b;border-radius:4px;">'
    + (memo['gp_memo'] or '').replace(chr(10), '<br>') + '</p>') if memo.get('gp_memo') else ''}
  <p>Best,<br>DGA Capital</p>
</body></html>"""

    # Resolve recipients
    recipients: list[str] = []
    if mode == "lp_list":
        if not memo.get("fund_id"):
            raise HTTPException(422, "Memo is not assigned to a fund — cannot use lp_list mode")
        try:
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT email FROM lps
                                WHERE fund_id::text = %s AND status = 'active'
                                  AND email IS NOT NULL AND email <> ''""", (memo["fund_id"],))
                recipients = [r["email"] for r in cur.fetchall() if r.get("email")]
        except Exception as e:
            raise HTTPException(500, f"LP lookup failed: {e!s:.200}")
        if not recipients:
            raise HTTPException(422, "No active LPs with email found for this fund")
    else:
        if not to_addr or "@" not in to_addr:
            raise HTTPException(422, "Provide a valid recipient email address")
        recipients = [to_addr]

    # Send
    results = []
    for addr in recipients:
        r = _send_email_with_pdf_attachment(addr, subject, default_html,
                                             pdf_bytes, filename)
        results.append({"to": addr, **r})

    sent_ok = [r for r in results if r.get("ok")]
    if sent_ok:
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("""UPDATE dga_memos
                                  SET last_sent_to = %s, last_sent_at = now()
                                WHERE id = %s""",
                            (", ".join(r["to"] for r in sent_ok)[:500], memo_id))
                conn.commit()
        except Exception: pass

    return {"ok": bool(sent_ok), "sent": len(sent_ok), "attempted": len(results),
            "results": results}


@app.patch("/api/memos/{memo_id}")
def update_memo(memo_id: str, request: Request):
    """Update assigned_fund_id and/or gp_memo. Regenerates the PDF so the new
    fund name + memo text appear inside the document."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    try:
        body = _request_json_sync(request)
    except Exception:
        body = {}
    new_fund = (body or {}).get("assigned_fund_id")  # may be None or "" to clear
    new_memo = (body or {}).get("gp_memo")
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""SELECT script_json, episode_title, assigned_fund_id::text AS fund_id, gp_memo
                             FROM dga_memos WHERE id = %s""", (memo_id,))
            row = cur.fetchone()
            if not row:
                raise HTTPException(404, "Memo not found")
        # Compute new values (None = leave alone)
        final_fund = row["fund_id"] if new_fund is None else (new_fund or None)
        final_memo = row["gp_memo"] if new_memo is None else (new_memo or None)
        script = json.loads(row["script_json"]) if isinstance(row["script_json"], str) else row["script_json"]
        fund_name = _fund_name_lookup(final_fund)
        from datetime import datetime as _dt, timezone as _tz
        pdf_bytes = _render_dga_memo_pdf(script, final_memo or "", fund_name,
                                          _dt.now(_tz.utc).isoformat())
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""UPDATE dga_memos
                              SET assigned_fund_id = %s, gp_memo = %s, pdf_bytes = %s
                            WHERE id = %s""",
                        (final_fund, final_memo, psycopg2.Binary(pdf_bytes), memo_id))
            conn.commit()
    except HTTPException: raise
    except Exception as e:
        raise HTTPException(500, f"Update failed: {e!s:.200}")
    return {"ok": True, "memo_id": memo_id, "fund_name": fund_name}


@app.delete("/api/memos/{memo_id}")
def delete_memo(memo_id: str, request: Request):
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("DELETE FROM dga_memos WHERE id = %s", (memo_id,))
            conn.commit()
    except Exception as e:
        raise HTTPException(500, f"Delete failed: {e!s:.200}")
    return {"ok": True}


# ── Podcast DB schema ──────────────────────────────────────────────────
@_ddl_once
def _ensure_podcast_table() -> None:
    """Create analyst_podcasts if missing. Idempotent, per-ALTER commits."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS analyst_podcasts (
                    ticker             TEXT PRIMARY KEY,
                    episode_title      TEXT,
                    script_json        JSONB,
                    audio_local_path   TEXT,
                    audio_dropbox_path TEXT,
                    duration_sec       REAL,
                    tts_model          TEXT,
                    voice_map          JSONB,
                    generated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
                    cost_usd           REAL
                )
            """)
            conn.commit()
            # ui133: alignment + DA brief columns (idempotent)
            # ui150: format column + composite (ticker, format) PK so each
            #        format gets its own row (Debate + Pre-Mortem + Memo etc
            #        for the same ticker coexist without overwriting).
            for stmt in [
                "ALTER TABLE analyst_podcasts ADD COLUMN IF NOT EXISTS alignment_json JSONB",
                "ALTER TABLE analyst_podcasts ADD COLUMN IF NOT EXISTS da_brief TEXT",
                "ALTER TABLE analyst_podcasts ADD COLUMN IF NOT EXISTS episode_mode TEXT",
                "ALTER TABLE analyst_podcasts ADD COLUMN IF NOT EXISTS format TEXT NOT NULL DEFAULT 'debate'",
                # ui156: real script-gen cost (sum of all LLM calls) — separate
                # from cost_usd which has historically held audio-only cost
                "ALTER TABLE analyst_podcasts ADD COLUMN IF NOT EXISTS script_cost_usd REAL",
            ]:
                try:
                    cur.execute(stmt); conn.commit()
                except Exception as _e:
                    print(f"⚠️  [podcast] schema ALTER skipped: {_e!s:.120}", flush=True)
            # Backfill format from script_json before flipping the PK
            try:
                cur.execute(
                    "UPDATE analyst_podcasts SET format = COALESCE(script_json->>'format', 'debate') "
                    "WHERE format IS NULL OR format = 'debate'"
                )
                conn.commit()
            except Exception as _e:
                print(f"⚠️  [podcast] format backfill skipped: {_e!s:.120}", flush=True)
            # Replace single-column PK with composite (ticker, format)
            try:
                cur.execute("""
                    DO $$
                    BEGIN
                        IF EXISTS (
                            SELECT 1 FROM pg_constraint
                            WHERE conname = 'analyst_podcasts_pkey'
                              AND conrelid = 'analyst_podcasts'::regclass
                              AND (SELECT array_length(conkey,1)) = 1
                        ) THEN
                            ALTER TABLE analyst_podcasts DROP CONSTRAINT analyst_podcasts_pkey;
                            ALTER TABLE analyst_podcasts ADD PRIMARY KEY (ticker, format);
                        END IF;
                    END$$;
                """)
                conn.commit()
            except Exception as _e:
                print(f"⚠️  [podcast] PK migration skipped: {_e!s:.120}", flush=True)
    except Exception as e:
        print(f"❌ [podcast] table ensure failed: {e!s:.200}", flush=True)


# Build-time hook (best-effort)
try:
    _ensure_podcast_table()
except Exception:
    pass


