def _safe_arith(expr: str) -> float:
    """Evaluate a pure-arithmetic expression with no builtins/names — only
    numbers and + - * / ** % and parens. Raises on anything else."""
    import ast as _ast, operator as _op
    OPS = {_ast.Add: _op.add, _ast.Sub: _op.sub, _ast.Mult: _op.mul,
           _ast.Div: _op.truediv, _ast.Pow: _op.pow, _ast.Mod: _op.mod,
           _ast.USub: _op.neg, _ast.UAdd: _op.pos, _ast.FloorDiv: _op.floordiv}
    def _ev(node):
        if isinstance(node, _ast.Constant):
            if isinstance(node.value, (int, float)): return node.value
            raise ValueError("non-numeric constant")
        if isinstance(node, _ast.BinOp):  return OPS[type(node.op)](_ev(node.left), _ev(node.right))
        if isinstance(node, _ast.UnaryOp): return OPS[type(node.op)](_ev(node.operand))
        raise ValueError(f"disallowed expression: {type(node).__name__}")
    tree = _ast.parse(expr, mode="eval")
    return _ev(tree.body)


def _agentic_exec_tool(name: str, args: dict) -> str:
    """Execute one agent tool call against the platform's real data.
    Returns a string (JSON or text) fed back to the model as tool_result."""
    try:
        if name == "get_quote":
            tks = (args.get("tickers") or "").upper()
            q = batch_quotes(tks) or {}
            out = {tk: {"price": (q.get(tk) or {}).get("price"),
                        "pct_change": (q.get(tk) or {}).get("pct_change")}
                   for tk in [t.strip() for t in tks.split(",") if t.strip()]}
            return json.dumps(out, default=str)

        if name == "get_sector":
            tk = (args.get("ticker") or "").upper().strip()
            sec, ind = analyst.fetch_sector_and_industry(tk)
            return json.dumps({"ticker": tk, "sector": sec, "industry": ind})

        if name == "scan_wheel":
            import options_engine as _opt
            tks = [t.strip().upper() for t in (args.get("tickers") or "").split(",")
                   if t.strip()][:8]   # cap: this tool runs synchronously
            if not tks:
                return "No tickers provided. Pass comma-separated symbols."
            try:
                dmax = float(args.get("delta_max") or 0.30)
            except Exception:
                dmax = 0.30
            dmax = max(0.05, min(dmax, 0.95))
            side = (args.get("side") or "both").lower()
            if side not in ("both", "calls", "puts"):
                side = "both"
            res = _opt.scan_wheel(tks, delta_max=dmax, side=side)
            return json.dumps(res, default=str)

        if name == "list_portfolios":
            if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
                return "DB unavailable."
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""
                    SELECT f.id, f.name, f.short_name, f.fund_type,
                           s.symbol, SUM(tl.quantity) AS qty,
                           SUM(tl.quantity * tl.cost_basis_per_unit) AS cost
                      FROM funds f
                      JOIN tax_lots tl ON tl.fund_id = f.id AND tl.closed_at IS NULL
                      JOIN securities s ON s.id = tl.security_id
                     WHERE f.fund_type = 'managed_account'
                       AND COALESCE(f.status, '') <> 'closed'
                     GROUP BY f.id, f.name, f.short_name, f.fund_type, s.symbol
                     HAVING SUM(tl.quantity) <> 0
                """)
                rows = cur.fetchall() or []
            allsyms = sorted({r["symbol"] for r in rows if r.get("symbol")})
            quotes = batch_quotes(",".join(allsyms)) if allsyms else {}
            funds: dict = {}
            for r in rows:
                f = funds.setdefault(str(r["id"]),
                                     {"name": r["name"], "short_name": r["short_name"],
                                      "type": r["fund_type"], "holdings": 0,
                                      "market_value": 0.0, "cost_basis": 0.0})
                f["holdings"] += 1
                f["cost_basis"] += float(r["cost"] or 0)
                px = (quotes.get(r["symbol"]) or {}).get("price")
                if px and r.get("qty"):
                    f["market_value"] += float(r["qty"]) * float(px)
            out = sorted(funds.values(), key=lambda x: -x["market_value"])
            for f in out:
                f["market_value"] = round(f["market_value"], 2)
                f["cost_basis"] = round(f["cost_basis"], 2)
            return json.dumps({"portfolios": out, "count": len(out)}, default=str)

        if name == "get_portfolio_holdings":
            qname = (args.get("portfolio") or "").strip()
            if not qname:
                return "portfolio name is required."
            if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
                return "DB unavailable."
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT id, name, short_name FROM funds
                                WHERE fund_type = 'managed_account'
                                  AND COALESCE(status, '') <> 'closed'
                                  AND (short_name ILIKE %s OR name ILIKE %s)
                                ORDER BY short_name LIMIT 1""",
                            (f"%{qname}%", f"%{qname}%"))
                fund = cur.fetchone()
                if not fund:
                    return json.dumps({"error": f"No managed account matches '{qname}'. "
                                       "Call list_portfolios for the exact account names."})
                cur.execute("""SELECT s.symbol, s.name AS sec_name, s.asset_class,
                                      SUM(tl.quantity) AS qty,
                                      SUM(tl.quantity * tl.cost_basis_per_unit)
                                          / NULLIF(SUM(tl.quantity), 0) AS avg_cost
                                 FROM tax_lots tl
                                 JOIN securities s ON s.id = tl.security_id
                                WHERE tl.fund_id = %s AND tl.closed_at IS NULL
                                GROUP BY s.id, s.symbol, s.name, s.asset_class
                                HAVING SUM(tl.quantity) <> 0""", (fund["id"],))
                rows = cur.fetchall() or []
            syms = [r["symbol"] for r in rows if r.get("symbol")]
            quotes = batch_quotes(",".join(syms)) if syms else {}
            metas = _db_meta(syms)
            holdings, total_mv = [], 0.0
            for r in rows:
                sym = r["symbol"]
                qty = float(r["qty"] or 0)
                px = (quotes.get(sym) or {}).get("price")
                avg = float(r["avg_cost"]) if r.get("avg_cost") is not None else None
                mv = qty * px if px else None
                if mv:
                    total_mv += mv
                sector = (metas.get(sym) or {}).get("sector")
                if not sector:
                    try:
                        sector = (get_ticker_meta(sym) or {}).get("sector")
                    except Exception:
                        sector = None
                holdings.append({
                    "symbol": sym, "name": r.get("sec_name"),
                    "asset_class": r.get("asset_class"),
                    "shares": round(qty, 4),
                    "avg_cost": round(avg, 2) if avg else None,
                    "price": round(px, 2) if px else None,
                    "market_value": round(mv, 2) if mv else None,
                    "unrealized_gain_pct": (round((px - avg) / avg * 100, 2)
                                            if (px and avg) else None),
                    "sector": sector or "Unknown"})
            sector_alloc: dict = {}
            for h in holdings:
                if h["market_value"] and total_mv:
                    h["weight_pct"] = round(h["market_value"] / total_mv * 100, 2)
                    sector_alloc[h["sector"]] = round(
                        sector_alloc.get(h["sector"], 0) + h["weight_pct"], 2)
                else:
                    h["weight_pct"] = None
            holdings.sort(key=lambda h: -(h["market_value"] or 0))
            return json.dumps({
                "portfolio": fund["short_name"] or fund["name"],
                "account_full_name": fund["name"],
                "total_market_value": round(total_mv, 2),
                "positions": len(holdings),
                "sector_allocation_pct": dict(sorted(sector_alloc.items(),
                                                     key=lambda x: -x[1])),
                "holdings": holdings}, default=str)[:9000]

        if name == "read_saved_report":
            tk = (args.get("ticker") or "").upper().strip()
            provider = (args.get("provider") or "both").lower()
            if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
                return "DB unavailable."
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT report_md, report_md_claude, rating, price_target,
                                      upside_pct, generated_at
                                 FROM analyst_reports WHERE ticker = %s""", (tk,))
                row = cur.fetchone()
            if not row:
                return f"No saved report for {tk}."
            grok_md   = (row.get("report_md") or "").strip()
            claude_md = (row.get("report_md_claude") or "").strip()
            MAX = 8000   # truncate hard so one report can't blow the context
            parts = [f"Ticker: {tk}  rating={row.get('rating')}  "
                     f"target={row.get('price_target')}  upside={row.get('upside_pct')}%"]
            if provider in ("grok", "both") and grok_md:
                parts.append(f"\n══ GROK REPORT ══\n{grok_md[:MAX]}")
            if provider in ("claude", "both") and claude_md:
                parts.append(f"\n══ CLAUDE REPORT ══\n{claude_md[:MAX]}")
            return "\n".join(parts) if len(parts) > 1 else f"No {provider} report text for {tk}."

        if name == "get_recent_news":
            tk = (args.get("ticker") or "").upper().strip()
            lim = max(1, min(int(args.get("limit") or 3), 3))
            items = _fetch_news_for_ticker(tk, limit=lim)
            if not items:
                return f"No recent news for {tk}."
            return json.dumps([{"title": i["title"], "publisher": i.get("publisher"),
                                "url": i.get("url")} for i in items], default=str)

        if name == "list_saved_reports":
            if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
                return "DB unavailable."
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT ticker, rating, upside_pct FROM analyst_reports
                                WHERE archived IS NOT TRUE
                                ORDER BY ticker LIMIT 200""")
                rows = cur.fetchall() or []
            return json.dumps([{"ticker": r["ticker"], "rating": r.get("rating"),
                                "upside_pct": float(r["upside_pct"]) if r.get("upside_pct") is not None else None}
                               for r in rows], default=str)

        if name == "get_financials":
            tk = (args.get("ticker") or "").upper().strip()
            try:
                import excel_financials as _xf
                import pull_sec_financials as _psf
            except Exception as e:
                return f"Financials module unavailable: {e!s:.120}"
            # Extract; if no XBRL cached yet, download then retry once.
            data = None
            try:
                data = _xf.extract_financials(tk)
            except FileNotFoundError:
                try:
                    _psf.download_financials(tk)
                    data = _xf.extract_financials(tk)
                except Exception as e:
                    return f"Could not fetch SEC financials for {tk}: {e!s:.150}"
            except Exception as e:
                return f"Financials error for {tk}: {e!s:.150}"
            if not data:
                return f"No financials found for {tk}."
            # Compact summary — annuals (last 2) + ttm headline, truncate hard
            def _slim(row):
                if not isinstance(row, dict): return row
                keep = ("end", "fp", "revenue", "net_income", "gross_profit",
                        "operating_income", "eps", "free_cash_flow", "total_debt",
                        "cash", "shares", "gross_margin", "operating_margin")
                return {k: row.get(k) for k in keep if k in row}
            summary = {
                "ticker": tk,
                "entity": data.get("entity_name"),
                "latest_filing_type": data.get("latest_filing_type"),
                "annuals": [_slim(r) for r in (data.get("annuals") or [])[-2:]],
                "ttm": _slim(data.get("ttm") or {}),
                "source": "SEC XBRL (filing-accurate)",
            }
            return json.dumps(summary, default=str)[:6000]

        if name == "get_financials_history":
            tk = (args.get("ticker") or "").upper().strip()
            pt = args.get("period_type") or "quarter"
            if pt not in ("quarter", "annual", "all"):
                pt = "quarter"
            lim = max(1, min(int(args.get("limit") or 12), 40))
            try:
                _ensure_financials_table()
                rows = _fin_rows_for_ticker(tk, pt)[:lim]
            except Exception as e:
                return f"Financials store error for {tk}: {e!s:.140}"
            if not rows:
                return (f"No stored financial history for {tk}. Use get_financials for "
                        f"the latest filing, or sync the Financials store first.")
            keep = ("fy", "fp", "period_end", "derived", "revenue", "gross_margin",
                    "operating_income", "operating_margin", "net_income", "net_margin",
                    "comprehensive_income", "other_comprehensive_income", "diluted_eps",
                    "operating_cash_flow", "free_cash_flow", "cash", "total_debt",
                    "total_assets", "stockholders_equity")
            def _slim(r):
                out = {}
                for k in keep:
                    v = r.get(k)
                    if v is None:
                        continue
                    if k in ("fy", "fp", "derived"):
                        out[k] = v
                    elif hasattr(v, "isoformat"):
                        out[k] = v.isoformat()
                    else:
                        try: out[k] = round(float(v), 4)
                        except Exception: out[k] = v
                return out
            payload = {"ticker": tk, "entity": rows[0].get("entity_name"),
                       "period_type": pt,
                       "note": "$ absolute; margins are fractions; derived=Q4 (FY−Q1..Q3); source: SEC XBRL store",
                       "periods": [_slim(r) for r in rows]}
            return json.dumps(payload, default=str)[:9000]

        if name == "compute":
            expr = (args.get("expression") or "").strip()
            try:
                val = _safe_arith(expr)
                return json.dumps({"expression": expr, "result": val})
            except Exception as e:
                return f"compute error for {expr!r}: {e!s:.120}"

        if name == "get_ytd_attribution":
            want_tk = (args.get("ticker") or "").upper().strip()
            if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
                return "DB unavailable."
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT c.ytd_pct, c.result_json, f.short_name, f.name
                                 FROM managed_account_ytd_cache c
                                 JOIN funds f ON f.id = c.fund_id
                                WHERE f.status != 'closed'""")
                rows = cur.fetchall() or []
            if not rows:
                return "No reconciled YTD data available."
            out = []
            for r in rows:
                fund = r.get("short_name") or r.get("name") or "account"
                rj = r.get("result_json")
                try:
                    rj = json.loads(rj) if isinstance(rj, str) else (rj or {})
                except Exception:
                    rj = {}
                if not want_tk:
                    out.append({"fund": fund,
                                "ytd_pct": float(r["ytd_pct"]) if r.get("ytd_pct") is not None else None,
                                "method": "Modified Dietz"})
                else:
                    for a in (rj.get("attribution") or []):
                        if (a.get("ticker") or "").upper() == want_tk:
                            out.append({"fund": fund, "ticker": want_tk,
                                        "ticker_return_pct": a.get("ticker_return_pct"),
                                        "contribution_pct": a.get("contribution_pct"),
                                        "dollar_gain": a.get("dollar_gain")})
            if not out:
                return (f"No YTD attribution row for {want_tk}." if want_tk
                        else "No portfolio YTD figures found.")
            return json.dumps(out, default=str)[:4000]

        if name == "web_search":
            query = (args.get("query") or "").strip()
            if not query:
                return "Empty query."
            try:
                res = analyst.call_grok(
                    system_prompt="You are a financial research assistant. Answer the "
                                  "query using fresh web + X results. Be concise and "
                                  "cite sources/dates inline.",
                    user_content=query, live_search=True,
                )
                return (res or "")[:4000]
            except Exception as e:
                return f"web_search error: {e!s:.150}"

        if name == "list_transcripts":
            if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
                return "DB unavailable."
            _ensure_transcripts_tables()
            person = (args.get("person") or "").strip()
            tk = (args.get("ticker") or "").upper().strip()
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                if tk:
                    cur.execute("""
                        SELECT DISTINCT t.id, t.person, t.title, t.created_at
                          FROM transcripts t
                          JOIN transcript_entities e ON e.transcript_id = t.id
                         WHERE t.source='youtube' AND e.ticker = %s
                         ORDER BY t.created_at DESC LIMIT 60""", (tk,))
                elif person:
                    cur.execute("""SELECT id, person, title, created_at FROM transcripts
                                    WHERE source='youtube' AND person ILIKE %s
                                    ORDER BY created_at DESC LIMIT 60""", (f"%{person}%",))
                else:
                    cur.execute("""SELECT id, person, title, created_at FROM transcripts
                                    WHERE source='youtube' ORDER BY created_at DESC LIMIT 60""")
                rows = cur.fetchall() or []
                out = []
                for r in rows:
                    cur.execute("""SELECT company, ticker, sentiment FROM transcript_entities
                                    WHERE transcript_id = %s ORDER BY id LIMIT 25""", (r["id"],))
                    ents = cur.fetchall() or []
                    out.append({"id": r["id"], "person": r.get("person"),
                                "title": r.get("title"),
                                "date": r["created_at"].isoformat() if r.get("created_at") else None,
                                "companies": [{"company": e.get("company"), "ticker": e.get("ticker"),
                                               "sentiment": e.get("sentiment")} for e in ents]})
            if not out:
                return "No transcripts ingested yet."
            return json.dumps(out, default=str)[:6000]

        if name == "read_transcript":
            tid = (args.get("transcript_id") or "").strip()
            if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
                return "DB unavailable."
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT person, title, channel, summary, full_text
                                 FROM transcripts WHERE id = %s""", (tid,))
                t = cur.fetchone()
                if not t:
                    return f"No transcript with id {tid}."
                cur.execute("""SELECT company, ticker, sentiment, quote, theme
                                 FROM transcript_entities WHERE transcript_id = %s ORDER BY id""", (tid,))
                ents = cur.fetchall() or []
            return json.dumps({
                "person": t.get("person"), "title": t.get("title"),
                "channel": t.get("channel"), "summary": t.get("summary"),
                "entities": [dict(e) for e in ents],
                "full_text": (t.get("full_text") or "")[:9000],
            }, default=str)

        if name == "search_transcripts":
            query = (args.get("query") or "").strip()
            if not query:
                return "Empty query."
            if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
                return "DB unavailable."
            _ensure_transcripts_tables()
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""
                    SELECT id, person, title,
                           ts_headline('english', full_text,
                                       plainto_tsquery('english', %s),
                                       'MaxFragments=2,MinWords=8,MaxWords=28') AS snippet
                      FROM transcripts
                     WHERE source='youtube'
                       AND to_tsvector('english', coalesce(full_text,'')) @@ plainto_tsquery('english', %s)
                     ORDER BY created_at DESC LIMIT 8
                """, (query, query))
                rows = cur.fetchall() or []
            if not rows:
                return f"No transcript passages matched {query!r}."
            return json.dumps([{"id": r["id"], "person": r.get("person"),
                                "title": r.get("title"),
                                "snippet": re.sub(r"\s+", " ", (r.get("snippet") or "")).strip()}
                               for r in rows], default=str)[:6000]

        if name == "search_call_transcripts":
            tk = (args.get("ticker") or "").upper().strip()
            query = (args.get("query") or "").strip()
            if not tk or not query:
                return "Provide ticker and query."
            hits = _search_call_chunks(tk, query, k=int(args.get("k") or 6))
            if not hits:
                return (f"No indexed earnings-call passages for {tk}. "
                        f"It may not be synced yet — calls are indexed on demand.")
            return json.dumps({"ticker": tk, "passages": hits}, default=str)[:6000]

        return f"Unknown tool: {name}"
    except Exception as e:
        return f"Tool '{name}' error: {e!s:.200}"


def _agentic_verify(client, model: str, question: str, answer: str,
                     tool_log: list[dict]) -> dict:
    """Option B — verification pass. A second model call audits every numeric
    claim in the answer against the tool-call record. Returns
    {ok, verdict, flags:[...]}. Errors degrade gracefully to ok=None."""
    try:
        tools_used = json.dumps(tool_log, default=str)[:4000]
        sys = (
            "You are a meticulous fact-checker for a fund's research output. You are "
            "given a research QUESTION, the ANSWER produced by an analyst agent, and "
            "the TOOL CALLS that agent made to gather data. Your job: flag every "
            "numeric or factual claim in the ANSWER that is NOT directly supported by "
            "a tool call, or that CONTRADICTS one. Be strict — an unsupported price, "
            "multiple, return, or rating is a flag. Respond ONLY with compact JSON: "
            '{"verdict": "clean" | "flags", "flags": [{"claim": "...", "issue": '
            '"unsupported" | "contradicted", "note": "..."}]}. If everything is '
            'supported, return {"verdict":"clean","flags":[]}.'
        )
        user = (f"QUESTION:\n{question}\n\nANSWER:\n{answer}\n\n"
                f"TOOL CALLS (name + input the agent ran):\n{tools_used}")
        # max_tokens generous: a long strategist dossier can produce many
        # flags; 2000 was truncating mid-JSON → parse failure → "unchecked".
        resp = client.messages.create(
            model=model, max_tokens=6000,
            system=sys, messages=[{"role": "user", "content": user}],
        )
        text = next((b.text for b in resp.content
                     if getattr(b, "type", None) == "text"), "") or ""
        parsed = _extract_json_object(text)
        if parsed is None:
            print(f"⚠️ [agentic verify] no JSON in response: {text[:200]!r}", flush=True)
            return {"ok": None, "verdict": "unchecked", "flags": []}
        verdict = parsed.get("verdict") or "clean"
        flags = parsed.get("flags") or []
        if flags and verdict == "clean":
            verdict = "flags"   # model sometimes lists flags but forgets the verdict
        return {"ok": True, "verdict": verdict, "flags": flags}
    except Exception as e:
        print(f"⚠️ [agentic verify] failed: {e!s:.150}", flush=True)
        return {"ok": None, "verdict": "unchecked", "flags": []}


def _extract_json_object(text: str):
    """Pull the first balanced top-level JSON object out of a model response,
    tolerating code fences, leading prose, and trailing commentary. Returns a
    dict or None. Robust against the 'Verification did not run' failure where a
    strict json.loads() on the whole string throws on any surrounding text."""
    if not text:
        return None
    t = text.strip()
    # Strip a leading ```json / ``` fence if present.
    if t.startswith("```"):
        body = t.split("```", 2)
        t = (body[1] if len(body) > 1 else t).lstrip()
        if t[:4].lower() == "json":
            t = t[4:].lstrip()
    # Fast path: the whole thing is valid JSON.
    try:
        return json.loads(t)
    except Exception:
        pass
    # Scan for the first balanced {...}, respecting strings/escapes.
    start = t.find("{")
    while start != -1:
        depth, in_str, esc = 0, False, False
        for i in range(start, len(t)):
            c = t[i]
            if in_str:
                if esc:        esc = False
                elif c == "\\": esc = True
                elif c == '"':  in_str = False
            else:
                if c == '"':    in_str = True
                elif c == "{":  depth += 1
                elif c == "}":
                    depth -= 1
                    if depth == 0:
                        try:
                            return json.loads(t[start:i + 1])
                        except Exception:
                            break   # malformed; try next '{'
        start = t.find("{", start + 1)
    return None


_AGENTIC_SYSTEM_DEFAULT = (
    "You are a senior analyst at DGA Capital, a private fund. Answer the "
    "user's research question by calling tools to gather REAL data before "
    "drawing conclusions. Accuracy is paramount — this feeds investor-facing "
    "memos.\n\n"
    "TOOL DISCIPLINE (follow strictly):\n"
    "• Fundamentals (revenue, margins, EPS, debt, FCF): use get_financials — "
    "it's filing-accurate SEC XBRL. Never estimate these from memory.\n"
    "• ANY arithmetic (ratios, growth %, weighted avgs): use compute — never "
    "do mental math.\n"
    "• Portfolio / position returns: use get_ytd_attribution (real Modified "
    "Dietz). Never derive YTD from price changes.\n"
    "• Current price / daily move: get_quote. Sector: get_sector. Existing "
    "thesis: read_saved_report. Recent events: get_recent_news, then "
    "web_search if still uncovered.\n"
    "• Primary-source spoken word: search_call_transcripts for what MANAGEMENT "
    "said on earnings calls (margins, guidance, demand) — quote it. "
    "list_transcripts / read_transcript / search_transcripts for ingested "
    "interviews & keynotes (e.g. a CEO naming suppliers or trends). When a "
    "question is about what someone SAID, check these before the open web.\n"
    "• Specific named accounts/portfolios (e.g. a client's IRA vs. taxable): "
    "call list_portfolios FIRST for the exact account names, then "
    "get_portfolio_holdings for each — positions, weights, sectors, unrealized "
    "P&L. Use these to diagnose allocation, concentration, and risk/return.\n"
    "• NEVER invent a price, multiple, rating, sector, or return — call the "
    "tool. Cite the specific numbers you pulled and their source.\n\n"
    "TARGET SLEEVE: When you propose a TARGET SECTOR ALLOCATION (optimizing or "
    "rebalancing a portfolio), END your answer with a fenced code block tagged "
    "`sleeve` containing a JSON object with `weights` (sector→target weight % "
    "summing to ~100) and, when rebalancing a SPECIFIC account, `basket_size` "
    "set to THAT account's total market value (the total_market_value from "
    "get_portfolio_holdings) and `account` its name — so the Builder produces a "
    "TRUE rebalance at the real account size, not a generic $1M. Use EXACTLY "
    "these sector names: Technology, Financials, Healthcare, Energy, Industrials, "
    "Consumer Cyclical, Consumer Defensive, Utilities, Real Estate, "
    "Communication Services, Basic Materials. Example:\n"
    "```sleeve\n"
    '{"account": "ANAT IRA", "basket_size": 2750000, "weights": {"Technology": '
    '30, "Healthcare": 20, "Financials": 15, "Industrials": 15, "Consumer '
    'Defensive": 12, "Utilities": 8}}\n'
    "```\n"
    "The app turns that block into a one-click 'Build in Builder' button "
    "(pre-filled with the account's size), so always include it when "
    "recommending an allocation.\n\n"
    "Be concise and decisive: lead with the answer, then the evidence. This "
    "is internal analysis, not investment advice."
)


@_ddl_once
def _ensure_strategist_reviews_table() -> None:
    """Persist full Portfolio Strategist committee reviews so they survive
    Railway redeploys (the live job dict is in-memory and wiped on restart)."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS strategist_reviews (
                    id           TEXT PRIMARY KEY,
                    fund_id      TEXT,
                    fund_name    TEXT,
                    tickers      TEXT,
                    question     TEXT,
                    answer       TEXT,
                    verification JSONB,
                    cost_usd     NUMERIC,
                    model        TEXT,
                    generated_by TEXT,
                    generated_at TIMESTAMPTZ NOT NULL DEFAULT now()
                )
            """)
            cur.execute("CREATE INDEX IF NOT EXISTS strategist_reviews_gen_idx ON strategist_reviews(generated_at DESC)")
            conn.commit()
    except Exception as e:
        print(f"❌ _ensure_strategist_reviews_table: {e!s:.200}", flush=True)


def _persist_strategist_review(job_id: str, job: dict, answer: str,
                                verification: dict, cost_usd: float, model: str) -> None:
    """Insert one completed strategist review. Best-effort, never raises."""
    _ensure_strategist_reviews_table()
    try:
        tickers = ", ".join(job.get("tickers") or [])[:600]
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                INSERT INTO strategist_reviews
                    (id, fund_id, fund_name, tickers, question, answer,
                     verification, cost_usd, model, generated_by)
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                ON CONFLICT (id) DO NOTHING
            """, (job_id, job.get("fund_id"), job.get("fund_name"), tickers,
                  (job.get("question") or "")[:4000], answer or "",
                  json.dumps(verification or {}), cost_usd, model,
                  job.get("generated_by") or "gp"))
            conn.commit()
        print(f"🧭 [strategist] persisted review {job_id} ({tickers[:60]})", flush=True)
    except Exception as e:
        print(f"⚠️ [strategist persist insert] {e!s:.150}", flush=True)


@_ddl_once
def _ensure_analyst_reviews_table() -> None:
    """Persist completed AI Analyst answers so they survive Railway redeploys
    (the in-memory _agentic_jobs dict is wiped on restart) and can be re-opened
    or printed to PDF later — same idea as strategist_reviews."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS analyst_reviews (
                    id           TEXT PRIMARY KEY,
                    source       TEXT NOT NULL DEFAULT 'analyst',
                    question     TEXT,
                    answer       TEXT,
                    verification JSONB,
                    tool_calls   JSONB,
                    cost_usd     NUMERIC,
                    model        TEXT,
                    generated_at TIMESTAMPTZ NOT NULL DEFAULT now()
                )
            """)
            cur.execute("CREATE INDEX IF NOT EXISTS analyst_reviews_gen_idx ON analyst_reviews(generated_at DESC)")
            conn.commit()
    except Exception as e:
        print(f"❌ _ensure_analyst_reviews_table: {e!s:.200}", flush=True)


def _persist_analyst_review(job_id: str, source: str, question: str, answer: str,
                             verification: dict, tool_calls: list,
                             cost_usd: float, model: str) -> None:
    """Insert one completed AI Analyst answer. Best-effort, never raises."""
    if not (answer or "").strip():
        return
    _ensure_analyst_reviews_table()
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                INSERT INTO analyst_reviews
                    (id, source, question, answer, verification, tool_calls, cost_usd, model)
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s)
                ON CONFLICT (id) DO NOTHING
            """, (job_id, (source or "analyst")[:40], (question or "")[:4000],
                  answer or "", json.dumps(verification or {}),
                  json.dumps(tool_calls or []), cost_usd, model))
            conn.commit()
        print(f"🗂 [analyst] persisted review {job_id}", flush=True)
    except Exception as e:
        print(f"⚠️ [analyst persist insert] {e!s:.150}", flush=True)


def _render_strategist_review_pdf(review: dict) -> bytes:
    """Render the FULL committee review (verbatim, not the concise LP memo) as a
    branded PDF using the memo renderer in research-memo mode."""
    fund = review.get("fund_name") or "Portfolio"
    date_str = (review.get("generated_at") or "")[:10]
    title = f"Investment Committee Review — {fund}"
    script = {
        "ticker": "STRATEGIST", "format": "research_memo", "episode_title": title,
        "tickers": [t.strip() for t in (review.get("tickers") or "").split(",") if t.strip()],
        "sections": [
            {"id": "analysis", "turns": [{"speaker": "opus", "text": review.get("answer") or ""}]},
        ],
    }
    return _render_dga_memo_pdf(script, "", fund, review.get("generated_at") or date_str)


def _run_agentic_analysis(job_id: str, question: str,
                           system_override: str | None = None,
                           tools: list | None = None) -> None:
    """Background worker: manual tool-use loop. Streams progress into
    _agentic_jobs[job_id] so the UI can poll. Tracks cost per turn.
    system_override lets specialized modes (Portfolio Strategist) swap the
    persona while reusing the same loop and verification. `tools` overrides the
    tool set — the Strategist drops list_portfolios/get_portfolio_holdings so the
    agent analyzes ONLY the provided book and never enumerates the whole firm."""
    import anthropic as _anthropic
    _tools = tools if tools is not None else _AGENTIC_TOOLS

    def _set(**kw):
        _agentic_jobs[job_id] = {**(_agentic_jobs.get(job_id) or {}), **kw,
                                  "updated_at": time.time()}

    _set(stage="queued", status="running", label="Starting…",
         started_at=time.time(), steps=0, tool_calls=[], cost_usd=0.0)
    try:
        client = _anthropic.Anthropic(api_key=analyst.get_claude_api_key(), timeout=120.0)
        model = _AGENTIC_MODEL
        think = _agentic_thinking_kwargs(model)
        system = system_override or _AGENTIC_SYSTEM_DEFAULT
        messages = [{"role": "user", "content": question}]
        total_cost = 0.0
        tool_log: list[dict] = []

        for step in range(_AGENTIC_MAX_STEPS):
            _set(stage="thinking", label=f"Reasoning (step {step+1}/{_AGENTIC_MAX_STEPS})…",
                 steps=step, tool_calls=tool_log[:], cost_usd=round(total_cost, 4))
            resp = client.messages.create(
                model=model, max_tokens=8000,
                system=system, tools=_tools, messages=messages,
                **think,
            )
            # cost accounting
            try:
                u = resp.usage
                total_cost += analyst.estimate_claude_cost(model, u.input_tokens, u.output_tokens)
            except Exception:
                pass

            if resp.stop_reason != "tool_use":
                final = next((b.text for b in resp.content if getattr(b, "type", None) == "text"), "")
                # Option B — verification pass: audit numeric claims vs tool log.
                _set(stage="verifying", label="🔍 Verifying claims against tool data…",
                     steps=step + 1, tool_calls=tool_log[:], cost_usd=round(total_cost, 4))
                verification = _agentic_verify(client, model, question, final, tool_log)
                try:
                    # the verify call is one more model turn — count its cost too
                    total_cost += 0.0  # _agentic_verify doesn't return usage; rough no-op
                except Exception:
                    pass
                _set(stage="done", status="done", label="✓ Analysis complete",
                     steps=step + 1, tool_calls=tool_log[:],
                     cost_usd=round(total_cost, 4),
                     result={"answer": final, "tool_calls": tool_log[:],
                             "cost_usd": round(total_cost, 4), "model": model,
                             "verification": verification})
                # Persist the completed review so it survives dyno restarts
                # (in-memory jobs do not) and can be re-opened / PDF'd later.
                try:
                    jr = _agentic_jobs.get(job_id) or {}
                    if jr.get("mode") == "strategist":
                        _persist_strategist_review(job_id, jr, final, verification,
                                                   round(total_cost, 4), model)
                    else:
                        _persist_analyst_review(job_id, jr.get("source") or "analyst",
                                                question, final, verification,
                                                tool_log[:], round(total_cost, 4), model)
                except Exception as _pe:
                    print(f"⚠️ [review persist] {_pe!s:.150}", flush=True)
                return

            # Execute every tool the model requested this turn
            messages.append({"role": "assistant", "content": resp.content})
            results = []
            for b in resp.content:
                if getattr(b, "type", None) == "tool_use":
                    label = f"{b.name}({json.dumps(b.input, default=str)[:60]})"
                    tool_log.append({"tool": b.name, "input": b.input})
                    _set(stage="tool", label=f"🔧 {label}",
                         steps=step, tool_calls=tool_log[:],
                         cost_usd=round(total_cost, 4))
                    out = _agentic_exec_tool(b.name, b.input or {})
                    results.append({"type": "tool_result", "tool_use_id": b.id,
                                    "content": out})
            messages.append({"role": "user", "content": results})

        # Hit the step cap without a final answer
        _set(stage="error", status="error",
             label=f"❌ Reached {_AGENTIC_MAX_STEPS}-step limit without finishing",
             error="step_limit", cost_usd=round(total_cost, 4))
    except Exception as e:
        print(f"❌ [agentic {job_id}] failed: {e!s:.500}", flush=True)
        _set(stage="error", status="error", label=f"❌ {e!s:.200}", error=str(e))


@app.post("/api/research/agentic")
def research_agentic_start(req: Request, background_tasks: BackgroundTasks):
    if _request_is_demo(req):
        s = _kv_get("demo.samples.agentic") or {}
        _agentic_jobs["demo-agentic"] = {
            "stage": "done", "status": "done", "label": "Demo sample answer",
            "started_at": time.time(), "updated_at": time.time(), "steps": 1,
            "tool_calls": [], "cost_usd": 0.0,
            "result": {"markdown": s.get("markdown") or "*demo*"},
            "markdown": s.get("markdown") or "*demo*",
        }
        return {"ok": True, "job_id": "demo-agentic"}
    """Kick off an agentic research run. Body: {question: str}.
    Returns {ok, job_id}; poll GET /api/research/agentic/{job_id}."""
    claims = _claims_or_401(req)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    try:
        body = _request_json_sync(req)
    except Exception:
        body = {}
    question = ((body or {}).get("question") or "").strip()
    if len(question) < 4:
        return JSONResponse({"ok": False, "error": "Ask a real question."}, status_code=400)
    if len(question) > 2000:
        question = question[:2000]
    # source tags where the run came from ('analyst' = main Research card,
    # 'transcript' = transcript-scoped) so each list shows only its own.
    source = ((body or {}).get("source") or "analyst").strip()[:40] or "analyst"
    import uuid as _uuid
    job_id = "AGENTIC_" + _uuid.uuid4().hex[:12]
    _agentic_jobs[job_id] = {"stage": "queued", "status": "running",
                              "label": "Queued…", "started_at": time.time(),
                              "updated_at": time.time(), "question": question,
                              "source": source,
                              "steps": 0, "tool_calls": [], "cost_usd": 0.0}
    background_tasks.add_task(_run_agentic_analysis, job_id, question)
    print(f"🤖 [agentic] queued {job_id}: {question[:80]!r}  model={_AGENTIC_MODEL}", flush=True)
    return {"ok": True, "job_id": job_id, "model": _AGENTIC_MODEL}


@app.get("/api/research/agentic/{job_id}")
def research_agentic_status(job_id: str, request: Request):
    """Poll an agentic run. Returns live stage/label/tool_calls + final result."""
    _claims_or_401(request)
    job = _agentic_jobs.get(job_id)
    if not job:
        return JSONResponse({"ok": False, "stage": "idle", "error": "no such job"},
                            status_code=404)
    return {"ok": True, **job}


@app.get("/api/models/check")
def models_check(request: Request):
    """Diagnostic: list available Claude models, confirm the configured
    AGENTIC_MODEL is present, and ping it with a tiny call to prove it works.
    GP-only. Use this to verify opus-4-8 is live before relying on it."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    import anthropic as _anthropic
    out = {"ok": True, "configured_agentic_model": _AGENTIC_MODEL}
    try:
        client = _anthropic.Anthropic(api_key=analyst.get_claude_api_key(), timeout=120.0)
    except Exception as e:
        return {"ok": False, "error": f"client init failed: {e!s:.150}"}
    # 1. list models
    try:
        ids = [m.id for m in client.models.list()]
        out["available_models"] = ids
        out["agentic_model_in_list"] = _AGENTIC_MODEL in ids
    except Exception as e:
        out["list_error"] = str(e)[:200]
        out["available_models"] = []
        out["agentic_model_in_list"] = None
    # 2. ping the configured model with a 1-token call
    try:
        ping = client.messages.create(
            model=_AGENTIC_MODEL, max_tokens=8,
            messages=[{"role": "user", "content": "Reply with the single word: ok"}],
        )
        txt = next((b.text for b in ping.content if getattr(b, "type", None) == "text"), "")
        out["ping_ok"] = True
        out["ping_reply"] = (txt or "").strip()[:40]
        out["ping_resolved_model"] = getattr(ping, "model", None)
    except Exception as e:
        out["ping_ok"] = False
        out["ping_error"] = str(e)[:300]
    return out


_LP_MEMO_SYSTEM = (
    "You are an investment writer producing a CONFIDENTIAL, LP-facing investment "
    "memorandum for DGA Capital, a private fund. Convert the analyst material "
    "below into a polished, DRY, institutional memo in the register of a Goldman "
    "Sachs / Morgan Stanley research note. NO personas, NO dialogue, NO first "
    "person, NO 'I think'. Third-person, factual, decision-oriented.\n\n"
    "Output GitHub-flavored MARKDOWN with EXACTLY these sections, in this order:\n\n"
    "## Executive Summary\n"
    "2–4 sentences: the Fund's overall stance and the single most important action.\n\n"
    "## Positions\n"
    "A markdown table with these exact columns:\n"
    "| Position | Weight | Thesis | View | Action |\n"
    "- Position: ticker (add the company name if known)\n"
    "- Weight: the portfolio weight if the source states one, else —\n"
    "- Thesis: one concise clause on WHY the Fund holds it\n"
    "- View: the current analytical read — synthesize the bull and bear cases "
    "into ONE neutral, informational sentence (no he-said/she-said)\n"
    "- Action: exactly one of Hold / Add / Trim / Exit / Under review\n"
    "Include every position discussed in the source.\n\n"
    "## Portfolio Actions\n"
    "Bullet list of the SPECIFIC changes the Fund is making or evaluating "
    "(sizing changes, initiations, exits, hedges), each with a one-line rationale. "
    "If the source implies no changes, say so explicitly.\n\n"
    "## Key Risks\n"
    "3–5 concise bullets.\n\n"
    "HARD RULES: Never fabricate tickers, weights, prices, or numbers that are "
    "not in the source — use — when unknown. Keep every cell short and skimmable. "
    "Do NOT append a disclaimer (the document template adds one)."
)


def _synthesize_lp_memo(source_text: str, fund_name: str | None = None) -> str:
    """Processing step: rewrite raw analyst material into a structured LP memo
    (exec summary + per-position table + actions + risks) via Claude. Falls back
    to the original text if the model call fails, so a memo always renders."""
    import anthropic as _anthropic
    try:
        client = _anthropic.Anthropic(api_key=analyst.get_claude_api_key(), timeout=120.0)
    except Exception:
        return source_text
    ctx = (f"FUND: {fund_name}\n\n" if fund_name else "")
    user = ctx + "ANALYST MATERIAL TO CONVERT INTO THE MEMO:\n\n" + (source_text or "")[:30000]
    for mdl in (_AGENTIC_MODEL, _TRANSCRIPT_EXTRACT_MODEL):
        try:
            resp = client.messages.create(
                model=mdl, max_tokens=4000,
                system=_LP_MEMO_SYSTEM,
                messages=[{"role": "user", "content": user}],
            )
            txt = next((b.text for b in resp.content
                        if getattr(b, "type", None) == "text"), "") or ""
            if txt.strip() and "## " in txt:
                return txt.strip()
        except Exception as e:
            print(f"⚠️ [lp memo synth] {mdl} failed: {e!s:.150}", flush=True)
            continue
    return source_text


@app.post("/api/memos/from-analysis")
def memo_from_analysis(request: Request):
    """Option D handoff — turn an AI Analyst / Strategist answer into a DGA
    Capital LP memo PDF, saved to the Memos tab. Body: {question, answer,
    title?, assigned_fund_id?, gp_memo?, lp_memo?}. When lp_memo (default True),
    the raw analysis is RE-PROCESSED into a structured institutional memo
    (per-position table + actions + risks) before rendering."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    _ensure_dga_memos_table()
    try:
        body = _request_json_sync(request)
    except Exception:
        body = {}
    question = ((body or {}).get("question") or "").strip()
    answer   = ((body or {}).get("answer") or "").strip()
    if not answer:
        raise HTTPException(422, "No analysis text to convert")
    title = ((body or {}).get("title") or "").strip() or (
        (question[:70] + "…") if len(question) > 70 else question) or "Research Memo"
    assigned_fund_id = (body or {}).get("assigned_fund_id") or None
    gp_memo = ((body or {}).get("gp_memo") or "").strip()
    lp_memo = bool((body or {}).get("lp_memo", True))

    fund_name = _fund_name_lookup(assigned_fund_id)
    # Processing step — convert the conversational/raw analysis into a dry,
    # LP-grade institutional memo with a position table + actions.
    body_text = _synthesize_lp_memo(answer, fund_name) if lp_memo else answer

    # Synthesize a script dict the memo renderer understands: the question
    # becomes a small focus line, the processed body becomes the memo body.
    script = {
        "ticker": "ANALYSIS",
        "format": "research_memo",
        "episode_title": title,
        "sections": [
            {"id": "research_question",
             "turns": [{"speaker": "opus", "text": question or "Research question"}]},
            {"id": "analysis",
             "turns": [{"speaker": "opus", "text": body_text}]},
        ],
    }
    from datetime import datetime as _dt, timezone as _tz
    gen_iso = _dt.now(_tz.utc).isoformat()
    try:
        pdf_bytes = _render_dga_memo_pdf(script, gp_memo, fund_name, gen_iso)
    except Exception as e:
        raise HTTPException(500, f"PDF render failed: {e!s:.200}")
    import uuid as _uuid
    memo_id = str(_uuid.uuid4())
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                INSERT INTO dga_memos
                   (id, source_job_key, source_format, episode_title,
                    assigned_fund_id, gp_memo, script_json,
                    pdf_bytes, generated_by, generated_at)
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, now())
            """, (
                memo_id, "ai_analyst", "research_memo", title,
                assigned_fund_id, gp_memo or None,
                json.dumps(script), psycopg2.Binary(pdf_bytes),
                claims.get("email") or claims.get("lp_id") or "gp",
            ))
            conn.commit()
        print(f"📄 [memo-from-analysis] saved {memo_id} '{title[:50]}'", flush=True)
    except Exception as e:
        raise HTTPException(500, f"DB insert failed: {e!s:.200}")
    return {"ok": True, "memo_id": memo_id, "episode_title": title,
            "pdf_url": f"/api/memos/{memo_id}/pdf"}


# ═══════════════════════════════════════════════════════════════════════
# PORTFOLIO STRATEGIST — agentic cross-book analysis. Reuses the agentic
# loop + tools + verification, but with a portfolio persona and a
# pre-loaded book (real positions + weights + per-name upside from saved
# reports + reconciled YTD). Grounded + advisory: it reasons across the
# whole portfolio and proposes adjustments, grounding EV in the calculator.
# Hands off to the Portfolio Roundup podcast + strategy memo.
# ═══════════════════════════════════════════════════════════════════════
def _load_fund_positions_valued(fund_id: str) -> list[dict]:
    """[{ticker, mv}] for a fund's live book (market value from tax_lots, cash
    excluded). The market value lets multiple accounts be combined correctly."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return []
    rows = []
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""
                SELECT s.symbol, s.asset_class, SUM(tl.quantity) AS qty
                  FROM tax_lots tl
                  JOIN securities s ON s.id = tl.security_id
                 WHERE tl.fund_id::text = %s AND tl.closed_at IS NULL
                   AND tl.quantity > 0 AND s.asset_class != 'cash'
                 GROUP BY s.symbol, s.asset_class
            """, (str(fund_id),))
            rows = cur.fetchall() or []
    except Exception as e:
        print(f"⚠️ _load_fund_positions failed: {e!s:.150}", flush=True)
        return []
    syms = [r["symbol"] for r in rows if r.get("symbol")]
    if not syms:
        return []
    prices = _fetch_prices(syms)
    valued = []
    for r in rows:
        sym = r["symbol"]; qty = float(r.get("qty") or 0)
        px = float((prices.get(sym) or {}).get("price") or 0) if isinstance(prices.get(sym), dict) else float(prices.get(sym) or 0)
        mv = qty * px
        if mv > 0:
            valued.append({"ticker": sym.upper(), "mv": mv})
    return valued


def _positions_from_valued(valued: list[dict]) -> list[dict]:
    """[{ticker, mv}] → [{ticker, weight_pct}] on the combined total, sorted."""
    total = sum(v["mv"] for v in valued) or 1.0
    return [{"ticker": v["ticker"], "weight_pct": round(v["mv"] / total * 100, 2)}
            for v in sorted(valued, key=lambda x: -x["mv"])]


def _load_fund_positions(fund_id: str) -> list[dict]:
    """[{ticker, weight_pct}] for one fund's live book (market-value weights)."""
    return _positions_from_valued(_load_fund_positions_valued(fund_id))


def _combine_fund_positions(fund_ids: list[str]) -> list[dict]:
    """Combine several accounts into ONE book: aggregate each ticker's market
    value across all funds, then weight on the combined total (so e.g. ANAT-IRA +
    ANAT-DEF are analyzed as a single portfolio)."""
    agg: dict[str, float] = {}
    for fid in fund_ids:
        for v in _load_fund_positions_valued(fid):
            agg[v["ticker"]] = agg.get(v["ticker"], 0.0) + v["mv"]
    return _positions_from_valued([{"ticker": tk, "mv": mv} for tk, mv in agg.items()])


def _build_strategist_context(positions: list[dict], fund_name: str | None) -> str:
    """Enrich positions with per-name upside/rating (saved reports), sector,
    and produce a grounded context block for the strategist prompt."""
    tickers = [p["ticker"] for p in positions if p.get("ticker")]
    reports = {}
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL") and tickers:
        try:
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT ticker, rating, upside_pct, price_target
                                 FROM analyst_reports WHERE ticker = ANY(%s)""",
                            (tickers,))
                for r in cur.fetchall() or []:
                    reports[r["ticker"].upper()] = r
        except Exception:
            pass
    lines = []
    ev_terms = []
    for p in positions:
        tk = p["ticker"]; w = float(p.get("weight_pct") or 0)
        rep = reports.get(tk) or {}
        up = rep.get("upside_pct")
        rating = rep.get("rating") or "—"
        has_report = tk in reports
        if up is not None:
            ev_terms.append(w / 100.0 * float(up))
        lines.append(
            f"  {tk:<7} {w:5.1f}%  rating={rating:<10} "
            f"upside={'%+.1f%%' % float(up) if up is not None else 'n/a':<8} "
            f"{'[has saved report]' if has_report else '[NO report]'}")
    mech_ev = sum(ev_terms) if ev_terms else None
    ctx = [
        f"PORTFOLIO ({fund_name or 'uploaded book'}) — {len(positions)} positions:",
        *lines,
    ]
    if mech_ev is not None:
        ctx.append(f"\nMechanical EV (Σ weight × report-upside, current weights): "
                   f"{mech_ev:+.2f}%-pts  — this is the baseline you reason against.")
    ctx.append("\nNote: 'upside' is from each name's saved DGA report. Names marked "
               "[NO report] have no thesis on file — flag that as a gap.")
    return "\n".join(ctx)


_STRATEGIST_SYSTEM = (
    "You are the Chief Investment Officer at DGA Capital running an investment-"
    "committee review of the WHOLE book below. Your job: cross-portfolio "
    "analysis and GROUNDED, ADVISORY adjustments to optimize expected value "
    "while controlling risk. This feeds an investor podcast + memo, so accuracy "
    "is paramount.\n\n"
    "Reason ACROSS positions — not name-by-name in isolation. Specifically surface "
    "what a mechanical optimizer is blind to: concentration (single-name + sector + "
    "factor), correlation / theme overlap (the 'illusion of breadth' — e.g. 6 names "
    "that are really one AI-capex trade), catalyst clustering, and wipeout scenarios.\n\n"
    "TOOL DISCIPLINE: use compute for ALL math (EV, weighted avgs, % deltas — never "
    "mental math); get_financials for any fundamental; get_ytd_attribution for real "
    "returns; read_saved_report to ground each name's thesis; get_recent_news / "
    "web_search for fresh catalysts. NEVER invent a number.\n\n"
    "Deliver a structured dossier with these sections, in order:\n"
    "1. SNAPSHOT — sector mix, top concentrations, real YTD (cite the tool).\n"
    "2. CONCENTRATION & CORRELATION X-RAY — where the book is secretly one bet.\n"
    "3. EXPECTED VALUE — the mechanical EV baseline (compute it), then your "
    "reasoned read: which high-EV suggestions to TAKE and which to VETO and why.\n"
    "4. SUGGESTED ADJUSTMENTS — specific trims/adds with sizing deltas "
    "(e.g. 'NVDA 12.4% → 9%') and, for each, the rationale AND what it funds. "
    "Advisory only — the GP decides.\n"
    "5. WIPEOUT SCENARIOS — 2-3 specific drawdown paths + rough probability.\n"
    "6. BOTTOM LINE — the single highest-conviction move this week.\n\n"
    "Be specific and decisive. Internal analysis, not investment advice."
)


@app.post("/api/research/portfolio-strategist")
def research_portfolio_strategist(req: Request, background_tasks: BackgroundTasks):
    """Kick off an agentic whole-portfolio analysis. Body one of:
      {fund_id: "..."}                      → one fund's live book, OR
      {fund_ids: ["...","..."]}             → SEVERAL accounts COMBINED into one
                                              book (e.g. ANAT-IRA + ANAT-DEF), OR
      {positions: [{ticker, weight_pct}]}   → an uploaded/explicit book
    The agent is scoped to EXACTLY this book (no list_portfolios /
    get_portfolio_holdings), so it never wanders onto the whole firm.
    Returns {ok, job_id, tickers, positions, fund_name}."""
    claims = _claims_or_401(req)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    try:
        body = _request_json_sync(req)
    except Exception:
        body = {}
    fund_id  = (body or {}).get("fund_id") or None
    fund_ids = [str(f) for f in ((body or {}).get("fund_ids") or []) if f]
    if not fund_ids and fund_id:
        fund_ids = [str(fund_id)]
    positions = (body or {}).get("positions") or []
    fund_name = None

    if fund_ids:
        if len(fund_ids) == 1:
            positions = _load_fund_positions(fund_ids[0])
            fund_name = _fund_name_lookup(fund_ids[0])
        else:
            positions = _combine_fund_positions(fund_ids)
            names = [(_fund_name_lookup(f) or f) for f in fund_ids]
            fund_name = " + ".join(names) + " (combined)"
        if not positions:
            return JSONResponse({"ok": False,
                                 "error": "No live positions for the selected account(s)."},
                                status_code=400)
    else:
        # Normalize uploaded/explicit positions
        norm = []
        for p in positions:
            tk = (p.get("ticker") or "").upper().strip()
            if not tk: continue
            norm.append({"ticker": tk, "weight_pct": round(float(p.get("weight_pct") or 0), 2)})
        positions = norm
    if len(positions) < 3:
        return JSONResponse({"ok": False, "error": "Need at least 3 positions."},
                            status_code=400)
    positions = positions[:40]
    tickers = [p["ticker"] for p in positions]

    context = _build_strategist_context(positions, fund_name)
    question = (
        f"Run a full investment-committee review of this book and propose grounded, "
        f"advisory adjustments to optimize expected value while controlling risk.\n\n"
        f"{context}\n\n"
        f"IMPORTANT SCOPE: the position list above is the COMPLETE and ONLY book to "
        f"review — analyze exactly these names as a single portfolio"
        f"{' (it combines multiple accounts)' if (fund_name or '').endswith('(combined)') else ''}. "
        f"Do NOT look up, list, or fold in any other account or holding.\n\n"
        f"Work through every section of your dossier. Use the tools to ground every "
        f"number — pull each name's saved report, compute the EV math, and surface "
        f"cross-portfolio risks the weights alone don't show."
    )
    # Strategist tool set: drop the firm-wide enumeration tools so the agent can't
    # pull other accounts — it must reason from the book provided above.
    _strat_tools = [t for t in _AGENTIC_TOOLS
                    if t.get("name") not in ("list_portfolios", "get_portfolio_holdings")]
    import uuid as _uuid
    job_id = "STRAT_" + _uuid.uuid4().hex[:12]
    _agentic_jobs[job_id] = {"stage": "queued", "status": "running",
                              "label": "Queued · portfolio review", "started_at": time.time(),
                              "updated_at": time.time(), "question": question,
                              "steps": 0, "tool_calls": [], "cost_usd": 0.0,
                              "mode": "strategist", "positions": positions,
                              "tickers": tickers, "fund_name": fund_name,
                              "fund_id": fund_id,
                              "generated_by": claims.get("email") or claims.get("lp_id") or "gp"}
    background_tasks.add_task(_run_agentic_analysis, job_id, question, _STRATEGIST_SYSTEM, _strat_tools)
    print(f"🧭 [strategist] queued {job_id}  {len(tickers)} positions  fund={fund_name}", flush=True)
    return {"ok": True, "job_id": job_id, "tickers": tickers,
            "positions": positions, "fund_name": fund_name, "model": _AGENTIC_MODEL}


# ─────────────────────────────────────────────────────────────────────────────
#  Quarterly Letter — narrative LP/colleague memo built on the Strategist engine.
#  Phase 2: generate a draft from real YTD performance + SnapTrade activity +
#  saved research theses. The GP edits it and adds a manual note; drafts persist.
# ─────────────────────────────────────────────────────────────────────────────
def _quarterly_activity_context(fund_ids: list[str] | None, year: int) -> str:
    """Text block of YTD buys/sells/exits + realized gains, built from the stored
    transaction-aware ATTRIBUTION (managed_account_ytd_cache.result_json) — i.e. the
    authoritative Fidelity Activity-CSV parse, not the gated SnapTrade API. Aggregates
    per ticker across the funds in scope."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")) or not fund_ids:
        return "(No YTD attribution available — upload each account's YTD CSVs.)"
    agg, funds_with_data = {}, 0
    FIELDS = ("sold_sh", "proceeds", "bought_sh", "buy_cost", "reinv",
              "div", "end_val", "end_sh", "start_sh", "gain")
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("SELECT fund_id, result_json FROM managed_account_ytd_cache WHERE fund_id = ANY(%s)",
                        ([str(f) for f in fund_ids],))
            for r in cur.fetchall():
                rj = r["result_json"]
                if isinstance(rj, str):
                    try: rj = json.loads(rj)
                    except Exception: rj = {}
                attr = (rj or {}).get("attribution") or []
                if attr:
                    funds_with_data += 1
                for a in attr:
                    tk = (a.get("ticker") or "").upper().strip()
                    if not tk:
                        continue
                    e = agg.setdefault(tk, {k: 0.0 for k in FIELDS})
                    e["sold_sh"]   += a.get("total_sold_shares")   or 0
                    e["proceeds"]  += a.get("total_sell_proceeds") or 0
                    e["bought_sh"] += a.get("total_bought_shares") or 0
                    e["buy_cost"]  += a.get("total_buy_cost")      or 0
                    e["reinv"]     += a.get("reinvestment_cost")   or 0
                    e["div"]       += a.get("dividends_cash")      or 0
                    e["end_val"]   += a.get("end_value")           or 0
                    e["end_sh"]    += a.get("end_shares")          or 0
                    e["start_sh"]  += a.get("start_shares")        or 0
                    e["gain"]      += a.get("dollar_gain")         or 0
    except Exception as e:
        return f"(Attribution lookup failed: {e!s:.120})"
    if not agg:
        return ("(No YTD attribution on file for these funds. Upload each managed "
                "account's YTD Positions + Activity CSVs so the letter can cite real trades.)")
    bought = [(tk, e, e["start_sh"] < 1e-6) for tk, e in agg.items() if e["bought_sh"] > 1e-6]
    exited = [(tk, e) for tk, e in agg.items() if e["sold_sh"] > 1e-6 and e["end_sh"] < 1e-6]
    trimmed = [(tk, e) for tk, e in agg.items() if e["sold_sh"] > 1e-6 and e["end_sh"] >= 1e-6]
    winners = sorted(((tk, e["gain"]) for tk, e in agg.items()), key=lambda x: -x[1])
    lines = [f"YTD TRADES & ATTRIBUTION ({year}) — authoritative, from uploaded Fidelity CSVs, {funds_with_data} fund(s).",
             "This is the COMPLETE record of what we did this year. Cover every name below."]
    # Exits FIRST and in FULL (never truncate — these are the 'why did we sell' names).
    if exited:
        lines.append("  POSITIONS FULLY EXITED this year (sold out — no longer held):")
        for tk, e in sorted(exited, key=lambda x: -x[1]["proceeds"]):
            lines.append(f"    {tk:<7} sold {e['sold_sh']:.2f} sh for ~${e['proceeds']:,.0f}; realized YTD P&L ${e['gain']:+,.0f}")
    if trimmed:
        lines.append("  POSITIONS TRIMMED (partial sales, still held):")
        for tk, e in sorted(trimmed, key=lambda x: -x[1]["proceeds"]):
            lines.append(f"    {tk:<7} sold {e['sold_sh']:.2f} sh for ~${e['proceeds']:,.0f}; still hold ${e['end_val']:,.0f}; YTD P&L ${e['gain']:+,.0f}")
    if bought:
        lines.append("  BOUGHT / ADDED:")
        for tk, e, new in sorted(bought, key=lambda x: -x[1]["buy_cost"])[:20]:
            lines.append(f"    {tk:<7} bought {e['bought_sh']:.2f} sh for ~${e['buy_cost']:,.0f}  "
                         f"{'[NEW position]' if new else '[added to existing]'}  (now ${e['end_val']:,.0f})")
    if winners:
        top = winners[:5]
        bot = [w for w in winners if w[1] < 0][-5:]
        lines.append("  Top YTD contributors: " + ", ".join(f"{tk} ${g:+,.0f}" for tk, g in top))
        if bot:
            lines.append("  Top detractors: " + ", ".join(f"{tk} ${g:+,.0f}" for tk, g in sorted(bot, key=lambda x: x[1])))
    if not (exited or trimmed or bought):
        lines.append("  (No buys or sells recorded YTD — if that's wrong, re-run this fund's YTD with its Activity CSV.)")
    return "\n".join(lines)


