@app.get("/api/research/strategist/reviews/{review_id}/pdf")
def strategist_review_pdf(review_id: str, request: Request):
    """Render the FULL committee review as a branded, printable PDF and stream
    it inline (browser viewer = print/save). Also archives a copy to the
    Dropbox app folder under /Committee Reviews/."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""SELECT id, fund_name, tickers, answer, generated_at
                             FROM strategist_reviews WHERE id = %s""", (review_id,))
            r = cur.fetchone()
        if not r:
            raise HTTPException(404, "Review not found")
        review = {"fund_name": r.get("fund_name"), "tickers": r.get("tickers"),
                  "answer": r.get("answer"),
                  "generated_at": r["generated_at"].isoformat() if r.get("generated_at") else ""}
        pdf = _render_strategist_review_pdf(review)
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(500, f"PDF render failed: {e!s:.200}")
    fund = (r.get("fund_name") or "Portfolio").replace("/", "_")
    date_str = (review["generated_at"] or "")[:10]
    fname = f"IC-Review_{fund}_{date_str}.pdf".replace(" ", "_")
    # Best-effort archive to Dropbox /Committee Reviews/
    try:
        dbx = analyst._dropbox_client()
        if dbx:
            import dropbox as _dx
            folder = (analyst._dropbox_folder() or "")
            path = f"{folder}/Committee Reviews/{fname}"
            dbx.files_upload(pdf, path, mode=_dx.files.WriteMode.overwrite)
    except Exception as _be:
        print(f"⚠️ [IC review dropbox archive] {_be!s:.120}", flush=True)
    from fastapi.responses import Response as _Response
    return _Response(content=pdf, media_type="application/pdf",
                     headers={"Content-Disposition": _content_disposition("inline", fname)})


# ── Research → PDF / email (View-identical, DGA Capital template) ──────────────
# The client renders the answer with _dgaMarkdown into `.md-rendered` HTML — the
# exact markup shown on screen. It POSTs that HTML here; we wrap it in the DGA
# Capital letterhead and render with xhtml2pdf. Shared by the AI Analyst, the
# Portfolio Strategist, and the Transcripts Q&A.
def _md_table_colgroup(ncols: int) -> str:
    """Explicit column widths (first column a bit wider for labels). Widths are
    ABSOLUTE points, not percentages: with the embedded DejaVu Sans font,
    xhtml2pdf miscomputes percentage column widths and the columns overlap, but
    absolute widths render cleanly. Sized to the Letter content width (612pt −
    ~1.5cm margins each side ≈ 524pt)."""
    if ncols <= 1:
        return ""
    content_w  = 524.0
    first_frac = 0.40 if ncols >= 3 else 0.50
    first_w    = first_frac * content_w
    rest_w     = (content_w - first_w) / (ncols - 1)
    cols = ['<col width="%dpt"/>' % round(first_w)] + \
           ['<col width="%dpt"/>' % round(rest_w)] * (ncols - 1)
    return "<colgroup>" + "".join(cols) + "</colgroup>"


def _fix_md_table_widths(html: str) -> str:
    """xhtml2pdf corrupts markdown tables (columns overlap, numbers collide).
    Two root causes, both fixed per `.md-table`:
      1. An EMPTY cell (<td></td>) collapses the WHOLE table's column widths —
         fill empties with &nbsp; so every cell has width.
      2. xhtml2pdf's auto column-sizing hogs column 1 and overlaps the rest —
         strip <thead>/<tbody> (they block colgroup widths) and inject an
         explicit <colgroup> with absolute point widths."""
    def _repl(m):
        table = m.group(0)
        # 1. fill empty cells
        table = re.sub(r"<(td|th)([^>]*)>\s*</\1>", r"<\1\2>&nbsp;</\1>",
                       table, flags=re.IGNORECASE)
        fr = re.search(r"<tr\b[^>]*>(.*?)</tr>", table, re.DOTALL | re.IGNORECASE)
        if not fr:
            return table
        ncols = len(re.findall(r"<t[hd]\b", fr.group(1), re.IGNORECASE))
        if ncols < 2:
            return table
        # 2. strip thead/tbody + inject colgroup
        table = re.sub(r"</?(thead|tbody)\b[^>]*>", "", table, flags=re.IGNORECASE)
        if "<colgroup" not in table.lower():
            table = re.sub(r"(<table\b[^>]*>)",
                           lambda mm: mm.group(1) + _md_table_colgroup(ncols),
                           table, count=1)
        return table
    return re.sub(r'<table class="md-table">.*?</table>', _repl, html or "",
                  flags=re.DOTALL | re.IGNORECASE)


def _dga_research_pdf_html(title: str, question: str, answer_html: str,
                           stamp: str = "") -> str:
    """Wrap client-rendered `.md-rendered` HTML in the DGA Capital PDF template.

    CSS is written for xhtml2pdf (pure-Python, builds on reportlab — no native
    libraries, so it renders on Railway where WeasyPrint's pango/cairo are not
    installed). The subset used here (tables, borders, backgrounds, @frame
    footer, pagenumber) renders essentially identical to the on-screen View."""
    import html as _html
    from datetime import datetime as _dt
    if not stamp:
        try:
            stamp = _dt.now().strftime("%B %d, %Y · %-I:%M %p")
        except Exception:
            stamp = _dt.now().strftime("%B %d, %Y")
    # Subtitle next to the logo. The AI Analyst PDFs/emails show the logo ONLY
    # (no "Analyst" label, per request); other docs (e.g. the Portfolio
    # Strategist's "Investment Committee Review") keep their subtitle.
    sub_raw = (title or "")
    if sub_raw.strip().lower() in ("ai analyst", "analyst", ""):
        sub_raw = ""
    title_e = _html.escape(sub_raw)
    q_e     = _html.escape(question or "")
    logo    = _dga_logo_data_uri()
    css = """
      @font-face { font-family: "DejaVuSans"; src: url(DejaVuSans.ttf); }
      @font-face { font-family: "DejaVuSans"; src: url(DejaVuSans-Bold.ttf); font-weight: bold; }
      @font-face { font-family: "DejaVuSans"; src: url(DejaVuSans-Oblique.ttf); font-style: italic; }
      @font-face { font-family: "DejaVuSans"; src: url(DejaVuSans-BoldOblique.ttf); font-weight: bold; font-style: italic; }
      @page { size: letter; margin: 1.6cm 1.5cm 2.1cm;
        @frame footer_frame { -pdf-frame-content: footerContent;
                              bottom: 1cm; margin-left: 1.5cm; margin-right: 1.5cm; height: 1cm; } }
      body { font-family: "DejaVuSans"; font-size: 8.5pt; line-height: 1.5; color: #0A1628; }
      table.lh { width: 100%; border-bottom: 2px solid #0A1628; margin-bottom: 12pt; }
      table.lh td { padding-bottom: 7pt; vertical-align: middle; }
      .sub { color: #5BB8D4; font-size: 8pt; font-weight: bold; }
      .stamp { text-align: right; font-size: 7pt; color: #64748b; }
      .q { font-weight: bold; font-size: 8.5pt; color: #0A1628; margin-bottom: 12pt;
           padding: 8pt 10pt; background-color: #f1f5f9; border-left: 3pt solid #5BB8D4; }
      .md-rendered .md-h { font-weight: bold; color: #0A1628; }
      .md-rendered .md-h1, .md-rendered .md-h2 { font-size: 10.5pt; margin-top: 13pt;
           margin-bottom: 4pt; border-bottom: 1px solid #e2e8f0; padding-bottom: 2pt; }
      .md-rendered .md-h3, .md-rendered .md-h4 { font-size: 9pt; color: #334155;
           margin-top: 10pt; margin-bottom: 4pt; }
      .md-rendered p { margin-top: 0; margin-bottom: 7pt; }
      .md-rendered ul.md-list, .md-rendered ol.md-list { margin-top: 4pt; margin-bottom: 8pt; }
      .md-rendered li { margin-bottom: 3pt; }
      .md-rendered strong { font-weight: bold; color: #0A1628; }
      .md-rendered em { font-style: italic; }
      .md-rendered code { font-family: Courier; background-color: #f1f5f9; font-size: 7.5pt; }
      .md-rendered hr.md-hr { border: 0; border-top: 1px solid #cbd5e1; margin-top: 10pt; margin-bottom: 10pt; }
      .md-rendered a { color: #0A1628; }
      .md-rendered table.md-table { width: 100%; margin-top: 7pt; margin-bottom: 11pt;
           font-size: 8pt; }
      .md-rendered table.md-table th { background-color: #0A1628; color: #ffffff;
           text-align: left; padding: 5pt 8pt; font-weight: bold; font-size: 7pt; }
      .md-rendered table.md-table td { padding: 4pt 8pt; border-bottom: 1px solid #e2e8f0;
           color: #0A1628; }
      #footerContent { font-size: 6.5pt; color: #94a3b8; text-align: center; }
    """
    # Logo + subtitle in a nested table so the "· Analyst" label sits vertically
    # CENTERED against the logo (xhtml2pdf won't vertically align an inline image
    # with adjacent text, which left the label dangling at the logo's bottom).
    if logo and title_e:
        # Fixed-width nested table (NOT full width — that's what spread the logo
        # and label apart) so the label sits right beside the logo, centered.
        brand_block = (
            '<table style="width:188px;border:none;"><tr>'
            f'<td style="border:none;padding:0;vertical-align:middle;width:86px;">'
            f'<img src="{logo}" width="84" height="24" alt="DGA Capital" /></td>'
            f'<td style="border:none;padding:0 0 1px 0;vertical-align:middle;">'
            f'<span class="sub">&middot; {title_e}</span></td>'
            '</tr></table>')
    elif logo:
        brand_block = f'<img src="{logo}" width="84" height="24" alt="DGA Capital" />'
    else:
        brand_block = '<span style="font-size:12pt;font-weight:bold;color:#0A1628;">DGA CAPITAL</span>'
        if title_e:
            brand_block += f' <span class="sub">&middot; {title_e}</span>'
    head = (f'<table class="lh"><tr>'
            f'<td style="vertical-align:middle;">{brand_block}</td>'
            f'<td style="vertical-align:middle;"><div class="stamp">CONFIDENTIAL &middot; {_html.escape(stamp)}</div></td>'
            f'</tr></table>')
    qhtml = (f'<div class="q">{q_e}</div>') if q_e else ''
    footer = ('<div id="footerContent">DGA Capital &middot; Confidential — for the intended '
              'recipient only &middot; Page <pdf:pagenumber> of <pdf:pagecount></div>')
    return (f'<!doctype html><html><head><meta charset="utf-8">'
            f'<style>{css}</style></head><body>'
            f'{footer}{head}{qhtml}<div class="md-rendered">{_fix_md_table_widths(answer_html or "")}</div>'
            f'</body></html>')


_FONTS_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), "..", "assets", "fonts")

_DGA_LOGO_DATA_URI = None


def _dga_logo_data_uri() -> str:
    """The DGA Capital wordmark logo (branding/dga_logo_small.png) as a base64
    data URI — same asset the reportlab reports + HTML emails use, so the PDF
    letterhead is brand-consistent. Cached after first read."""
    global _DGA_LOGO_DATA_URI
    if _DGA_LOGO_DATA_URI is None:
        try:
            import base64 as _b64
            p = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                             "..", "branding", "dga_logo_small.png")
            with open(p, "rb") as f:
                _DGA_LOGO_DATA_URI = "data:image/png;base64," + _b64.b64encode(f.read()).decode("ascii")
        except Exception:
            _DGA_LOGO_DATA_URI = ""
    return _DGA_LOGO_DATA_URI


def _research_link_callback(uri, rel):
    """Resolve @font-face url() in the PDF template to the bundled font files, so
    xhtml2pdf embeds the full-Unicode DejaVu Sans face. (The standard base-14
    Helvetica renders em-dashes, non-breaking hyphens, smart quotes, arrows, …
    as black boxes — that was the 'worse than before' look.)"""
    try:
        p = os.path.join(_FONTS_DIR, os.path.basename(uri))
        if os.path.exists(p):
            return p
    except Exception:
        pass
    return uri


def _render_research_pdf(html_doc: str) -> bytes:
    """HTML → PDF via xhtml2pdf (pisa). Pure-Python (reportlab-backed) so it runs
    on Railway without WeasyPrint's native pango/cairo libraries. Embeds DejaVu
    Sans for full Unicode coverage so the PDF matches the on-screen View."""
    from xhtml2pdf import pisa
    import io as _io
    out = _io.BytesIO()
    result = pisa.CreatePDF(src=html_doc, dest=out, encoding="utf-8",
                            link_callback=_research_link_callback)
    if result.err:
        raise RuntimeError(f"xhtml2pdf reported {result.err} error(s)")
    data = out.getvalue()
    if not data:
        raise RuntimeError("xhtml2pdf produced no output")
    return data


class ResearchPdfRequest(BaseModel):
    title:       str = "AI Analyst"
    question:    str = ""
    answer_html: str = ""
    stamp:       str = ""
    filename:    Optional[str] = None
    to:          Optional[str] = None
    subject:     Optional[str] = None


def _research_pdf_filename(req: "ResearchPdfRequest") -> str:
    if req.filename:
        fn = req.filename
    else:
        t = (req.title or "").strip()
        if t.lower() in ("ai analyst", "analyst", ""):
            t = "Research"          # AI Analyst docs carry no "Analyst" word
        slug = re.sub(r"[^A-Za-z0-9]+", "_", t).strip("_") or "Research"
        fn = f"DGA_Capital_{slug}.pdf"
    return fn if fn.lower().endswith(".pdf") else fn + ".pdf"


@app.post("/api/research/pdf")
def research_pdf(body: ResearchPdfRequest, request: Request):
    """Render the on-screen View HTML to a DGA-branded PDF, served INLINE so the
    browser opens it in its PDF viewer (the user saves it themselves)."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    if not (body.answer_html or "").strip():
        raise HTTPException(400, "No content to render.")
    html_doc = _dga_research_pdf_html(body.title, body.question, body.answer_html, body.stamp)
    try:
        pdf = _render_research_pdf(html_doc)
    except Exception as e:
        raise HTTPException(500, f"PDF render failed: {e!s:.200}")
    from fastapi.responses import Response as _Response
    return _Response(content=pdf, media_type="application/pdf",
                     headers={"Content-Disposition": _content_disposition(
                         "inline", _research_pdf_filename(body))})


@app.post("/api/research/email-pdf")
def research_email_pdf(body: ResearchPdfRequest, request: Request):
    """Render the View HTML to a DGA-branded PDF and email it as an attachment."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    to_addr = (body.to or "").strip()
    if not to_addr or "@" not in to_addr:
        raise HTTPException(400, "A valid recipient email is required.")
    if not (body.answer_html or "").strip():
        raise HTTPException(400, "No content to render.")
    html_doc = _dga_research_pdf_html(body.title, body.question, body.answer_html, body.stamp)
    try:
        pdf = _render_research_pdf(html_doc)
    except Exception as e:
        raise HTTPException(500, f"PDF render failed: {e!s:.200}")
    import html as _html
    # Drop the word "Analyst" from analyst emails; keep a real label (e.g. the
    # Strategist's "Investment Committee Review") when present.
    _t = (body.title or "").strip()
    doc_label = "" if _t.lower() in ("ai analyst", "analyst", "") else _t
    subject = (body.subject or (f"DGA Capital — {doc_label}" if doc_label
                                else "DGA Capital — Research Note")).strip()
    lead = (f'Please find the attached <strong>{_html.escape(doc_label)}</strong> report from DGA Capital.'
            if doc_label else 'Please find the attached research note from DGA Capital.')
    q_line  = (f'<p style="color:#475569;font-size:14px;">{_html.escape(body.question)}</p>'
               if body.question else '')
    email_html = (
        '<div style="font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;'
        'color:#0A1628;">'
        f'<p>{lead}</p>' + q_line +
        '<p style="color:#94a3b8;font-size:12px;margin-top:18px;">DGA Capital · Confidential — '
        'for the intended recipient only. Not investment advice.</p></div>')
    res = _send_email_with_pdf_attachment(
        to_addr, subject, email_html, pdf, _research_pdf_filename(body))
    if not res.get("ok"):
        raise HTTPException(502, res.get("error", "Email send failed"))
    return {"ok": True, "sent_to": to_addr, "transport": res.get("transport")}


@app.get("/api/research/analyst/reviews")
def analyst_reviews_list(request: Request, source: str = "analyst"):
    """List saved AI Analyst answers (newest first). source='all' for every kind."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    _ensure_analyst_reviews_table()
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            if source and source != "all":
                cur.execute("""SELECT id, source, question, cost_usd, model, generated_at,
                                      length(answer) AS answer_len
                                 FROM analyst_reviews WHERE source = %s
                                ORDER BY generated_at DESC LIMIT 100""", (source,))
            else:
                cur.execute("""SELECT id, source, question, cost_usd, model, generated_at,
                                      length(answer) AS answer_len
                                 FROM analyst_reviews
                                ORDER BY generated_at DESC LIMIT 100""")
            rows = cur.fetchall() or []
        return {"ok": True, "reviews": [{
            "id": r["id"], "source": r.get("source"), "question": r.get("question"),
            "cost_usd": float(r["cost_usd"]) if r.get("cost_usd") is not None else None,
            "model": r.get("model"), "answer_len": int(r.get("answer_len") or 0),
            "generated_at": r["generated_at"].isoformat() if r.get("generated_at") else None,
        } for r in rows]}
    except Exception as e:
        return JSONResponse({"ok": False, "error": str(e)[:200]}, status_code=500)


@app.get("/api/research/analyst/reviews/{review_id}")
def analyst_review_get(review_id: str, request: Request):
    """Full saved AI Analyst answer (markdown + verification + tool calls) — used
    to re-open or print the review to PDF."""
    _claims_or_401(request)
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""SELECT id, source, question, answer, verification, tool_calls,
                                  cost_usd, model, generated_at
                             FROM analyst_reviews WHERE id = %s""", (review_id,))
            r = cur.fetchone()
        if not r:
            raise HTTPException(404, "Review not found")
        return {"ok": True, "review": {
            "id": r["id"], "source": r.get("source"), "question": r.get("question"),
            "answer": r.get("answer"), "verification": r.get("verification"),
            "tool_calls": r.get("tool_calls"),
            "cost_usd": float(r["cost_usd"]) if r.get("cost_usd") is not None else None,
            "model": r.get("model"),
            "generated_at": r["generated_at"].isoformat() if r.get("generated_at") else None,
        }}
    except HTTPException:
        raise
    except Exception as e:
        return JSONResponse({"ok": False, "error": str(e)[:200]}, status_code=500)


