# ═══════════════════════════════════════════════════════════════════════
# TRANSCRIPT INTELLIGENCE — Part A (YouTube/interview transcripts) and
# Part B (earnings-call RAG index). Both feed the same agentic AI Analyst
# via four new tools. YouTube transcripts are stored whole + entity-mapped;
# earnings calls are chunked + embedded so the bot retrieves only the
# relevant passages (cheap per-query token cost, never the whole call).
# ═══════════════════════════════════════════════════════════════════════
_transcript_jobs: dict[str, dict] = {}           # YouTube ingest jobs
_call_sync_jobs: dict[str, dict] = {}            # earnings-call sync jobs

_TRANSCRIPT_EXTRACT_MODEL = (os.environ.get("TRANSCRIPT_MODEL", "").strip()
                             or "claude-sonnet-4-6")
_EMBED_MODEL = "text-embedding-3-small"          # 1536-dim, ~$0.02/1M tokens


@_ddl_once
def _ensure_transcripts_tables() -> None:
    """Create transcript tables. Idempotent. Embeddings are stored as JSONB
    float arrays (cosine computed in Python) — no pgvector extension needed,
    which keeps this portable across Postgres images."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transcripts (
                    id            TEXT PRIMARY KEY,
                    source        TEXT NOT NULL DEFAULT 'youtube',
                    person        TEXT,
                    ticker        TEXT,
                    title         TEXT,
                    video_url     TEXT,
                    channel       TEXT,
                    published_at  TEXT,
                    full_text     TEXT,
                    summary       TEXT,
                    word_count    INTEGER,
                    created_by    TEXT,
                    created_at    TIMESTAMPTZ NOT NULL DEFAULT now()
                )
            """)
            cur.execute("CREATE INDEX IF NOT EXISTS transcripts_created_idx ON transcripts(created_at DESC)")
            cur.execute("CREATE INDEX IF NOT EXISTS transcripts_ticker_idx  ON transcripts(ticker)")
            cur.execute("CREATE INDEX IF NOT EXISTS transcripts_fts_idx ON transcripts "
                        "USING gin(to_tsvector('english', coalesce(full_text,'')))")
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transcript_entities (
                    id            BIGSERIAL PRIMARY KEY,
                    transcript_id TEXT NOT NULL REFERENCES transcripts(id) ON DELETE CASCADE,
                    company       TEXT,
                    ticker        TEXT,
                    sentiment     TEXT,
                    quote         TEXT,
                    timestamp_sec INTEGER,
                    theme         TEXT
                )
            """)
            cur.execute("CREATE INDEX IF NOT EXISTS transcript_entities_tid_idx    ON transcript_entities(transcript_id)")
            cur.execute("CREATE INDEX IF NOT EXISTS transcript_entities_ticker_idx ON transcript_entities(ticker)")
            cur.execute("""
                CREATE TABLE IF NOT EXISTS call_chunks (
                    id          BIGSERIAL PRIMARY KEY,
                    ticker      TEXT NOT NULL,
                    quarter     TEXT,
                    call_date   TEXT,
                    speaker     TEXT,
                    chunk_idx   INTEGER,
                    chunk_text  TEXT NOT NULL,
                    embedding   JSONB,
                    created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
                )
            """)
            cur.execute("CREATE INDEX IF NOT EXISTS call_chunks_ticker_idx ON call_chunks(ticker)")
            cur.execute("CREATE UNIQUE INDEX IF NOT EXISTS call_chunks_uniq ON call_chunks(ticker, quarter, chunk_idx)")
            conn.commit()
    except Exception as e:
        print(f"❌ _ensure_transcripts_tables failed: {e!s:.300}", flush=True)


# ── YouTube fetch ──────────────────────────────────────────────────────
def _extract_youtube_id(url: str) -> str | None:
    """Parse an 11-char YouTube video id from any common URL shape."""
    if not url:
        return None
    url = url.strip()
    m = re.search(r"(?:v=|/shorts/|youtu\.be/|/embed/|/live/)([A-Za-z0-9_-]{11})", url)
    if m:
        return m.group(1)
    if re.fullmatch(r"[A-Za-z0-9_-]{11}", url):   # bare id
        return url
    return None


def _yt_proxy_config():
    """Build a youtube-transcript-api proxy_config from env, or None.

    YouTube blanket-blocks datacenter/cloud IPs for transcript fetches (the
    "RequestBlocked / your IP is a cloud provider" error). The library's
    sanctioned fix is to route requests through a RESIDENTIAL proxy. This is
    opt-in: with no env vars set we return None and behaviour is unchanged.

    Supported (first match wins):
      • Webshare residential (recommended by the library):
          WEBSHARE_PROXY_USERNAME, WEBSHARE_PROXY_PASSWORD
      • Any generic HTTP/HTTPS proxy URL:
          YT_PROXY_HTTP and/or YT_PROXY_HTTPS  (e.g. http://user:pass@host:port)
    """
    import os as _os
    ws_user = _os.environ.get("WEBSHARE_PROXY_USERNAME")
    ws_pass = _os.environ.get("WEBSHARE_PROXY_PASSWORD")
    http_url = _os.environ.get("YT_PROXY_HTTP")
    https_url = _os.environ.get("YT_PROXY_HTTPS")
    try:
        if ws_user and ws_pass:
            from youtube_transcript_api.proxies import WebshareProxyConfig
            return WebshareProxyConfig(proxy_username=ws_user, proxy_password=ws_pass)
        if http_url or https_url:
            from youtube_transcript_api.proxies import GenericProxyConfig
            return GenericProxyConfig(http_url=http_url or https_url,
                                      https_url=https_url or http_url)
    except Exception as e:
        print(f"[yt] proxy config ignored: {e!s:.120}", flush=True)
    return None


def _yt_fetch_segments(vid: str) -> list[dict]:
    """Fetch caption segments [{text, start}] for a video id. Supports both the
    v1.x instance API (.fetch → FetchedTranscript) and the legacy v0.6.x
    classmethod (.get_transcript). Real fetch errors (IP block, captions
    disabled, none found) are surfaced verbatim, not masked by a fallback.

    If a residential proxy is configured (see _yt_proxy_config), requests are
    routed through it — required when this server runs on a cloud IP that
    YouTube blocks."""
    from youtube_transcript_api import YouTubeTranscriptApi
    langs = ["en", "en-US", "en-GB"]
    proxy_config = _yt_proxy_config()
    # ── v1.x: instance .fetch() ──────────────────────────────────────────
    inst = None
    try:
        inst = YouTubeTranscriptApi(proxy_config=proxy_config) if proxy_config \
            else YouTubeTranscriptApi()
    except Exception:
        inst = None
    if inst is not None and hasattr(inst, "fetch"):
        fetched = inst.fetch(vid, languages=langs)   # let real errors propagate
        if hasattr(fetched, "to_raw_data"):
            raw = fetched.to_raw_data()
            return [{"text": s.get("text", "") or "",
                     "start": float(s.get("start", 0) or 0)} for s in raw]
        return [{"text": getattr(s, "text", "") or "",
                 "start": float(getattr(s, "start", 0) or 0)} for s in fetched]
    # ── legacy v0.6.x: classmethod .get_transcript() ─────────────────────
    if hasattr(YouTubeTranscriptApi, "get_transcript"):
        raw = YouTubeTranscriptApi.get_transcript(vid, languages=langs)
        return [{"text": s.get("text", ""), "start": float(s.get("start", 0) or 0)} for s in raw]
    raise RuntimeError("youtube-transcript-api: no usable fetch()/get_transcript() method")


def _yt_metadata(url: str) -> dict:
    """Title + channel via the free oEmbed endpoint (no API key)."""
    try:
        import requests
        r = requests.get("https://www.youtube.com/oembed",
                         params={"url": url, "format": "json"}, timeout=10)
        if r.ok:
            j = r.json()
            return {"title": j.get("title"), "channel": j.get("author_name")}
    except Exception:
        pass
    return {"title": None, "channel": None}


# ── Entity extraction (Claude) ─────────────────────────────────────────
_TRANSCRIPT_EXTRACT_SYSTEM = (
    "You read interview/keynote transcripts and extract every PUBLICLY-TRADED "
    "company a public-market investor could act on. For each, capture the "
    "speaker's actual stance and the exact sentence they said it in. Ignore the "
    "speaker's own employer unless they make a forward-looking claim about it. "
    "Map each company to its US-listed ticker when you are confident; use null "
    "for private/unknown. Respond with ONLY compact JSON, no prose:\n"
    '{"summary": "2-3 sentence gist of the conversation", "entities": ['
    '{"company": "...", "ticker": "NVDA"|null, "sentiment": "bull"|"bear"|"neutral", '
    '"quote": "exact sentence from the transcript", "theme": "short tag e.g. AI capex"}]}'
    "\nDo not invent companies or tickers — only what is actually discussed."
)


def _extract_transcript_entities(text: str) -> dict:
    """One Claude call → {summary, entities:[...]}. Tries the cheap model first,
    falls back to the agentic model on error. Degrades to empty on failure."""
    import anthropic as _anthropic
    snippet = (text or "")[:42000]   # keep the extraction call bounded
    client = _anthropic.Anthropic(api_key=analyst.get_claude_api_key(), timeout=120.0)
    user = f"TRANSCRIPT:\n{snippet}"
    for mdl in (_TRANSCRIPT_EXTRACT_MODEL, _AGENTIC_MODEL):
        try:
            resp = client.messages.create(
                model=mdl, max_tokens=4000,
                system=_TRANSCRIPT_EXTRACT_SYSTEM,
                messages=[{"role": "user", "content": user}],
            )
            txt = next((b.text for b in resp.content
                        if getattr(b, "type", None) == "text"), "") or ""
            parsed = _extract_json_object(txt)
            if parsed is not None:
                ents = parsed.get("entities") or []
                # normalize
                clean = []
                for e in ents:
                    if not isinstance(e, dict):
                        continue
                    comp = (e.get("company") or "").strip()
                    if not comp:
                        continue
                    tk = (e.get("ticker") or "") or None
                    tk = (tk.upper().strip() if isinstance(tk, str) else None) or None
                    sent = (e.get("sentiment") or "neutral").lower().strip()
                    if sent not in ("bull", "bear", "neutral"):
                        sent = "neutral"
                    clean.append({"company": comp[:120], "ticker": tk,
                                  "sentiment": sent, "quote": (e.get("quote") or "")[:600],
                                  "theme": (e.get("theme") or "")[:80]})
                return {"summary": (parsed.get("summary") or "")[:1000], "entities": clean}
        except Exception as e:
            print(f"⚠️ [transcript extract] {mdl} failed: {e!s:.150}", flush=True)
            continue
    return {"summary": "", "entities": []}


def _approx_timestamp(quote: str, segments: list[dict]) -> int | None:
    """Best-effort: find the segment whose text overlaps the quote, return its
    start time in seconds. Used to deep-link YouTube at the right moment."""
    if not quote or not segments:
        return None
    q = re.sub(r"\s+", " ", quote.lower())[:40]
    if not q:
        return None
    for s in segments:
        st = re.sub(r"\s+", " ", (s.get("text") or "").lower())
        if st and (st in q or q[:20] in st):
            return int(s.get("start") or 0)
    return None


def _run_youtube_ingest(job_id: str, url: str, person: str, created_by: str) -> None:
    """Background worker: fetch transcript → extract entities → persist."""
    import uuid as _uuid
    def _set(**kw):
        _transcript_jobs[job_id] = {**(_transcript_jobs.get(job_id) or {}), **kw,
                                     "updated_at": time.time()}
    _set(stage="queued", status="running", label="Queued…", started_at=time.time())
    try:
        _ensure_transcripts_tables()
        vid = _extract_youtube_id(url)
        if not vid:
            raise ValueError("Could not parse a YouTube video ID from that URL.")
        canonical = f"https://www.youtube.com/watch?v={vid}"
        _set(stage="fetching", label="📥 Fetching transcript…")
        segments = _yt_fetch_segments(vid)
        text = " ".join((s.get("text") or "").replace("\n", " ") for s in segments).strip()
        if len(text) < 200:
            raise ValueError("Transcript too short or unavailable (video may have no captions).")
        meta = _yt_metadata(canonical)
        wc = len(text.split())
        _set(stage="extracting", label=f"🔍 Extracting companies ({wc:,} words)…")
        extracted = _extract_transcript_entities(text)
        _set(stage="saving", label="💾 Saving…")
        tid = str(_uuid.uuid4())
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                INSERT INTO transcripts
                    (id, source, person, ticker, title, video_url, channel,
                     published_at, full_text, summary, word_count, created_by)
                VALUES (%s,'youtube',%s,NULL,%s,%s,%s,NULL,%s,%s,%s,%s)
            """, (tid, (person or "").strip() or (meta.get("channel") or None),
                  meta.get("title") or f"YouTube {vid}", canonical, meta.get("channel"),
                  text, extracted.get("summary"), wc, created_by))
            for e in extracted.get("entities") or []:
                cur.execute("""
                    INSERT INTO transcript_entities
                        (transcript_id, company, ticker, sentiment, quote, timestamp_sec, theme)
                    VALUES (%s,%s,%s,%s,%s,%s,%s)
                """, (tid, e["company"], e.get("ticker"), e.get("sentiment"),
                      e.get("quote"), _approx_timestamp(e.get("quote") or "", segments),
                      e.get("theme")))
            conn.commit()
        _set(stage="done", status="done", label="✓ Transcript ingested",
             result={"transcript_id": tid, "title": meta.get("title"),
                     "word_count": wc, "entities": extracted.get("entities") or [],
                     "summary": extracted.get("summary")})
        print(f"📺 [transcript] ingested {tid} '{(meta.get('title') or vid)[:50]}' "
              f"({len(extracted.get('entities') or [])} entities)", flush=True)
    except Exception as e:
        print(f"❌ [transcript ingest {job_id}] {e!s:.300}", flush=True)
        _set(stage="error", status="error", label=f"❌ {e!s:.200}", error=str(e))


# ── Embeddings + earnings-call RAG ─────────────────────────────────────
def _embed_texts(texts: list[str]) -> list[list[float]]:
    """Batch-embed with OpenAI text-embedding-3-small. Returns list of vectors."""
    if not texts:
        return []
    from openai import OpenAI
    key = os.environ.get("OPENAI_API_KEY")
    if not key:
        raise RuntimeError("OPENAI_API_KEY not set")
    client = OpenAI(api_key=key)
    out: list[list[float]] = []
    for i in range(0, len(texts), 96):
        batch = [t[:8000] for t in texts[i:i + 96]]
        resp = client.embeddings.create(model=_EMBED_MODEL, input=batch)
        out.extend([d.embedding for d in resp.data])
    return out


def _chunk_call_text(text: str, words_per_chunk: int = 300, overlap: int = 40) -> list[str]:
    """Split a long earnings transcript into overlapping ~300-word passages."""
    words = (text or "").split()
    if not words:
        return []
    chunks, i = [], 0
    step = max(1, words_per_chunk - overlap)
    while i < len(words):
        chunk = " ".join(words[i:i + words_per_chunk]).strip()
        if chunk:
            chunks.append(chunk)
        i += step
    return chunks


def _fetch_api_ninjas_transcript(ticker: str, year: int, quarter: int) -> dict:
    """One earnings-call transcript from API Ninjas. Always returns a dict:
      ok=True  → {ok, status, transcript, date}
      ok=False → {ok, status, error[, keys]}
    Never raises or silently returns None — so the sync job can report WHY a
    fetch came back empty (403 premium gate vs. no data vs. bad shape)."""
    key = os.environ.get("API_NINJAS_KEY")
    if not key:
        return {"ok": False, "status": 0, "error": "API_NINJAS_KEY not set"}
    import requests
    url = "https://api.api-ninjas.com/v1/earningstranscript"
    try:
        r = requests.get(url, params={"ticker": ticker, "year": year, "quarter": quarter},
                         headers={"X-Api-Key": key}, timeout=30)
    except Exception as e:
        return {"ok": False, "status": -1, "error": f"request failed: {e!s:.160}"}
    if r.status_code != 200:
        return {"ok": False, "status": r.status_code, "error": (r.text or "")[:300]}
    try:
        j = r.json()
    except Exception:
        return {"ok": False, "status": 200, "error": "non-JSON body: " + (r.text or "")[:200]}
    if isinstance(j, list):
        j = j[0] if j else {}
    txt = ((j or {}).get("transcript") or "").strip()
    if not txt:
        return {"ok": False, "status": 200, "error": "empty transcript",
                "keys": list((j or {}).keys()) if isinstance(j, dict) else None}
    return {"ok": True, "status": 200, "transcript": txt, "date": (j or {}).get("date")}


# Default earnings-transcript source. API Ninjas' endpoint is premium-only, so
# we default to Grok live-search (reuses the existing xAI key, no new signup).
_CALL_SOURCE = (os.environ.get("CALL_TRANSCRIPT_SOURCE", "").strip().lower() or "grok")

_GROK_CALL_SYSTEM = (
    "You are an earnings-call transcript retrieval tool. Using live web search, "
    "find the company's MOST RECENT reported quarterly earnings call transcript "
    "(prefer a full, free transcript such as The Motley Fool / fool.com). "
    "Respond in EXACTLY this format and nothing else:\n"
    "QUARTER: <YYYYQn>\n"
    "DATE: <YYYY-MM-DD or unknown>\n"
    "---\n"
    "<the transcript: management's prepared remarks AND the analyst Q&A, quoted "
    "as fully and verbatim as the published transcript allows — reproduce the "
    "speakers' actual words, do NOT summarize, paraphrase, or add commentary>\n\n"
    "If you genuinely cannot find a real transcript, reply with exactly: NO_TRANSCRIPT"
)

# Per-quarter variant: used by the walk-back so we can fill EVERY recent quarter
# (the HF backfill dataset ends ~Q1 2025, and the "latest only" fetch above left
# the quarters between that cutoff and today perpetually missing).
_GROK_CALL_Q_SYSTEM = (
    "You are an earnings-call transcript retrieval tool. Using live web search, "
    "find the company's earnings call transcript for the SPECIFIC fiscal quarter "
    "the user names (prefer a full, free transcript such as The Motley Fool / "
    "fool.com or the company IR site). Respond in EXACTLY this format and nothing "
    "else:\n"
    "QUARTER: <YYYYQn>\n"
    "DATE: <YYYY-MM-DD or unknown>\n"
    "---\n"
    "<the transcript: management's prepared remarks AND the analyst Q&A, quoted "
    "as fully and verbatim as the published transcript allows — reproduce the "
    "speakers' actual words, do NOT summarize, paraphrase, or add commentary>\n\n"
    "QUARTER must be the quarter the transcript actually covers. If that quarter "
    "has not been reported yet, or you cannot find a real transcript for it, "
    "reply with exactly: NO_TRANSCRIPT"
)


def _recent_quarters(n: int) -> list[tuple]:
    """The `n` most recent calendar quarters, newest first, starting from the
    quarter we are currently in (which may not have reported yet)."""
    from datetime import datetime as _dt
    now = _dt.utcnow()
    y, q = now.year, (now.month - 1) // 3 + 1
    out = []
    for _ in range(max(1, n)):
        out.append((y, q))
        q -= 1
        if q == 0:
            q, y = 4, y - 1
    return out


def _parse_grok_transcript(out: str, default_quarter: str = None) -> dict:
    """Parse a Grok transcript response into
    {ok, transcript, quarter, date} or {ok:False, status, error}."""
    out = (out or "").strip()
    if not out or "NO_TRANSCRIPT" in out[:80].upper():
        return {"ok": False, "status": 200, "error": "Grok found no transcript"}
    quarter = date = None
    m = re.search(r"QUARTER:\s*([0-9]{4}\s*Q\s*[1-4])", out, re.I)
    if m:
        quarter = re.sub(r"\s+", "", m.group(1)).upper()
    m = re.search(r"DATE:\s*([0-9]{4}-[0-9]{2}-[0-9]{2})", out)
    if m:
        date = m.group(1)
    body = out.split("---", 1)[1].strip() if "---" in out else out
    if len(body) < 400:
        return {"ok": False, "status": 200, "error": f"transcript too short ({len(body)} chars)"}
    if not quarter:
        if date:
            y, mo = int(date[:4]), int(date[5:7])
            quarter = f"{y}Q{max(1, (mo - 1) // 3 + 1)}"   # rough calendar quarter
        else:
            quarter = default_quarter or "latest"
    return {"ok": True, "status": 200, "transcript": body, "quarter": quarter, "date": date}


def _fetch_grok_call_transcript(ticker: str) -> dict:
    """Retrieve the latest earnings-call transcript via Grok live-search.
    Returns {ok, transcript, quarter, date} or {ok:False, status, error}."""
    try:
        out = analyst.call_grok(system_prompt=_GROK_CALL_SYSTEM,
                                user_content=f"Company ticker: {ticker}. "
                                             f"Retrieve its most recent reported earnings call transcript.",
                                live_search=True) or ""
    except Exception as e:
        return {"ok": False, "status": -1, "error": f"grok error: {e!s:.160}"}
    return _parse_grok_transcript(out)


def _fetch_grok_call_transcript_for_quarter(ticker: str, year: int, quarter: int) -> dict:
    """Retrieve ONE specific quarter's earnings-call transcript via Grok
    live-search. Returns the same shape as _fetch_grok_call_transcript."""
    qtag = f"{year}Q{quarter}"
    sfd = f"{year}-{(quarter - 1) * 3 + 1:02d}-01"   # bias search to >= quarter start
    try:
        out = analyst.call_grok(
            system_prompt=_GROK_CALL_Q_SYSTEM,
            user_content=(f"Company ticker: {ticker}. Retrieve the earnings call "
                          f"transcript for fiscal {qtag} (the call held to discuss "
                          f"that quarter's results)."),
            live_search=True, search_from_date=sfd) or ""
    except Exception as e:
        return {"ok": False, "status": -1, "error": f"grok error: {e!s:.160}"}
    return _parse_grok_transcript(out, default_quarter=qtag)


def _store_call_chunks(ticker: str, qtag: str, call_date, transcript: str) -> tuple:
    """Chunk + embed + store one transcript. Returns (indexed_count, error|None)."""
    chunks = _chunk_call_text(transcript)
    if not chunks:
        return 0, "no chunks"
    try:
        embs = _embed_texts(chunks)
    except Exception as e:
        return 0, f"embed failed {e!s:.100}"
    n = 0
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            for idx, (ch, emb) in enumerate(zip(chunks, embs)):
                cur.execute("""
                    INSERT INTO call_chunks (ticker, quarter, call_date, speaker, chunk_idx, chunk_text, embedding)
                    VALUES (%s,%s,%s,NULL,%s,%s,%s)
                    ON CONFLICT (ticker, quarter, chunk_idx) DO NOTHING
                """, (ticker, qtag, call_date, idx, ch, json.dumps(emb)))
                n += 1
            conn.commit()
    except Exception as e:
        return 0, f"store failed {e!s:.100}"
    print(f"📞 [calls] {ticker} {qtag}: indexed {len(chunks)} chunks", flush=True)
    return n, None


def _already_indexed(ticker: str, qtag: str) -> bool:
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("SELECT 1 FROM call_chunks WHERE ticker=%s AND quarter=%s LIMIT 1",
                        (ticker, qtag))
            return bool(cur.fetchone())
    except Exception:
        return False


def _sync_one_ticker_calls(ticker: str, max_quarters: int = 4) -> dict:
    """Index recent earnings calls for one ticker. Returns
    {indexed, found:[quarters], errors:[str]}. Source defaults to Grok
    live-search (API Ninjas transcripts are premium-gated)."""
    if _CALL_SOURCE == "grok":
        # Walk recent calendar quarters newest-first, fetching each MISSING one
        # via Grok live-search. This fills the gap between the Hugging Face
        # backfill cutoff (~Q1 2025) and the latest reported quarter — the old
        # behaviour grabbed only the single most-recent call, so 3-4 quarters
        # stayed perpetually missing. Already-indexed quarters are skipped for
        # free (no Grok call), so re-running sync just extends forward cheaply.
        indexed, found, errors = 0, [], []
        seen, new_count, consec_miss = set(), 0, 0
        for (y, q) in _recent_quarters(max_quarters + 4):
            if new_count >= max_quarters:
                break
            qtag = f"{y}Q{q}"
            if _already_indexed(ticker, qtag):
                if qtag not in found:
                    found.append(qtag)
                consec_miss = 0
                continue
            res = _fetch_grok_call_transcript_for_quarter(ticker, y, q)
            if not res.get("ok"):
                # The current (not-yet-reported) quarter is an expected miss;
                # only give up after a couple of consecutive empty quarters
                # once we've already landed at least one real transcript.
                consec_miss += 1
                st = res.get("status")
                if st not in (200,):
                    errors.append(f"{qtag}: [{st}] {str(res.get('error'))[:120]}")
                if consec_miss >= 3 and found:
                    break
                continue
            consec_miss = 0
            act = res.get("quarter") or qtag            # trust Grok's detected quarter
            if act in seen or _already_indexed(ticker, act):
                if act not in found:
                    found.append(act)
                continue
            seen.add(act)
            n, err = _store_call_chunks(ticker, act, res.get("date"), res["transcript"])
            if err:
                errors.append(f"{act}: {err}")
            else:
                found.append(act); indexed += n; new_count += 1
        return {"indexed": indexed, "found": found, "errors": errors}

    # ── API Ninjas path (premium) — multi-quarter walk-back ──
    from datetime import datetime as _dt
    cur_year = _dt.utcnow().year
    indexed, got = 0, 0
    found, errors = [], []
    candidates = [(y, q) for y in (cur_year, cur_year - 1, cur_year - 2)
                         for q in (4, 3, 2, 1)]
    for (y, q) in candidates:
        if got >= max_quarters:
            break
        qtag = f"{y}Q{q}"
        try:                                  # skip if already indexed
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("SELECT 1 FROM call_chunks WHERE ticker=%s AND quarter=%s LIMIT 1",
                            (ticker, qtag))
                if cur.fetchone():
                    got += 1; found.append(qtag); continue
        except Exception:
            pass
        res = _fetch_api_ninjas_transcript(ticker, y, q)
        if not res.get("ok"):
            # Record only "real" failures (auth/quota/shape), not the expected
            # "future quarter has no data yet" 200-empty misses.
            st = res.get("status")
            if st not in (200,) or res.get("error") != "empty transcript":
                errors.append(f"{qtag}: [{st}] {str(res.get('error'))[:120]}")
            continue
        got += 1; found.append(qtag)
        chunks = _chunk_call_text(res["transcript"])
        if not chunks:
            continue
        try:
            embs = _embed_texts(chunks)
        except Exception as e:
            errors.append(f"{qtag}: embed failed {e!s:.100}"); continue
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                for idx, (ch, emb) in enumerate(zip(chunks, embs)):
                    cur.execute("""
                        INSERT INTO call_chunks (ticker, quarter, call_date, speaker, chunk_idx, chunk_text, embedding)
                        VALUES (%s,%s,%s,NULL,%s,%s,%s)
                        ON CONFLICT (ticker, quarter, chunk_idx) DO NOTHING
                    """, (ticker, qtag, res.get("date"), idx, ch, json.dumps(emb)))
                    indexed += 1
                conn.commit()
        except Exception as e:
            errors.append(f"{qtag}: store failed {e!s:.100}"); continue
        print(f"📞 [calls] {ticker} {qtag}: indexed {len(chunks)} chunks", flush=True)
    return {"indexed": indexed, "found": found, "errors": errors}


def _run_call_sync(job_id: str, tickers: list[str], max_quarters: int) -> None:
    """Background worker: build/refresh the earnings RAG index for tickers."""
    def _set(**kw):
        _call_sync_jobs[job_id] = {**(_call_sync_jobs.get(job_id) or {}), **kw,
                                    "updated_at": time.time()}
    _set(stage="queued", status="running", label="Queued…", started_at=time.time(),
         total=len(tickers), done=0, indexed=0)
    try:
        _ensure_transcripts_tables()
        total_indexed = 0
        names_with_calls = 0
        all_errors = []
        for i, tk in enumerate(tickers):
            _set(stage="syncing", label=f"📞 {tk} ({i+1}/{len(tickers)})…", done=i)
            try:
                r = _sync_one_ticker_calls(tk, max_quarters=max_quarters)
                total_indexed += r.get("indexed", 0)
                if r.get("found"):
                    names_with_calls += 1
                for e in (r.get("errors") or [])[:2]:
                    all_errors.append(f"{tk} {e}")
            except Exception as e:
                all_errors.append(f"{tk}: {e!s:.100}")
                print(f"⚠️ [call sync {tk}] {e!s:.150}", flush=True)
            _set(indexed=total_indexed)
        # Build an honest label: if nothing indexed, surface the dominant reason.
        if total_indexed > 0:
            label = f"✓ Indexed {total_indexed} passages across {names_with_calls} names"
        else:
            src = "Grok" if _CALL_SOURCE == "grok" else "API Ninjas"
            reason = all_errors[0] if all_errors else f"no transcripts returned by {src}"
            label = f"⚠ Indexed 0 passages — {reason[:160]}"
        _set(stage="done", status="done", done=len(tickers), label=label,
             result={"tickers": tickers, "chunks_indexed": total_indexed,
                     "names_with_calls": names_with_calls,
                     "errors": all_errors[:12]})
    except Exception as e:
        print(f"❌ [call sync {job_id}] {e!s:.300}", flush=True)
        _set(stage="error", status="error", label=f"❌ {e!s:.200}", error=str(e))


# ── Historical backfill: Hugging Face dataset via DuckDB + Dropbox backup ──
_HF_TRANSCRIPT_DATASET = os.environ.get(
    "HF_TRANSCRIPT_DATASET", "kurry/sp500_earnings_transcripts").strip()
_DBX_TRANSCRIPTS_BACKUP = "/earnings_transcripts_backup.jsonl.gz"


def _hf_parquet_urls(dataset: str = None, config: str = "default", split: str = "train") -> list:
    """Resolve the auto-converted Parquet file URLs for an HF dataset via the
    datasets-server API (no big download to enumerate)."""
    import requests
    ds = dataset or _HF_TRANSCRIPT_DATASET
    url = f"https://huggingface.co/api/datasets/{ds}/parquet/{config}/{split}"
    r = requests.get(url, timeout=30)
    r.raise_for_status()
    data = r.json()
    # API returns either a bare list of URLs or {"parquet_files":[{"url":...}]}
    if isinstance(data, dict):
        if "parquet_files" in data:
            return [f.get("url") for f in data["parquet_files"] if f.get("url")]
        # nested {config:{split:[urls]}}
        urls = []
        for cfg in data.values():
            if isinstance(cfg, dict):
                for sp in cfg.values():
                    if isinstance(sp, list):
                        urls.extend(sp)
        return urls
    return list(data or [])


def _backfill_from_hf(tickers: list[str], years_back: int = 3) -> list[dict]:
    """Use DuckDB to read the HF transcript Parquet filtered to our tickers +
    recent years. Predicate/projection pushdown keeps memory low. Returns
    [{symbol, year, quarter, date, content}]."""
    import duckdb
    from datetime import datetime as _dt
    urls = _hf_parquet_urls()
    if not urls:
        raise RuntimeError("Could not resolve HF parquet URLs")
    cutoff = _dt.utcnow().year - max(1, int(years_back or 3))
    syms = ",".join("'" + t.replace("'", "").upper() + "'" for t in tickers if t)
    if not syms:
        return []
    url_list = "[" + ",".join("'" + u + "'" for u in urls) + "]"
    con = duckdb.connect()
    try:
        con.execute("INSTALL httpfs; LOAD httpfs;")
    except Exception as e:
        print(f"⚠️ duckdb httpfs load: {e!s:.120}", flush=True)
    q = (f"SELECT upper(symbol) AS symbol, year, quarter, "
         f"CAST(date AS VARCHAR) AS date, content "
         f"FROM read_parquet({url_list}) "
         f"WHERE upper(symbol) IN ({syms}) AND year >= {cutoff} "
         f"ORDER BY symbol, year, quarter")
    rows = con.execute(q).fetchall()
    cols = [d[0] for d in con.description]
    con.close()
    return [dict(zip(cols, r)) for r in rows]


def _index_call_rows(rows: list[dict], on_progress=None) -> tuple:
    """Chunk + embed + store a list of transcript rows. Returns
    (indexed_chunks, {ticker: n_quarters})."""
    indexed, per = 0, {}
    n = len(rows)
    for i, row in enumerate(rows):
        tk = (row.get("symbol") or "").upper().strip()
        y, q = row.get("year"), row.get("quarter")
        if not tk or y is None or q is None:
            continue
        qtag = f"{int(y)}Q{int(q)}"
        if _already_indexed(tk, qtag):
            per[tk] = per.get(tk, 0) + 1
            if on_progress and i % 10 == 0: on_progress(i, n, indexed)
            continue
        cnt, err = _store_call_chunks(tk, qtag, (row.get("date") or "")[:10], row.get("content") or "")
        if not err:
            indexed += cnt
            per[tk] = per.get(tk, 0) + 1
        if on_progress and i % 5 == 0:
            on_progress(i, n, indexed)
    return indexed, per


def _dropbox_backup_transcripts(rows: list[dict]) -> tuple:
    """Save the filtered transcript corpus to the Dropbox app folder as a
    gzipped JSONL backup. Returns (ok, path_or_error)."""
    try:
        dbx = analyst._dropbox_client()
    except Exception as e:
        return False, f"dropbox client error: {e!s:.100}"
    if not dbx:
        return False, "Dropbox not configured"
    try:
        import gzip, io as _io, dropbox as _dx
        buf = _io.BytesIO()
        with gzip.GzipFile(fileobj=buf, mode="wb") as gz:
            for r in rows:
                rec = {k: r.get(k) for k in ("symbol", "year", "quarter", "date", "content")}
                gz.write((json.dumps(rec, default=str) + "\n").encode("utf-8"))
        data = buf.getvalue()
        folder = analyst._dropbox_folder() or ""
        path = folder + _DBX_TRANSCRIPTS_BACKUP
        dbx.files_upload(data, path, mode=_dx.files.WriteMode.overwrite)
        return True, f"{path} ({len(data)//1024} KB)"
    except Exception as e:
        return False, f"upload failed: {e!s:.120}"


def _dropbox_restore_transcripts() -> list[dict]:
    """Load the transcript corpus back from the Dropbox app-folder backup."""
    dbx = analyst._dropbox_client()
    if not dbx:
        raise RuntimeError("Dropbox not configured")
    import gzip
    folder = analyst._dropbox_folder() or ""
    path = folder + _DBX_TRANSCRIPTS_BACKUP
    _md, resp = dbx.files_download(path)
    raw = gzip.decompress(resp.content).decode("utf-8")
    rows = []
    for line in raw.splitlines():
        line = line.strip()
        if line:
            try: rows.append(json.loads(line))
            except Exception: pass
    return rows


def _run_calls_backfill(job_id: str, tickers: list[str], years_back: int,
                         restore: bool = False, backup: bool = True) -> None:
    """Background worker: bulk-index historical transcripts from Hugging Face
    (or restore from the Dropbox backup), then back up to Dropbox."""
    def _set(**kw):
        _call_sync_jobs[job_id] = {**(_call_sync_jobs.get(job_id) or {}), **kw,
                                    "updated_at": time.time()}
    _set(stage="queued", status="running", label="Queued…", started_at=time.time(),
         total=0, done=0, indexed=0)
    try:
        _ensure_transcripts_tables()
        if restore:
            _set(stage="loading", label="📥 Restoring transcripts from Dropbox backup…")
            rows = _dropbox_restore_transcripts()
            if tickers:
                ts = {t.upper() for t in tickers}
                rows = [r for r in rows if (r.get("symbol") or "").upper() in ts]
        else:
            _set(stage="loading", label="📥 Pulling history from Hugging Face (DuckDB)…")
            rows = _backfill_from_hf(tickers, years_back)
        if not rows:
            _set(stage="done", status="done",
                 label="⚠ No transcripts matched (check tickers / dataset coverage).",
                 result={"chunks_indexed": 0, "transcripts": 0, "names": []})
            return
        _set(stage="indexing", label=f"🧮 Indexing {len(rows)} transcripts…", total=len(rows))
        indexed, per = _index_call_rows(
            rows, on_progress=lambda i, n, ix: _set(done=i, indexed=ix,
                                                    label=f"🧮 Indexing… {i}/{n} ({ix} passages)"))
        backup_note = ""
        if backup and not restore and rows:
            _set(stage="backup", label="☁️ Backing up to Dropbox…", indexed=indexed)
            ok, info = _dropbox_backup_transcripts(rows)
            backup_note = " · ☁️ backed up" if ok else f" · backup skipped ({info[:60]})"
        # 0 NEW passages with rows present just means everything was already
        # indexed on a prior run — that's "up to date", not a failure.
        if indexed > 0:
            label = f"✓ Indexed {indexed} new passages from {len(per)} names ({len(rows)} calls){backup_note}"
        else:
            label = (f"✓ Already up to date — {len(rows)} calls across {len(per)} names "
                     f"already indexed{backup_note}. Use ⚡ Latest calls to extend past the dataset cutoff.")
        _set(stage="done", status="done", done=len(rows), indexed=indexed,
             label=label,
             result={"chunks_indexed": indexed, "transcripts": len(rows),
                     "names": sorted(per.keys()), "source": "dropbox" if restore else "huggingface"})
    except Exception as e:
        print(f"❌ [backfill {job_id}] {e!s:.300}", flush=True)
        _set(stage="error", status="error", label=f"❌ {e!s:.200}", error=str(e))


def _search_call_chunks(ticker: str, query: str, k: int = 6) -> list[dict]:
    """Semantic retrieval over one ticker's indexed earnings-call chunks.
    Embeds the query, cosine-ranks the ticker's chunks in Python, returns top-k."""
    ticker = (ticker or "").upper().strip()
    if not ticker or not query:
        return []
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return []
    rows = []
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""SELECT quarter, call_date, chunk_text, embedding
                             FROM call_chunks WHERE ticker = %s""", (ticker,))
            rows = cur.fetchall() or []
    except Exception as e:
        print(f"⚠️ [_search_call_chunks {ticker}] {e!s:.150}", flush=True)
        return []
    if not rows:
        return []
    try:
        import numpy as np
        qvec = np.array(_embed_texts([query])[0], dtype="float32")
        mats, meta = [], []
        for r in rows:
            emb = r.get("embedding")
            if isinstance(emb, str):
                try: emb = json.loads(emb)
                except Exception: emb = None
            if not emb:
                continue
            mats.append(emb); meta.append(r)
        if not mats:
            return []
        M = np.array(mats, dtype="float32")
        sims = (M @ qvec) / (np.linalg.norm(M, axis=1) * (np.linalg.norm(qvec) + 1e-9) + 1e-9)
        order = np.argsort(-sims)[:max(1, min(int(k or 6), 12))]
        out = []
        for i in order:
            r = meta[int(i)]
            out.append({"quarter": r.get("quarter"), "call_date": r.get("call_date"),
                        "score": round(float(sims[int(i)]), 3),
                        "passage": (r.get("chunk_text") or "")[:900]})
        return out
    except Exception as e:
        print(f"⚠️ [_search_call_chunks rank {ticker}] {e!s:.150}", flush=True)
        return []


