# ─────────────────────────── Options wheel scanner ───────────────────────────
# Full-portfolio sweep for covered-call + cash-secured-put "wheel" candidates.
# Mirrors the financials-sync background-job pattern. The math lives in
# options_engine.py; this layer only resolves the universe and runs the sweep.
_options_scan_jobs: dict[str, dict] = {}


def _held_tickers() -> list:
    """Distinct symbols currently held (open tax-lots) across all funds — the
    covered-call universe (you must own shares to sell calls against them)."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return []
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""
                SELECT DISTINCT s.symbol AS symbol
                  FROM tax_lots tl
                  JOIN securities s ON s.id = tl.security_id
                 WHERE tl.closed_at IS NULL AND tl.quantity > 0
            """)
            return sorted({(r.get("symbol") or "").strip().upper()
                           for r in (cur.fetchall() or []) if r.get("symbol")})
    except Exception as e:
        print(f"[options scan] held-tickers query failed: {e!s:.150}", flush=True)
        return []


def _held_share_counts() -> dict:
    """Total shares held PER symbol across ALL open tax-lots (managed accounts +
    LP funds) — the actual position size used to size covered calls. Contracts =
    shares // 100, so premium $ = contracts * premium * 100."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return {}
    out: dict = {}
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("""
                SELECT s.symbol AS symbol, SUM(tl.quantity) AS qty
                  FROM tax_lots tl
                  JOIN securities s ON s.id = tl.security_id
                 WHERE tl.closed_at IS NULL AND tl.quantity > 0
                   AND s.asset_class != 'cash'
                 GROUP BY s.symbol
            """)
            for r in (cur.fetchall() or []):
                sym = (r.get("symbol") or "").strip().upper()
                if not sym:
                    continue
                try:
                    out[sym] = float(r.get("qty") or 0)
                except Exception:
                    pass
    except Exception as e:
        print(f"[options scan] held-share-counts query failed: {e!s:.150}", flush=True)
    return out


def _saved_report_tickers() -> list:
    """Tickers with a saved (non-archived) analyst report — the research
    coverage universe shown on the Research page (the 'Saved Reports' list)."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return []
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("SELECT ticker FROM analyst_reports "
                        "WHERE archived IS NOT TRUE ORDER BY ticker")
            return [(r.get("ticker") or "").strip().upper()
                    for r in (cur.fetchall() or []) if r.get("ticker")]
    except Exception as e:
        print(f"[options scan] saved-report tickers query failed: {e!s:.150}", flush=True)
        return []


# Each name costs option-chain fetches (yfinance free chains
# is slower on the cloud IP), so cap the sweep. Raised 60 → 120 so the WHOLE
# saved-report universe is scanned — at 60, alphabetically-late names (e.g. TSLA,
# the 66th-ish report) were silently truncated. Per-name calls are 25s-timeout-
# guarded and the job runs in the background, so the larger cap is safe.
_OPTIONS_SCAN_CAP = 120


def _wheel_rank_key(row: dict, side_key: str, yield_field: str):
    """Sort key implementing 'rank by the WEEKLY annualized yield; monthly and
    quarterly trail behind.' A name with a weekly setup always ranks above one
    with only a longer tenor; within a tenor, higher annualized yield wins."""
    m = row.get(side_key) or {}
    for tier, bucket in ((2, "weekly"), (1, "monthly"), (0, "quarterly")):
        c = m.get(bucket)
        if c:
            return (tier, c.get(yield_field) or 0)
    return (-1, 0)


def _snaptrade_short_options_map() -> dict:
    """{UNDERLYING: {"short_calls": contracts, "short_puts": contracts}} —
    calls/puts ALREADY written, so the wheel scan never recommends selling
    calls against shares that are already covered.

    Fetched LIVE from SnapTrade AT SCAN TIME (per Alec's rule, options logic
    runs only on explicit Options-tab use — the daily sync makes no option
    calls). Timeout-capped per account; empty map on any failure just means
    no coverage badges."""
    out: dict = {}
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return out
    try:
        import snaptrade_link as _st
        uid, secret = _snaptrade_ensure_user()
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("SELECT account_id FROM snaptrade_accounts WHERE status='active' "
                        "AND account_id NOT LIKE 'demo-%'")
            acct_ids = [r[0] for r in cur.fetchall()]
        for aid in acct_ids:
            opts = _builder_call_timeout(
                lambda a=aid: _snaptrade_normalize_options(_st.get_option_holdings(uid, secret, a)),
                10.0, []) or []
            for p in opts:
                if not isinstance(p, dict) or p.get("asset_class") != "option":
                    continue
                u = (p.get("underlying") or "").strip().upper()
                try:
                    q = float(p.get("quantity"))
                except (TypeError, ValueError):
                    continue
                if not u or q >= 0:   # long options aren't wheel inventory
                    continue
                txt = f"{p.get('symbol') or ''} {p.get('name') or ''}".upper()
                e = out.setdefault(u, {"short_calls": 0.0, "short_puts": 0.0})
                if "PUT" in txt or re.search(r"\sP[\d.]", txt):
                    e["short_puts"] += -q
                else:
                    e["short_calls"] += -q
    except Exception as e:
        print(f"[options] short-options map failed: {e!s:.120}", flush=True)
    return out


def _run_options_scan(job_id: str, universe: list, held_set: list,
                      delta_max: float) -> None:
    """Background worker. Scans each name for BOTH covered calls and cash-secured
    puts. Covered-call rows are limited to names you HOLD (you must own the
    shares); cash-secured-put rows span the whole universe (watchlist + saved
    reports + holdings). Both tables are ranked by weekly annualized yield."""
    import options_engine as _opt
    held = set(held_set)
    share_counts = _held_share_counts()   # {symbol: total shares} for premium $ sizing
    short_map = _snaptrade_short_options_map()   # calls/puts already written

    def _set(**kw):
        _options_scan_jobs[job_id] = {**(_options_scan_jobs.get(job_id) or {}), **kw,
                                      "updated_at": time.time()}
    total = len(universe)
    _set(stage="scanning", status="running", label="Starting…", total=total, done=0)
    try:
        rows = []
        for i, tk in enumerate(universe):
            _set(label=f"⚙ {tk} ({i+1}/{total})…", done=i)
            # ALWAYS scan LIVE (yfinance) for fresh, COMPLETE chains
            # (incl. weekly expiries) across every name. The persisted store is
            # sparse/stale for options, so reading it first produced a degraded
            # pool (a few held names, no weeklies). Live is what worked.
            r = _builder_call_timeout(
                lambda: _opt.scan_ticker(tk, delta_max=delta_max, side="both"),
                25.0, {"ticker": tk, "ok": False, "error": "timed out"})
            if not isinstance(r, dict):
                r = {"ticker": tk, "ok": False, "error": "no result"}
            r["held"] = tk in held
            r["shares_held"] = share_counts.get(tk) or 0
            so = short_map.get(tk) or {}
            r["short_calls"] = so.get("short_calls") or 0
            r["short_puts"]  = so.get("short_puts") or 0
            _sh = r["shares_held"]
            # Fully covered = every 100-share block already has a written call.
            r["fully_covered"] = bool(_sh and r["short_calls"] * 100 >= _sh)
            rows.append(r)

        def _has(r, k):
            m = r.get(k) or {}
            return any(m.get(b) for b in ("weekly", "monthly", "quarterly"))
        # Covered calls span the WHOLE universe (not just holdings) so the table
        # isn't sparse — names you HOLD are badged + ranked first (actionable
        # now), the rest are forward-looking (a call you'd sell once you own it).
        cc_rows = [r for r in rows if _has(r, "covered_calls")]
        csp_rows = [r for r in rows if _has(r, "cash_secured_puts")]
        # Held-and-uncovered first (actionable now); names whose shares are
        # already fully covered by written calls rank below them.
        cc_rows.sort(key=lambda r: (1 if r.get("held") else 0,
                                    0 if r.get("fully_covered") else 1,
                                    _wheel_rank_key(r, "covered_calls",
                                                    "static_return_annualized")), reverse=True)
        csp_rows.sort(key=lambda r: _wheel_rank_key(r, "cash_secured_puts",
                                                    "yield_on_cash_annualized"), reverse=True)
        ok_n = sum(1 for r in rows if r.get("ok"))
        _set(stage="done", status="done", done=total,
             label=f"✓ Scanned {ok_n}/{total} names · {len(cc_rows)} call / {len(csp_rows)} put setups",
             result={"delta_max": delta_max,
                     "universe_size": total,
                     "held_count": len(held),
                     "covered_calls": cc_rows,
                     "cash_secured_puts": csp_rows,
                     "scanned_at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())})
    except Exception as e:
        print(f"❌ [options scan {job_id}] {e!s:.300}", flush=True)
        _set(stage="error", status="error", label=f"❌ {e!s:.200}", error=str(e))


@app.post("/api/options/scan")
def options_scan(req: Request, background_tasks: BackgroundTasks):
    """Queue a wheel scan. Body: {delta_max?, tickers?}. With no tickers, sweeps
    the union of holdings + watchlist + saved-report names. Covered calls are
    limited to held names; cash-secured puts span the whole universe."""
    claims = _claims_or_401(req)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP only")
    try:
        body = _request_json_sync(req)
    except Exception:
        body = {}
    body = body or {}
    try:
        delta_max = float(body.get("delta_max") or 0.30)
    except Exception:
        delta_max = 0.30
    delta_max = max(0.05, min(delta_max, 0.95))
    held = _filter_scan_tickers(_held_tickers())
    explicit = [str(t).upper().strip() for t in (body.get("tickers") or [])
                if t and str(t).strip()]
    if explicit:
        universe = _filter_scan_tickers(explicit)
    else:
        # Union: holdings, then watchlist, then saved-report coverage. Held names
        # go first so they're never pushed out of the cap.
        watch = _filter_scan_tickers(_all_watchlist_tickers())
        reports = _filter_scan_tickers(_saved_report_tickers())
        seen, universe = set(), []
        for src in (held, watch, reports):
            for t in src:
                if t not in seen:
                    seen.add(t)
                    universe.append(t)
    truncated = len(universe) > _OPTIONS_SCAN_CAP
    universe = universe[:_OPTIONS_SCAN_CAP]
    uset = set(universe)
    held_set = [t for t in held if t in uset]
    if not universe:
        return JSONResponse({"ok": False,
                             "error": "No tickers to scan (no holdings, watchlist, or saved reports found)."},
                            status_code=400)
    import uuid as _uuid
    job_id = "OPTSCAN_" + _uuid.uuid4().hex[:12]
    _options_scan_jobs[job_id] = {"stage": "queued", "status": "running", "label": "Queued…",
                                  "started_at": time.time(), "updated_at": time.time(),
                                  "total": len(universe), "done": 0}
    background_tasks.add_task(_run_options_scan, job_id, universe, held_set, delta_max)
    print(f"⚙ [options scan] queued {job_id}  universe={len(universe)} "
          f"held={len(held_set)} trunc={truncated} dmax={delta_max}", flush=True)
    return {"ok": True, "job_id": job_id, "universe": universe, "held": held_set,
            "truncated": truncated, "cap": _OPTIONS_SCAN_CAP, "delta_max": delta_max}


@app.get("/api/options/scan/{job_id}")
def options_scan_status(job_id: str, request: Request):
    """Poll an options wheel scan job."""
    _claims_or_401(request)
    job = _options_scan_jobs.get(job_id)
    if not job:
        return JSONResponse({"ok": False, "stage": "idle", "error": "no such job"}, status_code=404)
    return {"ok": True, **job}



# Separate dict for script-generation jobs so they don't collide with audio
# generation (which uses _podcast_jobs). Schema is the same:
#   {stage, current, total, label, status, started_at, [result], [error]}
_podcast_script_jobs: dict[str, dict] = {}


def _podcast_progress(ticker: str):
    """Return a closure that records progress for one ticker job."""
    def _record(stage: str, current: int, total: int, label: str) -> None:
        try:
            _podcast_jobs[ticker.upper()] = {
                **(_podcast_jobs.get(ticker.upper()) or {}),
                "stage":      stage,
                "current":    current,
                "total":      total,
                "label":      label,
                "updated_at": time.time(),
            }
        except Exception:
            pass
    return _record


def _run_podcast_generation(ticker: str, tts_model: str, format: str = "debate") -> None:
    """Background worker: pull script (or generate one), synthesize audio,
    upload to Dropbox, update DB.

    format scopes everything — separate MP3 + DB row per (ticker, format),
    so generating Pre-Mortem audio for INTC doesn't overwrite the Debate
    audio for INTC.
    """
    import podcast_engine as pe
    tk = ticker.upper()
    # Job key includes format so concurrent jobs for different formats of
    # the same ticker don't collide in the progress dict.
    job_key = f"{tk}::{format}"
    _podcast_jobs[job_key] = {
        "stage": "queued", "current": 0, "total": 0,
        "label": "Loading reports…", "status": "running",
        "started_at": time.time(), "format": format,
    }
    try:
        # 1. Look for a cached script for THIS (ticker, format). Check FIRST,
        #    before report loading — because for multi-ticker formats (roundup,
        #    portfolio_roundup) the "ticker" is a synthetic key like
        #    PORTFOLIO_18TICKERS_1779728533 and there are no underlying reports
        #    in analyst_reports by that name. The cached script is all we need.
        cached_script = None
        cached_script_format = format
        try:
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT script_json, format FROM analyst_podcasts
                               WHERE ticker = %s AND format = %s""", (tk, format))
                pr = cur.fetchone()
                if pr and pr.get("script_json"):
                    cached_script = pr["script_json"]
        except Exception:
            pass

        # Synthetic multi-ticker keys carry their own format implicitly
        # (PORTFOLIO_* → portfolio_roundup, ROUNDUP_* → roundup). If the
        # caller passed the wrong format (e.g. the script-format dropdown
        # was on "debate"), the cached_script lookup above missed. Recover
        # by ignoring the requested format and picking up whatever format
        # ACTUALLY exists for this ticker.
        is_synthetic = tk.startswith("PORTFOLIO_") or tk.startswith("ROUNDUP_")
        if is_synthetic and not cached_script:
            try:
                with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                    cur.execute("""SELECT script_json, format FROM analyst_podcasts
                                    WHERE ticker = %s
                                    ORDER BY generated_at DESC LIMIT 1""", (tk,))
                    pr = cur.fetchone()
                    if pr and pr.get("script_json"):
                        cached_script        = pr["script_json"]
                        cached_script_format = pr.get("format") or format
                        if cached_script_format != format:
                            print(f"🛠 [podcast/audio {job_key}] format {format!r} mismatched "
                                  f"cached row; using {cached_script_format!r} from DB", flush=True)
                            format = cached_script_format   # use the real format downstream
            except Exception: pass

        # Multi-ticker formats can ONLY use cached scripts — they're generated
        # via dedicated workers (run_roundup_generation / run_portfolio_roundup_
        # generation) that need ticker lists. We can't regenerate them here.
        is_multi = format in ("roundup", "portfolio_roundup") or is_synthetic
        if is_multi and not cached_script:
            raise RuntimeError(
                f"No cached script found for {tk} (any format). Generate the script "
                f"first via the appropriate Generate button (not this audio button)."
            )

        if cached_script:
            script = cached_script
            _podcast_jobs[job_key] = {**_podcast_jobs[job_key],
                "label": f"Re-using cached {format} script (regenerating audio only)…"}
        else:
            # Single-ticker formats with no cached script → need to write one
            # from the underlying reports.
            grok_md, claude_md = "", ""
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT report_md, report_md_claude FROM analyst_reports
                               WHERE ticker = %s""", (tk,))
                row = cur.fetchone()
                if row:
                    grok_md   = row.get("report_md") or ""
                    claude_md = row.get("report_md_claude") or ""
            if not (grok_md.strip() and claude_md.strip()):
                raise RuntimeError(
                    f"{tk} needs BOTH Grok + Claude reports — generate them first."
                )
            _podcast_jobs[job_key] = {**_podcast_jobs[job_key],
                "label": f"Writing {format} script with Claude Opus (~40s)…"}
            result = pe.generate_script(tk, grok_md, claude_md, format=format)
            if not result.get("script"):
                raise RuntimeError("Script generation failed: " +
                    ", ".join(result.get("validation", {}).get("errors", []) or ["unknown"]))
            script = result["script"]

        # 3. Synthesize audio (apply UI-edited speed + voice config first)
        try:
            cfg = _kv_get("podcast.speed_config") or {}
            pe.apply_speed_overrides(
                intensity=cfg.get("intensity"),
                speaker=cfg.get("speaker"),
            )
            vcfg = _kv_get("podcast.voice_config") or {}
            pe.apply_voice_overrides(voices=vcfg.get("voices"))
            print(f"🎙️ [podcast/audio {job_key}] speed={pe.get_speed_config()} voices={pe.get_voice_config()['voices']}", flush=True)
        except Exception as _e:
            print(f"⚠️  [podcast/audio {job_key}] config override load failed: {_e!s:.120}", flush=True)
        out_dir = analyst.STOCKS_FOLDER / "podcasts"
        out_dir.mkdir(parents=True, exist_ok=True)
        # Format-specific filename so Pre-Mortem doesn't clobber Debate on disk
        mp3_name = f"{tk}_{format}_podcast.mp3" if format != "debate" else f"{tk}_podcast.mp3"
        out_path = out_dir / mp3_name
        # Compliance disclaimer (intro + outro audio) — looked up from
        # kv_store so legal/counsel can edit text via the API without a
        # deploy. Defaults inside the engine are conservative and ON.
        dcfg = _kv_get("podcast.disclaimer_config") or {}
        disc_intro = dcfg.get("intro_text", pe.DEFAULT_DISCLAIMER_INTRO) \
                        if dcfg.get("intro_enabled", True) else None
        disc_outro = dcfg.get("outro_text", pe.DEFAULT_DISCLAIMER_OUTRO) \
                        if dcfg.get("outro_enabled", True) else None
        disc_voice = dcfg.get("voice", pe.DEFAULT_DISCLAIMER_VOICE)
        syn = pe.synthesize_episode(
            script,
            out_path=out_path,
            tts_model=tts_model,
            disclaimer_intro=disc_intro,
            disclaimer_outro=disc_outro,
            disclaimer_voice=disc_voice,
            on_progress=_podcast_progress(job_key),
        )

        # 4. Upload to Dropbox under /podcast/episodes/
        dropbox_path = None
        try:
            dbx = analyst._dropbox_client()
            if dbx is not None:
                import dropbox as _dbx
                base = analyst._dropbox_folder()
                sub = f"{base}/podcast/episodes" if base else "/podcast/episodes"
                dropbox_path = f"{sub}/{mp3_name}"
                dbx.files_upload(
                    out_path.read_bytes(),
                    dropbox_path,
                    mode=_dbx.files.WriteMode.overwrite,
                    mute=True,
                )
                print(f"✅ [podcast] uploaded {tk} → {dropbox_path}", flush=True)
        except Exception as e:
            print(f"⚠️  [podcast] dropbox upload failed for {tk}: {e!s:.200}", flush=True)

        # 5. Persist row
        cost = pe.estimate_tts_cost(script, tts_model)
        try:
            _ensure_podcast_table()
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("""
                    INSERT INTO analyst_podcasts
                        (ticker, format, episode_title, script_json, audio_local_path,
                         audio_dropbox_path, duration_sec, tts_model, voice_map,
                         generated_at, cost_usd)
                    VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, NOW(), %s)
                    ON CONFLICT (ticker, format) DO UPDATE SET
                        episode_title      = EXCLUDED.episode_title,
                        script_json        = EXCLUDED.script_json,
                        audio_local_path   = EXCLUDED.audio_local_path,
                        audio_dropbox_path = EXCLUDED.audio_dropbox_path,
                        duration_sec       = EXCLUDED.duration_sec,
                        tts_model          = EXCLUDED.tts_model,
                        voice_map          = EXCLUDED.voice_map,
                        generated_at       = NOW(),
                        cost_usd           = EXCLUDED.cost_usd
                """, (
                    tk,
                    format,
                    script.get("episode_title") or f"{tk}: Bull vs Bear",
                    json.dumps(script),
                    str(out_path),
                    dropbox_path,
                    syn.get("duration_sec"),
                    syn.get("tts_model"),
                    json.dumps(syn.get("voice_map") or {}),
                    cost.get("estimated_usd"),
                ))
                conn.commit()
        except Exception as e:
            print(f"❌ [podcast] DB persist failed for {job_key}: {e!s:.200}", flush=True)

        _podcast_jobs[job_key] = {
            **_podcast_jobs[job_key],
            "stage": "done", "status": "done",
            "label": f"✓ Done — {syn['duration_sec']:.0f}s episode",
            "duration_sec": syn.get("duration_sec"),
            "audio_url": f"/api/podcast/{tk}/audio.mp3?format={format}",
            "dropbox_path": dropbox_path,
            "cost_usd": cost.get("estimated_usd"),
        }
    except Exception as e:
        print(f"❌ [podcast] generation failed for {job_key}: {e!s:.500}", flush=True)
        _podcast_jobs[job_key] = {
            **(_podcast_jobs.get(job_key) or {}),
            "stage": "error", "status": "error",
            "label": f"❌ {e!s:.200}", "error": str(e),
        }


@app.post("/api/podcast/{ticker}/generate")
def podcast_generate(ticker: str, background_tasks: BackgroundTasks,
                     tts_model: str = "tts-1-hd", format: str = "debate"):
    """Kick off podcast audio generation in the background.

    format scopes the entire job — separate MP3 + DB row per (ticker, format)
    so Pre-Mortem audio doesn't overwrite Debate audio for the same ticker.

    Poll progress via GET /api/podcast/{ticker}/status?format=X.
    When status.stage='done', play GET /api/podcast/{ticker}/audio.mp3?format=X.
    """
    tk = ticker.upper().strip()
    if not os.environ.get("OPENAI_API_KEY"):
        return JSONResponse({"ok": False, "error": "OPENAI_API_KEY not set on server"},
                            status_code=400)
    job_key = f"{tk}::{format}"
    existing = _podcast_jobs.get(job_key)
    if existing and existing.get("status") == "running":
        return {"ok": True, "ticker": tk, "format": format, "already_running": True}
    background_tasks.add_task(_run_podcast_generation, tk, tts_model, format)
    return {"ok": True, "ticker": tk, "format": format, "tts_model": tts_model}


@app.get("/api/podcast/{ticker}/status")
def podcast_status(ticker: str, format: str = "debate"):
    tk = ticker.upper().strip()
    job_key = f"{tk}::{format}"
    job = _podcast_jobs.get(job_key) or {"stage": "idle", "status": "idle"}
    return {"ok": True, "ticker": tk, "format": format, **job}


def _locate_or_rehydrate_mp3(tk: str, format: str) -> Path | None:
    """Resolve the on-disk MP3 path for (ticker, format), rehydrating from
    Dropbox if the local copy was wiped by a Railway restart. Returns None
    if no audio exists anywhere. Shared by the authenticated audio endpoint
    AND the public-mirror endpoint."""
    tk = tk.upper().strip()
    local_path: str | None = None
    dropbox_path: str | None = None
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        try:
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("""SELECT audio_local_path, audio_dropbox_path, format
                                 FROM analyst_podcasts
                                WHERE ticker = %s
                                ORDER BY (format = %s) DESC, generated_at DESC
                                LIMIT 1""", (tk, format))
                row = cur.fetchone()
                if row:
                    local_path   = row.get("audio_local_path")
                    dropbox_path = row.get("audio_dropbox_path")
        except Exception:
            pass
    if local_path:
        p = Path(local_path)
        if p.exists(): return p
    mp3_name = f"{tk}_{format}_podcast.mp3" if format != "debate" else f"{tk}_podcast.mp3"
    fallback = analyst.STOCKS_FOLDER / "podcasts" / mp3_name
    if fallback.exists(): return fallback
    if dropbox_path:
        try:
            dbx = analyst._dropbox_client()
            if dbx is not None:
                _, res = dbx.files_download(dropbox_path)
                fallback.parent.mkdir(parents=True, exist_ok=True)
                fallback.write_bytes(res.content)
                return fallback
        except Exception as e:
            print(f"⚠️  [podcast] dropbox rehydrate failed for {tk}/{format}: {e!s:.200}", flush=True)
    return None


# ── Share-link signing (HMAC-based, no DB rows for tokens) ─────────────
def _share_signing_secret() -> str:
    """Secret used to sign public share-link tokens. Prefers env var
    SHARE_SIGNING_SECRET; falls back to a stable kv_store-backed key
    generated on first call so links survive across restarts."""
    s = os.environ.get("SHARE_SIGNING_SECRET", "").strip()
    if s: return s
    kv = _kv_get("podcast.share_signing_secret") or {}
    cur = (kv.get("secret") or "").strip()
    if cur: return cur
    import secrets as _sec
    new = _sec.token_urlsafe(48)
    try: _kv_put("podcast.share_signing_secret", {"secret": new})
    except Exception: pass
    return new


def _make_share_token(ticker: str, format: str, ttl_seconds: int = 30 * 86400) -> tuple[str, int]:
    """Return (token, expires_unix). Token is base64url(payload + '.' + sig).
    Payload = 'tk|fmt|exp', sig = HMAC-SHA256(secret, payload).hex[:32]."""
    import base64 as _b64, time as _t
    exp = int(_t.time()) + max(60, int(ttl_seconds))
    payload = f"{ticker.upper()}|{format}|{exp}"
    sig = hmac.new(_share_signing_secret().encode(), payload.encode(),
                    hashlib.sha256).hexdigest()[:32]
    raw = f"{payload}|{sig}".encode()
    token = _b64.urlsafe_b64encode(raw).rstrip(b"=").decode()
    return token, exp


def _verify_share_token(token: str) -> tuple[str, str]:
    """Validate a share token. Returns (ticker, format). Raises HTTPException
    on tampering / expiry / malformed input."""
    import base64 as _b64, time as _t
    try:
        # Restore padding then decode
        pad = "=" * (-len(token) % 4)
        raw = _b64.urlsafe_b64decode((token + pad).encode()).decode()
        tk, fmt, exp_s, sig = raw.split("|", 3)
        exp = int(exp_s)
    except Exception:
        raise HTTPException(status_code=400, detail="malformed share token")
    if _t.time() > exp:
        raise HTTPException(status_code=410, detail="share link expired")
    payload = f"{tk}|{fmt}|{exp}"
    expected = hmac.new(_share_signing_secret().encode(), payload.encode(),
                         hashlib.sha256).hexdigest()[:32]
    if not hmac.compare_digest(sig, expected):
        raise HTTPException(status_code=403, detail="invalid share token")
    return tk, fmt


@app.post("/api/podcast/{ticker}/share-link")
def podcast_share_link(ticker: str, request: Request,
                        format: str = "debate", ttl_hours: int = 720):
    """Mint a signed, time-bounded public URL for an episode. The returned
    URL bypasses auth so it can be texted/emailed/shared externally.

    Defaults to a 30-day TTL (720 hours). Bound to [1 hour, 365 days].
    Compliance disclaimer is already baked into the audio itself."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "Only GP can mint share links")
    tk = ticker.upper().strip()
    fmt = (format or "debate").strip().lower()
    # Confirm the episode actually exists before handing out a link
    if _locate_or_rehydrate_mp3(tk, fmt) is None:
        raise HTTPException(404, f"No {fmt} audio found for {tk}")
    ttl_h = max(1, min(int(ttl_hours or 720), 24 * 365))
    token, exp_unix = _make_share_token(tk, fmt, ttl_seconds=ttl_h * 3600)
    # Build absolute URLs using the request's scheme + host
    base = f"{request.url.scheme}://{request.url.netloc}".rstrip("/")
    pretty = f"DGA_{tk}_{fmt}.mp3"
    audio_url    = f"{base}/api/public/podcast/{token}/audio.mp3?name={pretty}"
    landing_url  = f"{base}/listen/{token}"
    return {
        "ok": True, "ticker": tk, "format": fmt,
        "token": token,
        # `url` is the landing page (best for sharing — OG/Twitter previews
        # render a card). `audio_url` is the raw MP3 (for pipes that need
        # a direct media URL, e.g. RSS enclosures or embeddable players).
        "url":        landing_url,
        "audio_url":  audio_url,
        "expires_at": exp_unix,
        "expires_in_hours": ttl_h,
        "note": "Anyone with this link can stream the audio until it expires. "
                "Disclaimer is in the audio itself.",
    }


@app.get("/api/public/podcast/{token}/audio.mp3")
def podcast_public_audio(token: str, name: str | None = None):
    """Public mirror of an episode's MP3. Auth bypassed (path ends in
    /audio.mp3 so the middleware lets it through), validation via HMAC
    share token. Streams the same file the authenticated endpoint serves."""
    from fastapi.responses import FileResponse
    tk, fmt = _verify_share_token(token)
    p = _locate_or_rehydrate_mp3(tk, fmt)
    if p is None:
        raise HTTPException(404, f"Episode not found ({tk}/{fmt})")
    # Use the user-supplied `name` (if reasonable) for the download filename;
    # otherwise default to the on-disk name.
    safe_name = (name or "").strip()[:80]
    if not safe_name or not safe_name.lower().endswith(".mp3"):
        safe_name = p.name
    return FileResponse(
        p, media_type="audio/mpeg", filename=safe_name,
        headers={
            "Cache-Control": "public, max-age=3600",
            "X-Content-Type-Options": "nosniff",
        },
    )


@app.get("/api/podcast/{ticker}/audio.mp3")
def podcast_audio(ticker: str, format: str = "debate"):
    """Stream the MP3 for (ticker, format). DB row → local file → Dropbox rehydrate."""
    from fastapi.responses import FileResponse
    p = _locate_or_rehydrate_mp3(ticker, format)
    if p is None:
        return JSONResponse({"ok": False,
                              "error": f"No {format} audio found for {ticker.upper()}"},
                             status_code=404)
    return FileResponse(p, media_type="audio/mpeg", filename=p.name)


