# ─────────────────────────────────────────────────────────────────────────────
#  Plaid — Fidelity auto-import (Investments)
#
#  GP-only. The Plaid access_token is the key to all the account data, so it is
#  ENCRYPTED at rest (secure_store / Fernet, key held separately from the DB) and
#  NEVER returned to any client. The browser only ever handles short-lived
#  link/public tokens. Fidelity credentials are entered on Fidelity's own OAuth
#  page via Plaid Link and never reach this server.
# ─────────────────────────────────────────────────────────────────────────────
@_ddl_once
def _ensure_plaid_tables() -> None:
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS plaid_items (
                    item_id           TEXT PRIMARY KEY,
                    institution_name  TEXT,
                    institution_id    TEXT,
                    access_token_enc  TEXT NOT NULL,
                    accounts_json     JSONB,
                    holdings_json     JSONB,
                    status            TEXT DEFAULT 'active',
                    fund_id           UUID,
                    created_at        TIMESTAMPTZ DEFAULT now(),
                    updated_at        TIMESTAMPTZ DEFAULT now(),
                    last_synced_at    TIMESTAMPTZ
                )""")
            # Additive: link a Plaid connection to a managed account (fund). Nullable;
            # a NULL fund_id just means "not assigned yet". Never touches the CSV path.
            cur.execute("ALTER TABLE plaid_items ADD COLUMN IF NOT EXISTS fund_id UUID")
            conn.commit()
    except Exception as e:
        print(f"[plaid] ensure tables failed: {e!s:.150}", flush=True)


def _plaid_require_gp(request: Request) -> dict:
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP access required")
    return claims


def _plaid_error_detail(e) -> str:
    """Pull Plaid's real error_code + error_message out of an ApiException body."""
    body = getattr(e, "body", None)
    if body:
        try:
            j = json.loads(body) if isinstance(body, str) else body
            code = j.get("error_code") or ""
            msg = j.get("error_message") or j.get("display_message") or ""
            if code or msg:
                return f"{code}: {msg}".strip(": ")
        except Exception:
            pass
    return str(e)[:300]


def _plaid_normalize_holdings(holdings_json: dict) -> dict:
    """Turn Plaid's raw {accounts, holdings, securities} into clean positions for
    the UI — at READ time only. Pure function; writes nothing. Returns
    {positions: [...], total_value, total_cost, currency}. Manual tax_lots are
    never involved, so this is fully additive to the CSV path."""
    hj = holdings_json or {}
    secs = {s.get("security_id"): s for s in (hj.get("securities") or [])}
    accts = {a.get("account_id"): a for a in (hj.get("accounts") or [])}
    positions = []
    total_value = 0.0
    total_cost = 0.0
    ccy = "USD"
    for h in (hj.get("holdings") or []):
        sec = secs.get(h.get("security_id")) or {}
        acct = accts.get(h.get("account_id")) or {}
        qty = h.get("quantity")
        price = h.get("institution_price")
        if price is None:
            price = sec.get("close_price")
        mv = h.get("institution_value")
        if mv is None and qty is not None and price is not None:
            try:
                mv = float(qty) * float(price)
            except Exception:
                mv = None
        cost = h.get("cost_basis")
        symbol = sec.get("ticker_symbol") or sec.get("name") or "—"
        if h.get("iso_currency_code"):
            ccy = h.get("iso_currency_code")
        try:
            if mv is not None:
                total_value += float(mv)
        except Exception:
            pass
        try:
            if cost is not None:
                total_cost += float(cost)
        except Exception:
            pass
        positions.append({
            "symbol":       symbol,
            "name":         sec.get("name"),
            "asset_class":  str(sec.get("type") or ""),
            "quantity":     qty,
            "price":        price,
            "market_value": mv,
            "cost_basis":   cost,
            "account_name": acct.get("official_name") or acct.get("name"),
            "account_mask": acct.get("mask"),
        })
    positions.sort(key=lambda p: (p.get("market_value") or 0), reverse=True)
    return {"positions": positions, "total_value": total_value,
            "total_cost": total_cost, "currency": ccy, "count": len(positions)}


def _plaid_managed_accounts() -> list:
    """Funds a linked brokerage account can be assigned to — both managed accounts
    AND LP funds (the GP tracks 8 managed + 3 LP fund accounts at Fidelity)."""
    out = []
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return out
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""SELECT id, short_name, name, fund_type FROM funds
                           WHERE fund_type IN ('managed_account','lp_fund') AND status NOT IN ('dissolved')
                           ORDER BY fund_type, short_name NULLS LAST, name""")
            for r in cur.fetchall():
                out.append({"fund_id": str(r[0]), "short_name": r[1], "name": r[2], "fund_type": r[3]})
    except Exception:
        pass
    return out


def _plaid_accounts_summary(accounts: list) -> list:
    """Masked, non-sensitive account list for the UI (last-4 only, no full #s)."""
    out = []
    for a in (accounts or []):
        bal = (a.get("balances") or {})
        out.append({
            "account_id": a.get("account_id"),
            "name":       a.get("official_name") or a.get("name"),
            "mask":       a.get("mask"),            # last 4 only
            "type":       str(a.get("type") or ""),
            "subtype":    str(a.get("subtype") or ""),
            "value":      bal.get("current"),
            "currency":   bal.get("iso_currency_code") or "USD",
        })
    return out


@app.get("/api/plaid/status")
def plaid_status(request: Request):
    """GP-only: is Plaid configured + how many institutions are connected."""
    _plaid_require_gp(request)
    import plaid_client as _plaid
    import secure_store as _sec
    n = 0
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        _ensure_plaid_tables()
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("SELECT count(*) FROM plaid_items WHERE status='active'")
                n = cur.fetchone()[0]
        except Exception:
            pass
    return {"ok": True, "configured": _plaid.available(), "env": _plaid.PLAID_ENV,
            "encryption_ready": _sec.is_configured(), "connected_items": n}


@app.post("/api/plaid/link-token")
def plaid_link_token(request: Request):
    """GP-only: mint a short-lived Link token for the Investments product."""
    claims = _plaid_require_gp(request)
    import plaid_client as _plaid
    if not _plaid.available():
        raise HTTPException(503, "Plaid is not configured (set PLAID_CLIENT_ID / PLAID_SECRET).")
    import secure_store as _sec
    if not _sec.is_configured():
        raise HTTPException(503, "DATA_ENCRYPTION_KEY not set — refusing to link accounts without at-rest encryption.")
    try:
        res = _plaid.create_link_token(user_id=claims.get("lp_id") or "dga-gp")
    except Exception as e:
        raise HTTPException(502, f"Plaid link-token failed: {_plaid_error_detail(e)}")
    return {"ok": True, "link_token": res.get("link_token"), "expiration": str(res.get("expiration") or "")}


def _plaid_ingest_public_token(public_token: str) -> dict:
    """Exchange a public_token, encrypt + store the access_token, and snapshot the
    first holdings. Shared by the live Link exchange and the sandbox test link.
    The access_token never leaves the server. Raises on Plaid/DB failure."""
    import plaid_client as _plaid
    import secure_store as _sec
    ex = _plaid.exchange_public_token(public_token)
    access_token = ex["access_token"]
    item_id = ex["item_id"]
    # Institution name (best-effort)
    inst_name, inst_id = None, None
    try:
        item = _plaid.get_item(access_token)
        inst_id = (item.get("item") or {}).get("institution_id")
        if inst_id:
            inst = _plaid.get_institution(inst_id)
            inst_name = (inst.get("institution") or {}).get("name")
    except Exception:
        pass
    # First holdings snapshot
    holdings = _plaid.get_holdings(access_token)
    accounts = _plaid_accounts_summary(holdings.get("accounts"))

    enc = _sec.encrypt(access_token)
    _ensure_plaid_tables()
    with _fund_conn() as conn, conn.cursor() as cur:
        cur.execute("""
            INSERT INTO plaid_items (item_id, institution_name, institution_id,
                                     access_token_enc, accounts_json, holdings_json,
                                     status, last_synced_at, updated_at)
            VALUES (%s,%s,%s,%s, %s::jsonb, %s::jsonb, 'active', now(), now())
            ON CONFLICT (item_id) DO UPDATE SET
                institution_name=EXCLUDED.institution_name,
                institution_id=EXCLUDED.institution_id,
                access_token_enc=EXCLUDED.access_token_enc,
                accounts_json=EXCLUDED.accounts_json,
                holdings_json=EXCLUDED.holdings_json,
                status='active', last_synced_at=now(), updated_at=now()
        """, (item_id, inst_name, inst_id, enc,
              json.dumps(accounts, default=str),
              json.dumps(holdings, default=str)))
        conn.commit()
    return {"ok": True, "item_id": item_id, "institution": inst_name, "accounts": accounts}


@app.post("/api/plaid/exchange")
def plaid_exchange(request: Request):
    """GP-only: exchange a public_token, encrypt the access_token, store it, and
    pull the first holdings snapshot. The access_token never leaves the server."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    body = _request_json_sync(request)
    public_token = (body or {}).get("public_token", "")
    if not public_token:
        raise HTTPException(400, "public_token required")
    try:
        return _plaid_ingest_public_token(public_token)
    except Exception as e:
        raise HTTPException(502, f"Plaid exchange/holdings failed: {_plaid_error_detail(e)}")


@app.get("/api/plaid/items")
def plaid_items(request: Request):
    """GP-only: connected institutions + masked accounts. No tokens returned."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return {"ok": True, "items": []}
    _ensure_plaid_tables()
    items = []
    with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
        cur.execute("""SELECT item_id, institution_name, institution_id, accounts_json,
                              status, created_at, last_synced_at, fund_id
                         FROM plaid_items WHERE status='active'
                        ORDER BY created_at""")
        for r in cur.fetchall():
            items.append({
                "item_id":        r["item_id"],
                "institution":    r["institution_name"],
                "accounts":       r["accounts_json"] or [],
                "status":         r["status"],
                "fund_id":        str(r["fund_id"]) if r["fund_id"] else None,
                "last_synced_at": r["last_synced_at"].isoformat() if r["last_synced_at"] else None,
            })
    return {"ok": True, "items": items, "managed_accounts": _plaid_managed_accounts()}


@app.post("/api/plaid/sync")
def plaid_sync(request: Request):
    """GP-only: refresh holdings for one item (or all). Decrypts the token in
    memory only, re-pulls, and stores the new snapshot."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    body = _request_json_sync(request)
    only = (body or {}).get("item_id")
    import plaid_client as _plaid
    import secure_store as _sec
    _ensure_plaid_tables()
    rows = []
    with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
        if only:
            cur.execute("SELECT item_id, access_token_enc FROM plaid_items WHERE item_id=%s AND status='active'", (only,))
        else:
            cur.execute("SELECT item_id, access_token_enc FROM plaid_items WHERE status='active'")
        rows = cur.fetchall()
    synced = []
    for r in rows:
        try:
            tok = _sec.decrypt(r["access_token_enc"])
            holdings = _plaid.get_holdings(tok)
            accounts = _plaid_accounts_summary(holdings.get("accounts"))
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("""UPDATE plaid_items SET accounts_json=%s::jsonb,
                                    holdings_json=%s::jsonb, last_synced_at=now(), updated_at=now()
                                WHERE item_id=%s""",
                            (json.dumps(accounts, default=str),
                             json.dumps(holdings, default=str), r["item_id"]))
                conn.commit()
            synced.append({"item_id": r["item_id"], "accounts": accounts})
        except Exception as e:
            synced.append({"item_id": r["item_id"], "error": str(e)[:160]})
    return {"ok": True, "synced": synced}


@app.post("/api/plaid/remove")
def plaid_remove(request: Request):
    """GP-only: disconnect an institution at Plaid and purge its stored data."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    body = _request_json_sync(request)
    item_id = (body or {}).get("item_id")
    if not item_id:
        raise HTTPException(400, "item_id required")
    import plaid_client as _plaid
    import secure_store as _sec
    _ensure_plaid_tables()
    with _fund_conn() as conn, conn.cursor() as cur:
        cur.execute("SELECT access_token_enc FROM plaid_items WHERE item_id=%s", (item_id,))
        row = cur.fetchone()
    if row:
        try:
            _plaid.remove_item(_sec.decrypt(row[0]))   # revoke at Plaid first
        except Exception as e:
            print(f"[plaid] item_remove warning {item_id}: {e!s:.120}", flush=True)
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("DELETE FROM plaid_items WHERE item_id=%s", (item_id,))
            conn.commit()
    return {"ok": True, "removed": item_id}


@app.get("/api/plaid/holdings")
def plaid_holdings(request: Request):
    """GP-only: normalized positions from each linked institution's stored holdings
    snapshot (READ-only transform of holdings_json). Does NOT read or write tax_lots,
    so the manual CSV path is unaffected. Optional ?item_id= to scope to one."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return {"ok": True, "items": []}
    only = request.query_params.get("item_id")
    _ensure_plaid_tables()
    out = []
    with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
        if only:
            cur.execute("""SELECT item_id, institution_name, holdings_json, fund_id, last_synced_at
                             FROM plaid_items WHERE status='active' AND item_id=%s""", (only,))
        else:
            cur.execute("""SELECT item_id, institution_name, holdings_json, fund_id, last_synced_at
                             FROM plaid_items WHERE status='active' ORDER BY created_at""")
        rows = cur.fetchall()
    for r in rows:
        norm = _plaid_normalize_holdings(r["holdings_json"] or {})
        out.append({
            "item_id":        r["item_id"],
            "institution":    r["institution_name"],
            "fund_id":        str(r["fund_id"]) if r["fund_id"] else None,
            "last_synced_at": r["last_synced_at"].isoformat() if r["last_synced_at"] else None,
            **norm,
        })
    return {"ok": True, "items": out, "managed_accounts": _plaid_managed_accounts()}


@app.post("/api/plaid/assign")
def plaid_assign(request: Request):
    """GP-only: link (or unlink) a Plaid connection to a managed account. This only
    sets plaid_items.fund_id — it never writes holdings into tax_lots or the CSV
    tables, so manual uploads keep working untouched. Pass fund_id=null to unlink."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    body = _request_json_sync(request)
    item_id = (body or {}).get("item_id")
    fund_id = (body or {}).get("fund_id") or None
    if not item_id:
        raise HTTPException(400, "item_id required")
    _ensure_plaid_tables()
    with _fund_conn() as conn, conn.cursor() as cur:
        if fund_id:
            cur.execute("SELECT 1 FROM funds WHERE id=%s AND fund_type IN ('managed_account','lp_fund')", (fund_id,))
            if not cur.fetchone():
                raise HTTPException(400, "Unknown managed account.")
        cur.execute("UPDATE plaid_items SET fund_id=%s, updated_at=now() WHERE item_id=%s",
                    (fund_id, item_id))
        if cur.rowcount == 0:
            raise HTTPException(404, "Unknown Plaid item.")
        conn.commit()
    return {"ok": True, "item_id": item_id, "fund_id": fund_id}


# ── SnapTrade (Fidelity holdings — Plaid can't connect Fidelity since Oct 2023) ──
@_ddl_once
def _ensure_snaptrade_tables():
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    try:
        with _fund_conn() as conn, conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS snaptrade_user (
                    user_id          TEXT PRIMARY KEY,
                    user_secret_enc  TEXT NOT NULL,
                    created_at       TIMESTAMPTZ DEFAULT now(),
                    updated_at       TIMESTAMPTZ DEFAULT now()
                )""")
            cur.execute("""
                CREATE TABLE IF NOT EXISTS snaptrade_accounts (
                    account_id        TEXT PRIMARY KEY,
                    connection_id     TEXT,
                    brokerage_name    TEXT,
                    account_name      TEXT,
                    account_mask      TEXT,
                    total_value       NUMERIC,
                    holdings_json     JSONB,
                    fund_id           UUID,
                    status            TEXT DEFAULT 'active',
                    last_synced_at    TIMESTAMPTZ,
                    created_at        TIMESTAMPTZ DEFAULT now(),
                    updated_at        TIMESTAMPTZ DEFAULT now()
                )""")
            # Migration: per-account hide so unwanted accounts (e.g. empty IRAs)
            # can be dismissed from the list WITHOUT removing the whole connection.
            cur.execute("ALTER TABLE snaptrade_accounts ADD COLUMN IF NOT EXISTS hidden BOOLEAN DEFAULT FALSE")
            # Transaction history (buys/sells/flows) — the basis for YTD trade
            # lists and external-cash-flow-aware return reconstruction.
            cur.execute("""
                CREATE TABLE IF NOT EXISTS snaptrade_activities (
                    activity_id      TEXT PRIMARY KEY,
                    account_id       TEXT,
                    trade_date       DATE,
                    settlement_date  DATE,
                    type             TEXT,
                    symbol           TEXT,
                    description      TEXT,
                    units            NUMERIC,
                    price            NUMERIC,
                    amount           NUMERIC,
                    currency         TEXT,
                    fee              NUMERIC,
                    raw_json         JSONB,
                    synced_at        TIMESTAMPTZ DEFAULT now()
                )""")
            cur.execute("CREATE INDEX IF NOT EXISTS snaptrade_activities_acct_idx "
                        "ON snaptrade_activities(account_id, trade_date)")
            # Daily account-value snapshots — the raw series behind the automatic
            # balance/returns path (one row per account per Pacific day; the daily
            # scheduler upserts so re-syncs just refresh that day's value).
            cur.execute("""
                CREATE TABLE IF NOT EXISTS snaptrade_balances (
                    account_id   TEXT NOT NULL,
                    d            DATE NOT NULL,
                    total_value  NUMERIC(20,4),
                    cash         NUMERIC(20,4),
                    synced_at    TIMESTAMPTZ DEFAULT now(),
                    PRIMARY KEY (account_id, d)
                )""")
            conn.commit()
    except Exception as e:
        print(f"[snaptrade] ensure tables failed: {e!s:.150}", flush=True)


def _snaptrade_error_detail(e) -> str:
    body = getattr(e, "body", None)
    if body:
        try:
            j = json.loads(body) if isinstance(body, str) else body
            if isinstance(j, dict):
                msg = j.get("detail") or j.get("message") or j.get("error") or ""
                code = j.get("code") or j.get("status_code") or ""
                if msg:
                    return f"{code}: {msg}".strip(": ")
        except Exception:
            pass
    txt = getattr(e, "reason", None) or getattr(e, "text", None)
    base = f"{type(e).__name__}: {str(e)}"
    return (f"{str(txt)[:200]} | {base}")[:300] if txt else base[:300]


def _snaptrade_ensure_user():
    """Return (user_id, user_secret) for the single GP SnapTrade user, registering
    one (encrypted at rest) on first use. Uses a generated userId so a lost DB row
    just mints a fresh user rather than colliding with SnapTrade's 'already exists'."""
    import snaptrade_link as _st
    import secure_store as _sec
    import uuid as _uuid
    _ensure_snaptrade_tables()
    with _fund_conn() as conn, conn.cursor() as cur:
        cur.execute("SELECT user_id, user_secret_enc FROM snaptrade_user ORDER BY created_at LIMIT 1")
        row = cur.fetchone()
    if row:
        return row[0], _sec.decrypt(row[1])
    uid = "dga-gp-" + _uuid.uuid4().hex[:12]
    reg = _st.register_user(uid)
    secret = reg.get("userSecret") if isinstance(reg, dict) else None
    if not secret:
        raise RuntimeError("SnapTrade registration returned no userSecret")
    enc = _sec.encrypt(secret)
    with _fund_conn() as conn, conn.cursor() as cur:
        cur.execute("INSERT INTO snaptrade_user (user_id, user_secret_enc, updated_at) VALUES (%s,%s,now())", (uid, enc))
        conn.commit()
    return uid, secret


def _snaptrade_user_invalid(err: str) -> bool:
    """True when SnapTrade rejects our stored user — code 1083 'Invalid userID
    or userSecret'. Happens after a key swap: users are scoped to a clientId,
    so a user registered under the old (free) client is invalid under the new
    production client."""
    low = (err or "").lower()
    return "1083" in low or "invalid userid" in low or "invalid usersecret" in low


def _snaptrade_reset_stale_user() -> None:
    """Purge the stored SnapTrade user + account rows so _snaptrade_ensure_user
    re-registers under the CURRENT client id. Saves each account's fund
    assignment (keyed by mask+name — account ids change with the client) to
    kv so the first sync after re-linking restores it automatically."""
    import snaptrade_link as _st
    import secure_store as _sec
    with _fund_conn() as conn, conn.cursor() as cur:
        # Back up assignments before wiping.
        backup = {}
        try:
            cur.execute("SELECT account_mask, account_name, fund_id FROM snaptrade_accounts "
                        "WHERE fund_id IS NOT NULL AND account_id NOT LIKE 'demo-%'")
            for mask, name, fid in cur.fetchall():
                backup[f"{mask or ''}|{(name or '').strip().lower()}"] = str(fid)
        except Exception:
            pass
        if backup:
            try:
                _kv_put("snaptrade.assignment_backup", backup)
            except Exception:
                pass
        # Best-effort delete of the old user at SnapTrade (fails under the new
        # client id — that's fine, it belongs to the old one).
        try:
            cur.execute("SELECT user_id, user_secret_enc FROM snaptrade_user ORDER BY created_at LIMIT 1")
            row = cur.fetchone()
            if row:
                try:
                    _st.delete_user(row[0])
                except Exception:
                    pass
        except Exception:
            pass
        # Wipe user + per-client data. Activities/balances reference old
        # account ids that can never sync again under the new client.
        cur.execute("DELETE FROM snaptrade_user")
        # Demo sandbox rows (account_id 'demo-…') are synthetic, not tied to
        # any SnapTrade client — a key-swap purge must leave them alone.
        cur.execute("DELETE FROM snaptrade_accounts WHERE account_id NOT LIKE 'demo-%'")
        cur.execute("DELETE FROM snaptrade_activities WHERE account_id NOT LIKE 'demo-%'")
        cur.execute("DELETE FROM snaptrade_balances WHERE account_id NOT LIKE 'demo-%'")
        conn.commit()
    print("[snaptrade] stale user reset — re-register under current client id", flush=True)


def _snaptrade_mask(num) -> str | None:
    if not num:
        return None
    s = str(num)
    return s[-4:] if len(s) >= 4 else s


def _snaptrade_symbol(pos: dict):
    """Drill SnapTrade's nested PositionSymbol → (ticker, description)."""
    node = pos.get("symbol")
    ticker, desc = None, None
    seen = 0
    while isinstance(node, dict) and seen < 6:
        if not ticker and isinstance(node.get("raw_symbol"), str):
            ticker = node.get("raw_symbol")
        if not desc and node.get("description"):
            desc = node.get("description")
        nxt = node.get("symbol")
        if isinstance(nxt, str):
            ticker = ticker or nxt
            break
        node = nxt
        seen += 1
    if isinstance(node, str) and not ticker:
        ticker = node
    return ticker, desc


def _snaptrade_normalize_account(ah: dict) -> dict:
    """One SnapTrade account-holding → normalized positions in the SAME shape as
    the Plaid normalizer (symbol, name, quantity, price, market_value, cost_basis)."""
    acct = ah.get("account") or {}
    positions, total_value, total_cost = [], 0.0, 0.0
    for p in (ah.get("positions") or []):
        ticker, desc = _snaptrade_symbol(p)
        units = p.get("units")
        price = p.get("price")
        avg = p.get("average_purchase_price")
        mv = cost = None
        try:
            if units is not None and price is not None:
                mv = float(units) * float(price); total_value += mv
        except Exception:
            pass
        try:
            if units is not None and avg is not None:
                cost = float(units) * float(avg); total_cost += cost
        except Exception:
            pass
        positions.append({
            "symbol": ticker or "—", "name": desc,
            "asset_class": "cash" if p.get("cash_equivalent") else "equity",
            "quantity": units, "price": price, "market_value": mv, "cost_basis": cost,
            "cost_basis_per_unit": avg,
        })
    positions.sort(key=lambda x: (x.get("market_value") or 0), reverse=True)
    tv = ah.get("total_value")
    if isinstance(tv, dict):
        tv = tv.get("value")
    if tv is None:
        # Fall back to the account's reported balance, then the summed positions.
        bal = acct.get("balance") or {}
        tot = bal.get("total") if isinstance(bal, dict) else None
        if isinstance(tot, dict):
            tv = tot.get("amount")
        elif isinstance(bal, (int, float)):
            tv = bal
    if tv is None:
        tv = total_value
    brk = acct.get("institution_name")
    if not brk and isinstance(acct.get("brokerage"), dict):
        brk = acct["brokerage"].get("name")
    conn_id = acct.get("brokerage_authorization")
    if isinstance(conn_id, dict):
        conn_id = conn_id.get("id")
    return {
        "account_id":    acct.get("id"),
        "connection_id": conn_id,
        "brokerage":     brk,
        "account_name":  acct.get("name"),
        "account_mask":  _snaptrade_mask(acct.get("number")),
        "total_value":   tv,
        "positions":     positions,
        "count":         len(positions),
    }


def _snaptrade_normalize_options(raw) -> list:
    """SnapTrade OptionsPosition list → normalized rows in the same shape as
    _snaptrade_normalize_account's positions. Short contracts keep their negative
    units (Alec sells covered calls / CSPs); market value uses the ×100 contract
    multiplier. These rows are display/valuation-only — _snaptrade_write_lots
    excludes asset_class='option' so tax_lots stays share-based like the CSV path."""
    if isinstance(raw, dict):
        raw = raw.get("option_positions") or raw.get("positions") or raw.get("data") or []
    out = []
    for p in (raw or []):
        if not isinstance(p, dict):
            continue
        node = p.get("symbol")
        occ, desc, under, otype, strike, expiry = None, None, None, None, None, None
        seen = 0
        while isinstance(node, dict) and seen < 6:
            if not desc and node.get("description"):
                desc = node.get("description")
            occ    = occ    or node.get("ticker") or node.get("raw_symbol")
            otype  = otype  or node.get("option_type")
            strike = strike if strike is not None else node.get("strike_price")
            expiry = expiry or node.get("expiration_date")
            us = node.get("underlying_symbol")
            if isinstance(us, dict):
                under = under or us.get("symbol") or us.get("raw_symbol")
            nxt = node.get("option_symbol") or node.get("symbol")
            if isinstance(nxt, str):
                occ = occ or nxt
                break
            node = nxt
            seen += 1
        units = _snaptrade_num(p.get("units"))
        price = _snaptrade_num(p.get("price"))
        mv = (units * price * 100.0) if (units is not None and price is not None) else None
        avg = _snaptrade_num(p.get("average_purchase_price"))
        label = occ
        if not label and under and otype and strike is not None and expiry:
            label = f"{under} {str(expiry)[:10]} {str(otype)[:1]}{strike}"
        if not label:
            continue
        if not desc and under:
            side = "short" if (units or 0) < 0 else "long"
            desc = f"{under} {otype or 'option'} ({side})"
        out.append({
            "symbol": label, "name": desc, "asset_class": "option",
            "underlying": under, "quantity": units, "price": price,
            "market_value": mv,
            "cost_basis": (units * avg * 100.0) if (units is not None and avg is not None) else None,
            "cost_basis_per_unit": avg,
        })
    return out


def _snaptrade_write_lots(cur, fund_id: str, positions: list) -> int:
    """Make SnapTrade the LIVE position source for one fund.

    DIFF-BASED (ui336): if the desired positions match the fund's open lots
    (same symbols, quantities, per-unit costs), this is a NO-OP — no lots
    rewritten, no adjustment transaction. The old behavior closed ALL open
    lots and reinserted with acquired_at=NOW() on every daily sync, which
    (a) reset every position's first-acquired date each morning and
    (b) accrued one ledger adjustment per fund per day. When positions DID
    change, the rewrite still happens, but each surviving symbol carries its
    earliest previous acquired_at forward.

    Mirrors the YTD-CSV positions-sync path (close open → adjustment txn →
    transaction_lines → tax_lots), so the Positions panel + live NAV reflect
    Fidelity. Does NOT touch managed_account_ytd_cache / account_balance_history.
    `cur` must be a RealDictCursor. Returns the number of open lots.

    Passing positions=[] closes the fund's open lots (used on unassign).
    """
    # Keep only real, positive-quantity rows with a symbol. Option positions are
    # valuation-only (often short/negative, priced per-contract) — tax_lots is
    # share-based, matching the manual CSV import which never carried options.
    rows = []
    for p in (positions or []):
        sym = (p.get("symbol") or "").strip()
        try:
            qty = float(p.get("quantity"))
        except (TypeError, ValueError):
            qty = 0.0
        if not sym or sym == "—" or qty <= 0 or p.get("asset_class") == "option":
            continue
        rows.append((p, sym, qty))

    # Existing open lots, aggregated per symbol.
    cur.execute("""
        SELECT s.symbol, SUM(t.quantity) AS qty,
               SUM(t.quantity * t.cost_basis_per_unit) AS cost,
               MIN(t.acquired_at) AS first_acquired
          FROM tax_lots t JOIN securities s ON s.id = t.security_id
         WHERE t.fund_id = %s AND t.closed_at IS NULL
         GROUP BY s.symbol
    """, (fund_id,))
    existing = {}
    acquired_map = {}
    for r in cur.fetchall():
        q = float(r["qty"] or 0)
        pu = (float(r["cost"] or 0) / q) if q else 0.0
        existing[r["symbol"]] = (q, pu)
        acquired_map[r["symbol"]] = r["first_acquired"]

    def _per_unit(p):
        try:
            v = p.get("cost_basis_per_unit")
            return float(v) if v is not None else 0.0
        except (TypeError, ValueError):
            return 0.0

    desired = {sym: (qty, _per_unit(p)) for p, sym, qty in rows}
    unchanged = (set(desired) == set(existing) and all(
        abs(desired[s][0] - existing[s][0]) < 1e-4
        and abs(desired[s][1] - existing[s][1]) < 0.01
        for s in desired))
    if unchanged:
        return len(rows)

    _seed_coa_for_fund(cur, fund_id)
    cur.execute("""SELECT code, id FROM accounts
                    WHERE fund_id=%s AND code IN ('1020','1030','1100','3000')""", (fund_id,))
    acct_map = {r["code"]: str(r["id"]) for r in cur.fetchall()}
    sec_acct = acct_map.get("1100")
    mm_acct  = acct_map.get("1030") or acct_map.get("1020")
    cap_acct = acct_map.get("3000")
    if not (sec_acct and cap_acct):
        raise RuntimeError(f"fund {fund_id} missing chart-of-accounts (1100/3000)")

    # Close existing open lots so re-syncing never double-counts.
    cur.execute("UPDATE tax_lots SET closed_at=NOW() WHERE fund_id=%s AND closed_at IS NULL",
                (fund_id,))
    if not rows:
        return 0

    # Upsert securities, capturing ids.
    sec_ids = {}
    for p, sym, _qty in rows:
        is_cash = (p.get("asset_class") == "cash")
        cur.execute("""
            INSERT INTO securities (symbol, name, asset_class, is_public)
            VALUES (%s, %s, %s, %s)
            ON CONFLICT (symbol) DO UPDATE
                SET name=EXCLUDED.name, asset_class=EXCLUDED.asset_class,
                    is_public=EXCLUDED.is_public
            RETURNING id
        """, (sym, p.get("name") or sym, "cash" if is_cash else "equity", not is_cash))
        sec_ids[sym] = str(cur.fetchone()["id"])

    today_iso = datetime.utcnow().date().isoformat()
    cur.execute("""
        INSERT INTO transactions (fund_id, effective_date, category, description)
        VALUES (%s, %s, 'adjustment', 'Position import from SnapTrade (Fidelity)')
        RETURNING id
    """, (fund_id, today_iso))
    txn_id = str(cur.fetchone()["id"])

    total_cost = 0.0
    ln = 1
    for p, sym, qty in rows:
        per_unit = p.get("cost_basis_per_unit")
        try:
            per_unit = float(per_unit) if per_unit is not None else 0.0
        except (TypeError, ValueError):
            per_unit = 0.0
        cost = qty * per_unit
        if cost > 0:
            total_cost += cost
            acct = mm_acct if p.get("asset_class") == "cash" else sec_acct
            if acct:
                cur.execute("""INSERT INTO transaction_lines
                                 (transaction_id, line_number, account_id, debit, security_id)
                               VALUES (%s,%s,%s,%s,%s)""",
                            (txn_id, ln, acct, round(cost, 4), sec_ids[sym]))
                ln += 1
        cur.execute("""INSERT INTO tax_lots
                         (fund_id, security_id, acquired_at, quantity,
                          cost_basis_per_unit, open_transaction_id)
                       VALUES (%s,%s,COALESCE(%s, NOW()),%s,%s,%s)""",
                    (fund_id, sec_ids[sym], acquired_map.get(sym), qty, per_unit, txn_id))
    if total_cost > 0:
        cur.execute("""INSERT INTO transaction_lines
                         (transaction_id, line_number, account_id, credit)
                       VALUES (%s,%s,%s,%s)""",
                    (txn_id, ln, cap_acct, round(total_cost, 4)))
    return len(rows)


def _snaptrade_recompute_fund(cur, fund_id: str) -> int:
    """Rewrite a fund's live tax_lots from the stored holdings of EVERY active
    SnapTrade account currently assigned to it. If none are assigned, this just
    closes the fund's open lots. `cur` must be a RealDictCursor."""
    cur.execute("SELECT holdings_json FROM snaptrade_accounts "
                "WHERE status='active' AND fund_id=%s", (fund_id,))
    poss = []
    for r in cur.fetchall():
        hj = r["holdings_json"]
        if isinstance(hj, str):
            try:
                hj = json.loads(hj)
            except Exception:
                hj = []
        if isinstance(hj, list):
            poss.extend(hj)
    return _snaptrade_write_lots(cur, fund_id, poss)


def _snaptrade_activity_symbol(a: dict):
    """Ticker from a SnapTrade activity (equity `symbol` or `option_symbol`)."""
    node = a.get("symbol")
    if isinstance(node, dict):
        for k in ("raw_symbol", "symbol"):
            v = node.get(k)
            if isinstance(v, str):
                return v
            if isinstance(v, dict):
                for k2 in ("raw_symbol", "symbol"):
                    if isinstance(v.get(k2), str):
                        return v[k2]
    if isinstance(node, str):
        return node
    opt = a.get("option_symbol")
    if isinstance(opt, dict):
        return opt.get("ticker") or opt.get("raw_symbol")
    return None


def _snaptrade_num(v):
    try:
        return float(v) if v is not None else None
    except (TypeError, ValueError):
        return None


def _snaptrade_parse_activity(a: dict) -> dict | None:
    """Normalize one SnapTrade UniversalActivity → flat row for snaptrade_activities."""
    if not isinstance(a, dict):
        return None
    aid = a.get("id") or a.get("activity_id")
    if not aid:
        return None
    cur = a.get("currency")
    if isinstance(cur, dict):
        cur = cur.get("code")
    acct = a.get("account")
    acct_id = acct.get("id") if isinstance(acct, dict) else acct
    return {
        "activity_id":     str(aid),
        "account_id":      str(acct_id) if acct_id else None,
        # Key variants: the legacy combined endpoint says trade_date/
        # settlement_date; the per-account endpoint (the one that actually
        # works on current plans) may say date / settled_at.
        "trade_date":      (a.get("trade_date") or a.get("date") or "")[:10] or None,
        "settlement_date": (a.get("settlement_date") or a.get("settled_at")
                            or a.get("settled_date") or "")[:10] or None,
        "type":            (a.get("type") or "").upper() or None,
        "symbol":          _snaptrade_activity_symbol(a),
        "description":     a.get("description"),
        "units":           _snaptrade_num(a.get("units")),
        "price":           _snaptrade_num(a.get("price")),
        "amount":          _snaptrade_num(a.get("amount")),
        "currency":        cur,
        "fee":             _snaptrade_num(a.get("fee")),
    }


# Activity-type buckets for YTD math. ("REI" = reinvestment as delivered by
# the per-account endpoint — confirmed from the live row census 2026-07-02.)
_SNAP_BUY_TYPES   = {"BUY", "REINVESTMENT", "DRIP", "REI"}
_SNAP_SELL_TYPES  = {"SELL"}
# External cash flows (move money in/out of the account; not performance).
_SNAP_FLOW_TYPES  = {"CONTRIBUTION", "DEPOSIT", "WITHDRAWAL", "TRANSFER",
                     "TRANSFER_IN", "TRANSFER_OUT", "FUNDING"}
# Income/expense buckets for the automatic monthly balance records.
_SNAP_DIV_TYPES   = {"DIVIDEND", "CASH_DIVIDEND"}
_SNAP_INT_TYPES   = {"INTEREST"}
_SNAP_FEE_TYPES   = {"FEE", "MANAGEMENT_FEE", "ADMINISTRATIVE_FEE"}

# Money-market / core-cash symbols — cash sweeps "trade" constantly (every
# deposit/settlement buys or sells the sweep), so letting them into per-stock
# attribution booked millions of sweep churn as stock trading (the SPAXX
# −$2.75M incident). Fidelity/typical MM tickers end in XX.
_SNAP_MM_SYMBOLS = {"SPAXX", "FDRXX", "FZFXX", "FZDXX", "FCASH", "CORE"}


def _snaptrade_cashlike(sym: str) -> bool:
    s = (sym or "").strip().upper()
    return s in _SNAP_MM_SYMBOLS or (len(s) >= 4 and s.endswith("XX"))


def _snaptrade_pacific_today():
    """Civil date in the user's timezone — snapshot rows key on this so the
    6:00-Pacific scheduler and a late-night manual sync land on the same day."""
    try:
        from zoneinfo import ZoneInfo
        return datetime.now(ZoneInfo("America/Los_Angeles")).date()
    except Exception:
        return datetime.utcnow().date()


def _snaptrade_plan_gated(err: str) -> bool:
    """True when a SnapTrade error means the endpoint isn't on our plan (the
    free key gates get_activities — the pay-as-you-go production key unlocks it)."""
    low = (err or "").lower()
    return ("no longer available" in low or "not available for your account" in low
            or "upgrade" in low or "1020" in low)


def _snaptrade_ingest_activities(uid: str, secret: str, acct_ids: list,
                                 start: str | None = None, end: str | None = None):
    """Upsert transaction history into snaptrade_activities for the given
    accounts. Window: explicit [start, end] when passed (manual endpoint);
    otherwise per-account — Jan-1 backfill on first sync, then a rolling
    35-day incremental. Returns (synced, errors); a plan-gated failure is
    reported once with a production-key hint instead of per account."""
    import snaptrade_link as _st
    today = datetime.utcnow().date()
    default_end = end or today.isoformat()
    synced, errors = [], []
    gated_reported = False
    # One autocommit connection for the whole ingest (was: two per account).
    conn = _fund_conn()
    conn.autocommit = True
    cur = conn.cursor()
    try:
        for acct_id in acct_ids:
            bf_key = f"snaptrade.activities_backfilled.{acct_id}"
            full_backfill = False
            if start:
                a_start = start
            else:
                # Completeness flag, NOT row-existence: the killed first import
                # left RECENT rows behind, so max(trade_date) made every later
                # sync incremental-only and Jan–May trades were never pulled —
                # closed positions (WBD/TSM/NKE) vanished from attribution and
                # partial histories flipped signs (HAL). Full-year backfill
                # until a COMPLETE Jan-1 fetch succeeds for the current year.
                try:
                    bf = _kv_get(bf_key)
                except Exception:
                    bf = None
                if str(bf or "") != str(today.year):
                    a_start = f"{today.year}-01-01"
                    full_backfill = True
                else:
                    cur.execute("SELECT max(trade_date) FROM snaptrade_activities WHERE account_id=%s",
                                (acct_id,))
                    row = cur.fetchone()
                    last_td = row[0] if row else None
                    if not last_td:
                        a_start = f"{today.year}-01-01"
                        full_backfill = True
                    else:
                        # Rolling 35-day incremental; never leave a gap if the
                        # app was down for longer.
                        base = today - timedelta(days=35)
                        if last_td < base:
                            base = last_td - timedelta(days=3)
                        a_start = base.isoformat()
            _snaptrade_sync_stage(f"Importing activity (…{str(acct_id)[-4:]})…")
            # Timeout-guarded fetch (the SDK has none): a hung SnapTrade call
            # was the likely core of the 36-minute-sync incident. The wrapper
            # swallows exceptions, so capture the error explicitly to keep the
            # plan-gating detection working.
            _res: dict = {}

            def _fetch(a=acct_id, s=a_start):
                try:
                    _res["acts"] = _st.get_account_activities(uid, secret, a, s, default_end)
                except Exception as e:
                    _res["err"] = e
            _builder_call_timeout(_fetch, 180.0, None)
            if "err" in _res:
                detail = _snaptrade_error_detail(_res["err"])
                if _snaptrade_plan_gated(detail):
                    if not gated_reported:
                        errors.append({"stage": "activities", "error":
                            "SnapTrade transactions are gated on this plan. "
                            f"({detail[:120]})"})
                        gated_reported = True
                else:
                    errors.append({"account_id": acct_id, "stage": "activities", "error": detail})
                continue
            if "acts" not in _res:
                errors.append({"account_id": acct_id, "stage": "activities",
                               "error": "SnapTrade activities fetch timed out (180s) — retried next sync"})
                continue
            acts = _res["acts"]
            # Dedup by activity id (pagination overlap would make the batched
            # ON CONFLICT fail: 'cannot affect row a second time'), then upsert
            # in 500-row batches — the per-row autocommit round-trips made the
            # first 6-month backfill crawl.
            rows_by_id: dict = {}
            for a in (acts or []):
                p = _snaptrade_parse_activity(a)
                if not p:
                    continue
                p["account_id"] = p["account_id"] or acct_id
                rows_by_id[p["activity_id"]] = (
                    p["activity_id"], p["account_id"], p["trade_date"], p["settlement_date"],
                    p["type"], p["symbol"], p["description"], p["units"], p["price"],
                    p["amount"], p["currency"], p["fee"], json.dumps(a, default=str))
            rows = list(rows_by_id.values())
            n = 0
            upsert_failed = False
            if rows:
                from psycopg2.extras import execute_values as _ev
                for i in range(0, len(rows), 500):
                    chunk = rows[i:i + 500]
                    try:
                        _ev(cur, """
                            INSERT INTO snaptrade_activities
                                (activity_id, account_id, trade_date, settlement_date, type, symbol,
                                 description, units, price, amount, currency, fee, raw_json, synced_at)
                            VALUES %s
                            ON CONFLICT (activity_id) DO UPDATE SET
                                account_id=EXCLUDED.account_id, trade_date=EXCLUDED.trade_date,
                                settlement_date=EXCLUDED.settlement_date, type=EXCLUDED.type,
                                symbol=EXCLUDED.symbol, description=EXCLUDED.description,
                                units=EXCLUDED.units, price=EXCLUDED.price, amount=EXCLUDED.amount,
                                currency=EXCLUDED.currency, fee=EXCLUDED.fee,
                                raw_json=EXCLUDED.raw_json, synced_at=now()
                        """, chunk,
                            template="(%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s::jsonb, now())")
                        n += len(chunk)
                    except Exception as e:
                        upsert_failed = True
                        errors.append({"account_id": acct_id, "stage": "activity_upsert",
                                       "error": _snaptrade_error_detail(e)})
            # Mark the year's backfill complete ONLY after a clean full run —
            # fetch succeeded (no timeout) and every chunk landed.
            if full_backfill and not upsert_failed:
                try:
                    _kv_put(bf_key, str(today.year))
                except Exception:
                    pass
            synced.append({"account_id": acct_id, "activities": n, "since": a_start})
    finally:
        try:
            cur.close()
            conn.close()
        except Exception:
            pass
    return synced, errors


# Per-process failure counts for Jan-1 close prewarm (see the prewarm loop).
_JAN1_FAIL: dict = {}


def _sync_jan1_close(sym: str, year: int) -> None:
    """Fetch ONLY a ~5-week window of daily closes around Jan 1 of `year` and
    upsert into price_history. _sync_price_history was the wrong tool for
    attribution prewarm: its first call per symbol backfills ~11 YEARS
    (thousands of single-row inserts) — 40 of those wedged the whole app
    (ui343 incident). Attribution needs exactly one close on/before Jan 1."""
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return
    try:
        import market_data as _md
        start = f"{year - 1}-12-10"
        end   = f"{year}-01-15"
        # Fetch with the provider-format symbol (BRKB→BRK-B, NLYPRF→NLY-PF);
        # rows are stored under the ORIGINAL symbol so attribution lookups hit.
        # adjusted=True: Jan-1 closes feed the rewind — raw pre-split bars
        # doubled BSX's apparent Jan-1 value (−$124K phantom loss).
        bars = _md.get_price_history(_resolve_ticker_alias(sym), interval="daily",
                                     start=start, end=end, adjusted=True)
        if not bars:
            return
        src = "yahoo"
        with _fund_conn() as conn, conn.cursor() as cur:
            for b in bars:
                if not b.get("date") or b.get("close") is None:
                    continue
                cur.execute("""INSERT INTO price_history (symbol, d, close, source, updated_at)
                               VALUES (%s,%s,%s,%s, now())
                               ON CONFLICT (symbol, d) DO UPDATE SET
                                 close=EXCLUDED.close, source=EXCLUDED.source, updated_at=now()""",
                            (sym, b["date"], b["close"], src))
            conn.commit()
    except Exception as e:
        print(f"[price-hist] jan1 {sym} failed: {e!s:.120}", flush=True)


def _snaptrade_build_attribution(cur, fund_id: str, year: int, begin_value: float) -> list:
    """Per-stock YTD attribution built automatically from SnapTrade data —
    replaces the manual positions+activity CSV run as the attribution source.

    Per symbol (current equity holdings ∪ symbols traded YTD, so full exits
    are covered): rewind YTD buys/sells to get Jan-1 shares, price them from
    price_history, and compute
        dollar_gain = end_value − jan1_value − (buy_cost − sell_proceeds) + dividends.
    Output rows match renderAcctAttribution: ticker, end_shares, jan1_price,
    end_price, dollar_gain, ticker_return_pct, contribution_pct (vs the
    account's Jan-1 balance). Cash and option rows are excluded (options are
    per-contract and covered by the account-level balance history).
    `cur` must be a RealDictCursor. Returns [] when there's nothing to build.
    """
    jan1 = f"{year}-01-01"
    # Demo partition: demo funds only ever match demo accounts' legs and
    # vice versa — synthetic transfers must never anchor real attribution.
    _demo_part = str(fund_id).lower() in {
        str(x).lower() for x in ((_demo_registry() or {}).get("fund_ids") or [])}
    holdings = _snaptrade_fund_holdings(cur, fund_id)
    holdings = {s: h for s, h in holdings.items()
                if h.get("asset_class") not in ("cash", "option")
                and not _snaptrade_cashlike(s)}

    # YTD trade + dividend aggregation per symbol, RAW rows aggregated in
    # Python for full control over option handling:
    #  • contract premium trades (BUY/SELL with an option marker) are excluded
    #    from share math — counting contracts as shares flipped signs (INTC);
    #  • ASSIGNMENT / EXERCISE rows ARE share movements at the strike — Alec
    #    exits most positions via covered-call assignment, and excluding these
    #    erased every called-away sale (the BKLN/HAL/DIS dash incident):
    #    call → shares out (sell), put → shares in (buy), 100/contract;
    #  • rows missing units/price but carrying a cash amount still credit
    #    cost/proceeds from the amount.
    def _apply_row(e: dict, r) -> None:
        """One activity row → aggregate. CENSUS FACTS (2026-07-02): units are
        SIGNED (sells negative) — |units| with direction from TYPE; option
        rows stay out (assignment SHARE legs arrive as plain SELLs); rows
        missing units/price credit cost/proceeds from |amount|. TRANSFER rows
        WITH units are in-kind share moves at the transfer's marked value."""
        t = (r["type"] or "").upper()
        u   = float(r["units"] or 0)
        px  = float(r["price"] or 0)
        amt = float(r["amount"] or 0)
        opt = r["opt"]
        if isinstance(opt, str):
            try:
                opt = json.loads(opt)
            except Exception:
                opt = None
        if bool(opt) or "OPTION" in t:
            return
        u_abs = abs(u)
        gross = (u_abs * px) if (u_abs and px) else abs(amt)
        if t in _SNAP_FLOW_TYPES:
            # Transfers move SHARES + (maybe) a marked value. Units ALWAYS
            # move — zero-valued legs (outbound/fractional in-kind legs often
            # carry amount:0) must not null the symbol outright: matching
            # consumes them first (a matched leg needs no value at all), and
            # only a RESIDUAL unmatched unvalued leg nulls the gain. Value
            # rides xfer_net_val; trade stats stay pure (exit avg / SOLD use
            # real sells only).
            if u_abs > 1e-9:
                val = abs(amt)
                side = "in" if u > 0 else "out"
                e["net_units"] += u_abs if u > 0 else -u_abs
                e[f"xfer_{side}_units"] = e.get(f"xfer_{side}_units", 0.0) + u_abs
                if val > 0:
                    e[f"xfer_{side}_val"] = e.get(f"xfer_{side}_val", 0.0) + val
                    e["xfer_net_val"] = e.get("xfer_net_val", 0.0) + (val if u > 0 else -val)
                else:
                    e[f"xfer_{side}_unval"] = e.get(f"xfer_{side}_unval", 0.0) + u_abs
                e["had_unit_transfer"] = True
            return
        if t in _SNAP_BUY_TYPES:
            e["net_units"] += u_abs
            e["buy_cost"] += gross
            e["bought_units"] += u_abs
        elif t in _SNAP_SELL_TYPES:
            e["net_units"] -= u_abs
            e["sell_proceeds"] += gross
            e["sold_units"] += u_abs
        elif t in _SNAP_DIV_TYPES:
            e["dividends"] += amt

    def _new_agg() -> dict:
        return {"net_units": 0.0, "buy_cost": 0.0, "sell_proceeds": 0.0,
                "dividends": 0.0, "bought_units": 0.0, "sold_units": 0.0}

    cur.execute("""
        SELECT a.symbol, a.type, a.units, a.price, a.amount,
               a.raw_json -> 'option_symbol' AS opt
          FROM snaptrade_activities a
          JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
         WHERE sa.fund_id = %s AND a.trade_date >= %s AND a.symbol IS NOT NULL
    """, (fund_id, jan1))
    trades = {}
    for r in cur.fetchall():
        sym = (r["symbol"] or "").strip()
        if not sym:
            continue
        _apply_row(trades.setdefault(sym, _new_agg()), r)

    # CROSS-ACCOUNT LEG MATCH: an in-kind transfer between Alec's OWN linked
    # accounts is consolidation, not new money — but the fix must be scoped
    # to THE TRANSFERRED SHARES ONLY. (The first stitch merged the source
    # account's ENTIRE ticker history and inflated ANAT-DEF's INTC to $890K
    # with the old account's separate Jan–Apr sales.) For each transfer leg
    # in this fund, look for the OPPOSITE leg in OTHER linked accounts; the
    # matched quantity is neutralized — units drop out of the flow so the
    # Jan-1 rewind treats those shares as held-through, and the marked value
    # is removed. Unmatched (external-source) legs keep the marked-value
    # anchor. The counterparty account's own buys/sells stay in ITS books.
    xfer_syms = [s for s, e in trades.items()
                 if e.get("xfer_in_units") or e.get("xfer_out_units")]
    if xfer_syms:
        # Source-side stats across OTHER linked accounts: transfer legs PLUS
        # the source's own buys/sells and holdings, so matched transfers can
        # re-anchor at the source's BLENDED BASIS — Jan-1 close for shares it
        # held on Jan 1, average buy cost for shares it bought this year
        # (pro-rata pool). Jan-1-anchoring everything showed BSX/CRM at
        # −$124K/−$54K when the old IRA bought them mid-year at $50/$179.
        cur.execute("""
            SELECT UPPER(a.symbol) AS sym,
                   SUM(CASE WHEN UPPER(COALESCE(a.type,'')) = ANY(%s)
                             AND a.units > 0 THEN a.units ELSE 0 END)  AS in_units,
                   SUM(CASE WHEN UPPER(COALESCE(a.type,'')) = ANY(%s)
                             AND a.units < 0 THEN -a.units ELSE 0 END) AS out_units,
                   SUM(CASE WHEN UPPER(COALESCE(a.type,'')) = ANY(%s)
                             AND jsonb_typeof(a.raw_json -> 'option_symbol') IS DISTINCT FROM 'object'
                             AND POSITION('OPTION' IN UPPER(COALESCE(a.type,''))) = 0
                        THEN ABS(COALESCE(a.units, 0)) ELSE 0 END)     AS bought_units,
                   SUM(CASE WHEN UPPER(COALESCE(a.type,'')) = ANY(%s)
                             AND jsonb_typeof(a.raw_json -> 'option_symbol') IS DISTINCT FROM 'object'
                             AND POSITION('OPTION' IN UPPER(COALESCE(a.type,''))) = 0
                        THEN COALESCE(ABS(a.units) * NULLIF(a.price, 0), ABS(a.amount), 0)
                        ELSE 0 END)                                    AS buy_cost,
                   SUM(CASE WHEN UPPER(COALESCE(a.type,'')) = ANY(%s)
                             AND jsonb_typeof(a.raw_json -> 'option_symbol') IS DISTINCT FROM 'object'
                             AND POSITION('OPTION' IN UPPER(COALESCE(a.type,''))) = 0
                        THEN ABS(COALESCE(a.units, 0)) ELSE 0 END)     AS sold_units
              FROM snaptrade_activities a
              JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
             WHERE sa.status = 'active'
               AND (sa.fund_id IS NULL OR sa.fund_id::text <> %s)
               AND (sa.account_id LIKE 'demo-%%') = %s
               AND a.trade_date >= %s
               AND UPPER(a.symbol) = ANY(%s)
             GROUP BY 1
        """, (list(_SNAP_FLOW_TYPES), list(_SNAP_FLOW_TYPES),
              list(_SNAP_BUY_TYPES), list(_SNAP_BUY_TYPES), list(_SNAP_SELL_TYPES),
              str(fund_id), _demo_part, jan1, [s.upper() for s in xfer_syms]))
        src_stats = {r["sym"]: {"in": float(r["in_units"] or 0),
                                "out": float(r["out_units"] or 0),
                                "bought_units": float(r["bought_units"] or 0),
                                "buy_cost": float(r["buy_cost"] or 0),
                                "sold_units": float(r["sold_units"] or 0)}
                     for r in cur.fetchall()}
        other_legs = {k: {"in": v["in"], "out": v["out"]} for k, v in src_stats.items()}
        # Source accounts' current holdings per symbol (for the Jan-1 rewind
        # of the SOURCE pool).
        src_hold: dict = {}
        cur.execute("""SELECT holdings_json FROM snaptrade_accounts
                        WHERE status='active' AND (fund_id IS NULL OR fund_id::text <> %s)
                          AND (account_id LIKE 'demo-%%') = %s""",
                    (str(fund_id), _demo_part))
        for hr in cur.fetchall():
            hj = hr["holdings_json"]
            if isinstance(hj, str):
                try:
                    hj = json.loads(hj)
                except Exception:
                    hj = []
            for p in (hj or []):
                ps = (p.get("symbol") or "").strip().upper()
                if ps:
                    src_hold[ps] = src_hold.get(ps, 0.0) + (_snaptrade_num(p.get("quantity")) or 0.0)

        def _consume_leg(e: dict, qty: float, side: str) -> None:
            """Neutralize `qty` units of the fund's `side` transfer legs:
            unvalued units first (they carry nothing to remove), then valued
            proportionally out of xfer_net_val."""
            unval_k, val_k, units_k = f"xfer_{side}_unval", f"xfer_{side}_val", f"xfer_{side}_units"
            unval = e.get(unval_k, 0.0)
            valued_units = max(e.get(units_k, 0.0) - unval, 0.0)
            m_unval = min(qty, unval)
            e[unval_k] = unval - m_unval
            rem = qty - m_unval
            if rem > 1e-9 and valued_units > 1e-9:
                remove = e.get(val_k, 0.0) * min(rem / valued_units, 1.0)
                e[val_k] = e.get(val_k, 0.0) - remove
                e["xfer_net_val"] = e.get("xfer_net_val", 0.0) + (-remove if side == "in" else remove)
            e[units_k] = max(e.get(units_k, 0.0) - qty, 0.0)

        for s in xfer_syms:
            e = trades[s]
            # 1) INTERNAL pairing — both legs inside this fund's scope (e.g. a
            #    source account assigned to the same fund): units already net
            #    to zero in net_units; cancel the leg values against each other.
            m_int = min(e.get("xfer_in_units", 0.0), e.get("xfer_out_units", 0.0))
            if m_int > 1e-9:
                _consume_leg(e, m_int, "in")
                _consume_leg(e, m_int, "out")
            legs = other_legs.get(s.upper()) or {"in": 0.0, "out": 0.0}
            # 2) fund IN ↔ other-account OUT → re-anchor the matched shares at
            #    the SOURCE's blended basis: Jan-1 close for the fraction it
            #    held on Jan 1, average buy cost for the fraction it bought
            #    this year (pro-rata pool). This is what makes INTC (held
            #    since Jan-1) anchor at $37 while BSX/CRM (bought mid-year at
            #    $50/$179 in the old IRA) anchor at purchase — matching both
            #    Alec's expectation and Fidelity's G/L.
            m = min(e.get("xfer_in_units", 0.0), legs["out"])
            if m > 1e-9:
                src = src_stats.get(s.upper()) or {}
                s_end = src_hold.get(s.upper(), 0.0)
                s_net = (src.get("bought_units", 0.0) - src.get("sold_units", 0.0)
                         + src.get("in", 0.0) - src.get("out", 0.0))
                jan1_pool = max(s_end - s_net, 0.0)
                buy_pool  = src.get("bought_units", 0.0)
                pool = jan1_pool + buy_pool
                if pool > 1e-9:
                    f_buy = buy_pool / pool
                    avg_buy = (src.get("buy_cost", 0.0) / buy_pool) if buy_pool > 1e-9 else 0.0
                    cur.execute("SELECT close FROM price_history WHERE symbol=%s AND d <= %s "
                                "ORDER BY d DESC LIMIT 1", (s, jan1))
                    _pr = cur.fetchone()
                    j1px = float(_pr["close"]) if _pr and _pr["close"] is not None else None
                    if j1px is not None or (1.0 - f_buy) <= 1e-6:
                        anchor = m * (f_buy * avg_buy + (1.0 - f_buy) * (j1px or 0.0))
                        _consume_leg(e, m, "in")   # strip the marked value…
                        e["xfer_net_val"] = e.get("xfer_net_val", 0.0) + anchor
                        # …and re-book at the blended basis. net_units stays —
                        # matched shares behave like a buy at that basis.
                    # jan1 fraction unpriceable → keep marked-value anchor.
                # pool empty (source story unknown) → keep marked-value anchor.
            # 3) fund OUT ↔ other-account IN → their YTD follows them out
            m2 = min(e.get("xfer_out_units", 0.0), legs["in"])
            if m2 > 1e-9:
                e["net_units"] += m2
                _consume_leg(e, m2, "out")
            # Only a RESIDUAL unmatched unvalued leg is truly unpriceable.
            e["transfer_unvalued"] = (e.get("xfer_in_unval", 0.0)
                                      + e.get("xfer_out_unval", 0.0)) > 1e-6

        # PREDECESSOR ADOPTION: donor accounts (unassigned, with transfer-out
        # legs feeding this fund) often SOLD positions before consolidating —
        # e.g. WBD, exited in the old account in the spring, funding the
        # transfer. Those stories belong to this fund's lineage but displayed
        # NOWHERE (donors are unassigned by design). Adopt donor symbols the
        # fund itself never held or traded; overlapping symbols (INTC!) keep
        # their leg-matched treatment so nothing double-counts.
        # Donor → successor is ONE-TO-ONE: each donor account is adopted by
        # the single fund whose transfer-IN legs best pair with the donor's
        # OUT legs (summed unit overlap per symbol). Plain symbol overlap let
        # one donor qualify for MULTIPLE funds — HAL/WBD/MU/SRLN/BKLN showed
        # up in both ANAT-DEF and ANAT-IRA.
        cur.execute("""
            SELECT a.account_id, UPPER(a.symbol) AS sym, SUM(-a.units) AS out_units
              FROM snaptrade_activities a
              JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
             WHERE sa.status = 'active' AND sa.fund_id IS NULL
               AND (sa.account_id LIKE 'demo-%%') = %s
               AND a.trade_date >= %s AND a.units < 0 AND a.symbol IS NOT NULL
               AND UPPER(COALESCE(a.type, '')) = ANY(%s)
             GROUP BY 1, 2
        """, (_demo_part, jan1, list(_SNAP_FLOW_TYPES)))
        donor_out: dict = {}
        for r in cur.fetchall():
            donor_out.setdefault(r["account_id"], {})[r["sym"]] = float(r["out_units"] or 0)
        cur.execute("""
            SELECT sa.fund_id::text AS fid, UPPER(a.symbol) AS sym, SUM(a.units) AS in_units
              FROM snaptrade_activities a
              JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
             WHERE sa.status = 'active' AND sa.fund_id IS NOT NULL
               AND (sa.account_id LIKE 'demo-%%') = %s
               AND a.trade_date >= %s AND a.units > 0 AND a.symbol IS NOT NULL
               AND UPPER(COALESCE(a.type, '')) = ANY(%s)
             GROUP BY 1, 2
        """, (_demo_part, jan1, list(_SNAP_FLOW_TYPES)))
        fund_in: dict = {}
        for r in cur.fetchall():
            fund_in.setdefault(r["fid"], {})[r["sym"]] = float(r["in_units"] or 0)
        # CASH-MERGE donors have no in-kind legs to pair (they sold everything
        # and moved cash) — map those by same-day cash-transfer overlap
        # instead: cash leaves the donor and lands in the successor fund on
        # the same date.
        cur.execute("""
            SELECT a.account_id, a.trade_date::date::text AS d, SUM(ABS(a.amount)) AS amt
              FROM snaptrade_activities a
              JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
             WHERE sa.status = 'active' AND sa.fund_id IS NULL
               AND (sa.account_id LIKE 'demo-%%') = %s
               AND a.trade_date >= %s AND COALESCE(a.units, 0) = 0
               AND COALESCE(a.amount, 0) < 0
               AND UPPER(COALESCE(a.type, '')) = ANY(%s)
             GROUP BY 1, 2
        """, (_demo_part, jan1, list(_SNAP_FLOW_TYPES)))
        donor_cash: dict = {}
        for r in cur.fetchall():
            donor_cash.setdefault(r["account_id"], {})[r["d"]] = float(r["amt"] or 0)
        cur.execute("""
            SELECT sa.fund_id::text AS fid, a.trade_date::date::text AS d, SUM(a.amount) AS amt
              FROM snaptrade_activities a
              JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
             WHERE sa.status = 'active' AND sa.fund_id IS NOT NULL
               AND (sa.account_id LIKE 'demo-%%') = %s
               AND a.trade_date >= %s AND COALESCE(a.units, 0) = 0
               AND COALESCE(a.amount, 0) > 0
               AND UPPER(COALESCE(a.type, '')) = ANY(%s)
             GROUP BY 1, 2
        """, (_demo_part, jan1, list(_SNAP_FLOW_TYPES)))
        fund_cash: dict = {}
        for r in cur.fetchall():
            fund_cash.setdefault(r["fid"], {})[r["d"]] = float(r["amt"] or 0)
        donor_ids = []
        for _acct in set(donor_out) | set(donor_cash):
            _outs = donor_out.get(_acct) or {}
            best_fid, best_score = None, 0.0
            for _fid, _ins in fund_in.items():
                _score = sum(min(q, _ins.get(s, 0.0)) for s, q in _outs.items())
                if _score > best_score:
                    best_fid, best_score = _fid, _score
            if best_fid is None:
                _cash = donor_cash.get(_acct) or {}
                for _fid, _fc in fund_cash.items():
                    _score = sum(min(v, _fc.get(d, 0.0)) for d, v in _cash.items())
                    if _score > best_score:
                        best_fid, best_score = _fid, _score
            if best_fid == str(fund_id) and best_score > 1e-9:
                donor_ids.append(_acct)
        if donor_ids:
            cur.execute("""
                SELECT a.symbol, a.type, a.units, a.price, a.amount,
                       a.raw_json -> 'option_symbol' AS opt
                  FROM snaptrade_activities a
                 WHERE a.account_id = ANY(%s) AND a.trade_date >= %s
                   AND a.symbol IS NOT NULL
            """, (donor_ids, jan1))
            donor_trades: dict = {}
            for r in cur.fetchall():
                sym = (r["symbol"] or "").strip()
                if not sym or sym in trades or sym in holdings:
                    continue
                _apply_row(donor_trades.setdefault(sym, _new_agg()), r)
            for sym, e in donor_trades.items():
                # Only self-contained trading stories — pure transfer echoes
                # stay out, and a symbol the donor transferred ELSEWHERE
                # belongs to that fund's leg-match, not here.
                if ((e.get("sold_units", 0.0) > 1e-6 or e.get("bought_units", 0.0) > 1e-6)
                        and not e.get("had_unit_transfer")):
                    e["predecessor"] = True
                    trades[sym] = e
    if not holdings and not trades:
        return []

    # Option symbols leak into activities too (assignments etc.) — keep only
    # plausible equity tickers, and never cash sweeps.
    def _equityish(s):
        return (bool(re.fullmatch(r"[A-Z][A-Z0-9.\-]{0,9}", s))
                and not any(c.isdigit() for c in s[:4])
                and not _snaptrade_cashlike(s))

    syms = {s for s in set(holdings) | set(trades) if _equityish(s)}
    rows, missing_price = [], 0
    for sym in sorted(syms):
        h = holdings.get(sym) or {}
        tr = trades.get(sym) or {"net_units": 0.0, "buy_cost": 0.0,
                                 "sell_proceeds": 0.0, "dividends": 0.0,
                                 "bought_units": 0.0, "sold_units": 0.0}
        end_qty = float(h.get("qty") or 0.0)
        end_px  = _snaptrade_num(h.get("price"))
        jan1_qty = end_qty - tr["net_units"]
        # Jan-1 close from the price store — STRICTLY read-only. The store is
        # prewarmed by _sync_jan1_close OUTSIDE this transaction (doing network
        # fetches while holding the rebuild txn wedged the app — ui343).
        cur.execute("SELECT close FROM price_history WHERE symbol=%s AND d <= %s "
                    "ORDER BY d DESC LIMIT 1", (sym, jan1))
        pr = cur.fetchone()
        jan1_px = float(pr["close"]) if pr and pr["close"] is not None else None
        if jan1_px is None:
            missing_price += 1
        end_value  = end_qty * (end_px or 0.0)
        # Impossible rewind (jan1 shares < 0) = the activity record is missing
        # something we can't see (split, assignment, transfer-in-kind). Show an
        # honest "—" instead of a fabricated gain — a wrong sign on a big name
        # destroys trust in the whole table.
        rewind_ok = jan1_qty >= -1e-4
        jan1_qty = max(jan1_qty, 0.0)
        jan1_value = (jan1_qty * jan1_px) if (jan1_px is not None and jan1_qty > 1e-6) else (0.0 if jan1_qty <= 1e-6 else None)
        gain = None
        if rewind_ok and jan1_value is not None and not tr.get("transfer_unvalued"):
            gain = (end_value - jan1_value
                    - (tr["buy_cost"] - tr["sell_proceeds"])
                    - tr.get("xfer_net_val", 0.0)
                    + tr["dividends"])
        # Stock return: live price vs Jan-1 for open names. Closed names use
        # their average EXIT price (they rendered null across the board); for
        # within-year round trips (not held on Jan 1) the base is the average
        # BUY price — the Jan-1 close is meaningless for those.
        closed = end_qty <= 1e-6 and tr["sold_units"] > 1e-6
        px_for_ret = end_px
        base_px = jan1_px
        origin_buy = False
        if closed:
            px_for_ret = tr["sell_proceeds"] / tr["sold_units"]
        # Positions NOT held on Jan 1 (bought this year — IPOs like PSUS have
        # no Jan-1 close at all) originate at the average ACQUISITION price
        # from the activity records; the Jan-1 close is meaningless/absent.
        if jan1_qty <= 1e-6 and tr["bought_units"] > 1e-6:
            base_px = tr["buy_cost"] / tr["bought_units"]
            origin_buy = True
        ret = ((px_for_ret / base_px - 1.0) * 100.0) if (px_for_ret and base_px) else None
        contrib = (gain / begin_value * 100.0) if (gain is not None and begin_value) else None
        if end_qty <= 1e-6 and not (tr["buy_cost"] or tr["sell_proceeds"]):
            continue   # neither held nor traded this year
        rows.append({
            "ticker": sym,
            "end_shares": round(end_qty, 4),
            # For this-year entries the "origin" column shows the avg
            # acquisition price (flagged origin_buy), not a Jan-1 close.
            "jan1_price": (round(base_px, 4) if origin_buy and base_px
                           else (round(jan1_px, 4) if jan1_px is not None else None)),
            "origin_buy": origin_buy,
            # Closed names show their average EXIT price, not a live quote.
            "end_price": round(px_for_ret, 4) if px_for_ret is not None else None,
            "dollar_gain": round(gain, 2) if gain is not None else None,
            "ticker_return_pct": round(ret, 2) if ret is not None else None,
            "contribution_pct": round(contrib, 2) if contrib is not None else None,
            "dividends_cash": round(tr["dividends"], 2),
            "closed": bool(closed),
            "predecessor": bool(tr.get("predecessor")),
            "source": "snaptrade_auto",
        })
    rows.sort(key=lambda r: -(abs(r["contribution_pct"] or 0)))
    return rows


def _snaptrade_rebuild_balance_history(cur, fund_id: str) -> dict | None:
    """Task-3 core: synthesize monthly balance records (same shape as the parsed
    Balance & Income Detail CSV) from SnapTrade daily snapshots + activities, and
    merge them into account_balance_history strictly AFTER the last CSV month.

    CSV-imported months are never modified — re-importing the CSV stays the
    authoritative backup and overwrites everything (the next sync re-appends the
    live months). Each synthesized month uses the same Modified-Dietz formula as
    the CSV parser, so chained TWRR matches Fidelity's methodology; when
    activities are unavailable (free-plan gating) flows are zero and the row is
    flagged estimated. Recomputes managed_account_ytd_cache from the merged
    series, preserving any attribution overlay from a manual 3-file run.

    Caveat (multi-account funds): an account linked mid-month first appears in
    the summed daily series as a jump; unless the transfer-in shows up in
    activities as a flow, that month's return is misstated — the row is at
    least flagged `estimated` when activity coverage is missing.

    `cur` must be a RealDictCursor. Returns a small summary dict, or None when
    there is nothing to build.
    """
    import calendar as _cal
    # Fresh deployments may not have SnapTrade tables yet — bail without
    # erroring so callers' transactions (e.g. the CSV import) stay healthy.
    cur.execute("SELECT to_regclass('snaptrade_accounts') AS t1, "
                "to_regclass('snaptrade_balances') AS t2, "
                "to_regclass('snaptrade_activities') AS t3")
    reg = cur.fetchone()
    if not (reg and reg.get("t1") and reg.get("t2") and reg.get("t3")):
        return None
    cur.execute("SELECT account_id FROM snaptrade_accounts "
                "WHERE status='active' AND fund_id=%s", (fund_id,))
    acct_ids = [r["account_id"] for r in cur.fetchall()]
    if not acct_ids:
        return None

    cur.execute("SELECT data_json FROM account_balance_history WHERE fund_id=%s", (fund_id,))
    row = cur.fetchone()
    existing = []
    if row and row.get("data_json"):
        try:
            existing = (row["data_json"] if isinstance(row["data_json"], list)
                        else json.loads(row["data_json"]))
        except Exception:
            existing = []
    csv_rows = sorted([r for r in existing if r.get("source") != "snaptrade"],
                      key=lambda r: (r["year"], r["month"]))

    # Fund-level daily value = sum across accounts, carrying each account's last
    # known value forward over days it wasn't snapshotted.
    cur.execute("SELECT account_id, d, total_value FROM snaptrade_balances "
                "WHERE account_id = ANY(%s) ORDER BY d", (acct_ids,))
    snaps = cur.fetchall()
    if not snaps:
        return None
    per_acct = {}
    for r in snaps:
        per_acct.setdefault(r["account_id"], {})[r["d"]] = float(r["total_value"] or 0)
    days = sorted({r["d"] for r in snaps})
    by_day, last_val = {}, {}
    for d in days:
        for aid in acct_ids:
            v = per_acct.get(aid, {}).get(d)
            if v is not None:
                last_val[aid] = v
        by_day[d] = sum(last_val.values())

    anchor_key = (csv_rows[-1]["year"], csv_rows[-1]["month"]) if csv_rows else None
    month_keys = sorted({(d.year, d.month) for d in days
                         if anchor_key is None or (d.year, d.month) > anchor_key})
    # month_keys may be empty (CSV already covers the latest snapshot month) —
    # still fall through with synth=[] so the YTD cache gets its automatic
    # attribution + flows refreshed even when no new balance month is added.

    # Month-level activity aggregates (empty when the plan gates get_activities).
    cur.execute("""
        SELECT date_trunc('month', trade_date)::date AS mo, type,
               COALESCE(SUM(amount),0) AS amt, COALESCE(SUM(ABS(COALESCE(fee,0))),0) AS fees
          FROM snaptrade_activities
         WHERE account_id = ANY(%s) AND trade_date IS NOT NULL
         GROUP BY 1, 2
    """, (acct_ids,))
    acts_by_month = {}
    has_acts = False
    for r in cur.fetchall():
        has_acts = True
        key = (r["mo"].year, r["mo"].month)
        b = acts_by_month.setdefault(key, {"deposits": 0.0, "withdrawals": 0.0,
                                           "dividends": 0.0, "interest": 0.0, "fees": 0.0})
        t, amt = (r["type"] or ""), float(r["amt"] or 0)
        b["fees"] += float(r["fees"] or 0)
        if t in _SNAP_FLOW_TYPES:
            if amt >= 0:
                b["deposits"] += amt
            else:
                b["withdrawals"] += -amt
        elif t in _SNAP_DIV_TYPES:
            b["dividends"] += amt
        elif t in _SNAP_INT_TYPES:
            b["interest"] += amt
        elif t in _SNAP_FEE_TYPES and float(r["fees"] or 0) == 0:
            # FEE activities usually carry the charge in `amount`; only count it
            # when the `fee` column (already summed above) didn't capture it.
            b["fees"] += abs(amt)

    synth = []
    prev_end = float(csv_rows[-1]["end_balance"]) if csv_rows else None
    for (y, m) in month_keys:
        mdays = [d for d in days if d.year == y and d.month == m]
        if not mdays:
            continue
        end_bal = by_day[mdays[-1]]
        # Inception (no CSV history): month-open is the first snapshot we have.
        beg_bal = prev_end if prev_end is not None else by_day[mdays[0]]
        a = acts_by_month.get((y, m), {"deposits": 0.0, "withdrawals": 0.0,
                                       "dividends": 0.0, "interest": 0.0, "fees": 0.0})
        # A month is "estimated" when we have no activity rows for it — either
        # genuinely no transactions, or coverage is missing (free-plan gating).
        # Conservative per-month flag: a covered month with a big deposit and a
        # gated month must not look equally trustworthy.
        month_estimated = (y, m) not in acts_by_month
        net_flow   = a["deposits"] - a["withdrawals"]
        net_income = end_bal - beg_bal - net_flow
        mkt_chg    = net_income - a["dividends"] - a["interest"] + a["fees"]
        denom      = beg_bal + 0.5 * net_flow
        if beg_bal == 0.0:
            safe = net_flow if net_flow > 0 else (end_bal if end_bal > 0 else 0.0)
            return_pct = round(net_income / safe * 100, 4) if safe else 0.0
        elif denom != 0:
            return_pct = round(net_income / denom * 100, 4)
        else:
            return_pct = 0.0
        synth.append({
            "year": y, "month": m, "label": f"{_cal.month_abbr[m]} {y}",
            "beg_balance": round(beg_bal, 2), "end_balance": round(end_bal, 2),
            "market_change": round(mkt_chg, 2),
            "dividends": round(a["dividends"], 2), "interest": round(a["interest"], 2),
            "deposits": round(a["deposits"], 2), "withdrawals": round(a["withdrawals"], 2),
            "fees": round(a["fees"], 2), "return_pct": return_pct, "skip": False,
            "source": "snaptrade", "estimated": month_estimated,
        })
        prev_end = end_bal

    merged = csv_rows + synth
    cur.execute("""
        INSERT INTO account_balance_history (fund_id, data_json, updated_at)
        VALUES (%s, %s, now())
        ON CONFLICT (fund_id) DO UPDATE
          SET data_json = EXCLUDED.data_json, updated_at = now()
    """, (fund_id, json.dumps(merged)))

    overview = _account_overview_from_balance(merged)
    if not overview:
        return {"fund_id": str(fund_id), "months_added": len(synth)}
    overview["source"] = "balance_history_snaptrade"
    overview["live_months"] = len(synth)
    overview["flows_estimated"] = any(r.get("estimated") for r in synth)

    # Attribution: built automatically from SnapTrade holdings + activities.
    # Falls back to whatever a manual 3-file run left when auto can't compute
    # (no activities yet — free plan, or a brand-new link).
    cur.execute("SELECT result_json FROM managed_account_ytd_cache WHERE fund_id=%s",
                (fund_id,))
    prev_row = cur.fetchone()
    prev = None
    if prev_row and prev_row.get("result_json"):
        try:
            prev = (prev_row["result_json"] if isinstance(prev_row["result_json"], dict)
                    else json.loads(prev_row["result_json"]))
        except Exception:
            prev = None
    yr = overview.get("year") or datetime.utcnow().year
    auto_attr = []
    # NOT gated on has_acts (that gate hid working attribution for a whole
    # day): with zero activities the builder still produces a price-based
    # estimate from holdings + Jan-1 closes (jan1_qty = end_qty). It's flagged
    # estimated and self-corrects once SnapTrade delivers transactions.
    # Own savepoint: a failure here must not abort the transaction and take
    # the balance-history/flows writes down with it.
    # Contribution denominator: the SAME flow-weighted capital base the
    # account's Modified-Dietz return divides by (implied from gain/md), so
    # Σ contribution ≈ the portfolio YTD % — attribution is that number's
    # decomposition. Raw Jan-1 balance overstated contributions badly for
    # accounts funded by mid-year consolidations. Fallback: begin + ½·flows.
    _beg = float(overview.get("begin_value") or 0)
    _ig  = overview.get("investment_gain")
    _md  = overview.get("md_return_pct")
    attr_base = None
    try:
        if _ig is not None and _md and abs(float(_md)) >= 0.25:
            _b = float(_ig) / (float(_md) / 100.0)
            if _b > 0:
                attr_base = _b
    except Exception:
        attr_base = None
    if not attr_base:
        attr_base = _beg + 0.5 * float(overview.get("net_external_flows") or 0)
    if attr_base <= 0:
        attr_base = _beg
    try:
        cur.execute("SAVEPOINT snap_attr")
        auto_attr = _snaptrade_build_attribution(cur, fund_id, int(yr), float(attr_base))
        cur.execute("RELEASE SAVEPOINT snap_attr")
    except Exception as e:
        try:
            cur.execute("ROLLBACK TO SAVEPOINT snap_attr")
        except Exception:
            pass
        print(f"[snaptrade] auto-attribution failed {fund_id}: {e!s:.140}", flush=True)
    if auto_attr:
        overview["attribution"] = auto_attr
        overview["attribution_source"] = "snaptrade_auto"
        overview["attribution_estimated"] = not has_acts
        overview["attribution_capital_base"] = round(float(attr_base), 2)
        overview["attribution_contrib_sum"] = round(
            sum((r.get("contribution_pct") or 0) for r in auto_attr), 2)
    elif prev:
        for k in ("attribution", "top_gainers", "top_losers"):
            if prev.get(k) is not None:
                overview[k] = prev[k]
    if has_acts:
        cur.execute("""
            SELECT trade_date, type, symbol, amount FROM snaptrade_activities
             WHERE account_id = ANY(%s) AND type = ANY(%s)
               AND EXTRACT(YEAR FROM trade_date) = %s
             ORDER BY trade_date DESC
        """, (acct_ids, list(_SNAP_FLOW_TYPES), yr))
        overview["flows"] = [
            {"date": r["trade_date"].isoformat() if r["trade_date"] else None,
             "action": (r["type"] or "").replace("_", " ").title(),
             "symbol": r["symbol"],
             "amount": float(r["amount"]) if r["amount"] is not None else None}
            for r in cur.fetchall()]
    elif prev and prev.get("flows") is not None:
        overview["flows"] = prev["flows"]

    nav     = overview.get("end_value") or 0.0
    ytd_pct = overview.get("twrr_return_pct") or 0.0
    cur.execute("""
        INSERT INTO managed_account_ytd_cache (fund_id, nav, ytd_pct, result_json, updated_at)
        VALUES (%s, %s, %s, %s, now())
        ON CONFLICT (fund_id) DO UPDATE
          SET nav = EXCLUDED.nav, ytd_pct = EXCLUDED.ytd_pct,
              result_json = EXCLUDED.result_json, updated_at = now()
    """, (fund_id, float(nav), float(ytd_pct), json.dumps(overview)))
    return {"fund_id": str(fund_id), "months_added": len(synth),
            "ytd_pct": ytd_pct, "nav": nav,
            "flows_estimated": any(r.get("estimated") for r in synth),
            "activities_available": has_acts,
            "attribution_rows": len(overview.get("attribution") or [])}


@app.get("/api/snaptrade/attribution-debug")
def snaptrade_attribution_debug(request: Request, fund_id: str, symbol: str = None):
    """GP-only: stage-by-stage state of the auto-attribution pipeline for one
    managed account — assigned accounts, activity counts by type, equity
    holdings, Jan-1 price coverage, what's in the YTD cache, and a LIVE run of
    the builder (rolled back) including its exception if it fails. Wired to
    the Diagnose button in the empty attribution panel."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    _ensure_snaptrade_tables()
    out: dict = {"ok": True, "fund_id": fund_id}
    yr = datetime.utcnow().year
    with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
        fid = str(_resolve_fund_id(cur, fund_id))
        out["fund_id"] = fid
        cur.execute("SELECT account_id, account_name, account_mask, last_synced_at "
                    "FROM snaptrade_accounts WHERE status='active' AND fund_id=%s", (fid,))
        accts = cur.fetchall()
        out["accounts"] = [{
            "account_id": a["account_id"], "name": a["account_name"],
            "mask": a["account_mask"],
            "last_synced_at": a["last_synced_at"].isoformat() if a["last_synced_at"] else None,
        } for a in accts]
        acct_ids = [a["account_id"] for a in accts]
        out["activities_by_type"] = []
        if acct_ids:
            cur.execute("""SELECT type, count(*) AS n, min(trade_date) AS min_d,
                                  max(trade_date) AS max_d
                             FROM snaptrade_activities
                            WHERE account_id = ANY(%s)
                            GROUP BY type ORDER BY n DESC""", (acct_ids,))
            out["activities_by_type"] = [{
                "type": r["type"], "count": int(r["n"]),
                "from": r["min_d"].isoformat() if r["min_d"] else None,
                "to": r["max_d"].isoformat() if r["max_d"] else None,
            } for r in cur.fetchall()]
        out["activities_total"] = sum(a["count"] for a in out["activities_by_type"])
        # THE mapping source of truth: every distinct row shape in the store
        # (type × option-marker × has-units × has-price) with counts, plus raw
        # samples for symbols whose rows map to NO share math. One Diagnose
        # click shows exactly what SnapTrade sends — no more guessed mappings.
        out["row_shapes"] = []
        out["unmapped_symbol_samples"] = {}
        if acct_ids:
            cur.execute("""
                SELECT a.type,
                       jsonb_typeof(a.raw_json -> 'option_symbol') = 'object' AS is_opt,
                       (a.units IS NOT NULL AND a.units <> 0)      AS has_units,
                       (a.price IS NOT NULL AND a.price <> 0)      AS has_price,
                       (a.amount IS NOT NULL AND a.amount <> 0)    AS has_amount,
                       count(*) AS n
                  FROM snaptrade_activities a
                 WHERE a.account_id = ANY(%s)
                   AND EXTRACT(YEAR FROM a.trade_date) = %s
                 GROUP BY 1, 2, 3, 4, 5 ORDER BY n DESC
            """, (acct_ids, yr))
            out["row_shapes"] = [
                {"type": r2["type"], "option": bool(r2["is_opt"]),
                 "units": bool(r2["has_units"]), "price": bool(r2["has_price"]),
                 "amount": bool(r2["has_amount"]), "count": int(r2["n"])}
                for r2 in cur.fetchall()]
            _known = (_SNAP_BUY_TYPES | _SNAP_SELL_TYPES | _SNAP_DIV_TYPES
                      | _SNAP_FLOW_TYPES | _SNAP_INT_TYPES | _SNAP_FEE_TYPES)
            cur.execute("""
                SELECT a.symbol, a.type, a.units, a.price, a.amount, a.trade_date,
                       a.description,
                       jsonb_typeof(a.raw_json -> 'option_symbol') = 'object' AS is_opt
                  FROM snaptrade_activities a
                 WHERE a.account_id = ANY(%s) AND a.symbol IS NOT NULL
                   AND EXTRACT(YEAR FROM a.trade_date) = %s
                 ORDER BY a.symbol, a.trade_date
            """, (acct_ids, yr))
            _by_sym: dict = {}
            for r2 in cur.fetchall():
                _by_sym.setdefault(r2["symbol"], []).append(r2)
            for s, rws in _by_sym.items():
                if len(out["unmapped_symbol_samples"]) >= 5:
                    break
                mapped = any((not x["is_opt"]) and (x["type"] or "").upper() in _known
                             for x in rws)
                if not mapped:
                    out["unmapped_symbol_samples"][s] = [
                        {"type": x["type"], "units": float(x["units"] or 0),
                         "price": float(x["price"] or 0), "amount": float(x["amount"] or 0),
                         "option": bool(x["is_opt"]),
                         "desc": (x["description"] or "")[:60],
                         "date": x["trade_date"].isoformat() if x["trade_date"] else None}
                        for x in rws[:5]]
        holdings = _snaptrade_fund_holdings(cur, fid)
        eq = {s: h for s, h in holdings.items()
              if h.get("asset_class") not in ("cash", "option")}
        out["equity_holdings"] = len(eq)
        out["equity_symbols"] = sorted(eq)[:40]
        cov = 0
        for s in list(eq)[:40]:
            cur.execute("SELECT 1 FROM price_history WHERE symbol=%s AND d <= %s LIMIT 1",
                        (s, f"{yr}-01-01"))
            if cur.fetchone():
                cov += 1
        out["jan1_price_coverage"] = f"{cov}/{len(eq)}"
        # Current cache state
        cur.execute("SELECT result_json, updated_at FROM managed_account_ytd_cache WHERE fund_id=%s", (fid,))
        rj = cur.fetchone()
        cache = {}
        if rj and rj.get("result_json"):
            try:
                cache = (rj["result_json"] if isinstance(rj["result_json"], dict)
                         else json.loads(rj["result_json"]))
            except Exception:
                cache = {}
        out["cache_source"] = cache.get("source")
        out["cache_attribution_rows"] = len(cache.get("attribution") or [])
        out["cache_begin_value"] = cache.get("begin_value")
        out["cache_updated_at"] = rj["updated_at"].isoformat() if rj and rj.get("updated_at") else None
        # Live builder run — rolled back, exception surfaced
        cur.execute("SAVEPOINT attr_dbg")
        try:
            rows = _snaptrade_build_attribution(cur, fid, yr, float(cache.get("begin_value") or 0))
            out["live_builder_rows"] = len(rows)
            out["live_builder_sample"] = rows[:3]
        except Exception as e:
            import traceback
            out["live_builder_error"] = f"{type(e).__name__}: {e!s:.300}"
            out["live_builder_trace"] = traceback.format_exc()[-800:]
        finally:
            try:
                cur.execute("ROLLBACK TO SAVEPOINT attr_dbg")
            except Exception:
                pass
    # LIVE SnapTrade probe — stored-count 0 is ambiguous (SnapTrade returns
    # nothing vs our call/parse is wrong vs plan gating). Ask SnapTrade NOW.
    live_err = None
    try:
        import snaptrade_link as _st
        uid, secret = _snaptrade_ensure_user()
        end_iso = datetime.utcnow().date().isoformat()
        out["live_activities"] = []
        for a in out["accounts"][:3]:
            try:
                acts = _st.get_account_activities(uid, secret, a["account_id"],
                                                  f"{yr}-01-01", end_iso)
                sample = (acts or [])[:2]
                out["live_activities"].append({
                    "account_id": a["account_id"], "returned": len(acts or []),
                    "sample": json.loads(json.dumps(sample, default=str)) if sample else [],
                })
            except Exception as e:
                live_err = _snaptrade_error_detail(e)
                out["live_activities"].append({"account_id": a["account_id"], "error": live_err})
        # Direct call failed or returned zero everywhere → enumerate every
        # transactions/activity SDK method and report which ones return data.
        if out["accounts"] and (live_err or all((x.get("returned") or 0) == 0
                                                for x in out["live_activities"])):
            try:
                rep = _st.probe_activity_methods(uid, secret, out["accounts"][0]["account_id"],
                                                 start_date=f"{yr}-01-01", end_date=end_iso)
                out["method_probe"] = [
                    {"method": r.get("method"), "count": r.get("count"),
                     "sample": (r.get("sample") or "")[:200]}
                    for r in rep.get("results", []) if r.get("ok")][:8]
            except Exception as e:
                out["method_probe_error"] = _snaptrade_error_detail(e)
    except Exception as e:
        out["live_activities_error"] = _snaptrade_error_detail(e)

    # Per-ticker trace: every stored YTD row for one symbol, classified through
    # the SAME bucket logic the builder uses, plus the resulting aggregate,
    # Jan-1 close, and current holdings qty. Settles "this number is wrong"
    # claims (the INTC/ANAT-DEF case) with rows instead of theories.
    if symbol:
        s_up = symbol.strip().upper()
        trace = {"symbol": s_up, "rows": [], "aggregate": None,
                 "jan1_price": None, "holdings_qty": None}
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur2:
            fid2 = str(_resolve_fund_id(cur2, out["fund_id"]))
            cur2.execute("""
                SELECT a.type, a.units, a.price, a.amount, a.trade_date, a.description,
                       a.raw_json -> 'option_symbol' AS opt
                  FROM snaptrade_activities a
                  JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
                 WHERE sa.fund_id = %s AND UPPER(a.symbol) = %s
                   AND EXTRACT(YEAR FROM a.trade_date) = %s
                 ORDER BY a.trade_date
            """, (fid2, s_up, yr))
            agg = {"net_units": 0.0, "buy_cost": 0.0, "sell_proceeds": 0.0,
                   "dividends": 0.0, "bought_units": 0.0, "sold_units": 0.0}
            for r3 in cur2.fetchall():
                t3 = (r3["type"] or "").upper()
                u3 = float(r3["units"] or 0)
                p3 = float(r3["price"] or 0)
                a3 = float(r3["amount"] or 0)
                opt3 = r3["opt"]
                is_opt3 = bool(opt3) or "OPTION" in t3
                if is_opt3:
                    bucket = "EXCLUDED (option row)"
                elif t3 in _SNAP_FLOW_TYPES and abs(u3) > 1e-9:
                    ua = abs(u3)
                    val3 = abs(a3)
                    _side = "IN" if u3 > 0 else "OUT"
                    bucket = ("TRANSFER %s (%s%s sh%s)" % (
                        _side, "+" if u3 > 0 else "−", round(ua, 3),
                        (" @ value %s" % round(val3, 2)) if val3 > 0
                        else " — UNVALUED leg (nulls gain only if unmatched)"))
                    agg["net_units"] += ua if u3 > 0 else -ua
                    if val3 > 0:
                        agg["xfer_net_val"] = agg.get("xfer_net_val", 0.0) + (val3 if u3 > 0 else -val3)
                    else:
                        agg["xfer_unval_units"] = agg.get("xfer_unval_units", 0.0) + ua
                    agg["xfer_in_units" if u3 > 0 else "xfer_out_units"] = \
                        agg.get("xfer_in_units" if u3 > 0 else "xfer_out_units", 0.0) + ua
                else:
                    ua = abs(u3)
                    g3 = (ua * p3) if (ua and p3) else abs(a3)
                    if t3 in _SNAP_BUY_TYPES:
                        bucket = "BUY (+%s sh, cost %s)" % (round(ua, 3), round(g3, 2))
                        agg["net_units"] += ua; agg["buy_cost"] += g3; agg["bought_units"] += ua
                    elif t3 in _SNAP_SELL_TYPES:
                        bucket = "SELL (−%s sh, proceeds %s)" % (round(ua, 3), round(g3, 2))
                        agg["net_units"] -= ua; agg["sell_proceeds"] += g3; agg["sold_units"] += ua
                    elif t3 in _SNAP_DIV_TYPES:
                        bucket = "DIVIDEND (+%s)" % round(a3, 2)
                        agg["dividends"] += a3
                    else:
                        bucket = "IGNORED (type not bucketed)"
                trace["rows"].append({
                    "date": r3["trade_date"].isoformat() if r3["trade_date"] else None,
                    "type": r3["type"], "units": u3, "price": p3, "amount": a3,
                    "option": is_opt3, "bucket": bucket,
                    "desc": (r3["description"] or "")[:70]})
            trace["aggregate"] = {k: round(v, 3) for k, v in agg.items()}
            # Other-account transfer legs for this symbol — what the builder's
            # leg-match will consume (the trace shows fund-scope rows only).
            cur2.execute("""
                SELECT SUM(CASE WHEN a.units > 0 THEN a.units ELSE 0 END)  AS in_units,
                       SUM(CASE WHEN a.units < 0 THEN -a.units ELSE 0 END) AS out_units
                  FROM snaptrade_activities a
                  JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
                 WHERE sa.status = 'active'
                   AND (sa.fund_id IS NULL OR sa.fund_id::text <> %s)
                   AND EXTRACT(YEAR FROM a.trade_date) = %s
                   AND UPPER(a.symbol) = %s
                   AND UPPER(COALESCE(a.type, '')) = ANY(%s)
                   AND a.units IS NOT NULL AND a.units <> 0
            """, (fid2, yr, s_up, list(_SNAP_FLOW_TYPES)))
            lr = cur2.fetchone() or {}
            trace["other_account_legs"] = {"in": float(lr.get("in_units") or 0),
                                           "out": float(lr.get("out_units") or 0)}
            cur2.execute("SELECT close FROM price_history WHERE symbol=%s AND d <= %s "
                         "ORDER BY d DESC LIMIT 1", (s_up, f"{yr}-01-01"))
            pr3 = cur2.fetchone()
            trace["jan1_price"] = float(pr3["close"]) if pr3 and pr3["close"] is not None else None
            h3 = _snaptrade_fund_holdings(cur2, fid2).get(s_up) or {}
            trace["holdings_qty"] = h3.get("qty")
        out["symbol_trace"] = trace

    # Human-readable verdict so the GP doesn't have to interpret raw fields.
    live_rows = sum((x.get("returned") or 0) for x in out.get("live_activities") or [])
    if not out["accounts"]:
        out["verdict"] = "No SnapTrade account is assigned to this fund."
    elif live_err:
        out["verdict"] = ("SnapTrade is REFUSING the activities call: " + live_err[:200]
                          + " — if this mentions plan/availability, the transactions "
                            "add-on isn't enabled on the production key (check the "
                            "SnapTrade dashboard billing/add-ons).")
    elif live_rows and out["activities_total"] == 0:
        out["verdict"] = ("SnapTrade RETURNS activity data but our ingest stored none — "
                          "parse/shape bug on our side; see live_activities sample.")
    elif not live_rows and out["activities_total"] == 0:
        _working = [m for m in (out.get("method_probe") or []) if (m.get("count") or 0) > 0]
        if _working:
            out["verdict"] = ("get_activities returns ZERO but SDK method "
                              + str(_working[0]["method"]) + " DOES return data — the "
                              "ingest should switch to that method (sample included).")
        else:
            out["verdict"] = ("SnapTrade returns ZERO activities for the YTD window on "
                              "every SDK method — their transaction backfill for this "
                              "connection genuinely hasn't landed. Force refresh "
                              "(Settings → SnapTrade), wait, and re-check here.")
    elif out.get("live_builder_error"):
        out["verdict"] = "Attribution builder is failing — see live_builder_error."
    elif out.get("live_builder_rows") and out["cache_attribution_rows"] == 0:
        out["verdict"] = "Builder produces rows but the cache is empty — run ↻ Sync to rebuild it."
    elif out.get("live_builder_rows"):
        out["verdict"] = "Attribution pipeline healthy."
    else:
        out["verdict"] = "Activities exist but the builder returned 0 rows — inspect equity_symbols / activities_by_type."
    return out


def _snaptrade_holdings_items(body):
    if isinstance(body, dict):
        return body.get("accounts") or body.get("account_holdings") or []
    if isinstance(body, list):
        return body
    return []


@app.get("/api/snaptrade/status")
def snaptrade_status(request: Request):
    _plaid_require_gp(request)
    import snaptrade_link as _st
    import secure_store as _sec
    n = 0
    if _PSYCOPG2_OK and os.environ.get("DATABASE_URL"):
        _ensure_snaptrade_tables()
        try:
            with _fund_conn() as conn, conn.cursor() as cur:
                cur.execute("SELECT count(*) FROM snaptrade_accounts WHERE status='active'")
                n = cur.fetchone()[0]
        except Exception:
            pass
    return {"ok": True, "configured": _st.available(),
            "encryption_ready": _sec.is_configured(), "connected_accounts": n}


@app.post("/api/snaptrade/connect")
def snaptrade_connect(request: Request):
    """GP-only: register the SnapTrade user (if needed) and return a Connection
    Portal URL (read-only). Open it in a new tab to link Fidelity."""
    _plaid_require_gp(request)
    import snaptrade_link as _st
    if not _st.available():
        raise HTTPException(503, "SnapTrade is not configured (set SNAPTRADE_CLIENT_ID / SNAPTRADE_CONSUMER_KEY).")
    import secure_store as _sec
    if not _sec.is_configured():
        raise HTTPException(503, "DATA_ENCRYPTION_KEY not set — refusing to store the SnapTrade secret without at-rest encryption.")
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    redirect = os.environ.get("SNAPTRADE_REDIRECT_URI", "").strip() or _st.DEFAULT_REDIRECT
    broker = os.environ.get("SNAPTRADE_BROKER", "").strip()
    try:
        uid, secret = _snaptrade_ensure_user()
        try:
            url = _st.login_url(uid, secret, custom_redirect=redirect, broker=broker, connection_type="read")
        except Exception as e:
            # Key swap: the stored user belongs to the previous clientId (1083).
            # Self-heal — back up assignments, mint a fresh user under the new
            # client, and retry once. The user just re-links Fidelity.
            if not _snaptrade_user_invalid(_snaptrade_error_detail(e)):
                raise
            print("[snaptrade] connect: stored user invalid under current client — resetting", flush=True)
            _snaptrade_reset_stale_user()
            uid, secret = _snaptrade_ensure_user()
            url = _st.login_url(uid, secret, custom_redirect=redirect, broker=broker, connection_type="read")
    except HTTPException:
        raise
    except Exception as e:
        import traceback; traceback.print_exc()
        raise HTTPException(502, f"SnapTrade connect failed: {_snaptrade_error_detail(e)}")
    if not url:
        raise HTTPException(502, "SnapTrade returned no connection URL.")
    return {"ok": True, "redirect_uri": url}


def _snaptrade_run_sync() -> dict:
    """Pull holdings for all connected accounts, upsert them, and push assigned
    accounts' holdings into tax_lots. Request-free so both the /sync endpoint and
    the daily scheduler can call it. Preserves each account's fund_id assignment.
    Raises on a fatal accounts-fetch failure; per-account issues go in errors[]."""
    import snaptrade_link as _st
    _snaptrade_sync_stage("Contacting SnapTrade…")
    uid, secret = _snaptrade_ensure_user()

    # ── Stage 0: freshness. Our sync reads SNAPTRADE'S cache of Fidelity,
    # which they re-pull ~daily on their own schedule — same-day money moves
    # (settled cash, intraday trades) aren't in it yet. So every sync FIRST
    # asks SnapTrade to re-pull the brokerage, waits for the async refresh,
    # then imports. One button, fresh data. A 10-min kv cooldown keeps
    # repeated clicks from spamming SnapTrade's refresh API; the wait is
    # skipped entirely when the cooldown says data was just refreshed.
    try:
        _last = _kv_get("snaptrade.last_refresh")
        _last_ts = float(_last) if _last else 0.0
    except Exception:
        _last_ts = 0.0
    if time.time() - _last_ts > 600:
        _snaptrade_sync_stage("Asking Fidelity for fresh data…")
        _refreshed = 0
        try:
            with _fund_conn() as _rconn, _rconn.cursor() as _rcur:
                _rcur.execute("SELECT DISTINCT connection_id FROM snaptrade_accounts "
                              "WHERE status='active' AND connection_id IS NOT NULL "
                              "AND account_id NOT LIKE 'demo-%'")
                _conn_ids = [r[0] for r in _rcur.fetchall()]
            for _cid in _conn_ids:
                try:
                    _st.refresh_connection(uid, secret, _cid)
                    _refreshed += 1
                except Exception as _re:
                    print(f"[snaptrade] refresh {_cid} failed: {_snaptrade_error_detail(_re)}", flush=True)
        except Exception as _re:
            print(f"[snaptrade] refresh stage skipped: {_re!s:.150}", flush=True)
        if _refreshed:
            _kv_put("snaptrade.last_refresh", time.time())
            # SnapTrade's brokerage re-pull is async — give it time to land
            # before importing. Background job, so the wait costs nothing.
            for _w in range(45, 0, -15):
                _snaptrade_sync_stage(f"Fidelity refresh in flight… importing in {_w}s")
                time.sleep(15)

    accts = _st.list_accounts(uid, secret)
    if isinstance(accts, dict):
        accts = accts.get("accounts") or accts.get("data") or []
    _ensure_snaptrade_tables()
    out = []
    errors = []
    acct_norm = {}   # account_id -> normalized positions, for the tax_lots bridge
    # ONE autocommit connection for the whole account loop (was: two fresh
    # connections per account — TLS setup per iteration). Autocommit keeps a
    # failed statement from poisoning the rest of the loop.
    _loop_conn = _fund_conn()
    _loop_conn.autocommit = True
    _loop_cur = _loop_conn.cursor()
    for acct in (accts or []):
        if not isinstance(acct, dict):
            continue
        acct_id = acct.get("id")
        if not acct_id:
            continue
        _snaptrade_sync_stage(f"Pulling holdings ({(acct.get('name') or str(acct_id)[-4:])})…")
        # Per-account holdings (get_all_user_holdings is deprecated).
        try:
            ah = _st.get_account_holdings(uid, secret, acct_id)
        except Exception as e:
            print(f"[snaptrade] holdings {acct_id}: {e!s:.140}", flush=True)
            errors.append({"account_id": acct_id, "error": _snaptrade_error_detail(e)})
            ah = {}
        # Merge: list_user_accounts has the richest account metadata (number,
        # institution, brokerage_authorization); holdings response has positions.
        merged = {
            "account": acct,
            "positions": (ah.get("positions") if isinstance(ah, dict) else None) or [],
            "total_value": (ah.get("total_value") if isinstance(ah, dict) else None),
        }
        norm = _snaptrade_normalize_account(merged)
        if not norm.get("account_id"):
            norm["account_id"] = str(acct_id)
        # NOTE (ui353): option positions are NOT fetched here anymore — Alec's
        # rule: options logic runs ONLY on explicit Options-tab use. The wheel
        # scan fetches option holdings live at scan-click time
        # (_snaptrade_short_options_map). Balance snapshots are unaffected:
        # they prefer the brokerage-reported account total, which already
        # includes short-option liabilities.
        # Daily balance snapshot — the raw series for the automatic returns path.
        # Prefer the brokerage-reported account total (includes short option
        # liabilities, matching Fidelity's balance page); fall back to our sum.
        snap_val = None
        bal = acct.get("balance")
        if isinstance(bal, dict):
            tot = bal.get("total")
            snap_val = tot.get("amount") if isinstance(tot, dict) else tot
        if snap_val is None:
            snap_val = norm["total_value"]
        # Guard: a failed/initial pull can yield 0.0 (no positions, no balance).
        # Writing that as a real snapshot would poison the month's Dietz return
        # (-100% at a month boundary) — skip zero/negative totals entirely.
        try:
            if snap_val is not None and float(snap_val) <= 0:
                snap_val = None
        except (TypeError, ValueError):
            snap_val = None
        if snap_val is not None:
            try:
                _loop_cur.execute("""
                    INSERT INTO snaptrade_balances (account_id, d, total_value, synced_at)
                    VALUES (%s, %s, %s, now())
                    ON CONFLICT (account_id, d) DO UPDATE
                      SET total_value = EXCLUDED.total_value, synced_at = now()
                """, (norm["account_id"], _snaptrade_pacific_today(), float(snap_val)))
            except Exception as e:
                errors.append({"account_id": norm["account_id"], "stage": "balance_snapshot",
                               "error": _snaptrade_error_detail(e)})
        try:
            _loop_cur.execute("""
                INSERT INTO snaptrade_accounts (account_id, connection_id, brokerage_name,
                                                account_name, account_mask, total_value,
                                                holdings_json, status, last_synced_at, updated_at)
                VALUES (%s,%s,%s,%s,%s,%s, %s::jsonb, 'active', now(), now())
                ON CONFLICT (account_id) DO UPDATE SET
                    connection_id=EXCLUDED.connection_id, brokerage_name=EXCLUDED.brokerage_name,
                    account_name=EXCLUDED.account_name, account_mask=EXCLUDED.account_mask,
                    total_value=EXCLUDED.total_value, holdings_json=EXCLUDED.holdings_json,
                    status='active', last_synced_at=now(), updated_at=now()
            """, (norm["account_id"], norm["connection_id"], norm["brokerage"],
                  norm["account_name"], norm["account_mask"], norm["total_value"],
                  json.dumps(norm["positions"], default=str)))
        except Exception as e:
            errors.append({"account_id": norm["account_id"], "stage": "account_upsert",
                           "error": _snaptrade_error_detail(e)})
            continue
        # After a key-swap reset, account ids change — restore the saved
        # fund assignment by mask+name so the user doesn't have to re-pick.
        # Consumed one key at a time so it never fights a manual unassign.
        try:
            backup = _kv_get("snaptrade.assignment_backup") or {}
            bkey = f"{norm.get('account_mask') or ''}|{(norm.get('account_name') or '').strip().lower()}"
            if backup.get(bkey):
                _loop_cur.execute("UPDATE snaptrade_accounts SET fund_id=%s, updated_at=now() "
                                  "WHERE account_id=%s AND fund_id IS NULL",
                                  (backup[bkey], norm["account_id"]))
                if _loop_cur.rowcount:
                    print(f"[snaptrade] restored assignment {bkey} → {backup[bkey]}", flush=True)
                backup.pop(bkey, None)
                _kv_put("snaptrade.assignment_backup", backup)
        except Exception:
            pass
        acct_norm[norm["account_id"]] = norm["positions"]
        out.append({"account_id": norm["account_id"], "account_name": norm["account_name"],
                    "brokerage": norm["brokerage"], "positions": norm["count"],
                    "total_value": norm["total_value"]})
    try:
        _loop_cur.close()
        _loop_conn.close()
    except Exception:
        pass

    # ── Bridge: push assigned accounts' holdings into tax_lots (live positions) ──
    # Group by fund (a fund may have >1 linked account) and write once per fund.
    _snaptrade_sync_stage("Updating positions…")
    lots_written = []
    try:
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("SELECT account_id, fund_id FROM snaptrade_accounts "
                        "WHERE status='active' AND fund_id IS NOT NULL "
                        "AND account_id NOT LIKE 'demo-%'")
            by_fund = {}
            for r in cur.fetchall():
                if r["account_id"] in acct_norm:
                    by_fund.setdefault(str(r["fund_id"]), []).extend(acct_norm[r["account_id"]])
            for fid, poss in by_fund.items():
                try:
                    n = _snaptrade_write_lots(cur, fid, poss)
                    lots_written.append({"fund_id": fid, "lots": n})
                except Exception as e:
                    errors.append({"fund_id": fid, "error": _snaptrade_error_detail(e)})
            conn.commit()
    except Exception as e:
        import traceback; traceback.print_exc()
        errors.append({"stage": "tax_lots", "error": _snaptrade_error_detail(e)})

    # ── Activities (automatic) — Jan-1 backfill on first sync, then 35-day
    # incremental. Gated on the free plan; the ingester reports that once with
    # a production-key hint instead of failing the sync.
    _snaptrade_sync_stage("Importing activity…")
    activities = []
    try:
        activities, act_errors = _snaptrade_ingest_activities(uid, secret, list(acct_norm.keys()))
        errors.extend(act_errors)
    except Exception as e:
        errors.append({"stage": "activities", "error": _snaptrade_error_detail(e)})

    # ── Balance history (automatic) — synthesize monthly records after the last
    # CSV month for every assigned managed account, then refresh its YTD cache.
    balance_history = []
    try:
        # Prewarm the SPY benchmark cache (900s TTL) so the overview computed
        # inside the transaction below never does network I/O while holding
        # row locks — un-timed-out yfinance calls have hung endpoints before.
        try:
            get_spy_monthly_data()
        except Exception:
            pass
        # Prewarm Jan-1 closes for attribution OUTSIDE the rebuild transaction.
        # Lean per-symbol fetch (~5 weeks of bars, ~20 rows) with a HARD 30s
        # total budget — the first version of this used _sync_price_history
        # (11-YEAR backfill per symbol × 40) and wedged the app.
        _snaptrade_sync_stage("Fetching Jan-1 prices (first runs only)…")
        try:
            _yr = datetime.utcnow().year
            _jan1 = f"{_yr}-01-01"
            _need = set()
            with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
                cur.execute("SELECT DISTINCT fund_id FROM snaptrade_accounts "
                            "WHERE status='active' AND fund_id IS NOT NULL")
                _cands = set()
                for _fr in cur.fetchall():
                    for s, h in _snaptrade_fund_holdings(cur, str(_fr["fund_id"])).items():
                        if h.get("asset_class") in ("cash", "option") or _snaptrade_cashlike(s):
                            continue
                        _cands.add(s)
                # CLOSED positions need Jan-1 closes too — attribution rewinds
                # every symbol TRADED this year, not just current holdings
                # (the prewarm skipping exits left WBD/TSM/NKE priceless → null).
                # Include UNASSIGNED (donor) accounts too — predecessor
                # adoption surfaces their exits (e.g. WBD) in successor funds.
                cur.execute("""SELECT DISTINCT a.symbol FROM snaptrade_activities a
                                 JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
                                WHERE sa.status = 'active' AND a.symbol IS NOT NULL
                                  AND a.trade_date >= %s
                                  AND (a.raw_json ->> 'option_symbol') IS NULL""", (_jan1,))
                for r in cur.fetchall():
                    s = (r["symbol"] or "").strip()
                    if (re.fullmatch(r"[A-Z][A-Z0-9.\-]{0,9}", s)
                            and not any(c.isdigit() for c in s[:4])
                            and not _snaptrade_cashlike(s)):
                        _cands.add(s)
                # One-time forced re-warm (v2 = split-ADJUSTED closes): rows
                # fetched before ui361 may hold raw pre-split Jan-1 prices
                # (BSX $95 vs true ~$47) — refetch EVERY candidate once, then
                # go back to missing-only.
                _rewarm_key = "price_history.jan1_adjusted_rewarm"
                try:
                    _force_all = str(_kv_get(_rewarm_key) or "") != f"{_yr}-v2"
                except Exception:
                    _force_all = False
                if _force_all:
                    _need = set(_cands)
                else:
                    for s in _cands:
                        cur.execute("SELECT 1 FROM price_history WHERE symbol=%s AND d <= %s LIMIT 1",
                                    (s, _jan1))
                        if not cur.fetchone():
                            _need.add(s)
            # Skip symbols that already failed twice this process — a handful
            # of permanently-failing names used to burn the whole alphabetical
            # budget every sync, starving the tail (WBD never got its Jan-1
            # close). Fresh names go first for the same reason.
            _order = sorted(_need, key=lambda s: (_JAN1_FAIL.get(s, 0), s))
            _budget_end = time.time() + 75
            _warmed = 0
            _budget_hit = False
            for s in _order:
                if _JAN1_FAIL.get(s, 0) >= 2:
                    continue
                if time.time() > _budget_end:
                    _budget_hit = True
                    print(f"[snaptrade] jan1 prewarm budget hit — {_warmed}/{len(_need)} done, "
                          "rest next sync", flush=True)
                    break
                _builder_call_timeout(lambda tk=s: _sync_jan1_close(tk, _yr), 6.0, None)
                _warmed += 1
                with _fund_conn() as conn, conn.cursor() as cur:
                    cur.execute("SELECT 1 FROM price_history WHERE symbol=%s AND d <= %s LIMIT 1",
                                (s, _jan1))
                    if cur.fetchone():
                        _JAN1_FAIL.pop(s, None)
                    else:
                        _JAN1_FAIL[s] = _JAN1_FAIL.get(s, 0) + 1
            if _force_all and not _budget_hit:
                try:
                    _kv_put(_rewarm_key, f"{_yr}-v2")
                    print("[snaptrade] jan1 adjusted re-warm complete", flush=True)
                except Exception:
                    pass
            if _need:
                print(f"[snaptrade] jan1 closes prewarmed: {_warmed}/{len(_need)}", flush=True)
        except Exception as _e:
            print(f"[snaptrade] jan1 prewarm skipped: {_e!s:.120}", flush=True)
        _snaptrade_sync_stage("Rebuilding balance history & attribution…")
        with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
            cur.execute("SELECT DISTINCT fund_id FROM snaptrade_accounts "
                        "WHERE status='active' AND fund_id IS NOT NULL")
            fids = [str(r["fund_id"]) for r in cur.fetchall()]
            for fid in fids:
                try:
                    cur.execute("SAVEPOINT snap_bh")
                    h = _snaptrade_rebuild_balance_history(cur, fid)
                    cur.execute("RELEASE SAVEPOINT snap_bh")
                    if h:
                        balance_history.append(h)
                except Exception as e:
                    try:
                        cur.execute("ROLLBACK TO SAVEPOINT snap_bh")
                    except Exception:
                        pass
                    errors.append({"fund_id": fid, "stage": "balance_history",
                                   "error": _snaptrade_error_detail(e)})
            conn.commit()
    except Exception as e:
        errors.append({"stage": "balance_history", "error": _snaptrade_error_detail(e)})

    return {"ok": True, "synced": out, "errors": errors, "lots_written": lots_written,
            "activities": activities, "balance_history": balance_history}


# Single-slot sync job (one GP). A full sync legitimately takes minutes
# (per-account SnapTrade calls + activities + rebuild) — riding one HTTP
# request through Railway's edge proxy produced plain-text "upstream error"
# timeouts in the browser. POST starts (or joins) the job; GET polls it.
_SNAPTRADE_SYNC_JOB: dict = {}


def _snaptrade_sync_stage(label: str) -> None:
    """Progress note for the sync job — shown live on the Sync buttons so a
    long first-of-day sync (activity backfill, Jan-1 price prewarm) reads as
    progress instead of a stuck timer."""
    try:
        if _SNAPTRADE_SYNC_JOB.get("status") == "running":
            _SNAPTRADE_SYNC_JOB["stage"] = label
    except Exception:
        pass


def _snaptrade_sync_job_runner(job_id: str) -> None:
    _SNAPTRADE_SYNC_JOB.update({"job_id": job_id, "status": "running", "stage": None,
                                "started_at": time.time(), "result": None, "error": None})
    try:
        res = _snaptrade_run_sync()
        _SNAPTRADE_SYNC_JOB.update({"status": "done", "result": res,
                                    "finished_at": time.time()})
        # Manual syncs refresh the Data Health record too — a stale scheduler
        # "failed" used to linger on the card while button syncs worked fine.
        n_ok = len(res.get("synced", []) or [])
        n_err = len(res.get("errors", []) or [])
        _automation_record_run(
            "snaptrade_sync", n_ok > 0,
            f"manual · {n_ok} accounts" + (f" · {n_err} warning(s)" if n_err else ""))
    except Exception as e:
        import traceback; traceback.print_exc()
        detail = _snaptrade_error_detail(e)
        if _snaptrade_user_invalid(detail):
            detail = ("SnapTrade key changed: the stored user belongs to the previous "
                      "client id. Click “+ Connect Fidelity” to re-link — it resets "
                      "automatically and your account assignments are restored on the "
                      "next sync.")
        _SNAPTRADE_SYNC_JOB.update({"status": "error", "error": detail,
                                    "finished_at": time.time()})
        _automation_record_run("snaptrade_sync", False, f"manual · {detail[:300]}")


@app.post("/api/snaptrade/sync")
def snaptrade_sync(request: Request, background_tasks: BackgroundTasks):
    if _request_is_demo(request):
        return {"ok": True, "job_id": "demo-sync", "status": "done",
                "note": "Demo accounts are always in sync — sample data refreshes nightly."}
    """GP-only: START a background holdings/activities/balances sync and return
    immediately with {job_id}. Poll GET /api/snaptrade/sync-status. If a sync
    is already running, joins it (the connect flow polls aggressively)."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    j = _SNAPTRADE_SYNC_JOB
    if j.get("status") == "running" and time.time() - (j.get("started_at") or 0) < 600:
        return {"ok": True, "async": True, "job_id": j.get("job_id"), "status": "running"}
    import uuid as _uuid
    job_id = "SNAPSYNC_" + _uuid.uuid4().hex[:10]
    # Claim the slot BEFORE returning — BackgroundTasks start after the
    # response, and a fast poll must not read the previous job's "done".
    _SNAPTRADE_SYNC_JOB.update({"job_id": job_id, "status": "running", "stage": None,
                                "started_at": time.time(), "result": None, "error": None})
    background_tasks.add_task(_snaptrade_sync_job_runner, job_id)
    return {"ok": True, "async": True, "job_id": job_id, "status": "running"}


@app.get("/api/snaptrade/sync-status")
def snaptrade_sync_status(request: Request):
    """GP-only: state of the current/most-recent sync job."""
    _plaid_require_gp(request)
    if _request_is_demo(request):
        return {"ok": True, "status": "done", "stage": "Demo data is static",
                "finished_at": datetime.utcnow().isoformat(),
                "result": {"ok": True, "note": "demo"}}
    j = _SNAPTRADE_SYNC_JOB
    if not j:
        return {"ok": True, "status": "idle"}
    out = {"ok": True, "status": j.get("status"), "job_id": j.get("job_id"),
           "stage": j.get("stage"),
           "elapsed_s": round(time.time() - (j.get("started_at") or time.time()))}
    if j.get("status") == "done":
        out["result"] = j.get("result")
    if j.get("status") == "error":
        out["error"] = j.get("error")
    return out


@app.post("/api/snaptrade/refresh")
def snaptrade_refresh(request: Request):
    """GP-only: ask SnapTrade to RE-PULL Fidelity now (our ↻ Sync only reads
    SnapTrade's cache; this forces SnapTrade to fetch fresh from the brokerage).
    Async on SnapTrade's side — sync again ~30-60s later. May be rate-limited on
    the free tier."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    import snaptrade_link as _st
    uid, secret = _snaptrade_ensure_user()
    _ensure_snaptrade_tables()
    with _fund_conn() as conn, conn.cursor() as cur:
        cur.execute("SELECT DISTINCT connection_id FROM snaptrade_accounts "
                    "WHERE status='active' AND connection_id IS NOT NULL")
        conn_ids = [r[0] for r in cur.fetchall()]
    if not conn_ids:
        return {"ok": True, "refreshed": 0, "note": "No connections to refresh."}
    refreshed, errors = [], []
    for cid in conn_ids:
        try:
            _st.refresh_connection(uid, secret, cid)
            refreshed.append(cid)
        except Exception as e:
            errors.append({"connection_id": cid, "error": _snaptrade_error_detail(e)})
    print(f"⟳ [snaptrade] refresh: {len(refreshed)} ok, {len(errors)} err", flush=True)
    return {"ok": True, "refreshed": len(refreshed), "errors": errors}


@app.post("/api/snaptrade/activities/sync")
def snaptrade_activities_sync(request: Request):
    """GP-only: pull transaction history (YTD by default) for every connected
    account into snaptrade_activities. Body (optional): {start_date, end_date}
    as YYYY-MM-DD. Idempotent — upserts by SnapTrade activity id."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    import snaptrade_link as _st
    try:
        body = _request_json_sync(request)
    except Exception:
        body = {}
    year  = datetime.utcnow().year
    start = (body or {}).get("start_date") or f"{year}-01-01"
    end   = (body or {}).get("end_date")   or datetime.utcnow().date().isoformat()
    _ensure_snaptrade_tables()
    uid, secret = _snaptrade_ensure_user()
    with _fund_conn() as conn, conn.cursor() as cur:
        cur.execute("SELECT account_id FROM snaptrade_accounts WHERE status='active' "
                    "AND account_id NOT LIKE 'demo-%'")
        acct_ids = [r[0] for r in cur.fetchall()]
    out, errors = _snaptrade_ingest_activities(uid, secret, acct_ids, start, end)
    return {"ok": True, "start_date": start, "end_date": end, "synced": out, "errors": errors}


@app.get("/api/snaptrade/activities-probe")
def snaptrade_activities_probe(request: Request):
    """GP-only diagnostic: which transaction/activity SDK methods exist and what
    each returns for the first account — to find a non-gated path."""
    _plaid_require_gp(request)
    import snaptrade_link as _st
    uid, secret = _snaptrade_ensure_user()
    accts = _st.list_accounts(uid, secret)
    if isinstance(accts, dict):
        accts = accts.get("accounts") or accts.get("data") or []
    if not accts:
        return {"ok": True, "note": "No accounts."}
    aid = (accts[0] or {}).get("id")
    year = datetime.utcnow().year
    try:
        rep = _st.probe_activity_methods(uid, secret, aid,
                                         start_date=f"{year}-01-01",
                                         end_date=datetime.utcnow().date().isoformat())
    except Exception as e:
        raise HTTPException(502, f"probe failed: {_snaptrade_error_detail(e)}")
    return {"ok": True, "account_id": aid, **rep}


@app.get("/api/snaptrade/activities")
def snaptrade_activities_list(request: Request, fund_id: str = None, year: int = None):
    """GP-only: YTD activity feed joined to fund assignment, with buy/sell/flow
    aggregates. Optional ?fund_id= and ?year= (defaults to current year)."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return {"ok": True, "activities": [], "summary": {}}
    _ensure_snaptrade_tables()
    yr = int(year) if year else datetime.utcnow().year
    sql = """SELECT a.activity_id, a.account_id, a.trade_date, a.type, a.symbol,
                    a.description, a.units, a.price, a.amount, a.fee,
                    sa.fund_id, sa.account_name, sa.brokerage_name
               FROM snaptrade_activities a
               JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
              WHERE EXTRACT(YEAR FROM a.trade_date) = %s"""
    params = [yr]
    if fund_id:
        sql += " AND sa.fund_id = %s"
        params.append(fund_id)
    sql += " ORDER BY a.trade_date DESC, a.activity_id"
    acts = []
    with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
        cur.execute(sql, params)
        for r in cur.fetchall():
            acts.append({
                "activity_id": r["activity_id"], "account_id": r["account_id"],
                "fund_id": str(r["fund_id"]) if r["fund_id"] else None,
                "account_name": r["account_name"], "brokerage": r["brokerage_name"],
                "trade_date": r["trade_date"].isoformat() if r["trade_date"] else None,
                "type": r["type"], "symbol": r["symbol"], "description": r["description"],
                "units": float(r["units"]) if r["units"] is not None else None,
                "price": float(r["price"]) if r["price"] is not None else None,
                "amount": float(r["amount"]) if r["amount"] is not None else None,
                "fee": float(r["fee"]) if r["fee"] is not None else None,
            })
    # Aggregates
    buy_val = sell_val = net_flow = 0.0
    buy_n = sell_n = 0
    by_symbol = {}
    for a in acts:
        t = a["type"] or ""
        gross = (a["units"] or 0) * (a["price"] or 0)
        if t in _SNAP_BUY_TYPES:
            buy_val += gross; buy_n += 1
            by_symbol.setdefault(a["symbol"], {"buy_units": 0.0, "sell_units": 0.0})["buy_units"] += (a["units"] or 0)
        elif t in _SNAP_SELL_TYPES:
            sell_val += gross; sell_n += 1
            by_symbol.setdefault(a["symbol"], {"buy_units": 0.0, "sell_units": 0.0})["sell_units"] += (a["units"] or 0)
        elif t in _SNAP_FLOW_TYPES:
            net_flow += (a["amount"] or 0)
    return {"ok": True, "year": yr, "count": len(acts), "activities": acts,
            "summary": {"buy_count": buy_n, "buy_value": round(buy_val, 2),
                        "sell_count": sell_n, "sell_value": round(sell_val, 2),
                        "net_external_flow": round(net_flow, 2),
                        "by_symbol": by_symbol}}


def _snaptrade_fund_holdings(cur, fund_id: str) -> dict:
    """Aggregate current holdings (qty + last price) per symbol across every active
    account assigned to fund_id. `cur` must be a RealDictCursor."""
    cur.execute("SELECT holdings_json FROM snaptrade_accounts WHERE status='active' AND fund_id=%s",
                (fund_id,))
    agg = {}
    for r in cur.fetchall():
        hj = r["holdings_json"]
        if isinstance(hj, str):
            try: hj = json.loads(hj)
            except Exception: hj = []
        for p in (hj or []):
            sym = (p.get("symbol") or "").strip()
            if not sym or sym == "—":
                continue
            q = _snaptrade_num(p.get("quantity")) or 0.0
            e = agg.setdefault(sym, {"qty": 0.0, "price": _snaptrade_num(p.get("price")),
                                     "asset_class": p.get("asset_class"), "name": p.get("name")})
            e["qty"] += q
            if e["price"] is None:
                e["price"] = _snaptrade_num(p.get("price"))
    return agg


@app.get("/api/snaptrade/ytd-reconstruct")
def snaptrade_ytd_reconstruct(request: Request, fund_id: str, year: int = None):
    """GP-only DIAGNOSTIC: reconstruct a fund's Jan-1 equity value by rewinding YTD
    trades, price it from price_history, and compare a reconstructed YTD price-return
    to the CSV's official figure — to decide whether SnapTrade can drive a CSV-free
    YTD. Equity-only: ignores cash, dividends, and intra-period flow timing (noted)."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    _ensure_snaptrade_tables()
    yr   = int(year) if year else datetime.utcnow().year
    jan1 = f"{yr}-01-01"
    with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
        holdings = _snaptrade_fund_holdings(cur, fund_id)
        if not holdings:
            return {"ok": True, "fund_id": fund_id, "note": "No SnapTrade holdings assigned to this fund."}
        # External cash flows YTD (contributions/withdrawals/transfers).
        net_units, buy_gross, sell_gross, net_flow = {}, 0.0, 0.0, 0.0
        cur.execute("""
            SELECT a.type, COALESCE(SUM(a.amount),0) AS amt
              FROM snaptrade_activities a
              JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
             WHERE sa.fund_id = %s AND a.trade_date >= %s
             GROUP BY a.type
        """, (fund_id, jan1))
        for fr in cur.fetchall():
            if (fr["type"] or "") in _SNAP_FLOW_TYPES:
                net_flow += float(fr["amt"] or 0)
        # Net YTD units + gross trade value per symbol (buy +, sell −).
        cur.execute("""
            SELECT a.symbol, a.type,
                   COALESCE(SUM(a.units), 0)          AS units,
                   COALESCE(SUM(a.units * a.price), 0) AS gross
              FROM snaptrade_activities a
              JOIN snaptrade_accounts sa ON sa.account_id = a.account_id
             WHERE sa.fund_id = %s AND a.trade_date >= %s
             GROUP BY a.symbol, a.type
        """, (fund_id, jan1))
        for r in cur.fetchall():
            t, sym = (r["type"] or ""), r["symbol"]
            u, g = float(r["units"] or 0), float(r["gross"] or 0)
            if t in _SNAP_BUY_TYPES:
                net_units[sym] = net_units.get(sym, 0.0) + u; buy_gross += g
            elif t in _SNAP_SELL_TYPES:
                net_units[sym] = net_units.get(sym, 0.0) - u; sell_gross += g

        rows, jan1_equity, now_equity, priced = [], 0.0, 0.0, True
        for sym, h in holdings.items():
            if h.get("asset_class") == "cash":
                continue
            now_qty = h["qty"]; now_px = h["price"] or 0.0
            now_equity += now_qty * now_px
            jan1_qty = now_qty - net_units.get(sym, 0.0)
            try: _sync_price_history(sym)
            except Exception: pass
            cur.execute("SELECT close FROM price_history WHERE symbol=%s AND d <= %s ORDER BY d DESC LIMIT 1",
                        (sym, jan1))
            pr = cur.fetchone()
            jp = float(pr["close"]) if pr and pr["close"] is not None else None
            if jp is None:
                priced = False
            else:
                jan1_equity += jan1_qty * jp
            rows.append({"symbol": sym, "now_qty": round(now_qty, 4),
                         "jan1_qty": round(jan1_qty, 4), "jan1_close": jp,
                         "now_price": now_px, "net_ytd_units": round(net_units.get(sym, 0.0), 4)})
        # CSV official YTD for comparison
        csv_ytd = None
        try:
            cur.execute("SELECT ytd_pct FROM managed_account_ytd_cache WHERE fund_id=%s", (fund_id,))
            cr = cur.fetchone()
            if cr and cr["ytd_pct"] is not None:
                csv_ytd = float(cr["ytd_pct"])
        except Exception:
            pass

    net_invested = buy_gross - sell_gross          # net cash deployed into securities YTD
    price_gain   = now_equity - jan1_equity - net_invested
    recon_pct    = (price_gain / jan1_equity * 100.0) if jan1_equity else None
    return {
        "ok": True, "fund_id": fund_id, "year": yr,
        "fully_priced": priced,
        "jan1_equity": round(jan1_equity, 2), "now_equity": round(now_equity, 2),
        "net_securities_invested_ytd": round(net_invested, 2),
        "net_external_flow_ytd": round(net_flow, 2),
        "reconstructed_ytd_price_pct": round(recon_pct, 2) if recon_pct is not None else None,
        "csv_ytd_pct": csv_ytd,
        "diff_vs_csv": (round(recon_pct - csv_ytd, 2) if (recon_pct is not None and csv_ytd is not None) else None),
        "caveats": "Equity-only: excludes cash, dividends/interest, and intra-period flow timing. "
                   "CSV YTD is a total time-weighted return, so a few-point gap is expected.",
        "holdings_rewound": sorted(rows, key=lambda x: -(x["now_qty"] * (x["now_price"] or 0))),
    }


@app.get("/api/snaptrade/accounts")
def snaptrade_accounts(request: Request):
    """GP-only: stored SnapTrade accounts + normalized positions + managed accounts
    for the assign dropdown. No secrets returned."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        return {"ok": True, "accounts": []}
    _ensure_snaptrade_tables()
    out = []
    with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
        cur.execute("""SELECT account_id, connection_id, brokerage_name, account_name,
                              account_mask, total_value, holdings_json, fund_id, last_synced_at,
                              COALESCE(hidden, FALSE) AS hidden
                         FROM snaptrade_accounts WHERE status='active'
                           AND (account_id LIKE 'demo-%%') = %s
                         ORDER BY COALESCE(hidden, FALSE), created_at""",
                    (_request_is_demo(request),))
        for r in cur.fetchall():
            out.append({
                "account_id":    r["account_id"],
                "connection_id": r["connection_id"],
                "brokerage":     r["brokerage_name"],
                "account_name":  r["account_name"],
                "account_mask":  r["account_mask"],
                "total_value":   float(r["total_value"]) if r["total_value"] is not None else None,
                "positions":     r["holdings_json"] or [],
                "fund_id":       str(r["fund_id"]) if r["fund_id"] else None,
                "last_synced_at": r["last_synced_at"].isoformat() if r["last_synced_at"] else None,
                "hidden":        bool(r["hidden"]),
            })
    return {"ok": True, "accounts": out, "managed_accounts": _plaid_managed_accounts()}


@app.get("/api/snaptrade/debug")
def snaptrade_debug(request: Request):
    """GP-only diagnostic: the raw holdings shape for the first connected account,
    so we can tell whether positions are genuinely empty (SnapTrade still pulling /
    test-key gating) vs a parsing issue. Truncated; no secrets returned."""
    _plaid_require_gp(request)
    import snaptrade_link as _st
    try:
        uid, secret = _snaptrade_ensure_user()
        accts = _st.list_accounts(uid, secret)
    except Exception as e:
        raise HTTPException(502, f"SnapTrade accounts failed: {_snaptrade_error_detail(e)}")
    if isinstance(accts, dict):
        accts = accts.get("accounts") or accts.get("data") or []
    if not accts:
        return {"ok": True, "accounts": 0, "note": "SnapTrade returned no accounts."}
    # Probe EVERY account so a single failing one (e.g. ANAT-IRA) is visible.
    per_account = []
    for acct in accts:
        if not isinstance(acct, dict):
            continue
        aid = acct.get("id")
        row = {"account_id": aid, "name": acct.get("name"),
               "institution": acct.get("institution_name"),
               "number": _snaptrade_mask(acct.get("number")),
               "sync_status": acct.get("sync_status")}
        try:
            ah = _st.get_account_holdings(uid, secret, aid)
            poss = (ah.get("positions") if isinstance(ah, dict) else None) or []
            row["positions_count"] = len(poss)
            row["total_value"] = ah.get("total_value") if isinstance(ah, dict) else None
        except Exception as e:
            row["error"] = _snaptrade_error_detail(e)
        # Deep-probe any account that came back empty: what's REALLY in it?
        if row.get("positions_count") == 0 and not row.get("error"):
            try:
                opts = _st.get_option_holdings(uid, secret, aid)
                if isinstance(opts, dict):
                    opts = opts.get("option_positions") or opts.get("data") or []
                row["option_holdings_count"] = len(opts) if isinstance(opts, list) else None
                row["first_option"] = str(opts[0])[:1500] if opts else None
            except Exception as e:
                row["option_error"] = _snaptrade_error_detail(e)
            try:
                row["raw_balances"] = str(_st.get_balances(uid, secret, aid))[:1500]
            except Exception as e:
                row["balance_error"] = _snaptrade_error_detail(e)
        per_account.append(row)
    acct0 = accts[0] if isinstance(accts[0], dict) else {}
    return {"ok": True, "accounts": len(accts),
            "account_keys": sorted([str(k) for k in acct0.keys()]),
            "per_account": per_account}


@app.post("/api/snaptrade/assign")
def snaptrade_assign(request: Request):
    """GP-only: link (or unlink) a SnapTrade account to a managed account, then
    rewrite the affected fund(s)' live tax_lots so the Positions panel + live NAV
    update immediately (SnapTrade is the live position source for linked funds).
    Does not touch the YTD/all-time CSV path."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    body = _request_json_sync(request)
    account_id = (body or {}).get("account_id")
    fund_id = (body or {}).get("fund_id") or None
    if not account_id:
        raise HTTPException(400, "account_id required")
    _ensure_snaptrade_tables()
    lots = None
    with _fund_conn() as conn, conn.cursor(cursor_factory=_RealDictCursor) as cur:
        if fund_id:
            cur.execute("SELECT 1 FROM funds WHERE id=%s AND fund_type IN ('managed_account','lp_fund')", (fund_id,))
            if not cur.fetchone():
                raise HTTPException(400, "Unknown managed account.")
        cur.execute("SELECT fund_id FROM snaptrade_accounts WHERE account_id=%s", (account_id,))
        prev = cur.fetchone()
        if not prev:
            raise HTTPException(404, "Unknown SnapTrade account.")
        old_fund = str(prev["fund_id"]) if prev["fund_id"] else None
        cur.execute("UPDATE snaptrade_accounts SET fund_id=%s, updated_at=now() WHERE account_id=%s",
                    (fund_id, account_id))
        # Rewrite live lots for every fund whose membership changed.
        try:
            affected = {f for f in (fund_id, old_fund) if f}
            for fid in affected:
                n = _snaptrade_recompute_fund(cur, fid)
                if fid == fund_id:
                    lots = n
        except Exception as e:
            conn.rollback()
            raise HTTPException(500, f"Assignment saved-back failed (tax_lots): {_snaptrade_error_detail(e)}")
        conn.commit()
    return {"ok": True, "account_id": account_id, "fund_id": fund_id, "lots_written": lots}


@app.post("/api/snaptrade/hide")
def snaptrade_hide(request: Request):
    """GP-only: hide (or unhide) a single SnapTrade account from the list without
    touching the brokerage connection. Body: {account_id, hidden}. Hidden accounts
    stay hidden across syncs; unlike Remove, this never drops the connection."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    body = _request_json_sync(request)
    account_id = (body or {}).get("account_id")
    hidden = bool((body or {}).get("hidden", True))
    if not account_id:
        raise HTTPException(400, "account_id required")
    _ensure_snaptrade_tables()
    with _fund_conn() as conn, conn.cursor() as cur:
        cur.execute("UPDATE snaptrade_accounts SET hidden=%s, updated_at=now() WHERE account_id=%s",
                    (hidden, account_id))
        if cur.rowcount == 0:
            raise HTTPException(404, "Unknown SnapTrade account.")
        conn.commit()
    return {"ok": True, "account_id": account_id, "hidden": hidden}


@app.post("/api/snaptrade/remove")
def snaptrade_remove(request: Request):
    """GP-only: disconnect a brokerage connection at SnapTrade and purge its
    accounts. Body: {connection_id}."""
    _plaid_require_gp(request)
    if not (_PSYCOPG2_OK and os.environ.get("DATABASE_URL")):
        raise HTTPException(503, "Database not available.")
    body = _request_json_sync(request)
    connection_id = (body or {}).get("connection_id")
    if not connection_id:
        raise HTTPException(400, "connection_id required")
    import snaptrade_link as _st
    uid, secret = _snaptrade_ensure_user()
    try:
        _st.remove_connection(uid, secret, connection_id)
    except Exception as e:
        print(f"[snaptrade] remove_connection warning {connection_id}: {e!s:.120}", flush=True)
    with _fund_conn() as conn, conn.cursor() as cur:
        cur.execute("DELETE FROM snaptrade_accounts WHERE connection_id=%s", (connection_id,))
        conn.commit()
    return {"ok": True, "removed": connection_id}



# ─────────────────────────────────────────────────────────────────────────────
# Sliw Agent — Edyta Śliwińska corporate representation desk (OPTIONAL)
#
# Isolation guarantees (must not break DGA Capital research/fund):
#   • Fully optional: set SLIW_ENABLED=0 to skip mount entirely
#   • Import failures are swallowed — DGA continues without /sliw
#   • sys.path uses append (never insert(0)) so Sliw never shadows DGA pkgs
#   • Routes only under /sliw and /api/sliw — no DGA route overrides
#   • CRM/data under $STOCKS_FOLDER/sliw-agent/ (or SLIW_DATA_DIR) only
#   • Gamma: shared GAMMA_API_KEY is intentional (same credit pool as DGA research)
#   • Auth allowlist separate from LP fund access
# ─────────────────────────────────────────────────────────────────────────────
_SLIW_ROOT = Path(__file__).resolve().parent.parent / "apps" / "sliw-agent"
_SLIW_WEB = _SLIW_ROOT / "web"


def _sliw_enabled() -> bool:
    """Feature flag. Default on when the app folder exists; set SLIW_ENABLED=0 to kill-switch."""
    flag = (os.environ.get("SLIW_ENABLED") or "1").strip().lower()
    if flag in ("0", "false", "no", "off"):
        return False
    return _SLIW_ROOT.is_dir()


def _mount_sliw_agent() -> None:
    """Best-effort optional mount. Never raises into DGA startup."""
    try:
        if not _sliw_enabled():
            print("[sliw] disabled (SLIW_ENABLED=0 or apps/sliw-agent missing)", flush=True)
            return

        sliw_path = str(_SLIW_ROOT.resolve())
        # APPEND only — never insert(0). Prepending could shadow DGA modules.
        if sliw_path not in sys.path:
            sys.path.append(sliw_path)

        try:
            from sliw_agent.server import create_api_router as _sliw_create_router
            app.include_router(
                _sliw_create_router(),
                prefix="/api/sliw",
                tags=["sliw-agent"],
            )
            print("[sliw] API mounted at /api/sliw (isolated)", flush=True)
        except Exception as _sliw_exc:
            print(f"[sliw] API mount failed (DGA unaffected): {_sliw_exc!r}", flush=True)
            return

        if not _SLIW_WEB.is_dir():
            print("[sliw] web/ missing — API only", flush=True)
            return

        @app.get("/sliw")
        def _sliw_redir():
            return RedirectResponse(url="/sliw/", status_code=307)

        @app.get("/sliw/")
        def _sliw_index(request: Request):
            path = _SLIW_WEB / "index.html"
            if not path.exists():
                raise HTTPException(status_code=404, detail="Sliw Agent UI not found")
            return _shell_response(path, request)

        # Public master PDF for email body links (no login — cold recipients open this)
        @app.get("/sliw/media/master-packages.pdf")
        def _sliw_master_pdf():
            try:
                from sliw_agent.master_deck import master_pdf_exists, master_pdf_path
            except Exception:
                raise HTTPException(status_code=404, detail="PDF module unavailable")
            # master_pdf_exists hydrates from Dropbox /Apps/Sliw when local miss
            if not master_pdf_exists(hydrate=True):
                raise HTTPException(
                    status_code=404,
                    detail="No master PDF uploaded yet. Upload in Sliw → Materials.",
                )
            path = master_pdf_path()
            return FileResponse(
                str(path),
                media_type="application/pdf",
                filename="Edyta_Sliwinska_Corporate_Packages.pdf",
                headers={
                    "Cache-Control": "public, max-age=3600",
                    "Content-Disposition": 'inline; filename="Edyta_Sliwinska_Corporate_Packages.pdf"',
                },
            )

        @app.get("/sliw/{asset_path:path}")
        def _sliw_asset(asset_path: str):
            # Static assets only under apps/sliw-agent/web — no path traversal.
            if not asset_path or ".." in asset_path or asset_path.startswith(("/", "\\")):
                raise HTTPException(status_code=404)
            # media/ is handled above
            if asset_path.startswith("media/"):
                raise HTTPException(status_code=404)
            target = (_SLIW_WEB / asset_path).resolve()
            try:
                target.relative_to(_SLIW_WEB.resolve())
            except ValueError:
                raise HTTPException(status_code=404)
            if not target.is_file():
                raise HTTPException(status_code=404)
            media = None
            headers = {}
            if target.suffix == ".css":
                media = "text/css"
                headers["Cache-Control"] = "no-cache, must-revalidate"
            elif target.suffix == ".js":
                media = "application/javascript"
                headers["Cache-Control"] = "no-cache, must-revalidate"
            elif target.suffix == ".html":
                media = "text/html"
                headers["Cache-Control"] = "no-cache, no-store, must-revalidate"
            return FileResponse(str(target), media_type=media, headers=headers or None)

        print("[sliw] UI mounted at /sliw/ (isolated from /gp /lp /app)", flush=True)
    except Exception as _outer:
        # Absolute last resort — never take down DGA boot
        print(f"[sliw] mount aborted (DGA unaffected): {_outer!r}", flush=True)


_mount_sliw_agent()


if BRANDING_DIR.exists():
    app.mount("/branding", StaticFiles(directory=str(BRANDING_DIR)), name="branding")

if WEB_DIR.exists():
    app.mount("/app", StaticFiles(directory=str(WEB_DIR), html=True), name="web")


# ─────────────────────────────────────────────────────────────────────────────
#  Memory hygiene + Railway cost tracking
#
#  Two related concerns on Railway, where memory is metered and billed:
#    1. The ~14 in-memory job stores (_agentic_jobs, _bjobs, _podcast_jobs, …)
#       accumulate COMPLETED jobs — each holding a full result payload — forever.
#       A janitor thread caps them to their most-recent entries (dicts keep
#       insertion order, so capping drops the oldest, which are long done). The
#       persisted copies (analyst_reviews / strategist_reviews / DB tables) are
#       untouched — only the transient poll-state is trimmed.
#    2. A cost endpoint reads this container's real cgroup metrics and estimates
#       the Railway bill from published per-unit prices. Surfaced in Settings.
# ─────────────────────────────────────────────────────────────────────────────
_APP_START_TS = time.time()

# Transient job stores — poll-state only; safe to cap to recent entries.
_JANITOR_JOB_STORES = (
    "_jobs", "_bulk_reanalyze_jobs", "_pjobs", "_sjobs", "_ijobs", "_bjobs",
    "_podcast_jobs", "_podcast_script_jobs", "_agentic_jobs", "_transcript_jobs",
    "_call_sync_jobs", "_fin_sync_jobs", "_options_scan_jobs", "_market_sync_jobs",
)
# Ticker/key-keyed caches — smaller strings; keep more, but still bounded.
_JANITOR_CACHES = (
    ("_QUOTE_CACHE", 600), ("_NEWS_CACHE", 300), ("_GURUFOCUS_CACHE", 250),
    ("_ticker_meta_cache", 600), ("_summary_cache", 150), ("_bench_monthly_cache", 80),
    ("_INTRADAY_CACHE", 150), ("_PRICE_SYNC_TS", 1500), ("_user_resp_cache", 400),
    ("_IDEA_FEED_CACHE", 50), ("_ytd_bmark_cache", 200), ("_col_exists_cache", 200),
)
_JANITOR_JOB_CAP = 50      # recent jobs to retain per store
_JANITOR_INTERVAL = 600    # seconds between sweeps
_JANITOR_STATS = {"runs": 0, "evicted": 0, "last_run": None, "last_evicted": 0,
                  "trims": 0, "freed_mb_last": None}

# Rolling memory samples (taken each janitor sweep) so the cost projection tracks
# AVERAGE usage — how Railway actually bills (GB-hours) — instead of over-reacting
# to a single instantaneous spike.
_MEM_STATS = {"n": 0, "sum_gb": 0.0, "peak_gb": 0.0, "last_gb": None}


def _malloc_trim() -> "float | None":
    """Return glibc's free-but-retained heap memory to the OS. Python on Linux
    holds freed pandas/yfinance/JSON buffers in per-thread malloc arenas and
    rarely gives them back — this is the main reason a long-lived FastAPI worker's
    RSS balloons to multiple GB and never shrinks. Returns MB freed (best-effort;
    no-op / None off glibc, e.g. macOS)."""
    try:
        import ctypes
        before = _read_first_int("/sys/fs/cgroup/memory.current",
                                 "/sys/fs/cgroup/memory/memory.usage_in_bytes")
        ctypes.CDLL("libc.so.6").malloc_trim(0)
        after = _read_first_int("/sys/fs/cgroup/memory.current",
                                "/sys/fs/cgroup/memory/memory.usage_in_bytes")
        if before and after:
            return round((before - after) / (1024 ** 2), 1)
        return 0.0
    except Exception:
        return None


def _sample_memory() -> None:
    cur = _read_first_int("/sys/fs/cgroup/memory.current",
                          "/sys/fs/cgroup/memory/memory.usage_in_bytes")
    if not cur:
        return
    gb = cur / (1024 ** 3)
    _MEM_STATS["n"] += 1
    _MEM_STATS["sum_gb"] += gb
    _MEM_STATS["last_gb"] = round(gb, 4)
    if gb > _MEM_STATS["peak_gb"]:
        _MEM_STATS["peak_gb"] = round(gb, 4)


def _cap_store(store: dict, max_keep: int) -> int:
    """Bound an in-memory dict to its most-recent ``max_keep`` entries. Python
    dicts preserve insertion order, so popping from the front drops the oldest
    (= longest-finished) entries. Returns the number evicted."""
    evicted = 0
    try:
        while len(store) > max_keep:
            store.pop(next(iter(store)), None)
            evicted += 1
    except Exception:
        pass
    return evicted


def _janitor_store_sizes() -> dict:
    """Live entry counts per tracked store/cache (for the cost panel)."""
    g = globals()
    jobs = {n: len(g[n]) for n in _JANITOR_JOB_STORES if isinstance(g.get(n), dict)}
    caches = {n: len(g[n]) for n, _ in _JANITOR_CACHES if isinstance(g.get(n), dict)}
    return {
        "job_entries":   sum(jobs.values()),
        "cache_entries": sum(caches.values()),
        "jobs":          jobs,
        "caches":        caches,
    }


def _memory_janitor_loop():
    g = globals()
    while True:
        try:
            time.sleep(_JANITOR_INTERVAL)
            evicted = 0
            for name in _JANITOR_JOB_STORES:
                s = g.get(name)
                if isinstance(s, dict):
                    evicted += _cap_store(s, _JANITOR_JOB_CAP)
            for name, cap in _JANITOR_CACHES:
                s = g.get(name)
                if isinstance(s, dict):
                    evicted += _cap_store(s, cap)
            # Reclaim glibc's retained heap back to the OS (the real RSS lever),
            # then sample memory for the rolling average used by the cost panel.
            import gc as _gc
            _gc.collect()
            freed = _malloc_trim()
            _sample_memory()
            _JANITOR_STATS["runs"] += 1
            _JANITOR_STATS["evicted"] += evicted
            _JANITOR_STATS["last_evicted"] = evicted
            _JANITOR_STATS["last_run"] = time.time()
            if freed is not None:
                _JANITOR_STATS["trims"] += 1
                _JANITOR_STATS["freed_mb_last"] = freed
            if evicted or (freed and freed > 1):
                print(f"[memory-janitor] trimmed {evicted} entries, "
                      f"reclaimed {freed} MB to OS", flush=True)
        except Exception as exc:
            print(f"[memory-janitor] {str(exc)[:120]}", flush=True)


threading.Thread(target=_memory_janitor_loop, daemon=True, name="memory-janitor").start()


# ── Railway cost estimation ──────────────────────────────────────────────────
# Published Railway usage prices (overridable via env for plan changes).
def _envf(name: str, default: float) -> float:
    try:
        return float(os.environ.get(name, "") or default)
    except (TypeError, ValueError):
        return default


def _read_first_int(*paths) -> "int | None":
    for p in paths:
        try:
            with open(p) as fh:
                return int(fh.read().strip())
        except Exception:
            continue
    return None


def _cgroup_cpu_usec() -> "int | None":
    # cgroup v2: cpu.stat "usage_usec"; v1: cpuacct.usage (nanoseconds).
    try:
        with open("/sys/fs/cgroup/cpu.stat") as fh:
            for line in fh:
                if line.startswith("usage_usec"):
                    return int(line.split()[1])
    except Exception:
        pass
    ns = _read_first_int("/sys/fs/cgroup/cpuacct/cpuacct.usage",
                         "/sys/fs/cgroup/cpu/cpuacct.usage")
    return ns // 1000 if ns is not None else None


def _railway_metrics() -> dict:
    """Live resource snapshot for THIS container, read from cgroup + /proc."""
    GB = 1024 ** 3
    mem_cur = _read_first_int("/sys/fs/cgroup/memory.current",
                              "/sys/fs/cgroup/memory/memory.usage_in_bytes")
    mem_max = _read_first_int("/sys/fs/cgroup/memory.max")
    if mem_max is None or mem_max <= 0 or mem_max > (1 << 60):
        mem_max = _read_first_int("/sys/fs/cgroup/memory/memory.limit_in_bytes")
    if mem_max is not None and mem_max > (1 << 60):
        mem_max = None  # "max" / unlimited sentinel

    rss = None
    try:
        with open("/proc/self/status") as fh:
            for line in fh:
                if line.startswith("VmRSS:"):
                    rss = int(line.split()[1]) * 1024
                    break
    except Exception:
        pass

    cpu_usec = _cgroup_cpu_usec()
    uptime = max(1.0, time.time() - _APP_START_TS)
    avg_vcpu = (cpu_usec / 1e6) / uptime if cpu_usec else None

    return {
        "mem_current_bytes": mem_cur,
        "mem_current_gb":    round(mem_cur / GB, 4) if mem_cur else None,
        "mem_limit_bytes":   mem_max,
        "mem_limit_gb":      round(mem_max / GB, 3) if mem_max else None,
        "mem_pct":           round(100 * mem_cur / mem_max, 1) if (mem_cur and mem_max) else None,
        "rss_bytes":         rss,
        "rss_gb":            round(rss / GB, 4) if rss else None,
        "avg_vcpu":          round(avg_vcpu, 4) if avg_vcpu is not None else None,
        "uptime_seconds":    int(uptime),
    }


@app.get("/api/admin/railway-usage")
def railway_usage(request: Request):
    """GP-only: live container resource snapshot + estimated Railway cost,
    plus in-memory store sizes (proof the janitor is keeping memory bounded)."""
    claims = _claims_or_401(request)
    if claims.get("role") not in ("gp", "admin"):
        raise HTTPException(403, "GP access required")

    m = _railway_metrics()

    price_mem  = _envf("RAILWAY_PRICE_MEM_GB_MONTH", 10.0)   # $/GB/month
    price_cpu  = _envf("RAILWAY_PRICE_VCPU_MONTH", 20.0)     # $/vCPU/month
    base_fee   = _envf("RAILWAY_BASE_FEE_MONTH", 0.0)        # flat plan fee, if any
    incl_credit = _envf("RAILWAY_INCLUDED_CREDIT", 0.0)      # plan-included usage credit

    cur_gb   = m["mem_current_gb"] or 0.0
    avg_gb   = round(_MEM_STATS["sum_gb"] / _MEM_STATS["n"], 4) if _MEM_STATS["n"] else cur_gb
    peak_gb  = _MEM_STATS["peak_gb"] or cur_gb
    # Bill on AVERAGE memory (Railway meters GB-hours), not the latest snapshot —
    # so a transient spike that glibc hasn't yet released doesn't 4× the estimate.
    mem_gb   = avg_gb or cur_gb
    vcpu     = m["avg_vcpu"] or 0.0
    mem_cost = round(mem_gb * price_mem, 2)
    cpu_cost = round(vcpu * price_cpu, 2)
    usage_month = mem_cost + cpu_cost
    total_month = round(base_fee + max(0.0, usage_month - incl_credit), 2)

    now = datetime.now(timezone.utc)
    if now.month == 12:
        nxt = now.replace(year=now.year + 1, month=1, day=1, hour=0, minute=0, second=0, microsecond=0)
    else:
        nxt = now.replace(month=now.month + 1, day=1, hour=0, minute=0, second=0, microsecond=0)
    month_start = now.replace(day=1, hour=0, minute=0, second=0, microsecond=0)
    days_in_month = (nxt - month_start).days
    frac_elapsed = (now - month_start).total_seconds() / (nxt - month_start).total_seconds()
    mtd = round(total_month * frac_elapsed, 2)

    rw_env = {
        "project":     os.environ.get("RAILWAY_PROJECT_NAME"),
        "service":     os.environ.get("RAILWAY_SERVICE_NAME"),
        "environment": os.environ.get("RAILWAY_ENVIRONMENT_NAME"),
        "region":      os.environ.get("RAILWAY_REPLICA_REGION") or os.environ.get("RAILWAY_REGION"),
        "replica":     os.environ.get("RAILWAY_REPLICA_ID"),
        "deployment":  os.environ.get("RAILWAY_DEPLOYMENT_ID"),
    }
    on_railway = any(rw_env.values()) or os.environ.get("RAILWAY_ENVIRONMENT") is not None

    j = dict(_JANITOR_STATS)
    j["last_run_ago_s"] = int(time.time() - j["last_run"]) if j["last_run"] else None

    return {
        "ok":         True,
        "on_railway": on_railway,
        "env":        rw_env,
        "metrics":    m,
        "prices":     {"mem_gb_month": price_mem, "vcpu_month": price_cpu,
                       "base_fee_month": base_fee, "included_credit": incl_credit},
        "memory": {"current_gb": round(cur_gb, 4), "avg_gb": round(avg_gb, 4),
                   "peak_gb": round(peak_gb, 4), "samples": _MEM_STATS["n"],
                   "billed_gb": round(mem_gb, 4)},
        "cost": {
            "currency":       "USD",
            "memory_month":   mem_cost,
            "cpu_month":      cpu_cost,
            "base_month":     round(base_fee, 2),
            "included_credit": round(incl_credit, 2),
            "usage_month":    round(usage_month, 2),
            "projected_month": total_month,
            "month_to_date":  mtd,
            "per_day":        round(total_month / days_in_month, 2) if days_in_month else None,
            "day_of_month":   now.day,
            "days_in_month":  days_in_month,
            "pct_elapsed":    round(frac_elapsed * 100, 1),
            "remaining_month": round(total_month - mtd, 2),
        },
        "memory_hygiene": {**_janitor_store_sizes(), "janitor": j,
                           "job_cap": _JANITOR_JOB_CAP, "sweep_interval_s": _JANITOR_INTERVAL},
        "activity": {
            "active":               _app_active(),
            "idle_after_s":         _IDLE_AFTER_S,
            "last_activity_ago_s":  (int(time.time() - _LAST_ACTIVITY_TS) if _LAST_ACTIVITY_TS else None),
            "autosync_paused":      (not _app_active()),
            "autosync_runs":        _market_autosync_state.get("runs"),
        },
        "generated_at": now.isoformat(),
        "note": ("Projection bills AVERAGE memory (Railway meters GB-hours) × "
                 "published per-unit prices, so a transient spike doesn't skew it. "
                 "Egress/volume not metered here. Adjust prices via RAILWAY_PRICE_* "
                 "env vars. RSS is reclaimed to the OS every sweep via malloc_trim."),
    }


